class AIBridge:
    """
    Unified AI execution engine with LiteLLM for 100+ model support.
    3 execution paths:
      1. CUA Responses Loop (GPT-5.4 computer use)
      2. LiteLLM function calling (any model with tools)
      3. LiteLLM direct chat (models without tool support)
    """

    def __init__(self, config: Dict = None):
        self.config = config or {}
        self._openai_client = None
        self._openai_api_key = None
        self._compat_gateway_health: Dict[str, Dict[str, Any]] = {}
        self._provider_auth_health: Dict[str, Dict[str, Any]] = {}
        self._setup_litellm()
        self._seed_provider_auth_health_from_recent_logs()
        self._seed_compatible_gateway_health_from_recent_logs()

        # ── v3.0: Agentic Runtime ──
        self._retry_strategy = get_retry_strategy() if _AGENTIC_RUNTIME_AVAILABLE else None
        self._connection_pool: Optional[ConnectionPoolManager] = None
        self._agentic_events: List[Dict[str, Any]] = []  # Buffer for current execution
        # v3.0: Shared aiohttp session for persistent HTTP connection pooling
        # Avoids new TCP+TLS connection per API call (~200ms saved per request)
        self._shared_http_session: Optional[Any] = None
        self._session_lock = asyncio.Lock() if asyncio else None
        # V4.2 OPT: Cache OpenAI clients by (api_key, base_url) to reuse TCP+TLS connections
        self._openai_client_cache: Dict[str, Any] = {}
        # v6.0: per-pipeline-run state. MUST be reset at the start of every
        # new run — otherwise a kill switch armed in run N poisons run N+1.
        self._builder_direct_multifile_disabled = False
        self._builder_empty_batch_count = 0
        self._builder_deferred_context = ""
        # v6.3.1 (maintainer 2026-04-21): config generation id. Bumped by
        # reload_api_config() when the user saves new api_key / base_url.
        # Included in the OpenAI client cache key so post-reload requests
        # build fresh clients while in-flight requests keep their old ones.
        # See reload_api_config docstring for the full Aider/LiteLLM
        # rationale.
        self._config_generation: int = 0

    def reset_per_run_state(self) -> None:
        """Reset per-pipeline-run state so the next run starts clean.

        Called by the orchestrator at the top of `_execute_plan`. Without
        this, a kill switch / empty-batch counter accumulated in run N
        carries over to run N+1 and silently forces every future builder
        onto the slow tool_call path.
        """
        self._builder_direct_multifile_disabled = False
        self._builder_empty_batch_count = 0
        self._builder_deferred_context = ""
        # v6.0 P0-2: drop the cached OpenAI clients so stale TCP connections
        # (e.g. a half-closed stream from a prior run) can't linger. The
        # connection pool inside httpx will re-establish keepalive on first
        # use of the new run — one-time ~80ms cost per endpoint, worth it
        # to kill the edge case where a stuck socket makes run N+1 slow.
        if isinstance(getattr(self, "_openai_client_cache", None), dict):
            for _key, _client in list(self._openai_client_cache.items()):
                try:
                    _close = getattr(_client, "close", None)
                    if callable(_close):
                        _close()
                except Exception:
                    pass
            self._openai_client_cache.clear()
        # Don't touch provider_auth_health / compat_gateway_health — those
        # cooldowns genuinely outlive a single run (e.g. a 401 key stays
        # bad across runs). But DO clear the stream-idle heuristic:
        if hasattr(self, "_agentic_events"):
            self._agentic_events = []
        logger.info("AIBridge: per-run state reset (kill switch + empty counter + client cache cleared)")

    def _get_or_create_openai_client(self, api_key: str, base_url: str, extra_headers: Optional[Dict] = None, timeout: float = 120) -> "OpenAI":
        """Return a cached OpenAI client for the given (key, base_url) pair.
        Reuses TCP+TLS connections across calls (~100-300ms saved per request).
        Uses HTTP/2 when httpx[http2] is available for connection multiplexing.

        V4.3: Added max_retries=3 (SDK handles 429/5xx with exponential backoff),
        expanded connection pool limits, and keepalive for long-running streams.
        """
        from openai import OpenAI as _OpenAI
        # v6.3.1 (maintainer 2026-04-21): include config_generation in cache key so
        # a reload_api_config bump forces the NEXT request to build a fresh
        # client with the new env, while any previous request still holding
        # the old (key, base, gen-N) key keeps using its old client. Pairs
        # with reload_api_config's "let GC handle it" strategy.
        _gen = int(getattr(self, "_config_generation", 0) or 0)
        cache_key = f"{api_key[:20]}:{base_url}:g{_gen}"
        client = self._openai_client_cache.get(cache_key)
        if client is None:
            http_client = None
            try:
                import httpx as _httpx
                import socket as _socket
                # v6.0: tuned for agentic pipelines with long idle gaps between
                # builder tool calls.  keepalive 180 → 600 because qwen/minimax
                # on aigate produce 60-90s streams, and downstream compaction +
                # planner reflection can leave a socket idle 3-5 minutes before
                # the next node reuses it.  Re-establishing TLS costs ~200ms;
                # avoidable on every node transition.
                # v6.1.8 (maintainer 2026-04-19, research-confirmed): TCP_NODELAY
                # disables Nagle so the first SSE byte is not held 40ms on
                # the relay. Biggest TTFT win for relay-backed chat.
                pool_limits = _httpx.Limits(
                    max_connections=60,
                    max_keepalive_connections=30,
                    keepalive_expiry=600,
                )
                _socket_opts = [
                    (_socket.IPPROTO_TCP, _socket.TCP_NODELAY, 1),
                    (_socket.SOL_SOCKET, _socket.SO_KEEPALIVE, 1),
                ]
                http_client = _httpx.Client(
                    http2=True,
                    timeout=_httpx.Timeout(timeout, connect=30.0),
                    limits=pool_limits,
                    transport=_httpx.HTTPTransport(
                        retries=0,
                        socket_options=_socket_opts,
                    ),
                )
            except (ImportError, Exception):
                pass

            # v6.3 (maintainer 2026-04-21): override User-Agent so relays that do
            # anti-passthrough fingerprinting on the literal "OpenAI/Python"
            # UA (confirmed relay.cn returns 403 "Your request was
            # blocked.", expected to be widespread in Chinese relay market)
            # don't block every pipeline call. Only set it when the caller
            # didn't supply their own UA via extra_headers.
            _default_headers: Dict[str, str] = dict(extra_headers or {})
            if not any(str(k or "").lower() == "user-agent" for k in _default_headers):
                _default_headers["User-Agent"] = "evermind/6.3 httpx/openai-compat"
            kwargs: Dict[str, Any] = {
                "api_key": api_key,
                "base_url": base_url,
                "default_headers": _default_headers,
                "timeout": timeout,
                # v5.8.3: max_retries 3 → 1. Kimi's 429 under tier-<3 concurrency
                # turns one failing call into 3 retries in a tight loop — this
                # amplifies quota burn and makes the ratelimit worse not better.
                # Orchestrator already handles retry at the node level with
                # smarter fallback (switch model / switch mode), so 1 SDK retry
                # is enough to cover transient network hiccups.
                "max_retries": 1,
            }
            if http_client is not None:
                kwargs["http_client"] = http_client
            client = _OpenAI(**kwargs)
            self._openai_client_cache[cache_key] = client
            logger.info(
                "Created OpenAI client: base_url=%s http2=%s max_retries=1 pool=60/30",
                base_url,
                http_client is not None,
            )
            # v6.1.8 research-confirmed: prewarm TLS + TCP connection on
            # first client creation so the NEXT real call doesn't pay the
            # ~200ms TLS handshake. Fire-and-forget; swallow exceptions.
            if str(os.getenv("EVERMIND_CLIENT_PREWARM", "1") or "1").strip() not in ("0", "false", "no"):
                try:
                    import threading as _threading
                    def _warm():
                        try:
                            # Cheapest call on most OpenAI-compat servers
                            client.models.list(timeout=5.0)
                        except Exception:
                            pass
                    _threading.Thread(target=_warm, daemon=True, name=f"prewarm-{base_url[-30:]}").start()
                except Exception:
                    pass
        else:
            # Update timeout for this call (timeout varies per node type)
            client.timeout = timeout
        return client

    def _invalidate_openai_client(self, api_key: str, base_url: str, reason: str = "") -> None:
        """Remove a cached OpenAI client after persistent connection failures.

        V4.3 connection self-healing: on repeated ConnectionError / transport
        failures, evict the stale client so the next call creates a fresh one
        with a new TCP+TLS handshake.

        NOTE: We intentionally do NOT close the old client's transport here.
        Concurrent streams in worker threads may still hold references to
        the evicted client. Let Python GC reclaim it once all in-flight
        requests finish naturally.
        """
        _gen = int(getattr(self, "_config_generation", 0) or 0)
        cache_key = f"{api_key[:20]}:{base_url}:g{_gen}"
        old = self._openai_client_cache.pop(cache_key, None)
        if old is not None:
            logger.warning(
                "Invalidated OpenAI client cache: key=%s reason=%s",
                cache_key,
                reason[:200] if reason else "unknown",
            )

    def _setup_litellm(self):
        """Configure API key env vars and bind to the shared LiteLLM module.
        v5.2: LiteLLM is imported once at module load (_LITELLM_MODULE); this
        per-instance setup only applies config-driven env keys.

        v6.3 (maintainer 2026-04-20): also accepts nested `api_keys` / `api_bases`
        dicts so UI-saved Settings propagate without restart. Previous code
        only read flat fields like `openai_api_key`, missing the shape used
        by /api/settings/save.
        """
        if not _LITELLM_AVAILABLE:
            self._litellm = None
            if not getattr(AIBridge, "_litellm_warning_emitted", False):
                logger.warning("LiteLLM not installed, falling back to direct API calls")
                AIBridge._litellm_warning_emitted = True
            return
        key_map = {
            "openai_api_key": "OPENAI_API_KEY",
            "anthropic_api_key": "ANTHROPIC_API_KEY",
            "gemini_api_key": "GEMINI_API_KEY",
            "deepseek_api_key": "DEEPSEEK_API_KEY",
            "kimi_api_key": "KIMI_API_KEY",
            "qwen_api_key": "QWEN_API_KEY",
        }
        for config_key, env_key in key_map.items():
            if config_key in self.config:
                value = self.config.get(config_key, "")
                if value:
                    os.environ[env_key] = value
                else:
                    os.environ.pop(env_key, None)
        # v6.3: nested api_keys / api_bases (the shape the UI + settings.py
        # actually use) — cover every provider in MODEL_REGISTRY so new keys
        # go live immediately.
        _nested_key_map = {
            "openai": "OPENAI_API_KEY",
            "anthropic": "ANTHROPIC_API_KEY",
            "gemini": "GEMINI_API_KEY",
            "deepseek": "DEEPSEEK_API_KEY",
            "kimi": "KIMI_API_KEY",
            "qwen": "QWEN_API_KEY",
            "minimax": "MINIMAX_API_KEY",
            "zhipu": "ZHIPU_API_KEY",
            "doubao": "DOUBAO_API_KEY",
            "yi": "YI_API_KEY",
            "aigate": "AIGATE_API_KEY",
        }
        _nested_base_map = {
            "openai": "OPENAI_API_BASE",
            "anthropic": "ANTHROPIC_API_BASE",
            "gemini": "GEMINI_API_BASE",
            "deepseek": "DEEPSEEK_API_BASE",
            "kimi": "KIMI_API_BASE",
            "qwen": "QWEN_API_BASE",
            "minimax": "MINIMAX_API_BASE",
            "zhipu": "ZHIPU_API_BASE",
            "doubao": "DOUBAO_API_BASE",
            "yi": "YI_API_BASE",
            "aigate": "AIGATE_API_BASE",
        }
        api_keys_cfg = self.config.get("api_keys") if isinstance(self.config, dict) else None
        if isinstance(api_keys_cfg, dict):
            for provider, env_key in _nested_key_map.items():
                val = str(api_keys_cfg.get(provider, "") or "").strip()
                if val:
                    os.environ[env_key] = val
                # secondary key (name_2)
                sec = str(api_keys_cfg.get(f"{provider}_2", "") or "").strip()
                if sec:
                    os.environ[f"{env_key}_2"] = sec
        api_bases_cfg = self.config.get("api_bases") if isinstance(self.config, dict) else None
        if isinstance(api_bases_cfg, dict):
            for provider, env_key in _nested_base_map.items():
                val = str(api_bases_cfg.get(provider, "") or "").strip()
                if val:
                    os.environ[env_key] = val
        self._openai_client = None
        self._openai_api_key = None
        self._litellm = _LITELLM_MODULE
        if not getattr(AIBridge, "_litellm_init_logged", False):
            logger.info("LiteLLM initialized — 100+ models available")
            AIBridge._litellm_init_logged = True

    def reload_api_config(self, new_config: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        """v6.3.1 (maintainer 2026-04-21) — REWRITE to generation-id / let-GC-handle-it.

        ## Why this changed

        The first version of this method (v6.3.0) called `client.close()` on
        every cached OpenAI client during a reload. That reproduced the exact
        bug LiteLLM shipped as a P0 incident on 2026-02-21 (see their
        `httpx-cache-eviction-incident` post-mortem + fix PR #22247): closing
        an httpx-backed SDK client whose stream iterator is mid-flight
        detonates the asyncio event loop — the stream never surfaces
        `CancelledError`, the whole pipeline hangs. We reproduced the exact
        symptom: analyst's synthesis call hung silently for 10+ minutes after
        a user pressed "Save Settings" during a run.

        ## New behaviour (LiteLLM PR #22247 + Aider SwitchCoder pattern)

        1. Bump `_config_generation` — new clients created after this reload
           use a different cache key, so fresh requests pick up fresh env.
        2. Refresh env vars via _setup_litellm (so newly constructed clients
           read the new api_key / base_url).
        3. **Do NOT close cached clients.** Old clients stay in cache with
           the old generation tag; in-flight streams keep their socket.
           When the run referencing them finishes, Python GC drops them.
        4. Do NOT clear `_compat_gateway_health` / `_provider_auth_health`
           during a run either — these are keyed per (provider, host), not
           per credential. Clearing them cancels cooldowns the active
           pipeline is relying on to skip known-dead providers.

        Trade-off: a brief period (a few seconds) where parallel requests
        for the same provider may use two different clients (one pre-reload,
        one post-reload). Memory cost is ~2KB per idle client; all modern
        Pythons GC them within a minute of the last reference dropping.

        Returns a summary dict for the caller to log / emit on WS.
        """
        if isinstance(new_config, dict):
            self.config = dict(new_config)
        # (1) bump generation so new cache lookups miss old entries
        try:
            self._config_generation = int(getattr(self, "_config_generation", 0) or 0) + 1
        except Exception:
            self._config_generation = 1
        # (2) refresh env vars — new clients (built after this line) will
        # read the new api_key / api_base. Old clients keep their captured
        # values because they were constructed earlier.
        self._setup_litellm()
        cached_clients = 0
        if isinstance(getattr(self, "_openai_client_cache", None), dict):
            cached_clients = len(self._openai_client_cache)
        summary = {
            "config_generation": self._config_generation,
            "cached_clients_preserved": cached_clients,
            "in_flight_safe": True,
        }
        logger.info(
            "AIBridge.reload_api_config: generation=%d preserved %d cached client(s) (GC-on-drop, LiteLLM PR #22247 model)",
            self._config_generation, cached_clients,
        )
        return summary

    # ── Quick one-shot completion for lightweight tasks (report writing, etc.) ──

    def quick_completion(
        self,
        prompt: str,
        *,
        system: str = "",
        model: str = "kimi-coding",
        max_tokens: int = 1500,
        timeout_sec: int = 30,
        fallback_models: Optional[List[str]] = None,
    ) -> str:
        """Synchronous one-shot completion call for lightweight tasks.

        Returns the assistant message text, or empty string on any failure.
        Designed for non-critical tasks like report writing — failures are
        silently swallowed so they never break the main pipeline.

        If fallback_models is provided and the primary model fails, each
        fallback is tried in order before returning empty.
        """
        if not self._litellm:
            return ""
        chain = [model] + (fallback_models or [])
        for candidate in chain:
            model_info = MODEL_REGISTRY.get(candidate)
            if not model_info:
                continue
            litellm_id = model_info.get("litellm_id", candidate)
            messages: List[Dict[str, str]] = []
            if system:
                messages.append({"role": "system", "content": system})
            messages.append({"role": "user", "content": prompt})
            kwargs: Dict[str, Any] = {
                "model": litellm_id,
                "messages": messages,
                "max_tokens": max_tokens,
                "timeout": timeout_sec,
                "num_retries": 0,
            }
            if model_info.get("api_base"):
                kwargs["api_base"] = model_info["api_base"]
            if model_info.get("extra_headers"):
                kwargs["extra_headers"] = model_info["extra_headers"]
            resolved_key = self._resolved_api_key_for_model_info(model_info)
            if resolved_key:
                kwargs["api_key"] = resolved_key
            # V4.4 FIX: kimi-k2.5 defaults to thinking mode, which consumes
            # max_tokens on reasoning and returns empty content.  Disable
            # thinking for lightweight one-shot calls like speed tests.
            _provider = str(model_info.get("provider") or "").lower()
            if _provider == "kimi":
                kwargs["extra_body"] = {"thinking": {"type": "disabled"}}
                # Ensure at least 20 tokens for content after any overhead
                if kwargs["max_tokens"] < 20:
                    kwargs["max_tokens"] = 20
            try:
                kwargs["stream"] = True
                response = self._litellm.completion(**kwargs)
                content_parts = []
                for chunk in response:
                    if chunk.choices and chunk.choices[0].delta:
                        c = getattr(chunk.choices[0].delta, "content", None)
                        if c:
                            content_parts.append(c)
                result = "".join(content_parts).strip()
                if result:
                    return result
            except Exception as exc:
                logger.debug("quick_completion(%s) failed: %s", candidate, str(exc)[:200])
                continue
        return ""

    # ── Structured Output Validation (ported from Pydantic AI patterns) ──

    @staticmethod
    def validate_structured_output(
        raw: str,
        schema: Dict[str, Any],
        *,
        partial_ok: bool = False,
    ) -> Tuple[Dict[str, Any], List[str]]:
        """Validate AI output against a JSON schema.

        Ported from Pydantic AI's validation pattern: validates extracted JSON
        against a schema, returns (parsed_dict, violations). If partial_ok is
        True, missing required fields are downgraded to warnings instead of errors.

        Returns:
            (parsed_dict, violations) — parsed_dict may be partial on failure,
            violations is empty list on success.
        """
        # Step 1: Extract JSON from raw output
        text = str(raw or "").strip()
        parsed: Dict[str, Any] = {}
        if not text:
            return {}, ["Empty output — no JSON found"]

        # Try direct parse first, then search for embedded JSON
        candidate = text
        if not text.startswith("{"):
            start = text.find("{")
            end = text.rfind("}") + 1
            if start >= 0 and end > start:
                candidate = text[start:end]
            else:
                return {}, ["No JSON object found in output"]
        try:
            parsed = json.loads(candidate)
        except json.JSONDecodeError as e:
            return {}, [f"JSON parse error: {str(e)[:100]}"]
        if not isinstance(parsed, dict):
            return {}, ["Parsed value is not a dict"]

        # Step 2: Validate against schema
        if not schema:
            return parsed, []

        violations: List[str] = []
        try:
            import jsonschema as _jsonschema
            validator_cls = _jsonschema.Draft7Validator
            validator = validator_cls(schema)
            for error in sorted(validator.iter_errors(parsed), key=lambda e: list(e.path)):
                path_str = ".".join(str(p) for p in error.path) or "(root)"
                msg = f"{path_str}: {error.message}"
                if partial_ok and error.validator == "required":
                    continue  # Allow missing fields in partial mode
                violations.append(msg[:200])
        except ImportError:
            pass  # jsonschema not available — skip validation
        except Exception as exc:
            violations.append(f"Validation error: {str(exc)[:100]}")

        return parsed, violations[:10]

    # ── Output Guardrails (ported from OpenAI Agents SDK patterns) ──

    def run_output_guardrails(
        self,
        content: str,
        node_type: str,
    ) -> List[Dict[str, str]]:
        """Run output guardrails on AI model response.

        Returns list of {severity, message} dicts. Severity is 'reject' or 'warn'.
        Empty list means all checks passed.
        """
        results: List[Dict[str, str]] = []
        if not content:
            return results
        content_len = len(content)

        # Guard 1: Length sanity — builder output < 50 chars is almost certainly broken
        if node_type in ("builder", "merger", "polisher") and content_len < 50:
            results.append({"severity": "reject", "message": f"Output too short ({content_len} chars) for {node_type}"})

        # Guard 2: Prompt echo detection — if output contains system prompt fragments
        _prompt_echoes = [
            "You are a senior project planner",
            "IMPORTANT RULES for website",
            "EXECUTION REPORT (v4.0",
            "## OPTION ENUMERATION",
        ]
        for echo in _prompt_echoes:
            if echo in content:
                results.append({"severity": "warn", "message": f"Possible prompt echo detected: '{echo[:40]}...'"})
                break

        # Guard 3: Empty code block — builder wrote code fence but nothing inside
        if node_type in ("builder", "merger") and "```" in content:
            empty_blocks = re.findall(r'```\w*\s*```', content)
            if len(empty_blocks) > 2:
                results.append({"severity": "warn", "message": f"Multiple empty code blocks ({len(empty_blocks)}) — possible generation failure"})

        return results

    # ── API Preflight Probe & Timeout Tracking (v4.1) ──

    def preflight_api_probe(
        self,
        models: Optional[List[str]] = None,
        timeout_sec: int = 8,
    ) -> Dict[str, Dict[str, Any]]:
        """Probe relay/provider APIs before a run starts.

        V4.3: Runs probes CONCURRENTLY via ThreadPoolExecutor instead of
        serially. With 3 models at 12s timeout each, serial probes wasted
        up to 36s before the first subtask could start.  Concurrent probes
        complete in max(individual_latency) ≈ 3-8s.

        Returns: {model_name: {"ok": bool, "latency_ms": int, "error": str}}
        """
        if models is None:
            # v5.8.1: kimi-coding removed — legacy endpoint unreliable.
            models = ["kimi-k2.6-code-preview", "gpt-5.4", "gpt-5.3-codex"]
        results: Dict[str, Dict[str, Any]] = {}

        def _probe_one(model_name: str) -> tuple:
            model_info = MODEL_REGISTRY.get(model_name)
            if not model_info:
                return model_name, {"ok": False, "latency_ms": 0, "error": "not in registry"}
            t0 = time.time()
            try:
                reply = self.quick_completion(
                    "回复OK", model=model_name, max_tokens=5, timeout_sec=timeout_sec,
                )
                latency_ms = int((time.time() - t0) * 1000)
                ok = len(reply) > 0
                result = {"ok": ok, "latency_ms": latency_ms, "error": "" if ok else "empty reply"}
                if ok:
                    logger.info("[Preflight] %s OK in %dms", model_name, latency_ms)
                else:
                    logger.warning("[Preflight] %s returned empty in %dms", model_name, latency_ms)
                return model_name, result
            except Exception as exc:
                latency_ms = int((time.time() - t0) * 1000)
                error_str = str(exc)[:200]
                logger.warning("[Preflight] %s failed in %dms: %s", model_name, latency_ms, error_str)
                self._record_gateway_timeout(model_info, error_str)
                return model_name, {"ok": False, "latency_ms": latency_ms, "error": error_str}

        # V4.3: concurrent probes — all models tested in parallel
        import concurrent.futures as _cf
        with _cf.ThreadPoolExecutor(max_workers=min(len(models), 4)) as pool:
            futures = {pool.submit(_probe_one, m): m for m in models}
            for fut in _cf.as_completed(futures, timeout=timeout_sec + 5):
                try:
                    name, result = fut.result(timeout=2)
                    results[name] = result
                except Exception:
                    results[futures[fut]] = {"ok": False, "latency_ms": 0, "error": "probe thread failed"}
        return results

    def _record_gateway_timeout(self, model_info: Optional[Dict[str, Any]], error_message: str = "", node_type: str = "") -> None:
        """Record a timeout/slowness event for a gateway+model combo.

        V4.5: Node-type aware cooldown. Analyst/planner timeouts use shorter
        cooldown (30s) to avoid penalizing Builder which needs the same gateway.
        Builder/merger get 60s. Default 120s for unknown nodes.
        """
        info = model_info if isinstance(model_info, dict) else {}
        provider = str(info.get("provider") or "").strip().lower()
        if provider in ("relay", "ollama", ""):
            return
        model_key = self._compatible_gateway_key(info, model_specific=True)
        if not model_key:
            return
        state = self._compat_gateway_health.setdefault(model_key, {
            "consecutive_rejections": 0,
            "last_rejection_at": 0.0,
            "last_success_at": 0.0,
            "last_error": "",
            "rejection_cooldown_until": 0.0,
            "circuit_open_until": 0.0,
        })
        now = time.time()
        state["last_rejection_at"] = now
        state["last_error"] = _sanitize_error(str(error_message or "timeout"))[:200]
        # V4.6 SPEED: Drastically reduced cooldowns — prioritize throughput.
        # Old values (30/60/120) caused cascading idle time across nodes.
        # v6.4.11 (maintainer 2026-04-22): exponential back-off on consecutive
        # rejections. Previously fixed 10s cooldown meant a persistently-down
        # gateway (e.g. relay.cn on 2026-04-22) kept getting retried every
        # 10s, burning ~2 min of `initial-activity timeout after 120s` each
        # time. Tracking `consecutive_rejections` lets us back off aggressively
        # once we've confirmed the gateway is not recovering. Reset to 10s on
        # first success (logic in `_record_gateway_success`).
        state["consecutive_rejections"] = int(state.get("consecutive_rejections") or 0) + 1
        _streak = int(state["consecutive_rejections"])
        _nt = normalize_node_role(str(node_type or "").strip())
        if _nt in ("analyst", "planner", "router"):
            base_cooldown = 6.0
        elif _nt in ("builder", "polisher"):
            base_cooldown = 10.0
        else:
            base_cooldown = 10.0
        # Exponential tier: streak 1 = base, 2 = 6×base (60s/builder), 3 = 30×base (5min).
        if _streak >= 3:
            cooldown = base_cooldown * 30.0   # 5 min — gateway clearly unhealthy
        elif _streak >= 2:
            cooldown = base_cooldown * 6.0    # 1 min — second miss, probably not transient
        else:
            cooldown = base_cooldown          # first miss — retry quickly
        state["rejection_cooldown_until"] = max(
            float(state.get("rejection_cooldown_until") or 0.0),
            now + cooldown,
        )
        # v6.4.31 (maintainer 2026-04-23): HARD CIRCUIT BREAKER.
        # After 5 consecutive gateway rejections, slam the circuit open for
        # 30 min across the WHOLE gateway (not just this model). Observed
        # 2026-04-22 bug: relay.cn was rejecting every gpt-5.4 call for an
        # hour, yet each patcher retry STILL tried gpt-5.4 first (5 retries
        # per patcher attempt × 3 attempts = 15 failed round-trips to
        # relay = ~2 min of wasted time per patcher round on top of the
        # 403 itself). Force-open the circuit so candidate chain can pick
        # kimi first immediately.
        if _streak >= 5:
            state["circuit_open_until"] = max(
                float(state.get("circuit_open_until") or 0.0),
                now + 1800.0,   # 30 minutes
            )
            logger.warning(
                "[GatewayCircuit] HARD OPEN for %s (30min) after %d consecutive rejections — "
                "candidate chain will now skip this provider entirely.",
                model_key, _streak,
            )
        logger.info(
            "[GatewayTimeout] Marked %s unhealthy for %ds (node=%s): %s",
            model_key, int(cooldown), _nt or "unknown", state["last_error"][:100],
        )
        # V4.6 SPEED: Propagate to gateway-level key so sibling models
        # on the same host (e.g. gpt-5.4 on the same relay) are also
        # deprioritized. Prevents cascading timeouts when the gateway is down.
        gateway_key = self._compatible_gateway_key(info, model_specific=False)
        if gateway_key and gateway_key != model_key:
            gw_state = self._compat_gateway_health.setdefault(gateway_key, {
                "consecutive_rejections": 0,
                "last_rejection_at": 0.0,
                "last_success_at": 0.0,
                "last_error": "",
                "rejection_cooldown_until": 0.0,
                "circuit_open_until": 0.0,
            })
            gw_state["last_rejection_at"] = now
            gw_state["last_error"] = state["last_error"]
            gw_state["rejection_cooldown_until"] = max(
                float(gw_state.get("rejection_cooldown_until") or 0.0),
                now + cooldown,
            )
            # v6.4.31: propagate HARD circuit open to gateway level too so
            # sibling models on the same host (gpt-5.4, gpt-5.3-codex, etc
            # all proxied through relay.cn) also get skipped.
            gw_state["consecutive_rejections"] = int(gw_state.get("consecutive_rejections") or 0) + 1
            if int(gw_state.get("consecutive_rejections") or 0) >= 5:
                gw_state["circuit_open_until"] = max(
                    float(gw_state.get("circuit_open_until") or 0.0),
                    now + 1800.0,
                )

    def _tail_compat_gateway_log_lines(self, max_lines: int = 1200) -> List[str]:
        path = Path(COMPAT_GATEWAY_LOG_FILE)
        if not path.exists() or not path.is_file():
            return []
        try:
            with path.open("r", encoding="utf-8", errors="ignore") as handle:
                return list(deque(handle, maxlen=max_lines))
        except Exception:
            return []

    def _seed_compatible_gateway_health_from_recent_logs(self) -> None:
        lines = self._tail_compat_gateway_log_lines()
        if not lines:
            return

        latest_states: Dict[str, Dict[str, Any]] = {}
        for raw_line in lines:
            line = str(raw_line or "").strip()
            if not line:
                continue
            ts = _log_timestamp_epoch(line)

            rejection_match = _GATEWAY_REJECTION_RE.search(line)
            if rejection_match:
                provider = str(rejection_match.group("provider") or "").strip().lower()
                host = str(rejection_match.group("host") or "").strip()
                latest_states[f"{provider}:{host}"] = {
                    "status": "rejection_cooldown",
                    "provider": provider,
                    "host": host,
                    "observed_at": ts,
                    "cooldown_sec": int(rejection_match.group("cooldown") or 0),
                    "last_error": _sanitize_error(str(rejection_match.group("error") or ""))[:200],
                }
                continue

            circuit_match = _GATEWAY_CIRCUIT_RE.search(line)
            if circuit_match:
                provider = str(circuit_match.group("provider") or "").strip().lower()
                host = str(circuit_match.group("host") or "").strip()
                latest_states[f"{provider}:{host}"] = {
                    "status": "circuit_open",
                    "provider": provider,
                    "host": host,
                    "observed_at": ts,
                    "failure_count": int(circuit_match.group("failures") or 0),
                    "last_error": _sanitize_error(str(circuit_match.group("error") or ""))[:200],
                }
                continue

            recovered_match = _GATEWAY_RECOVERED_RE.search(line)
            if recovered_match:
                provider = str(recovered_match.group("provider") or "").strip().lower()
                host = str(recovered_match.group("host") or "").strip()
                latest_states[f"{provider}:{host}"] = {
                    "status": "healthy",
                    "provider": provider,
                    "host": host,
                    "observed_at": ts,
                    "last_error": "",
                }

        if not latest_states:
            return

        now = time.time()
        provider_to_base: Dict[str, str] = {}
        # v6.1: cover every provider registered in PROVIDER_ENV_KEY_MAP so the
        # auth-health seed isn't silently blind to zhipu/doubao/yi/minimax/aigate
        # 401 events. Previously only 6 vendors were polled here.
        for provider in PROVIDER_ENV_KEY_MAP.keys():
            env_key = self._provider_api_base_env_key(provider)
            base = str(os.getenv(env_key, "") if env_key else "").strip().rstrip("/")
            if base:
                provider_to_base[provider] = base

        for provider, base in provider_to_base.items():
            try:
                parsed = urlparse(base)
                host = str(parsed.netloc or parsed.path or base).strip()
            except Exception:
                host = base
            if not host:
                continue
            observed = latest_states.get(f"{provider}:{host}") or {}
            status = str(observed.get("status") or "").strip()
            if not status or status == "healthy":
                continue

            key = f"{provider}:{base}"
            state = self._compat_gateway_health.setdefault(key, {
                "consecutive_failures": 0,
                "failure_count": 0,
                "success_count": 0,
                "circuit_open_until": 0.0,
                "rejection_cooldown_until": 0.0,
                "last_error": "",
                "last_failure_at": 0.0,
                "last_rejection_at": 0.0,
                "last_success_at": 0.0,
                "last_latency_ms": 0,
                "ewma_latency_ms": 0.0,
            })

            observed_at = float(observed.get("observed_at") or 0.0)
            if status == "rejection_cooldown":
                cooldown_sec = int(observed.get("cooldown_sec") or 0)
                rejection_until = observed_at + cooldown_sec
                state["last_rejection_at"] = max(float(state.get("last_rejection_at") or 0.0), observed_at)
                if str(observed.get("last_error") or "").strip():
                    state["last_error"] = str(observed.get("last_error") or "")
                if rejection_until > now:
                    state["rejection_cooldown_until"] = rejection_until
                    logger.info(
                        "Seeded compatible gateway rejection cooldown from recent logs: provider=%s host=%s remaining=%ss",
                        provider,
                        host,
                        max(1, int(round(rejection_until - now))),
                    )
                elif (now - observed_at) <= self._compatible_gateway_recent_rejection_grace_seconds():
                    logger.info(
                        "Seeded compatible gateway recent rejection from logs: provider=%s host=%s age=%ss",
                        provider,
                        host,
                        max(1, int(round(now - observed_at))),
                    )
            elif status == "circuit_open":
                circuit_until = observed_at + self._compatible_gateway_circuit_open_seconds()
                if circuit_until > now:
                    state["circuit_open_until"] = circuit_until
                    state["consecutive_failures"] = max(
                        int(observed.get("failure_count") or 0),
                        self._compatible_gateway_failure_threshold(),
                    )
                    state["last_failure_at"] = observed_at
                    state["last_error"] = str(observed.get("last_error") or "")
                    logger.info(
                        "Seeded compatible gateway circuit-open state from recent logs: provider=%s host=%s remaining=%ss",
                        provider,
                        host,
                        max(1, int(round(circuit_until - now))),
                    )

    def _seed_provider_auth_health_from_recent_logs(self) -> None:
        lines = self._tail_compat_gateway_log_lines()
        if not lines:
            return

        latest_states: Dict[str, Dict[str, Any]] = {}
        for raw_line in lines:
            line = str(raw_line or "").strip()
            if not line:
                continue
            ts = _log_timestamp_epoch(line)

            failure_match = _PROVIDER_AUTH_FAILURE_RE.search(line)
            if failure_match:
                provider = str(failure_match.group("provider") or "").strip().lower()
                if not provider or provider in {"unknown", "relay", "ollama"}:
                    continue
                latest_states[provider] = {
                    "status": "blocked",
                    "provider": provider,
                    "observed_at": ts,
                    "cooldown_sec": int(failure_match.group("cooldown") or 0),
                    "last_error": _sanitize_error(str(failure_match.group("error") or ""))[:200],
                }
                continue

            cleared_match = _PROVIDER_AUTH_CLEARED_RE.search(line)
            if cleared_match:
                provider = str(cleared_match.group("provider") or "").strip().lower()
                if not provider or provider in {"unknown", "relay", "ollama"}:
                    continue
                latest_states[provider] = {
                    "status": "healthy",
                    "provider": provider,
                    "observed_at": ts,
                }

        if not latest_states:
            return

        now = time.time()
        max_seed_age = self._provider_auth_seed_max_age_seconds()
        for provider, observed in latest_states.items():
            state = self._provider_auth_state(provider)
            if not state:
                continue

            status = str(observed.get("status") or "").strip().lower()
            observed_at = float(observed.get("observed_at") or 0.0)
            age = now - observed_at if observed_at > 0 else float("inf")
            if status == "healthy":
                if observed_at >= float(state.get("last_failure_at") or 0.0):
                    state["blocked_until"] = 0.0
                    state["last_error"] = ""
                    state["last_success_at"] = max(float(state.get("last_success_at") or 0.0), observed_at)
                continue

            if status != "blocked":
                continue
            if max_seed_age > 0 and age > max_seed_age:
                continue

            cooldown_sec = int(observed.get("cooldown_sec") or 0)
            blocked_until = observed_at + cooldown_sec
            state["last_failure_at"] = max(float(state.get("last_failure_at") or 0.0), observed_at)
            if str(observed.get("last_error") or "").strip():
                state["last_error"] = str(observed.get("last_error") or "")
            if blocked_until > now:
                # V4.2 FIX: Previously we cleared blocked_until whenever an API
                # key was present.  But key presence is the NORMAL case for
                # configured providers — it says nothing about whether the auth
                # failure that triggered the cooldown has been resolved.
                # Now we only shorten the remaining cooldown: cap it to 60s so
                # the provider gets a fast retry on next request, but do NOT
                # clear it entirely (which would cause an immediate retry storm
                # on startup against still-broken credentials).
                remaining = blocked_until - now
                _max_seeded = 15.0  # V4.6 SPEED: cap seeded cooldowns to 15s on restart (was 60s)
                if remaining > _max_seeded:
                    state["blocked_until"] = now + _max_seeded
                    logger.info(
                        "Capped seeded cooldown for provider=%s: %ss → %ss",
                        provider,
                        max(1, int(round(remaining))),
                        int(_max_seeded),
                    )
                else:
                    state["blocked_until"] = max(float(state.get("blocked_until") or 0.0), blocked_until)
                    logger.info(
                        "Seeded provider auth failure cooldown from recent logs: provider=%s remaining=%ss",
                        provider,
                        max(1, int(round(remaining))),
                    )

    async def _get_openai(self):
        api_key = self.config.get("openai_api_key") or os.getenv("OPENAI_API_KEY")
        if api_key and (not self._openai_client or api_key != self._openai_api_key):
            from openai import AsyncOpenAI
            # v6.8 P0 (maintainer 2026-04-24): HTTP/2 + connection pooling.
            # OpenAI SDK default is HTTP/1.1 with per-instance pool; under
            # long streaming (kimi writes 30KB HTML → 7K-12K chunks over
            # one TCP connection), this caps throughput. Reusing a global
            # httpx.AsyncClient with http2=True + keepalive lets SSE
            # chunks arrive in parallel over multiplexed streams, and
            # saves TLS handshake on every call (observed uidesign
            # 87s→463s jitter was largely TLS handshake variance).
            # Fallback to default client if httpx[h2] missing.
            _http_client = None
            try:
                import httpx as _httpx
                _http_client = _httpx.AsyncClient(
                    http2=True,
                    limits=_httpx.Limits(
                        max_connections=100,
                        max_keepalive_connections=50,
                        keepalive_expiry=60.0,
                    ),
                    timeout=_httpx.Timeout(
                        connect=10.0, read=180.0, write=30.0, pool=5.0,
                    ),
                )
            except Exception as _h2_err:
                logger.debug("v6.8 http2 client init failed, falling back: %s", _h2_err)
            if _http_client is not None:
                self._openai_client = AsyncOpenAI(api_key=api_key, http_client=_http_client)
            else:
                self._openai_client = AsyncOpenAI(api_key=api_key)
            self._openai_api_key = api_key
        return self._openai_client

    def get_available_models(self) -> List[Dict]:
        """Return list of available models including relay models."""
        models = [{"id": k, **v} for k, v in MODEL_REGISTRY.items()]
        # Add relay models
        relay_mgr = get_relay_manager()
        for model_id, info in relay_mgr.get_all_models().items():
            models.append({"id": model_id, **info})
        return models

    def _resolve_model(self, model_name: str) -> Dict:
        """Resolve model info from registry or relay endpoints."""
        # Check static registry first
        if model_name in MODEL_REGISTRY:
            return MODEL_REGISTRY[model_name]
        # Check relay models
        relay_mgr = get_relay_manager()
        relay_models = relay_mgr.get_all_models()
        if model_name in relay_models:
            return relay_models[model_name]
        # Fallback — treat as raw LiteLLM model ID
        return {"litellm_id": model_name, "supports_tools": True, "supports_cua": False}

    def _model_provider_has_key(self, model_name: str) -> bool:
        """v6.2 (maintainer 2026-04-20): True iff the model's provider has an API
        key configured (environment var or self.config.api_keys). Used to
        filter forced-router fast chains on setups where only one provider
        has keys.
        """
        info = self._resolve_model(model_name) or {}
        provider = str(info.get("provider") or "").strip().lower()
        if not provider:
            return False
        # env var convention matches server.py provider_env_map
        env_names = {
            "openai": "OPENAI_API_KEY", "anthropic": "ANTHROPIC_API_KEY",
            "google": "GEMINI_API_KEY", "deepseek": "DEEPSEEK_API_KEY",
            "kimi": "KIMI_API_KEY", "qwen": "QWEN_API_KEY",
            "minimax": "MINIMAX_API_KEY", "zhipu": "ZHIPU_API_KEY",
            "doubao": "DOUBAO_API_KEY", "yi": "YI_API_KEY",
            "aigate": "AIGATE_API_KEY",
        }
        env_name = env_names.get(provider)
        if env_name and str(os.environ.get(env_name) or "").strip():
            return True
        keys_map = {}
        cfg = getattr(self, "config", None)
        if isinstance(cfg, dict):
            keys_map = cfg.get("api_keys") or {}
            if isinstance(keys_map, dict) and str(keys_map.get(provider) or "").strip():
                return True
        # ollama = local, always considered reachable
        return provider == "ollama"

    def _normalize_model_chain(self, raw_values: Any, *, limit: int = 6) -> List[str]:
        if isinstance(raw_values, str):
            values = [part.strip() for part in raw_values.split(",")]
        elif isinstance(raw_values, (list, tuple)):
            values = raw_values
        else:
            values = []

        normalized: List[str] = []
        seen: set[str] = set()
        for raw in values:
            model_name = str(raw or "").strip()
            if not model_name or model_name in seen:
                continue
            seen.add(model_name)
            normalized.append(model_name[:100])
            if len(normalized) >= limit:
                break
        return normalized

    def _normalized_node_model_preferences(self) -> Dict[str, List[str]]:
        raw_preferences = self.config.get("node_model_preferences", {})
        if not isinstance(raw_preferences, dict):
            return {}

        normalized: Dict[str, List[str]] = {}
        for raw_role, raw_chain in raw_preferences.items():
            role = normalize_node_role(str(raw_role or "").strip())
            if not role:
                continue
            chain = self._normalize_model_chain(raw_chain)
            if chain:
                normalized[role] = chain
        return normalized

    def _configured_thinking_depth(self) -> str:
        """Return 'fast' or 'deep' from config. Default: 'deep'.

        v6.3 (maintainer 2026-04-20): added disk fallback. The AIBridge instance
        sometimes misses update_config propagation (same SIGHUP / class rebind
        race documented in _effective_timeout_for_node), causing analyst /
        imagegen / reviewer timeouts to silently snap to fast-mode values
        while the user is in deep mode. Reading ~/.evermind/config.json is
        the authoritative fallback, matching the pattern already used by
        _effective_timeout_for_node.
        """
        cfg = getattr(self, "config", None)
        if isinstance(cfg, dict):
            raw = str(cfg.get("thinking_depth") or "").strip().lower()
            if raw in ("fast", "deep"):
                return raw
        env_val = os.getenv("EVERMIND_THINKING_DEPTH", "").strip().lower()
        if env_val in ("fast", "deep"):
            return env_val
        try:
            import json as _json
            _p = os.path.expanduser("~/.evermind/config.json")
            if os.path.exists(_p):
                with open(_p, "r", encoding="utf-8") as _fh:
                    _disk = _json.load(_fh) or {}
                _d = str(_disk.get("thinking_depth") or "").strip().lower()
                if _d in ("fast", "deep"):
                    return _d
        except Exception:
            pass
        return "deep"

    # ── V6.1 unified thinking/reasoning config ─────────────────────────────
    @staticmethod
    def _env_thinking_override(env_key: str) -> Optional[bool]:
        v = str(os.getenv(env_key, "") or "").strip().lower()
        if v in ("enabled", "on", "1", "true"):
            return True
        if v in ("disabled", "off", "0", "false"):
            return False
        return None

    # v6.1: Known relay / aggregator / gateway hosts. Any custom api_base that
    # matches one of these (or any third-party base a user types in) is treated
    # as an OpenAI-compat relay — we union ALL known thinking-toggle flags so
    # whichever backend the relay fronts receives the right one. Unknown keys
    # are silently ignored by well-behaved relays.
    # v6.1: Known relay / aggregator / gateway hosts. Substrings are matched
    # anywhere in the hostname; the list is conservative so we never tag an
    # official vendor endpoint (api.openai.com, api.anthropic.com, etc.) as a
    # relay. Self-hosted gateways whose hostname happens to include a marker
    # word (oneapi / newapi / litellm) are INTENTIONAL — if a user points
    # Evermind at their self-hosted OneAPI instance the union-flags behaviour
    # is the right call anyway.
    _RELAY_HOST_MARKERS: Tuple[str, ...] = (
        "private-relay.com",
        "private-relay.example",
        "aigate",
        "openrouter.ai",
        "oneapi",          # OneAPI self-hosted (github.com/songquanpeng/one-api)
        "newapi",          # NewAPI fork
        "litellm",         # LiteLLM Proxy
        "portkey.ai",
        "helicone.ai",
        "aihubmix.com",
        "laozhang.ai",
        "deepbricks.ai",
        "openkey.cloud",
        "apifox.cn",
        "closeai-asia",
        "fastaichat",
        "gptapi",
        "apiyi",
    )

    # v6.1: Hard denylist — official first-party vendor hosts. Even if a future
    # marker accidentally overlaps, these are NEVER treated as relay.
    _OFFICIAL_VENDOR_HOSTS: Tuple[str, ...] = (
        "api.openai.com",
        "api.anthropic.com",
        "api.deepseek.com",
        "generativelanguage.googleapis.com",
        "api.x.ai",
        "api.mistral.ai",
        "api.moonshot.ai",
        "api.moonshot.cn",
        "api.kimi.com",
        "dashscope.aliyuncs.com",
        "dashscope-intl.aliyuncs.com",
        "open.bigmodel.cn",
        "ark.cn-beijing.volces.com",
        "ark.ap-southeast.bytepluses.com",
        "api.minimax.io",
        "api.minimax.chat",
        "api.lingyiwanwu.com",
        "api.together.xyz",
        "api.groq.com",
        "api.fireworks.ai",
    )

    @classmethod
    def _extract_host(cls, api_base: str) -> str:
        """Return lowercased hostname from an api_base URL. Falls back to the
        first path-free segment if urlparse can't find a netloc (e.g. user
        typed `private-relay.com/v1` without a scheme)."""
        raw = str(api_base or "").strip().lower()
        if not raw:
            return ""
        try:
            from urllib.parse import urlparse
            parsed = urlparse(raw if "://" in raw else f"https://{raw}")
            host = (parsed.hostname or "").lower()
            if host:
                return host
        except Exception:
            pass
        # Fallback: strip scheme / path manually
        tail = raw.split("://", 1)[-1]
        return tail.split("/", 1)[0].split("?", 1)[0].split("@")[-1]

    @classmethod
    def _is_relay_endpoint(cls, provider: str, api_base: str) -> bool:
        """v6.1: Return True when the caller is hitting a multi-backend relay
        (official relay providers + any third-party gateway whose domain we
        recognize). Relays get the union-all-flags treatment so they can
        transparently forward to any upstream backend.

        Opus review #12 (P1): match markers against the parsed HOSTNAME, not
        the full URL, so path segments like `/v1/gptapi` cannot false-match.
        Official first-party vendor hosts are excluded via `_OFFICIAL_VENDOR_HOSTS`.
        """
        prov = str(provider or "").strip().lower()
        if prov in ("relay", "aigate"):
            return True
        host = cls._extract_host(api_base)
        if not host:
            return False
        # Opus review #3 P1: match via equality / dot-suffix, NOT substring.
        # Prevents `api.openai.com.evil.attacker.site` from being classified as
        # official (prior substring check was spoofable).
        for official in cls._OFFICIAL_VENDOR_HOSTS:
            if host == official or host.endswith("." + official):
                return False
        # Markers are matched against the HOSTNAME only (not the path) so a
        # request URL like `/v1/gptapi/foo` hitting api.openai.com does not
        # get mis-classified — Opus review #1-P12.
        for marker in cls._RELAY_HOST_MARKERS:
            if marker in host:
                return True
        return False

    # v6.1 hotfix: node-type thinking exemption.
    # Real-world observation: kimi/k2.6-code-preview with thinking=enabled
    # emits <think> tags + JSON tool_call prose instead of DOCTYPE HTML,
    # which the narration guard correctly rejects but the quality gate then
    # force-passes, leaving an empty task_N directory. Builder MUST go
    # directly to file_ops write — no reasoning turn before the first write.
    # Router/planner similarly don't benefit from thinking (they're
    # structured-output decisions, not creative reasoning).
    #
    # Classification:
    #   analyst/reviewer/debugger/polisher/tester → real gain from thinking
    #   builder/merger                            → hurt (must act, not think)
    #   router/planner/planner_degraded           → slow for no quality gain
    # v6.4.21 (maintainer 2026-04-22) — REMOVED "builder" and "merger" from this list.
    # User feedback: deep mode was producing low reasoning_effort on builder/merger
    # because they were blanket-exempt. Now they honor the difficulty dial:
    # deep → high, fast → medium/low (size-aware), normal → low. The
    # _reasoning_effort_for_build_node helper below applies the size heuristic.
    # Other nodes stay exempt (reviewer/tester/patcher/debugger previously
    # observed finish=length with content_chars=0 when thinking-enabled).
    _THINKING_EXEMPT_NODES: frozenset = frozenset({
        "router", "planner", "planner_degraded",
        "imagegen", "spritesheet", "assetimport",  # asset-producing: tool-heavy, not reasoning
        # v6.3.5 (maintainer 2026-04-21): added analyst after two runs on the same
        # 3D shooter goal showed kimi's reasoning_chars swinging from 2067
        # to 19764 — a 9.5× variance that cost 97s extra synthesis time
        # with no measurable quality difference (27KB vs 28KB XML content).
        "analyst",
        # v6.4 (maintainer 2026-04-21): reviewer/tester/patcher/debugger all
        # observed producing finish=length with content_chars=0 (300s
        # entirely thinking tokens, zero output). These are tool-heavy
        # action nodes — reviewer issues a verdict + browser tool_calls,
        # tester runs playthrough, patcher edits files, debugger patches.
        # Deep thinking doesn't improve their output; it just burns the
        # max_tokens budget with invisible reasoning that never emerges.
        "reviewer", "tester", "patcher", "debugger",
    })

    # v6.4.5 (maintainer 2026-04-21) — write-critical nodes must call file_ops.
    # Research finding: Aider/Cline root-cause analysis of "agent writes prose
    # instead of editing files" is tool_choice="auto" letting the model duck
    # out. Solution per OpenAI/Anthropic: force tool_choice to a specific
    # function. Applied here for builder/merger/patcher/polisher — nodes whose
    # ONLY valid output is a file_ops call.
    _FORCE_FILE_OPS_NODES: frozenset = frozenset({
        "builder", "merger", "patcher", "polisher",
    })

    @classmethod
    def _node_should_force_file_ops(cls, node_type: str) -> bool:
        role = str(node_type or "").strip().lower()
        if not role:
            return False
        for forced in cls._FORCE_FILE_OPS_NODES:
            if role == forced or role.startswith(forced):
                return True
        return False

    @classmethod
    def _tool_choice_for_node(cls, node_type: str, tools_list, model_name: str = "") -> Any:
        """Return tool_choice value suited to the node + provider.

        v6.4.7 (maintainer 2026-04-21) — REVERT to "auto" for Kimi family.
        Moonshot Kimi K2.6 docs explicitly error-out on tool_choice other
        than auto/none (confirmed from platform.kimi.ai/docs). The real
        fix for "prose before tool_call" is the stream-level prose-abort
        guard (see `_prose_byte_abort_threshold`) + forbidden-openings
        prompt contract, not tool_choice. Anthropic still accepts the
        dict form and benefits.

        v6.4.18 (maintainer 2026-04-22) — EXTEND dict form to OpenAI / DeepSeek /
        Qwen / GPT-5.x via relay / relays. Observed 2026-04-22 19:06
        patcher run: gpt-5.4 made 100+ tool_calls across 4 minutes with 0
        file_ops.write/edit — it kept invoking `file_ops.read` under
        `tool_choice="auto"`, so the patcher produced zero disk changes.
        OpenAI chat-completions (and the relay / relays that mimic
        it) accept the dict form `{"type": "function", "function": {"name":
        "file_ops"}}` just like Anthropic. Narrow the deny-list to models
        that demonstrably reject it (Kimi K2.6, GLM-5.x tool_stream issue).
        """
        if not tools_list or not cls._node_should_force_file_ops(node_type):
            return "auto"
        m = str(model_name or "").lower()
        # v6.4.18: models that we know REJECT the dict form — keep "auto".
        _dict_form_incompatible = (
            "kimi" in m
            or bool(re.match(r"^(?:openai/|zhipu/)?glm-5(?:\.\d+)?\b", m))
        )
        if not _dict_form_incompatible:
            try:
                names = set()
                for t in tools_list:
                    if isinstance(t, dict):
                        fn = t.get("function") or t
                        if isinstance(fn, dict):
                            names.add(str(fn.get("name") or "").lower())
                if "file_ops" in names:
                    return {"type": "function", "function": {"name": "file_ops"}}
            except Exception:
                pass
        if "claude" in m or "anthropic" in m:
            try:
                names = set()
                for t in tools_list:
                    if isinstance(t, dict):
                        fn = t.get("function") or t
                        if isinstance(fn, dict):
                            names.add(str(fn.get("name") or "").lower())
                if "file_ops" in names:
                    return {"type": "tool", "name": "file_ops"}
            except Exception:
                pass
        # Kimi/OpenAI via relay: keep auto; enforcement is stream-level.
        return "auto"

    @classmethod
    def _node_thinking_exempt(cls, node_type: str) -> bool:
        role = str(node_type or "").strip().lower()
        if not role:
            return False
        # normalise "builder1"/"builder2" → "builder"
        for exempt in cls._THINKING_EXEMPT_NODES:
            if role == exempt or role.startswith(exempt):
                return True
        return False

    @classmethod
    def _reasoning_effort_for_build_node(
        cls,
        node_type: str,
        *,
        want_deep: bool,
        want_fast: bool,
        input_data: Optional[Dict[str, Any]] = None,
    ) -> str:
        """v6.4.21 (maintainer 2026-04-22) — size-aware reasoning_effort for
        builder/merger. User feedback: fast mode shouldn't always be
        'minimal' — that makes the fast/deep dial meaningless for the
        heaviest nodes. Map:

          deep → high
          fast + large project → medium
          fast + small project → low
          normal → low

        Project size heuristic uses:
          - task_type (game/website) → game=large
          - assigned_targets count ≥ 2 → large (multi-page / multi-file)
          - goal text length ≥ 600 chars → large (rich brief)

        Non-build nodes are unaffected — caller only invokes this for
        builder/merger.
        """
        role = str(node_type or "").strip().lower()
        if role not in ("builder", "merger") and not role.startswith("builder"):
            return ""
        if want_deep:
            return "high"
        if not want_fast:
            return "low"
        # fast mode — size-aware
        _data = input_data if isinstance(input_data, dict) else {}
        _task_type = str(_data.get("task_type") or "").strip().lower()
        _assigned = _data.get("assigned_targets") or _data.get("assigned_files") or []
        _assigned_count = len(_assigned) if isinstance(_assigned, (list, tuple, set)) else 0
        _goal = str(_data.get("goal") or _data.get("user_goal") or "")
        _multi_page = bool(_data.get("is_multi_page") or _data.get("multi_page"))
        _large = (
            _task_type == "game"
            or _assigned_count >= 2
            or len(_goal) >= 600
            or _multi_page
        )
        return "medium" if _large else "low"

    def _apply_thinking_config_to_kwargs(
        self,
        kwargs: Dict[str, Any],
        model_info: Dict[str, Any],
        model_name: str,
        *,
        cache_key: str = "",
        thinking_depth: Optional[str] = None,
        node_type: str = "",
        input_data: Optional[Dict[str, Any]] = None,
    ) -> None:
        """v6.1: Unified thinking/reasoning config for every provider + relay.

        Replaces the two duplicated ~45-line provider if-branches that used to
        live in _call_streaming (compat path) and _call_chat_streaming (chat
        path). Behaviour:

        * thinking_depth='deep' → turn thinking ON for every family that has it,
          using the vendor-correct payload (Anthropic budget_tokens / 4.7 adaptive,
          Qwen enable_thinking + streaming, Kimi thinking=enabled + max_tokens>=16k
          + temp=1.0, Zhipu/Doubao thinking.type, MiniMax reasoning_split,
          OpenAI GPT-5 reasoning_effort=high, xAI grok-3-mini reasoning_effort=high
          (grok-4 excluded → 400), Mistral magistral reasoning_effort=high, aigate
          union-all-flags).
        * thinking_depth='fast' → force OFF across the board.
        * thinking_depth='normal' / other → leave provider defaults.

        Env overrides (EVERMIND_<PROVIDER>_THINKING=enabled|disabled) still win
        over the depth-driven default to keep per-deployment tuning possible.
        """
        if thinking_depth is None:
            thinking_depth = self._configured_thinking_depth()
        # v6.4.22 (maintainer 2026-04-22) — two-dimension split:
        #   * `thinking_depth` drives the binary thinking FLAG (Anthropic budget,
        #     Kimi thinking.enabled, Qwen enable_thinking, Zhipu thinking.type).
        #     Exempt nodes (planner/analyst/reviewer/etc.) and kimi-family
        #     builder/merger stay OFF to avoid finish=length truncation.
        #   * `effort_depth` drives the OpenAI/GPT-5.x `reasoning_effort` slider
        #     (high/medium/low/minimal). This stays at the USER-selected deep
        #     so planner/analyst keep "high" in deep mode — decoupled from the
        #     thinking-flag exemption. Observed: v6.1 hotfix bundled both
        #     dimensions together, accidentally degrading ALL exempt nodes'
        #     reasoning_effort to "low" in deep mode (user report 2026-04-22).
        _effort_depth = thinking_depth  # preserved before exempt rewrite
        # Thinking flag exempt: builder/merger with kimi family also blocked to
        # avoid thinking eating the 16k output budget (observed 2026-04-22
        # builder1: 418s total, 281s of thinking, 46s of actual HTML output
        # before finish=length hit the cap at 12KB).
        _mn_lower = str(model_name or "").lower()
        _role_lower = str(node_type or "").lower()
        _is_kimi_build_node = (
            ("kimi" in _mn_lower)
            and (_role_lower.startswith("builder") or _role_lower.startswith("merger"))
        )
        _force_override = str(os.getenv("EVERMIND_FORCE_NODE_THINKING", "") or "").strip().lower() in ("1", "true", "on", "enabled")
        if thinking_depth == "deep" and (self._node_thinking_exempt(node_type) or _is_kimi_build_node):
            if not _force_override:
                thinking_depth = "normal"
        provider = str((model_info or {}).get("provider") or "").strip().lower()
        mn = str(model_name or "").lower()
        api_base = str((model_info or {}).get("api_base") or "").strip()
        want_deep = thinking_depth == "deep"
        want_fast = thinking_depth == "fast"
        # effort_deep/effort_fast: used for reasoning_effort assignments so
        # exempt nodes keep their user-selected intensity even when the
        # thinking flag is forced off.
        _effort_deep = _effort_depth == "deep"
        _effort_fast = _effort_depth == "fast"
        extra: Dict[str, Any] = kwargs.setdefault("extra_body", {})

        # ── Generic relay / gateway (union all flags) ───────────────────
        # v6.1: Any third-party relay (private-relay / private-relay / OpenRouter / OneAPI /
        # NewAPI / LiteLLM-Proxy / aihubmix / laozhang / etc.) gets the
        # "fire every flag, let the backend pick" treatment. This lets Evermind
        # work with ANY OpenAI-compat gateway a user plugs in, not just the
        # handful we hard-coded. Well-behaved relays silently ignore keys they
        # don't understand; the right one lights up for each upstream.
        if provider == "relay" or self._is_relay_endpoint(provider, api_base):
            ov = self._env_thinking_override("EVERMIND_RELAY_THINKING")
            if ov is None:
                ov = self._env_thinking_override("EVERMIND_AIGATE_THINKING")
            on = ov if ov is not None else want_deep
            if on:
                extra["thinking"] = {"type": "enabled"}
                extra["enable_thinking"] = True
                extra["chat_template_kwargs"] = {"enable_thinking": True}
                extra["reasoning_split"] = True
                extra["reasoning"] = {"enabled": True, "effort": "high"}
            else:
                extra["thinking"] = {"type": "disabled"}
                extra["enable_thinking"] = False
                extra["chat_template_kwargs"] = {"enable_thinking": False}
                extra["reasoning_split"] = True
                extra["no_thinking"] = True
                extra["reasoning"] = {"enabled": False, "effort": "minimal"}
            if "kimi" in mn and cache_key:
                extra["prompt_cache_key"] = cache_key
            # reasoning_effort for OpenAI / Grok / Mistral models that the
            # relay may be proxying — harmless for others
            if model_info.get("supports_reasoning_effort") or "gpt-5" in mn or "grok" in mn or "magistral" in mn:
                if "reasoning_effort" not in kwargs:
                    # v6.4.22 — decoupled from the thinking flag. Use the
                    # USER-selected depth (_effort_deep/_effort_fast), so exempt
                    # nodes (planner/analyst/reviewer/patcher/tester/debugger)
                    # keep "high" in deep mode. Builder/merger still get the
                    # size-aware helper output.
                    _build_effort = self._reasoning_effort_for_build_node(
                        node_type, want_deep=_effort_deep, want_fast=_effort_fast, input_data=input_data,
                    )
                    kwargs["reasoning_effort"] = (
                        _build_effort
                        if _build_effort
                        else ("high" if _effort_deep else ("minimal" if _effort_fast else "low"))
                    )
            if not extra:
                kwargs.pop("extra_body", None)
            return

        # ── Kimi / Moonshot ─────────────────────────────────────────────
        if provider == "kimi":
            ov = self._env_thinking_override("EVERMIND_KIMI_THINKING")
            on = ov if ov is not None else want_deep
            if on:
                extra["thinking"] = {"type": "enabled"}
                if not kwargs.get("max_tokens") or kwargs["max_tokens"] < 16000:
                    kwargs["max_tokens"] = max(int(kwargs.get("max_tokens") or 0), 16000)
                kwargs["temperature"] = 1.0
            else:
                extra["thinking"] = {"type": "disabled"}
            if cache_key:
                extra["prompt_cache_key"] = cache_key

        # ── DeepSeek ────────────────────────────────────────────────────
        elif provider == "deepseek":
            ov = self._env_thinking_override("EVERMIND_DEEPSEEK_THINKING")
            on = ov if ov is not None else want_deep
            if "reasoner" in mn or mn.endswith("-r1"):
                pass  # reasoner always thinks; nothing to inject
            elif on:
                extra["thinking"] = {"type": "enabled"}
            else:
                extra["thinking"] = {"type": "disabled"}

        # ── Qwen / DashScope ────────────────────────────────────────────
        elif provider in ("qwen", "dashscope"):
            ov = self._env_thinking_override("EVERMIND_QWEN_THINKING")
            on = ov if ov is not None else want_deep
            extra["enable_thinking"] = bool(on)
            if on:
                kwargs["stream"] = True  # 400 if non-streaming with thinking
                extra.setdefault("thinking_budget", 8192)

        # ── Zhipu GLM ───────────────────────────────────────────────────
        elif provider in ("glm", "zhipu"):
            ov = self._env_thinking_override("EVERMIND_GLM_THINKING")
            on = ov if ov is not None else want_deep
            # v6.1.3 (maintainer 2026-04-19, research sources: Z.AI migrate-to-glm-new,
            # Z.AI stream-tool docs, sglang#11888, vllm#39611, LibreChat#12585):
            # GLM-4.6+ ships with `tool_stream` DEFAULT=False. In stream+tools
            # mode this silently buffers tool_call arguments until the full
            # assistant turn completes — which our 210s pre-write watchdog
            # interprets as "no tool progress" and aborts. Explicitly opting
            # into `tool_stream=True` restores per-chunk argument streaming.
            # Put it both in extra_body (passthrough via openai-compat) and
            # top-level kwargs (LiteLLM ZAIChatConfig v1.84+ forwards it) to
            # survive LiteLLM's unknown-param filter (litellm#19923).
            if kwargs.get("tools"):
                extra.setdefault("tool_stream", True)
                kwargs.setdefault("tool_stream", True)
            # v6.1.9 research (sglang#11888, zai-org/GLM-4.5/glm_4.6_tir_guide,
            # docs.z.ai/guides/overview/quick-start): when GLM has tools +
            # stream=True, official docs **do NOT** guarantee streamed
            # tool_call arguments. zai-org's own TIR guide uses stream=False
            # exclusively. For GLM-5.x specifically, the Coding-Plan endpoint
            # (api.z.ai/api/coding/paas/v4) is the only path with reliable
            # tool calling — and it requires stream=False. Force non-stream
            # for GLM+tools to bypass the 6-minute dead-stream hang.
            if kwargs.get("tools") and str(os.getenv("EVERMIND_GLM_FORCE_NONSTREAM", "1") or "1").strip() not in ("0", "false", "no"):
                # Only override if caller hadn't explicitly set stream yet;
                # otherwise respect the explicit choice.
                if "stream" not in kwargs:
                    kwargs["stream"] = False
                    logger.info(
                        "GLM+tools: forced stream=False to avoid tool_stream silent hang (model=%s)",
                        mn,
                    )
            # Builder tool-calling on GLM is fragile when thinking is ON:
            # GLM serializes the entire reasoning_content block BEFORE emitting
            # the first tool_call, which again trips pre-write. For builder
            # role we force-disable thinking on GLM regardless of deep mode
            # (the actual coding quality doesn't depend on reasoning here).
            if str(node_type or "").strip().lower().startswith("builder"):
                on = False
            extra["thinking"] = {"type": "enabled" if on else "disabled"}

        # ── Doubao / Volc Ark ───────────────────────────────────────────
        elif provider == "doubao":
            ov = self._env_thinking_override("EVERMIND_DOUBAO_THINKING")
            on = ov if ov is not None else want_deep
            extra["thinking"] = {"type": "enabled" if on else "disabled"}

        # ── MiniMax ─────────────────────────────────────────────────────
        elif provider == "minimax":
            # No clean on/off toggle; reasoning_split is always beneficial.
            extra.setdefault("reasoning_split", True)

        # ── aigate / private-relay relay (proxies 6 国产 backends) ─────────────
        elif provider == "aigate":
            ov = self._env_thinking_override("EVERMIND_AIGATE_THINKING")
            on = ov if ov is not None else want_deep
            if on:
                extra["thinking"] = {"type": "enabled"}
                extra["enable_thinking"] = True
                extra["chat_template_kwargs"] = {"enable_thinking": True}
                extra["reasoning_split"] = True
            else:
                extra["thinking"] = {"type": "disabled"}
                extra["enable_thinking"] = False
                extra["chat_template_kwargs"] = {"enable_thinking": False}
                extra["reasoning_split"] = True
                extra["no_thinking"] = True
            if "kimi" in mn and cache_key:
                extra["prompt_cache_key"] = cache_key

        # ── Anthropic Claude ────────────────────────────────────────────
        elif provider == "anthropic":
            ov = self._env_thinking_override("EVERMIND_ANTHROPIC_THINKING")
            on = ov if ov is not None else want_deep
            if on:
                # Claude 4.7 uses adaptive (no manual budget_tokens allowed).
                # Claude 4.6 and earlier accept explicit budget_tokens.
                is_v47 = any(tok in mn for tok in ("4.7", "4-7", "opus-4-7", "sonnet-4-7"))
                if is_v47:
                    extra["thinking"] = {"type": "enabled"}
                else:
                    max_t = int(kwargs.get("max_tokens") or 8000)
                    budget = max(1024, min(10000, max_t // 2))
                    extra["thinking"] = {"type": "enabled", "budget_tokens": budget}
            # else: Claude default is off — nothing to inject

        # ── xAI Grok (mini family only supports reasoning_effort) ───────
        if provider == "xai" or "grok" in mn:
            ov = self._env_thinking_override("EVERMIND_XAI_THINKING")
            on = ov if ov is not None else want_deep
            if "mini" in mn and "reasoning_effort" not in kwargs:
                kwargs["reasoning_effort"] = "high" if on else "low"
            # grok-4 explicitly excluded — sending reasoning_effort returns 400

        # ── OpenAI GPT-5.x / o-series (reasoning_effort) ────────────────
        if "reasoning_effort" not in kwargs and model_info.get("supports_reasoning_effort"):
            ov = self._env_thinking_override("EVERMIND_OPENAI_THINKING")
            # v6.4.22 — use user-selected depth for effort (thinking-flag
            # exemption no longer suppresses effort). Size helper for builder/
            # merger; binary mapping for all other nodes.
            _build_effort = self._reasoning_effort_for_build_node(
                node_type, want_deep=_effort_deep, want_fast=_effort_fast, input_data=input_data,
            )
            if ov is True:
                kwargs["reasoning_effort"] = "high"
            elif ov is False:
                kwargs["reasoning_effort"] = "minimal"
            elif _build_effort:
                kwargs["reasoning_effort"] = _build_effort
            elif _effort_deep:
                kwargs["reasoning_effort"] = "high"
            elif _effort_fast:
                kwargs["reasoning_effort"] = "minimal"
            else:
                kwargs["reasoning_effort"] = "low"

        # ── Mistral magistral reasoning ─────────────────────────────────
        if provider == "mistral" and ("magistral" in mn or "reasoning" in mn):
            ov = self._env_thinking_override("EVERMIND_MISTRAL_THINKING")
            on = ov if ov is not None else want_deep
            kwargs.setdefault("reasoning_effort", "high" if on else "none")

        # ── Gemini: not routed through openai-compat path (handled in
        #    providers/gemini.py); nothing to do here.

        # v6.4.21 — one-line log so user can verify depth→effort mapping in
        # backend logs. Emits for build nodes (builder/merger) every call and
        # for any node where reasoning_effort/thinking was actually chosen.
        _role_norm = str(node_type or "").strip().lower()
        if (
            "reasoning_effort" in kwargs
            or (isinstance(extra, dict) and extra.get("thinking"))
            or _role_norm.startswith(("builder", "merger"))
        ):
            _eff = kwargs.get("reasoning_effort", "(n/a)")
            _think = (extra or {}).get("thinking") if isinstance(extra, dict) else None
            _think_state = (
                (_think or {}).get("type") if isinstance(_think, dict) else _think
            ) or "(n/a)"
            try:
                logger.debug(
                    "thinking_config: node=%s model=%s depth=%s effort=%s thinking=%s",
                    node_type or "(unknown)",
                    model_name or "(unknown)",
                    thinking_depth,
                    _eff,
                    _think_state,
                )
            except Exception:
                pass

        if not extra:
            kwargs.pop("extra_body", None)

    def _provider_api_base_env_key(self, provider: str) -> str:
        return {
            "openai": "OPENAI_API_BASE",
            "anthropic": "ANTHROPIC_API_BASE",
            "google": "GEMINI_API_BASE",
            "deepseek": "DEEPSEEK_API_BASE",
            "kimi": "KIMI_API_BASE",
            "qwen": "QWEN_API_BASE",
            "zhipu": "ZHIPU_API_BASE",
            "doubao": "DOUBAO_API_BASE",
            "yi": "YI_API_BASE",
            "minimax": "MINIMAX_API_BASE",
            "aigate": "AIGATE_API_BASE",  # v5.8.6
        }.get(str(provider or "").strip().lower(), "")

    def _provider_api_key_env_key(self, provider: str) -> str:
        return {
            "openai": "OPENAI_API_KEY",
            "anthropic": "ANTHROPIC_API_KEY",
            "google": "GEMINI_API_KEY",
            "deepseek": "DEEPSEEK_API_KEY",
            "kimi": "KIMI_API_KEY",
            "qwen": "QWEN_API_KEY",
            "zhipu": "ZHIPU_API_KEY",
            "doubao": "DOUBAO_API_KEY",
            "yi": "YI_API_KEY",
            "minimax": "MINIMAX_API_KEY",
            "aigate": "AIGATE_API_KEY",  # v5.8.6: private-relay.example multi-model relay
        }.get(str(provider or "").strip().lower(), "")

    # ── v5.8.6: multi-key pool per provider ──────────────────────────────
    # Users can store `kimi_api_key` + `kimi_api_key_2` (same pattern for all
    # providers). When both are present, the bridge round-robins between them
    # so concurrent nodes (imagegen + spritesheet + assetimport + 2 builders)
    # don't all hit the same Kimi key's rate limit. If primary fails with
    # auth/429, secondary takes over transparently.
    _provider_key_cursor: Dict[str, int] = {}
    _provider_key_cooldowns: Dict[str, Dict[int, float]] = {}

    def _provider_key_pool(self, provider: str) -> List[str]:
        provider_lc = str(provider or "").strip().lower()
        env_primary = self._provider_api_key_env_key(provider_lc)
        if not env_primary:
            return []
        config_primary = env_primary.lower()          # e.g. "kimi_api_key"
        config_secondary = config_primary + "_2"      # e.g. "kimi_api_key_2"
        env_secondary = env_primary + "_2"
        keys: List[str] = []
        for candidate in (
            str(self.config.get(config_primary) or "").strip(),
            str(os.getenv(env_primary) or "").strip(),
        ):
            if candidate and candidate not in keys:
                keys.append(candidate)
                break
        for candidate in (
            str(self.config.get(config_secondary) or "").strip(),
            str(os.getenv(env_secondary) or "").strip(),
        ):
            if candidate and candidate not in keys:
                keys.append(candidate)
                break
        return keys

    def _choose_provider_key(self, provider: str) -> str:
        pool = self._provider_key_pool(provider)
        if not pool:
            return ""
        if len(pool) == 1:
            return pool[0]
        provider_lc = str(provider or "").strip().lower()
        cooldowns = AIBridge._provider_key_cooldowns.setdefault(provider_lc, {})
        now = time.time()
        active = [(i, k) for i, k in enumerate(pool) if cooldowns.get(i, 0) < now]
        if not active:
            # all cooled — ignore cooldowns and pick primary; the next request
            # will re-cool it, but at least we try.
            active = list(enumerate(pool))
        cursor = AIBridge._provider_key_cursor.get(provider_lc, 0)
        # Pick the next active key in round-robin fashion.
        for _ in range(len(pool)):
            idx = cursor % len(pool)
            cursor += 1
            # pick this slot only if active
            if any(slot_idx == idx for slot_idx, _ in active):
                AIBridge._provider_key_cursor[provider_lc] = cursor
                return pool[idx]
        # Shouldn't reach here but fallback to primary active
        AIBridge._provider_key_cursor[provider_lc] = cursor
        return active[0][1]

    def _mark_provider_key_cooldown(self, provider: str, api_key: str, seconds: int = 90) -> None:
        """Called by callers that hit 401/429 on a specific key — cools only that key."""
        provider_lc = str(provider or "").strip().lower()
        pool = self._provider_key_pool(provider_lc)
        if not pool or not api_key:
            return
        cooldowns = AIBridge._provider_key_cooldowns.setdefault(provider_lc, {})
        for idx, k in enumerate(pool):
            if k == api_key:
                cooldowns[idx] = time.time() + max(5, int(seconds))
                logger.info(
                    "[KeyPool] Cooled %s key #%d for %ds (%d-key pool)",
                    provider_lc, idx + 1, seconds, len(pool),
                )
                return

    @staticmethod
    def _model_supports_temperature(model_name: str) -> bool:
        """GPT-5 series (including codex) only accepts temperature=1."""
        name_lower = str(model_name or "").lower()
        # Strip provider prefix (e.g. "openai/gpt-5.3-codex" → "gpt-5.3-codex")
        if "/" in name_lower:
            name_lower = name_lower.rsplit("/", 1)[-1]
        return not name_lower.startswith("gpt-5")

    # V4.3 PERF: Per-node temperature — builder/reviewer use low temperature
    # for deterministic output (fewer retries, higher cache hit rate).
    _NODE_TEMPERATURE = {
        "builder": 0.3,
        "reviewer": 0.3,
        "planner": 0.5,
        "merger": 0.3,
        "polisher": 0.5,
        "analyst": 0.7,
        "debugger": 0.5,
        "tester": 0.5,
    }

    def _temperature_for_node(self, node_type: str, model_name: str) -> Optional[float]:
        """Return optimal temperature for this node type, or None if model doesn't support it."""
        if not self._model_supports_temperature(model_name):
            return None
        role = normalize_node_role(node_type) or str(node_type or "").lower()
        return self._NODE_TEMPERATURE.get(role, 0.5)

    @staticmethod
    def _is_kimi_coding_plan_key(key: str) -> bool:
        """v6.1: Kimi For Coding subscription keys carry a `sk-kimi-` prefix
        (platform.kimi.ai issues them). Platform.moonshot.cn / .ai issues plain
        `sk-xxx`. The scopes are mutually exclusive — coding keys must hit
        api.kimi.com/coding/v1 or they return 401 Invalid Authentication.
        """
        k = str(key or "").strip()
        return k.startswith("sk-kimi-")

    def _kimi_routing_adjusted(self, model_info: Optional[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
        """v6.1: reorder api_base / fallback_api_bases based on detected key type.

        If caller holds a coding-plan key (sk-kimi-*), promote api.kimi.com/coding/v1
        to primary; otherwise keep registry default. Returns a shallow copy so
        the global MODEL_REGISTRY is never mutated.
        """
        if not isinstance(model_info, dict):
            return model_info
        provider = str(model_info.get("provider") or "").strip().lower()
        if provider != "kimi":
            return model_info
        try:
            key = self._resolved_api_key_for_model_info(model_info)
        except Exception:
            key = ""
        coding_url = "https://api.kimi.com/coding/v1"
        cn_url = "https://api.moonshot.cn/v1"
        ai_url = "https://api.moonshot.ai/v1"
        is_coding = self._is_kimi_coding_plan_key(key)
        primary = coding_url if is_coding else cn_url
        if is_coding:
            fallbacks = [ai_url, cn_url]
        else:
            fallbacks = [ai_url, coding_url]
        if str(model_info.get("api_base") or "").rstrip("/") == primary.rstrip("/"):
            existing_fb = [str(b or "").rstrip("/") for b in (model_info.get("fallback_api_bases") or [])]
            if existing_fb == [f.rstrip("/") for f in fallbacks]:
                return model_info
        adjusted = dict(model_info)
        adjusted["api_base"] = primary
        adjusted["fallback_api_bases"] = fallbacks
        return adjusted

    def _resolved_api_base_for_model_info(self, model_info: Optional[Dict[str, Any]]) -> str:
        info = self._kimi_routing_adjusted(model_info) if isinstance(model_info, dict) else {}
        if not isinstance(info, dict):
            info = {}
        provider = str(info.get("provider") or "").strip().lower()
        env_base_key = self._provider_api_base_env_key(provider)
        env_base = str(os.getenv(env_base_key, "") if env_base_key else "").strip()
        configured_base = str(info.get("api_base") or "").strip()
        return (env_base or configured_base).rstrip("/")

    def _resolved_api_key_for_model_info(self, model_info: Optional[Dict[str, Any]]) -> str:
        info = model_info if isinstance(model_info, dict) else {}
        provider = str(info.get("provider") or "").strip().lower()
        env_key = self._provider_api_key_env_key(provider)
        if not env_key:
            return ""
        # v5.8.6: first try the key pool (supports primary + secondary round-robin
        # with per-key cooldowns for rate-limit resilience). Falls back to the
        # legacy single-key resolution chain if the pool is empty.
        pooled = self._choose_provider_key(provider)
        if pooled:
            return pooled
        # Legacy path: nested api_keys dict is still supported for speed-test endpoints.
        api_keys = self.config.get("api_keys")
        if isinstance(api_keys, dict):
            key = str(api_keys.get(provider) or "").strip()
            if key:
                return key
        return ""

    def _custom_compatible_gateway_base(self, model_info: Optional[Dict[str, Any]]) -> str:
        info = model_info if isinstance(model_info, dict) else {}
        provider = str(info.get("provider") or "").strip().lower()
        if provider in ("relay", "ollama", ""):
            return ""
        env_base_key = self._provider_api_base_env_key(provider)
        env_base = str(os.getenv(env_base_key, "") if env_base_key else "").strip().rstrip("/")
        if not env_base:
            return ""
        # A non-official base (e.g. private-relay.com) IS a custom gateway even when
        # model config and env var match — we need the streaming-capable path.
        _official = ("https://api.openai.com", "https://api.anthropic.com",
                     "https://api.deepseek.com", "https://generativelanguage.googleapis.com")
        if any(env_base.lower().startswith(o) for o in _official):
            return ""
        return env_base

    def _compatible_gateway_key(self, model_info: Optional[Dict[str, Any]], *, model_specific: bool = False) -> str:
        info = model_info if isinstance(model_info, dict) else {}
        base = self._custom_compatible_gateway_base(info)
        if not base:
            return ""
        provider = str(info.get("provider") or "").strip().lower() or "unknown"
        key = f"{provider}:{base}"
        if model_specific:
            litellm_id = str(info.get("litellm_id") or "").strip()
            if litellm_id:
                key = f"{key}:{litellm_id}"
        return key

    def _compatible_gateway_host(self, model_info: Optional[Dict[str, Any]]) -> str:
        base = self._custom_compatible_gateway_base(model_info)
        if not base:
            return ""
        try:
            parsed = urlparse(base)
            return parsed.netloc or parsed.path or base
        except Exception:
            return base

    def _fallback_gateway_bases(self, model_info: Optional[Dict[str, Any]]) -> List[str]:
        """Return alternative API base URLs for a model when the primary gateway is blocked."""
        info = self._kimi_routing_adjusted(model_info) if isinstance(model_info, dict) else {}
        if not isinstance(info, dict):
            info = {}
        provider = str(info.get("provider") or "").strip().lower()
        # Per-model configured fallbacks
        configured = list(info.get("fallback_api_bases") or [])
        # Provider-level env fallback
        if provider:
            env_key = f"EVERMIND_{provider.upper()}_FALLBACK_API_BASE"
            env_val = str(os.getenv(env_key, "")).strip().rstrip("/")
            if env_val and env_val not in configured:
                configured.append(env_val)
        return [b for b in configured if b]

    def _compatible_gateway_error_trips_circuit(self, error_message: str) -> bool:
        error_lower = str(error_message or "").lower()
        if not error_lower:
            return True
        request_rejection_markers = (
            "your request was blocked",
            "request was blocked",
            "content policy",
            "safety system",
            "invalid_request_error",
            "invalid request",
            "model not found",
            "does not exist",
            "unsupported model",
            "context length",
            "maximum context",
            "prompt too long",
            "messages must",
            "tool schema",
            "unsupported input",
            "invalid image",
            "api key",
            "api_key",
            "invalid key",
            "not configured",
            "unauthorized",
            "forbidden",
            "401",
            "403",
            "authentication",
            "auth failed",
            "permission",
            # V4.2 FIX: Timeouts should NOT trip the circuit breaker.
            # A timeout means OUR budget is too short, not that the gateway
            # is broken.  gpt-5.4 produced 9001 chars before hard-ceiling
            # timeout — the gateway was clearly working.
            "timeout",
            "hard-ceiling timeout",
            "initial-activity timeout",
            "api call exceeded",
            "timed out",
        )
        return not any(marker in error_lower for marker in request_rejection_markers)

    def _compatible_gateway_failure_threshold(self) -> int:
        # V4.6 SPEED: Raised from 2→5 — tolerate more transient failures before
        # tripping circuit breaker. Prioritize throughput over caution.
        return self._read_int_env("EVERMIND_COMPAT_GATEWAY_FAILURE_THRESHOLD", 5, 1, 20)

    def _compatible_gateway_circuit_open_seconds(self) -> float:
        # V4.6 SPEED: Reduced from 45→10s — recover from circuit-open state
        # much faster. With threshold=5, false trips are already rare.
        return self._read_float_env("EVERMIND_COMPAT_GATEWAY_CIRCUIT_OPEN_SEC", 10.0, 3.0, 300.0)

    def _compatible_gateway_rejection_cooldown_seconds(self) -> float:
        # V4.6 SPEED: Reduced from 120→15s — the old 120s cooldown was the
        # single biggest source of node idle time. Most gateway rejections
        # are transient (503, rate-limit bursts) and resolve in seconds.
        # For persistent policy blocks, the fallback chain handles it.
        return self._read_float_env("EVERMIND_COMPAT_GATEWAY_REJECTION_COOLDOWN_SEC", 15.0, 5.0, 1800.0)

    def _compatible_gateway_recent_rejection_grace_seconds(self) -> float:
        # V4.6 SPEED: Reduced from 3600→300s — don't carry stale failure
        # memory across restarts for an hour. 5 minutes is enough to avoid
        # immediate retry storms while not blocking fresh attempts.
        return self._read_float_env("EVERMIND_COMPAT_GATEWAY_RECENT_REJECTION_GRACE_SEC", 300.0, 60.0, 172800.0)

    def _compatible_gateway_error_trips_rejection_cooldown(self, error_message: str) -> bool:
        error_lower = str(error_message or "").lower()
        if not error_lower:
            return False
        rejection_cooldown_markers = (
            "your request was blocked",
            "request was blocked",
            "blocked by",
            "content policy",
            "safety system",
            "relay - ai api gateway",
            "model not found",
            "does not exist",
            "unsupported model",
            "empty or invalid response from llm endpoint",
            "invalid response from llm endpoint",
            "received: '<!doctype html",
            # v5.8.6: relay quota exhaustion is a hard persistent state, not a
            # transient blip. Treat it like a policy block so the cooldown kicks
            # in instead of retry-spamming the same 403 dozens of times.
            "insufficient_user_quota",
            "insufficient user quota",
            "用户额度不足",
            "quota exceeded",
            "exceeded your current quota",
            "余额不足",
            # v6.3 (maintainer 2026-04-20): auth permanent errors. Without these
            # markers, a bad key burns 15s of cooldown then retries forever.
            "invalid token",
            "invalid api key",
            "invalid_authentication_error",
            "api key appears to be invalid",
            "401 unauthorized",
        )
        return any(marker in error_lower for marker in rejection_cooldown_markers)

    def _compatible_gateway_state(self, model_info: Optional[Dict[str, Any]]) -> tuple[str, Optional[Dict[str, Any]]]:
        key = self._compatible_gateway_key(model_info)
        if not key:
            return "", None
        state = self._compat_gateway_health.setdefault(key, {
            "consecutive_failures": 0,
            "failure_count": 0,
            "success_count": 0,
            "circuit_open_until": 0.0,
            "rejection_cooldown_until": 0.0,
            "last_error": "",
            "last_failure_at": 0.0,
            "last_rejection_at": 0.0,
            "last_success_at": 0.0,
            "last_latency_ms": 0,
            "ewma_latency_ms": 0.0,
        })
        return key, state

    def _compatible_gateway_preflight_error(self, model_info: Optional[Dict[str, Any]]) -> str:
        _key, state = self._compatible_gateway_state(model_info)
        if not state:
            return ""
        # P0 FIX 2026-04-04: Check model-specific rejection first — if gpt-5.4 is
        # policy-blocked but gpt-4o is fine, only gpt-5.4 should be blocked.
        model_key = self._compatible_gateway_key(model_info, model_specific=True)
        ms_state = self._compat_gateway_health.get(model_key) if model_key and model_key != _key else None
        if ms_state:
            ms_rejection_until = float(ms_state.get("rejection_cooldown_until") or 0.0)
            if ms_rejection_until > time.time():
                remaining = max(1, int(round(ms_rejection_until - time.time())))
                host = self._compatible_gateway_host(model_info) or "custom gateway"
                model_id = str((model_info or {}).get("litellm_id") or "")
                last_error = _sanitize_error(str(ms_state.get("last_error") or "")).strip()
                detail = f"; last error: {last_error}" if last_error else ""
                return f"compatible gateway rejection cooldown for {host} model={model_id} ({remaining}s remaining{detail})"
        rejection_cooldown_until = float(state.get("rejection_cooldown_until") or 0.0)
        now = time.time()
        if rejection_cooldown_until > now:
            remaining = max(1, int(round(rejection_cooldown_until - now)))
            host = self._compatible_gateway_host(model_info) or "custom gateway"
            last_error = _sanitize_error(str(state.get("last_error") or "")).strip()
            detail = f"; last error: {last_error}" if last_error else ""
            return f"compatible gateway rejection cooldown for {host} ({remaining}s remaining{detail})"
        circuit_open_until = float(state.get("circuit_open_until") or 0.0)
        if circuit_open_until <= now:
            return ""
        remaining = max(1, int(round(circuit_open_until - now)))
        host = self._compatible_gateway_host(model_info) or "custom gateway"
        last_error = _sanitize_error(str(state.get("last_error") or "")).strip()
        detail = f"; last error: {last_error}" if last_error else ""
        return f"compatible gateway circuit open for {host} ({remaining}s remaining{detail})"

    def _compatible_gateway_recent_unhealthy_reason(self, model_info: Optional[Dict[str, Any]]) -> str:
        preflight_error = self._compatible_gateway_preflight_error(model_info)
        if preflight_error:
            return preflight_error
        _key, state = self._compatible_gateway_state(model_info)
        if not state:
            return ""
        last_rejection_at = float(state.get("last_rejection_at") or 0.0)
        if last_rejection_at <= 0:
            # V4.2 FIX (Codex #1 follow-up): gateway-level last_rejection_at
            # may be unset when the rejection was model-specific.  Check the
            # model-specific health state so that e.g. gpt-5.4 is still
            # deprioritised after a model-specific rejection, without blocking
            # sibling models on the same gateway.
            model_key = self._compatible_gateway_key(model_info, model_specific=True)
            ms_state = self._compat_gateway_health.get(model_key) if model_key and model_key != _key else None
            if not ms_state:
                return ""
            ms_rejection_at = float(ms_state.get("last_rejection_at") or 0.0)
            if ms_rejection_at <= 0:
                return ""
            ms_success_at = float(ms_state.get("last_success_at") or 0.0)
            if ms_success_at >= ms_rejection_at:
                return ""
            age_sec = max(0.0, time.time() - ms_rejection_at)
            grace_sec = self._compatible_gateway_recent_rejection_grace_seconds()
            if age_sec > grace_sec:
                return ""
            host = self._compatible_gateway_host(model_info) or "custom gateway"
            model_id = str((model_info or {}).get("litellm_id") or "")
            age_text = max(1, int(round(age_sec)))
            last_error = _sanitize_error(str(ms_state.get("last_error") or "")).strip()
            detail = f"; last error: {last_error}" if last_error else ""
            return f"compatible gateway recent rejection on {host} model={model_id} ({age_text}s ago{detail})"
        last_success_at = float(state.get("last_success_at") or 0.0)
        if last_success_at >= last_rejection_at:
            return ""
        age_sec = max(0.0, time.time() - last_rejection_at)
        grace_sec = self._compatible_gateway_recent_rejection_grace_seconds()
        if age_sec > grace_sec:
            return ""
        host = self._compatible_gateway_host(model_info) or "custom gateway"
        age_text = max(1, int(round(age_sec)))
        last_error = _sanitize_error(str(state.get("last_error") or "")).strip()
        detail = f"; last error: {last_error}" if last_error else ""
        return f"compatible gateway recent rejection on {host} ({age_text}s ago{detail})"

    def _record_compatible_gateway_success(self, model_info: Optional[Dict[str, Any]], latency_ms: float = 0.0) -> None:
        _key, state = self._compatible_gateway_state(model_info)
        if not state:
            return
        recovered = bool(
            state.get("consecutive_failures")
            or state.get("circuit_open_until")
            or state.get("rejection_cooldown_until")
        )
        now = time.time()
        state["consecutive_failures"] = 0
        # v6.4.11 (maintainer 2026-04-22): reset the exp-backoff rejection streak
        # on every successful response so a recovered gateway isn't held
        # hostage by its earlier failure history.
        state["consecutive_rejections"] = 0
        state["circuit_open_until"] = 0.0
        state["rejection_cooldown_until"] = 0.0
        state["success_count"] = int(state.get("success_count") or 0) + 1
        state["last_success_at"] = now
        state["last_error"] = ""
        if latency_ms > 0:
            latency_value = int(round(latency_ms))
            prev_ewma = float(state.get("ewma_latency_ms") or 0.0)
            state["last_latency_ms"] = latency_value
            state["ewma_latency_ms"] = (
                latency_value if prev_ewma <= 0 else round(prev_ewma * 0.7 + latency_value * 0.3, 1)
            )
        if recovered:
            logger.info(
                "Compatible gateway recovered: provider=%s host=%s latency_ms=%s ewma_ms=%s",
                str((model_info or {}).get("provider") or "").strip().lower() or "unknown",
                self._compatible_gateway_host(model_info) or "custom gateway",
                state.get("last_latency_ms", 0),
                state.get("ewma_latency_ms", 0),
            )

    def _record_compatible_gateway_failure(
        self,
        model_info: Optional[Dict[str, Any]],
        error_message: str,
        latency_ms: float = 0.0,
    ) -> None:
        _key, state = self._compatible_gateway_state(model_info)
        if not state:
            return
        now = time.time()
        state["failure_count"] = int(state.get("failure_count") or 0) + 1
        state["consecutive_failures"] = int(state.get("consecutive_failures") or 0) + 1
        state["last_failure_at"] = now
        state["last_error"] = _sanitize_error(str(error_message or "gateway error"))[:200]
        if latency_ms > 0:
            state["last_latency_ms"] = int(round(latency_ms))
        if self._compatible_gateway_error_trips_rejection_cooldown(error_message):
            cooldown_sec = self._compatible_gateway_rejection_cooldown_seconds()
            # v5.8.6: quota exhaustion is not transient — a 403
            # `insufficient_user_quota` / `用户额度不足` will keep returning until
            # the user tops up their relay account. Use a run-length cooldown
            # (1 hour) so we don't burn 100+ retry attempts on a dead wallet.
            err_lower = str(error_message or "").lower()
            if any(marker in err_lower for marker in (
                "insufficient_user_quota", "insufficient user quota",
                "用户额度不足", "余额不足",
                "quota exceeded", "exceeded your current quota",
            )):
                cooldown_sec = max(cooldown_sec, 3600.0)
            # v6.3 (maintainer 2026-04-20): permanent errors (model doesn't exist,
            # invalid API key, unsupported model) will keep returning forever
            # until config changes. Default 15s cooldown was burning 75s
            # pre-write timeout per retry, dozens of times per run. Escalate
            # to 30 min so the fallback chain exits this dead model quickly.
            _is_permanent_error = any(marker in err_lower for marker in (
                "does not exist",
                "model not found",
                "unsupported model",
                "invalid token",
                "invalid api key",
                "invalid_authentication_error",
                "api key appears to be invalid",
                "401 unauthorized",
            ))
            if _is_permanent_error:
                cooldown_sec = max(cooldown_sec, 1800.0)
            # v6.1.15 (maintainer 2026-04-20): 402 insufficient_quota affects the
            # WHOLE gateway account (e.g. private-relay all plans out of balance),
            # not just one model. Previously each model on the gateway got
            # 1h cooldown INDEPENDENTLY — so qwen/minimax/kimi each burned
            # a 402 roundtrip. Now set a GATEWAY-level cooldown too so
            # sibling models skip the dead gateway immediately.
            # v7.3 (maintainer 2026-04-26): include the membership-benefits 402
            # variant from kimi/private-relay/private-relay relays. Same semantics —
            # the entire gateway account is dry, not just one model.
            _is_quota_exhausted = any(marker in err_lower for marker in (
                "insufficient_quota", "用户额度不足", "余额不足",
                "quota exceeded", "exceeded your current quota",
                "额度不足", "账户余额",
                "membership benefits",
                "membership is active",
                "verify your membership",
            ))
            state["consecutive_failures"] = 0
            state["circuit_open_until"] = 0.0
            # P0 FIX 2026-04-13: Only write rejection cooldown to MODEL-SPECIFIC key,
            # NOT the gateway-level key. A gpt-5.4 "model not found" must NOT block
            # gpt-5.3-codex/gpt-5.4-mini on the same gateway for 300s.
            model_key = self._compatible_gateway_key(model_info, model_specific=True)
            # v6.1.15 quota-exhausted → always lock gateway-level too.
            if _is_quota_exhausted:
                state["rejection_cooldown_until"] = now + cooldown_sec
                state["last_rejection_at"] = now
                logger.warning(
                    "Gateway-level quota exhaustion cooldown %ss applied (all models on this gateway blocked): provider=%s host=%s",
                    int(round(cooldown_sec)),
                    str((model_info or {}).get("provider") or "").strip().lower() or "unknown",
                    self._compatible_gateway_host(model_info) or "custom gateway",
                )
            if model_key and model_key != _key:
                ms_state = self._compat_gateway_health.setdefault(model_key, {
                    "consecutive_failures": 0, "failure_count": 0, "success_count": 0,
                    "circuit_open_until": 0.0, "rejection_cooldown_until": 0.0,
                    "last_error": "", "last_failure_at": 0.0, "last_rejection_at": 0.0,
                    "last_success_at": 0.0, "last_latency_ms": 0, "ewma_latency_ms": 0.0,
                })
                ms_state["rejection_cooldown_until"] = now + cooldown_sec
                ms_state["last_rejection_at"] = now
                ms_state["last_error"] = state["last_error"]
                # V4.2 FIX (Codex #1): Do NOT set gateway-level last_rejection_at
                # when the rejection is model-specific.  Otherwise sibling models
                # on the same gateway (e.g. gpt-5.4-mini after gpt-5.4 "model not
                # found") are incorrectly skipped by _next_fallback_candidate.
            else:
                # No model-specific key — fall back to gateway-level as before
                state["rejection_cooldown_until"] = now + cooldown_sec
                state["last_rejection_at"] = now
            logger.warning(
                "Compatible gateway rejection cooldown: provider=%s host=%s model=%s cooldown=%ss error=%s",
                str((model_info or {}).get("provider") or "").strip().lower() or "unknown",
                self._compatible_gateway_host(model_info) or "custom gateway",
                str((model_info or {}).get("litellm_id") or ""),
                int(round(cooldown_sec)),
                state.get("last_error", ""),
            )
            return
        if not self._compatible_gateway_error_trips_circuit(error_message):
            state["consecutive_failures"] = 0
            state["circuit_open_until"] = 0.0
            state["rejection_cooldown_until"] = 0.0
            logger.warning(
                "Compatible gateway request rejected without opening circuit: provider=%s host=%s error=%s",
                str((model_info or {}).get("provider") or "").strip().lower() or "unknown",
                self._compatible_gateway_host(model_info) or "custom gateway",
                state.get("last_error", ""),
            )
            return
        threshold = self._compatible_gateway_failure_threshold()
        host = self._compatible_gateway_host(model_info) or "custom gateway"
        if int(state.get("consecutive_failures") or 0) >= threshold:
            state["circuit_open_until"] = now + self._compatible_gateway_circuit_open_seconds()
            logger.warning(
                "Compatible gateway circuit OPEN: provider=%s host=%s failures=%s error=%s",
                str((model_info or {}).get("provider") or "").strip().lower() or "unknown",
                host,
                state.get("consecutive_failures", 0),
                state.get("last_error", ""),
            )
            return
        logger.warning(
            "Compatible gateway failure: provider=%s host=%s failures=%s/%s error=%s",
            str((model_info or {}).get("provider") or "").strip().lower() or "unknown",
            host,
            state.get("consecutive_failures", 0),
            threshold,
            state.get("last_error", ""),
        )

    def _legacy_model_fallback_chain(self, primary_model: str) -> List[str]:
        chain: List[str] = []
        seen: set[str] = set()
        for model_name in [str(primary_model or "").strip(), *LEGACY_AUTO_FALLBACK_ORDER]:
            normalized = str(model_name or "").strip()
            if not normalized or normalized in seen:
                continue
            seen.add(normalized)
            chain.append(normalized)
        return chain

    def _provider_auth_failure_grace_seconds(self) -> float:
        # V4.4: Reduced from 600s to 90s — 600s was catastrophically long.
        # A single transient 401 (network hiccup, rate limit) would block an
        # entire provider for 10 minutes, killing every node in the pipeline.
        return self._read_float_env("EVERMIND_PROVIDER_AUTH_FAILURE_GRACE_SEC", 90.0, 15.0, 600.0)

    # V4.4: Minimum consecutive auth failures before triggering cooldown.
    # Prevents a single transient 401 from cascading into full provider block.
    _PROVIDER_AUTH_MIN_STRIKES = 2
    # v5.2: At this strike count the key is effectively invalid, not transient.
    # Escalate cooldown to 1h so we stop spamming the upstream API and the log.
    # User must fix the key and (typically) restart the backend.
    _PROVIDER_AUTH_PERMANENT_STRIKES = 5

    def _provider_auth_seed_max_age_seconds(self) -> float:
        """
        Limit how long auth-failure cooldowns recovered from historical logs stay valid.
        This prevents stale failures from poisoning a fresh backend session.
        """
        return self._read_float_env("EVERMIND_PROVIDER_AUTH_SEED_MAX_AGE_SEC", 900.0, 0.0, 43200.0)

    def _provider_auth_state(self, provider: str) -> Optional[Dict[str, Any]]:
        normalized = str(provider or "").strip().lower()
        if normalized in ("", "relay", "ollama"):
            return None
        return self._provider_auth_health.setdefault(normalized, {
            "blocked_until": 0.0,
            "last_error": "",
            "last_failure_at": 0.0,
            "last_success_at": 0.0,
            "consecutive_auth_failures": 0,  # V4.4: strike counter
        })

    def _provider_recent_auth_failure_reason(self, model_info: Optional[Dict[str, Any]]) -> str:
        provider = str((model_info or {}).get("provider") or "").strip().lower()
        state = self._provider_auth_state(provider)
        if not state:
            return ""
        blocked_until = float(state.get("blocked_until") or 0.0)
        if blocked_until <= time.time():
            return ""
        remaining = max(1, int(round(blocked_until - time.time())))
        last_error = _sanitize_error(str(state.get("last_error") or "")).strip()
        detail = f"; last error: {last_error}" if last_error else ""
        return f"recent {provider} auth failure ({remaining}s remaining{detail})"

    def _rotate_endpoint_on_auth_failure(self, model_info: Dict[str, Any]) -> None:
        """v5.3: Demote current api_base and promote next fallback_api_bases entry.
        Called on 401 for providers (kimi) where multiple valid endpoints exist.
        Mutates model_info IN PLACE — safe because _resolve_model returns the
        live MODEL_REGISTRY reference, so the rotation sticks for subsequent
        calls in this backend process. Reset on backend restart."""
        current = str(model_info.get("api_base") or "").strip()
        fallbacks = [str(b or "").strip() for b in (model_info.get("fallback_api_bases") or [])]
        fallbacks = [b for b in fallbacks if b]
        if not current or not fallbacks:
            return
        # Pick the first non-current fallback
        next_base = None
        for fb in fallbacks:
            if fb != current:
                next_base = fb
                break
        if not next_base:
            return
        # Demote current base to the end, promote next_base to api_base
        remaining = [b for b in fallbacks if b != next_base]
        if current not in remaining:
            remaining.append(current)
        model_info["api_base"] = next_base
        model_info["fallback_api_bases"] = remaining
        logger.warning(
            "v5.3 endpoint rotation: provider=%s api_base %s -> %s (after 401); remaining fallbacks=%s",
            model_info.get("provider", "?"),
            current,
            next_base,
            remaining,
        )

    def _record_provider_auth_failure(self, model_info: Optional[Dict[str, Any]], error_message: str) -> None:
        provider = str((model_info or {}).get("provider") or "").strip().lower()
        state = self._provider_auth_state(provider)
        if not state:
            return
        now = time.time()
        state["last_failure_at"] = now
        state["last_error"] = _sanitize_error(str(error_message or "authentication failed"))[:200]
        # v5.3: Endpoint rotation for providers with multi-region endpoints
        # (currently only `kimi` since it has 3 valid bases — moonshot.cn /
        # moonshot.ai / kimi.com-coding). On 401, demote the current api_base
        # and promote the next fallback_api_bases entry BEFORE cooldown fires,
        # so the next retry transparently hits the alternate endpoint. Users
        # frequently hit this when their key belongs to one endpoint family but
        # Evermind routed them to another.
        _rotation_disabled = str(os.getenv("EVERMIND_DISABLE_ENDPOINT_ROTATION", "0")).strip().lower() in ("1", "true", "yes", "on")
        # v5.3+: Rotation applies to ANY provider with >1 fallback_api_bases entry.
        # Currently active for: kimi (3 endpoints), minimax (2 endpoints).
        if (
            isinstance(model_info, dict)
            and not _rotation_disabled
            and len(model_info.get("fallback_api_bases") or []) >= 1
        ):
            self._rotate_endpoint_on_auth_failure(model_info)
        # V4.4: Require N consecutive auth failures before triggering cooldown.
        # A single transient 401 should NOT block the entire provider.
        strikes = int(state.get("consecutive_auth_failures") or 0) + 1
        state["consecutive_auth_failures"] = strikes
        if strikes < self._PROVIDER_AUTH_MIN_STRIKES:
            logger.info(
                "Provider auth strike %d/%d (no cooldown yet): provider=%s error=%s",
                strikes, self._PROVIDER_AUTH_MIN_STRIKES,
                provider or "unknown", state.get("last_error", ""),
            )
            return
        cooldown = self._provider_auth_failure_grace_seconds()
        # v5.2: Escalate cooldown to 1h once we've hit _PROVIDER_AUTH_PERMANENT_STRIKES.
        # Rationale: a 5th consecutive 401 is not a transient hiccup — the key is
        # invalid/expired. Continuing to retry every 90s wastes quota and spams logs.
        escalated = strikes >= self._PROVIDER_AUTH_PERMANENT_STRIKES
        if escalated:
            cooldown = max(cooldown, 3600.0)
        state["blocked_until"] = now + cooldown
        log_fn = logger.error if escalated else logger.warning
        log_fn(
            "Provider auth failure cooldown: provider=%s cooldown=%ss strikes=%d error=%s%s",
            provider or "unknown",
            int(round(cooldown)),
            strikes,
            state.get("last_error", ""),
            " (escalated — key likely invalid; fix config and restart backend)" if escalated else "",
        )

    def _record_provider_auth_success(self, model_info: Optional[Dict[str, Any]]) -> None:
        provider = str((model_info or {}).get("provider") or "").strip().lower()
        state = self._provider_auth_state(provider)
        if not state:
            return
        if not any(state.get(k) for k in ("blocked_until", "last_error", "last_failure_at", "consecutive_auth_failures")):
            return
        state["blocked_until"] = 0.0
        state["last_error"] = ""
        state["consecutive_auth_failures"] = 0  # V4.4: reset strike counter
        state["last_success_at"] = time.time()
        logger.info("Provider auth failure cooldown cleared: provider=%s", provider or "unknown")

    def _filter_viable_model_candidates(self, candidates: List[str]) -> List[str]:
        filtered: List[str] = []
        seen: set[str] = set()
        blocked_by_auth: List[str] = []
        for raw_name in candidates or []:
            model_name = str(raw_name or "").strip()
            if not model_name or model_name in seen:
                continue
            seen.add(model_name)
            model_info = self._resolve_model(model_name)
            provider = str(model_info.get("provider") or "").strip().lower()
            if provider in ("relay", "ollama", ""):
                filtered.append(model_name)
                continue
            auth_reason = self._provider_recent_auth_failure_reason(model_info)
            if auth_reason:
                blocked_by_auth.append(model_name)
                continue
            if self._check_api_key(model_name, model_info):
                continue
            filtered.append(model_name)

        # V4.4: Last-resort circuit breaker — if ALL candidates were blocked
        # by auth cooldown and none survived, clear the oldest cooldown and
        # let those candidates through.  This prevents the catastrophic
        # scenario where transient 401s on two providers kill an entire run.
        if not filtered and blocked_by_auth:
            self._emergency_clear_oldest_auth_cooldown()
            for model_name in blocked_by_auth:
                model_info = self._resolve_model(model_name)
                if not self._provider_recent_auth_failure_reason(model_info):
                    filtered.append(model_name)
            if filtered:
                logger.warning(
                    "Emergency auth cooldown clear recovered %d candidate(s): %s",
                    len(filtered), filtered[:4],
                )
            else:
                # Even after clearing oldest, still blocked — return all as last resort
                filtered = list(blocked_by_auth)
                logger.warning(
                    "All providers auth-blocked, returning all %d as last resort: %s",
                    len(filtered), filtered[:4],
                )

        return filtered

    def _emergency_clear_oldest_auth_cooldown(self) -> None:
        """Clear the provider auth cooldown that was set earliest.
        Called when ALL model candidates are blocked by auth cooldowns."""
        oldest_provider = ""
        oldest_failure_at = float("inf")
        for provider, state in self._provider_auth_health.items():
            blocked_until = float(state.get("blocked_until") or 0.0)
            if blocked_until <= time.time():
                continue
            failure_at = float(state.get("last_failure_at") or 0.0)
            if failure_at < oldest_failure_at:
                oldest_failure_at = failure_at
                oldest_provider = provider
        if oldest_provider:
            state = self._provider_auth_health.get(oldest_provider)
            if state:
                state["blocked_until"] = 0.0
                state["consecutive_auth_failures"] = 0
                logger.warning(
                    "Emergency cleared auth cooldown for provider=%s (oldest failure at %s)",
                    oldest_provider,
                    time.strftime("%H:%M:%S", time.localtime(oldest_failure_at)) if oldest_failure_at < float("inf") else "unknown",
                )

    def _augment_candidates_for_compatible_gateway(self, node_type: str, candidates: List[str]) -> List[str]:
        if len(candidates or []) != 1:
            return candidates
        normalized_node_type = normalize_node_role(str(node_type or "").strip())
        if normalized_node_type not in self._compatible_gateway_fail_fast_node_types():
            return candidates
        primary = str(candidates[0] or "").strip()
        if not primary:
            return candidates
        if not self._custom_compatible_gateway_base(self._resolve_model(primary)):
            return candidates
        augmented = list(candidates)
        for model_name in self._legacy_model_fallback_chain(primary):
            if model_name not in augmented:
                augmented.append(model_name)
        return augmented

    def _relay_model_candidates_for(self, model_name: str) -> List[str]:
        target = str(model_name or "").strip()
        if not target:
            return []
        relay_mgr = get_relay_manager()
        return relay_mgr.relay_model_candidates_for(target)

    def _augment_candidates_with_matching_relays(self, candidates: List[str]) -> List[str]:
        augmented: List[str] = []
        seen: set[str] = set()
        _model_cache: Dict[str, Dict] = {}  # Local cache to avoid repeated _resolve_model calls
        for model_name in candidates or []:
            normalized = str(model_name or "").strip()
            if not normalized or normalized in seen:
                continue
            seen.add(normalized)
            augmented.append(normalized)
            if normalized not in _model_cache:
                _model_cache[normalized] = self._resolve_model(normalized)
            provider = str(_model_cache[normalized].get("provider") or "").strip().lower()
            if provider == "relay":
                continue
            for relay_candidate in self._relay_model_candidates_for(normalized):
                if relay_candidate in seen:
                    continue
                seen.add(relay_candidate)
                augmented.append(relay_candidate)
        return augmented

    def _prefer_matching_relays_for_custom_gateway(self, node_type: str, candidates: List[str]) -> List[str]:
        normalized_node_type = normalize_node_role(str(node_type or "").strip())
        if normalized_node_type not in self._compatible_gateway_fail_fast_node_types():
            return candidates

        available = {
            str(model_name or "").strip()
            for model_name in (candidates or [])
            if str(model_name or "").strip()
        }
        preferred: List[str] = []
        seen: set[str] = set()
        _model_cache: Dict[str, Dict] = {}

        for raw_model_name in candidates or []:
            model_name = str(raw_model_name or "").strip()
            if not model_name or model_name in seen:
                continue

            if model_name not in _model_cache:
                _model_cache[model_name] = self._resolve_model(model_name)
            model_info = _model_cache[model_name]
            provider = str(model_info.get("provider") or "").strip().lower()
            if provider != "relay" and self._custom_compatible_gateway_base(model_info):
                for relay_candidate in self._relay_model_candidates_for(model_name):
                    relay_name = str(relay_candidate or "").strip()
                    if not relay_name or relay_name in seen or relay_name not in available:
                        continue
                    seen.add(relay_name)
                    preferred.append(relay_name)

            if model_name not in seen:
                seen.add(model_name)
                preferred.append(model_name)

        return preferred or candidates

    def _promote_matching_relays_for_unhealthy_gateway(self, node_type: str, candidates: List[str]) -> List[str]:
        normalized_node_type = normalize_node_role(str(node_type or "").strip())
        if normalized_node_type not in self._compatible_gateway_fail_fast_node_types():
            return candidates

        available = {
            str(model_name or "").strip()
            for model_name in (candidates or [])
            if str(model_name or "").strip()
        }
        promoted: List[str] = []
        seen: set[str] = set()
        _model_cache: Dict[str, Dict] = {}

        for raw_model_name in candidates or []:
            model_name = str(raw_model_name or "").strip()
            if not model_name or model_name in seen:
                continue

            if model_name not in _model_cache:
                _model_cache[model_name] = self._resolve_model(model_name)
            model_info = _model_cache[model_name]
            provider = str(model_info.get("provider") or "").strip().lower()
            if provider != "relay" and self._custom_compatible_gateway_base(model_info):
                unhealthy_reason = self._compatible_gateway_recent_unhealthy_reason(model_info)
                if unhealthy_reason:
                    for relay_candidate in self._relay_model_candidates_for(model_name):
                        relay_name = str(relay_candidate or "").strip()
                        if not relay_name or relay_name in seen or relay_name not in available:
                            continue
                        seen.add(relay_name)
                        promoted.append(relay_name)

            seen.add(model_name)
            promoted.append(model_name)

        return promoted or candidates

    def _deprioritize_unhealthy_compatible_gateway_candidates(self, node_type: str, candidates: List[str]) -> List[str]:
        normalized_node_type = normalize_node_role(str(node_type or "").strip())
        if normalized_node_type not in self._compatible_gateway_fail_fast_node_types():
            return candidates
        if len(candidates or []) < 2:
            return candidates

        healthy: List[str] = []
        unhealthy: List[str] = []
        for raw_model_name in candidates or []:
            model_name = str(raw_model_name or "").strip()
            if not model_name:
                continue
            model_info = self._resolve_model(model_name)
            if self._custom_compatible_gateway_base(model_info) and self._compatible_gateway_recent_unhealthy_reason(model_info):
                unhealthy.append(model_name)
            else:
                healthy.append(model_name)

        if not unhealthy or not healthy:
            return candidates
        return healthy + unhealthy

    def _augment_candidates_with_emergency_fallbacks(
        self,
        node_type: str,
        candidates: List[str],
        fallback_model: str,
    ) -> List[str]:
        normalized_node_type = normalize_node_role(str(node_type or "").strip())
        if normalized_node_type not in self._compatible_gateway_fail_fast_node_types():
            return candidates
        existing = [
            str(model_name or "").strip()
            for model_name in (candidates or [])
            if str(model_name or "").strip()
        ]
        # v6.4.57 (maintainer 2026-04-23): cross-host emergency fallback.
        # Previously: `if len(existing) >= 2: return existing` short-
        # circuited and never added kimi when the existing 2 candidates
        # were BOTH from the same unhealthy compatible gateway (observed
        # Apr 23 14:04 uidesign: [gpt-5.4, gpt-5.3-codex] both on
        # relay.cn, which entered 300s cooldown → 4 retries all rejected
        # in 5s total). New rule: if ALL existing candidates route through
        # the same UNHEALTHY compatible gateway, force-augment with kimi
        # (cross-host fallback). Only triggers when gateway is actually
        # unhealthy AT CALL TIME, so healthy flows aren't affected.
        def _all_on_unhealthy_gateway(_models: List[str]) -> bool:
            if not _models:
                return False
            _hosts_seen: set[str] = set()
            _any_unhealthy = False
            for _mn in _models:
                _info = self._resolve_model(_mn)
                _gw = self._custom_compatible_gateway_base(_info)
                if not _gw:
                    return False  # some model is NOT a compat-gateway model
                _hosts_seen.add(_gw)
                _reason = self._compatible_gateway_recent_unhealthy_reason(_info)
                if _reason:
                    _any_unhealthy = True
            # All gateway-based AND at least one currently unhealthy AND
            # only ONE host involved → cross-host rescue needed.
            return _any_unhealthy and len(_hosts_seen) == 1
        if len(existing) >= 2 and not _all_on_unhealthy_gateway(existing):
            return existing
        if existing and not _all_on_unhealthy_gateway(existing):
            primary_info = self._resolve_model(existing[0])
            primary_provider = str(primary_info.get("provider") or "").strip().lower()
            if primary_provider != "relay" and not self._custom_compatible_gateway_base(primary_info):
                return existing
        seen = set(existing)
        augmented = list(existing)
        # v6.4.57: when all existing candidates are on an unhealthy host,
        # prioritise kimi (cross-host) BEFORE the legacy gpt-based chain.
        if _all_on_unhealthy_gateway(existing):
            for _rescue in ("kimi-k2.6-code-preview", "kimi-coding", "deepseek-v3"):
                if _rescue in seen:
                    continue
                if not self._model_provider_has_key(_rescue):
                    continue
                seen.add(_rescue)
                augmented.append(_rescue)
                logger.info(
                    "emergency cross-host fallback injected: node=%s model=%s "
                    "(all %d existing candidates on unhealthy gateway)",
                    normalized_node_type, _rescue, len(existing),
                )
                break
        for model_name in self._legacy_model_fallback_chain(fallback_model):
            normalized = str(model_name or "").strip()
            if not normalized or normalized in seen:
                continue
            seen.add(normalized)
            augmented.append(normalized)
        return augmented

    def _fallback_skip_reason_for_candidate(self, node_type: str, model_name: str) -> str:
        normalized_node_type = normalize_node_role(str(node_type or "").strip())
        if normalized_node_type not in self._compatible_gateway_fail_fast_node_types():
            return ""
        normalized_model = str(model_name or "").strip()
        if not normalized_model:
            return ""
        model_info = self._resolve_model(normalized_model)
        if not self._custom_compatible_gateway_base(model_info):
            return ""
        return self._compatible_gateway_recent_unhealthy_reason(model_info)

    def _next_fallback_candidate(self, node_type: str, candidates: List[str], current_index: int) -> tuple[str, int]:
        for idx in range(max(-1, int(current_index)) + 1, len(candidates or [])):
            candidate_model = str(candidates[idx] or "").strip()
            if not candidate_model:
                continue
            skip_reason = self._fallback_skip_reason_for_candidate(node_type, candidate_model)
            if skip_reason:
                logger.info(
                    "Skipping unhealthy fallback candidate: node=%s model=%s reason=%s",
                    node_type,
                    candidate_model,
                    _sanitize_error(skip_reason[:200]),
                )
                continue
            return candidate_model, idx
        return "", -1

    def resolve_node_model_candidates(self, node: Dict, fallback_model: str) -> List[str]:
        effective_node = node or {}
        node_type = normalize_node_role(str(effective_node.get("type") or "").strip())
        configured_chain = self._normalized_node_model_preferences().get(node_type, [])
        explicit_chain = self._normalize_model_chain(
            effective_node.get("model_preferences") or effective_node.get("models") or []
        )
        explicit_model = self._normalize_model_chain([effective_node.get("model")])
        fallback_chain = self._normalize_model_chain([fallback_model])
        if explicit_model and bool(effective_node.get("model_is_default")):
            explicit_model = []
        # v6.1.14h (maintainer 2026-04-20): router is a 2KB classifier — it does
        # NOT need kimi-k2.6-code-preview (thinking model, 27-65s per call).
        # Force a fast path regardless of auto-filled defaults:
        # kimi-k2.5 (non-thinking) → minimax-m2.7-highspeed → deepseek-v3.
        # Expected: router call 5-10s instead of 30-60s.
        # v6.1.14h.1: previous check `not configured_chain` failed because
        # orchestrator auto-fills prefs with `kimi-k2.6-code-preview` even
        # when user's settings.json has `router: []`. New rule: PREPEND
        # fast models unless user explicitly set a non-thinking chain.
        if node_type == "router" and not explicit_chain and not configured_chain:
            # v6.2 (maintainer 2026-04-20 hotfix): Only activate fast-router override
            # when the user has set NEITHER per-node (explicit_chain) nor
            # Settings-level (configured_chain) router preference. Previous
            # behaviour wasted 120s×2 per unreachable model on Kimi-only
            # setups because it prepended minimax/deepseek (no keys) and
            # kimi-k2.5 (wrong for coding plan) ahead of the user's explicit
            # choice. User's settings are now authoritative.
            _fast_thinkfree = {"kimi-k2.5", "minimax-m2.7-highspeed", "deepseek-v3", "deepseek-v3.2", "qwen3-max", "doubao-seed-2.0-pro"}
            fast_router_chain_raw = self._normalize_model_chain([
                "kimi-k2.5",
                "minimax-m2.7-highspeed",
                "deepseek-v3",
            ])
            fast_router_chain = [
                m for m in fast_router_chain_raw
                if self._model_provider_has_key(m)
            ]
            if fast_router_chain:
                configured_chain = fast_router_chain[:]
                logger.info(
                    "router fast-path activated (user did not set preference): chain=%s",
                    configured_chain,
                )
            # else: fall through to legacy default below

        candidates: List[str] = []
        seen: set[str] = set()

        def _push_many(values: List[str]) -> None:
            for model_name in values:
                normalized = str(model_name or "").strip()
                if not normalized or normalized in seen:
                    continue
                seen.add(normalized)
                candidates.append(normalized)

        _push_many(explicit_model)
        _push_many(explicit_chain)
        _push_many(configured_chain)
        _push_many(fallback_chain)

        if not configured_chain and not explicit_chain:
            _push_many(self._legacy_model_fallback_chain(fallback_model))

        if not candidates:
            # v5.8.1: kimi-coding is the legacy K2.5 endpoint which has become
            # unreliable (401 Invalid Auth observed repeatedly). Default safety
            # net is now the current code-preview model instead.
            _push_many(["kimi-k2.6-code-preview"])
        candidates = self._augment_candidates_for_compatible_gateway(node_type, candidates)
        candidates = self._augment_candidates_with_matching_relays(candidates)
        candidates = self._prefer_matching_relays_for_custom_gateway(node_type, candidates)
        filtered_candidates = self._filter_viable_model_candidates(candidates)
        filtered_candidates = self._augment_candidates_with_emergency_fallbacks(
            node_type,
            filtered_candidates,
            fallback_model,
        )
        filtered_candidates = self._augment_candidates_with_matching_relays(filtered_candidates)
        filtered_candidates = self._filter_viable_model_candidates(filtered_candidates)
        filtered_candidates = self._promote_matching_relays_for_unhealthy_gateway(node_type, filtered_candidates)
        filtered_candidates = self._deprioritize_unhealthy_compatible_gateway_candidates(node_type, filtered_candidates)
        # v3.0.5 FIX: Respect single-model pin in node_model_preferences.
        # When the user pins EXACTLY one model for a node type (e.g. ["kimi-coding"]),
        # gateway health deprioritisation should not push it behind auto-added fallbacks.
        # Multi-model chains (e.g. ["gpt-5.4", "kimi-coding"]) are left as-is so the
        # user's secondary choice can rise above an unhealthy primary.
        if configured_chain and len(configured_chain) == 1 and filtered_candidates:
            pinned = str(configured_chain[0] or "").strip()
            if (
                pinned
                and pinned in filtered_candidates
                and filtered_candidates[0] != pinned
            ):
                filtered_candidates.remove(pinned)
                filtered_candidates.insert(0, pinned)
        # v6.1.7 (revised 2026-04-19): GLM-5.x tool_stream is unreliable per
        # sglang#11888 + BigModel official docs. We could demote it in the
        # builder chain, BUT maintainer explicitly prefers user-chosen model
        # ordering to stand as-is. Demotion is now opt-in via env var —
        # default OFF. User config order is the source of truth.
        if str(os.getenv("EVERMIND_AUTO_DEMOTE_GLM5", "0") or "0").strip() in ("1", "true", "yes"):
            filtered_candidates = self._demote_glm5_for_tool_nodes(node_type, filtered_candidates)
        # v6.3 (maintainer 2026-04-20): optional strict mode. When
        # EVERMIND_STRICT_NODE_PREFERENCES=1, discard any candidate that was
        # NOT listed in the user's configured_chain / explicit_chain. This
        # prevents emergency-fallback / relay-augmentation from reintroducing
        # provider families (claude, gpt-5.4, deepseek) the user explicitly
        # didn't authorise. Off by default to preserve existing resilience.
        if str(os.getenv("EVERMIND_STRICT_NODE_PREFERENCES", "0") or "0").strip() in ("1", "true", "yes"):
            user_allowed = {m.strip() for m in (explicit_model + explicit_chain + configured_chain) if m}
            if user_allowed:
                strict_candidates = [m for m in filtered_candidates if m in user_allowed]
                if strict_candidates:
                    logger.info(
                        "Strict node preferences active: node=%s dropped=%s kept=%s",
                        node_type,
                        [m for m in filtered_candidates if m not in user_allowed],
                        strict_candidates,
                    )
                    filtered_candidates = strict_candidates
        return filtered_candidates or candidates

    def _demote_glm5_for_tool_nodes(
        self, node_type: str, candidates: List[str]
    ) -> List[str]:
        """Opt-in (EVERMIND_AUTO_DEMOTE_GLM5=1) demotion of GLM-5.x in the
        tool-calling builder/merger chain. Kept as a manual lever, not a
        default — user's model order from settings wins by default.
        """
        if not candidates:
            return candidates
        if node_type not in {"builder", "merger", "debugger", "polisher"}:
            return candidates
        demoted: List[str] = []
        tail: List[str] = []
        for m in candidates:
            lower = str(m or "").lower()
            # Match glm-5, glm-5.1, glm-5.0, etc. but not glm-4.6/4.7.
            if re.match(r"^(?:openai/|zhipu/)?glm-5(?:\.\d+)?\b", lower):
                tail.append(m)
            else:
                demoted.append(m)
        if not tail or not demoted:
            return candidates
        logger.info(
            "Demoted GLM-5.x %r from %s chain (env EVERMIND_AUTO_DEMOTE_GLM5=1)",
            tail, node_type,
        )
        return demoted + tail

    def preferred_model_for_node(self, node: Dict, fallback_model: str) -> str:
        candidates = self.resolve_node_model_candidates(node, fallback_model)
        for model_name in candidates:
            model_info = self._resolve_model(model_name)
            if not self._check_api_key(model_name, model_info):
                return model_name
        return candidates[0] if candidates else str(fallback_model or "kimi-k2.6-code-preview")

    def _normalize_usage(self, usage: Any) -> Dict[str, int]:
        if not usage:
            return {"prompt_tokens": 0, "completion_tokens": 0, "total_tokens": 0}

        if hasattr(usage, "model_dump"):
            usage = usage.model_dump()
        elif hasattr(usage, "dict"):
            usage = usage.dict()
        elif not isinstance(usage, dict):
            usage = {
                "prompt_tokens": getattr(usage, "prompt_tokens", 0),
                "completion_tokens": getattr(usage, "completion_tokens", 0),
                "total_tokens": getattr(usage, "total_tokens", 0),
                "input_tokens": getattr(usage, "input_tokens", 0),
                "output_tokens": getattr(usage, "output_tokens", 0),
            }

        prompt_tokens = int(usage.get("prompt_tokens") or usage.get("input_tokens") or 0)
        completion_tokens = int(usage.get("completion_tokens") or usage.get("output_tokens") or 0)
        total_tokens = int(usage.get("total_tokens") or (prompt_tokens + completion_tokens))
        # V4.6 CACHE: Extract cached_tokens from OpenAI/Kimi prompt_tokens_details
        cached_tokens = 0
        ptd = usage.get("prompt_tokens_details") or {}
        if isinstance(ptd, dict):
            cached_tokens = int(ptd.get("cached_tokens") or 0)
        elif hasattr(ptd, "cached_tokens"):
            cached_tokens = int(getattr(ptd, "cached_tokens", 0) or 0)
        if cached_tokens > 0:
            logger.info(
                "CACHE HIT: cached_tokens=%d prompt_tokens=%d (%.0f%% cached)",
                cached_tokens, prompt_tokens,
                (cached_tokens / max(prompt_tokens, 1)) * 100,
            )
        return {
            "prompt_tokens": prompt_tokens,
            "completion_tokens": completion_tokens,
            "total_tokens": total_tokens,
            "cached_tokens": cached_tokens,
        }

    def _merge_usage(self, base: Dict[str, int], delta: Any) -> Dict[str, int]:
        normalized = self._normalize_usage(delta)
        # v5.8.6: accumulate cached_tokens too — otherwise the frontend's
        # "X tokens (Y cached)" indicator always reads 0 even when Kimi's
        # prefix cache is actually saving 30-60% on tool-loop iterations.
        return {
            "prompt_tokens": base.get("prompt_tokens", 0) + normalized.get("prompt_tokens", 0),
            "completion_tokens": base.get("completion_tokens", 0) + normalized.get("completion_tokens", 0),
            "total_tokens": base.get("total_tokens", 0) + normalized.get("total_tokens", 0),
            "cached_tokens": base.get("cached_tokens", 0) + normalized.get("cached_tokens", 0),
        }

    async def _litellm_stream_completion(self, **kwargs) -> Any:
        """Call litellm.acompletion with stream=True, collect chunks into a unified response.

        Returns a SimpleNamespace mimicking litellm's non-streaming response so
        callers need no changes.  Falls back to non-streaming acompletion if the
        stream setup itself fails before any data arrives.
        """
        from types import SimpleNamespace as _NS

        stream_kwargs = {**kwargs, "stream": True}
        content_parts: List[str] = []
        tool_calls_map: Dict[int, Dict[str, Any]] = {}
        usage_data: Any = None
        model_name = kwargs.get("model", "")

        # v6.1.3 (maintainer 2026-04-19): route delta.content through the same
        # ThinkStripper as the compat path — prevents <think>...</think>
        # folded into content by some relays (private-relay/aigate/private-relay proxies
        # kimi/glm) from ever reaching file writes. Also captures
        # reasoning_content deltas separately so they're never appended to
        # content_parts (the source for file_ops direct_text content).
        _think_strip_enabled = str(os.getenv("EVERMIND_STRIP_THINK", "1")).strip().lower() not in ("0", "false", "off", "no")
        _think_stripper = ThinkStripper()
        try:
            response = await self._litellm.acompletion(**stream_kwargs)
            async for chunk in response:
                if not chunk.choices:
                    if hasattr(chunk, "usage") and chunk.usage:
                        usage_data = chunk.usage
                    continue
                delta = chunk.choices[0].delta
                if delta:
                    # Capture reasoning_content separately — NEVER gets written.
                    _reasoning_delta = getattr(delta, "reasoning_content", None) or getattr(delta, "reasoning", None)
                    if _reasoning_delta:
                        _think_stripper.reasoning_parts.append(str(_reasoning_delta))
                    if getattr(delta, "content", None):
                        _raw = delta.content
                        _clean = _think_stripper.feed(_raw) if _think_strip_enabled else _raw
                        if _clean:
                            content_parts.append(_clean)
                    if getattr(delta, "tool_calls", None):
                        for tc_delta in delta.tool_calls:
                            idx = getattr(tc_delta, "index", 0)
                            if idx not in tool_calls_map:
                                tool_calls_map[idx] = {
                                    "id": getattr(tc_delta, "id", None) or f"tc_{idx}",
                                    "function": {"name": "", "arguments": ""},
                                }
                            fn = getattr(tc_delta, "function", None)
                            if fn:
                                if getattr(fn, "name", None):
                                    tool_calls_map[idx]["function"]["name"] += fn.name
                                if getattr(fn, "arguments", None):
                                    tool_calls_map[idx]["function"]["arguments"] += fn.arguments
                if hasattr(chunk, "usage") and chunk.usage:
                    usage_data = chunk.usage
                if getattr(chunk, "model", None):
                    model_name = chunk.model
        except Exception as _stream_err:
            if not content_parts and not tool_calls_map:
                # Stream never started — fall back to non-streaming async call
                return await self._litellm.acompletion(**kwargs)
            # Partial data received before error — discard tool_calls (may have
            # incomplete JSON arguments) and keep only text content.
            tool_calls_map.clear()
            logger.warning(
                "Streaming interrupted after partial data (%d chars); "
                "discarded tool_calls to avoid invalid JSON: %s",
                sum(len(p) for p in content_parts), _stream_err,
            )

        tool_calls = None
        if tool_calls_map:
            tool_calls = [
                _NS(
                    id=tool_calls_map[idx]["id"],
                    function=_NS(
                        name=tool_calls_map[idx]["function"]["name"],
                        arguments=tool_calls_map[idx]["function"]["arguments"],
                    ),
                )
                for idx in sorted(tool_calls_map.keys())
            ]

        if usage_data and not isinstance(usage_data, dict):
            if hasattr(usage_data, "model_dump"):
                usage_data = usage_data.model_dump()
            elif hasattr(usage_data, "dict"):
                usage_data = usage_data.dict()
            else:
                usage_data = {
                    "prompt_tokens": getattr(usage_data, "prompt_tokens", 0),
                    "completion_tokens": getattr(usage_data, "completion_tokens", 0),
                    "total_tokens": getattr(usage_data, "total_tokens", 0),
                }

        # v6.1.14 (maintainer 2026-04-20): expose reasoning_content on the
        # stitched message so downstream `_serialize_assistant_message`
        # preserves it (kimi thinking validator at aigate/private-relay requires
        # it on every replayed assistant message).
        _reasoning_joined = "".join(_think_stripper.reasoning_parts) if getattr(_think_stripper, "reasoning_parts", None) else ""
        return _NS(
            choices=[_NS(
                message=_NS(
                    content="".join(content_parts) if content_parts else "",
                    tool_calls=tool_calls,
                    reasoning_content=_reasoning_joined,
                ),
                finish_reason="tool_calls" if tool_calls else "stop",
            )],
            model=model_name,
            usage=usage_data or {},
        )

    def _estimate_litellm_cost(self, response: Any, model: str) -> float:
        if not self._litellm:
            return 0.0
        try:
            return float(self._litellm.completion_cost(completion_response=response, model=model))
        except Exception:
            return 0.0

    def _estimate_response_cost(self, model: str, usage: Any) -> float:
        normalized = self._normalize_usage(usage)
        pricing = {
            "computer-use-preview": {
                "input_per_million": float(os.getenv("COMPUTER_USE_INPUT_COST_PER_MILLION", "2.5")),
                "output_per_million": float(os.getenv("COMPUTER_USE_OUTPUT_COST_PER_MILLION", "15.0")),
            },
            "gpt-4o": {
                "input_per_million": 2.5,
                "output_per_million": 10.0,
            },
        }
        rates = pricing.get(model)
        if not rates:
            return 0.0
        return (
            normalized.get("prompt_tokens", 0) * rates["input_per_million"] / 1_000_000
            + normalized.get("completion_tokens", 0) * rates["output_per_million"] / 1_000_000
        )

    def _read_int_env(self, name: str, default: int, minimum: int, maximum: int) -> int:
        raw = os.getenv(name)
        if raw is None:
            return default
        try:
            value = int(raw)
        except ValueError:
            return default
        return max(minimum, min(maximum, value))

    def _read_float_env(self, name: str, default: float, minimum: float, maximum: float) -> float:
        raw = os.getenv(name)
        if raw is None:
            return default
        try:
            value = float(raw)
        except ValueError:
            return default
        return max(minimum, min(maximum, value))

    def _progress_event_timeout_sec(self) -> float:
        return self._read_float_env(
            "EVERMIND_PROGRESS_EVENT_TIMEOUT_SEC",
            1.0,
            0.05,
            5.0,
        )

    async def _get_shared_http_session(self):
        """Get or create a shared aiohttp session with persistent connection pooling.

        Benefits:
        - TCP connection reuse: avoids ~200ms TLS handshake per API call
        - DNS caching: avoids DNS lookup per call (~20ms)
        - Keep-alive: reuses existing connections for subsequent requests
        - Pool limit 100/host: supports concurrent multi-node calls
        """
        if self._shared_http_session is not None:
            if not getattr(self._shared_http_session, "closed", True):
                return self._shared_http_session
        try:
            import aiohttp
            connector = aiohttp.TCPConnector(
                limit=500,              # was 100 — match LiteLLM/openai-python scale
                limit_per_host=100,     # was 30 — relay hosts need more headroom
                ttl_dns_cache=300,      # DNS cache 5 min
                use_dns_cache=True,
                enable_cleanup_closed=True,
                keepalive_timeout=120,  # was 60 — LiteLLM uses 120s
            )
            timeout = aiohttp.ClientTimeout(total=180, connect=5, sock_read=120)
            self._shared_http_session = aiohttp.ClientSession(
                connector=connector,
                timeout=timeout,
                headers={
                    "User-Agent": "Evermind/3.0 (aiohttp; connection-pool)",
                    "Connection": "keep-alive",
                },
            )
            logger.info("Created shared HTTP session with connection pooling (limit=500, keepalive=120s)")
            return self._shared_http_session
        except ImportError:
            return None
        except Exception as exc:
            logger.warning("Failed to create shared HTTP session: %s", str(exc)[:200])
            return None

    async def _emit_noncritical_progress(
        self,
        on_progress: Optional[Callable],
        payload: Dict[str, Any],
        *,
        timeout_sec: Optional[float] = None,
    ) -> None:
        if not on_progress:
            return
        budget = float(timeout_sec if timeout_sec is not None else self._progress_event_timeout_sec())
        if budget <= 0:
            return
        stage = str((payload or {}).get("stage") or "").strip() or "unknown"
        try:
            await asyncio.wait_for(on_progress(payload), timeout=budget)
        except asyncio.TimeoutError:
            logger.warning(
                "Noncritical progress event timed out after %.2fs: stage=%s",
                budget,
                stage,
            )
        except Exception as exc:
            logger.warning(
                "Noncritical progress event failed: stage=%s error=%s",
                stage,
                _sanitize_error(str(exc)),
            )

    def _node_int_override(
        self,
        node: Optional[Dict[str, Any]],
        key: str,
        *,
        minimum: int,
        maximum: int,
    ) -> Optional[int]:
        if not isinstance(node, dict):
            return None
        raw = node.get(key)
        if raw in (None, ""):
            return None
        try:
            value = int(raw)
        except Exception:
            return None
        return max(minimum, min(maximum, value))

    def _node_capability_tier(self, node: Optional[Dict[str, Any]]) -> int:
        tier = self._node_int_override(node, "model_capability_tier", minimum=0, maximum=3)
        return tier or 0

    def _node_budget_tuning(self, node_type: str, node: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
        normalized_node_type = normalize_node_role(node_type)
        tier = self._node_capability_tier(node)
        tuning: Dict[str, Any] = {
            "token_scale": 1.0,
            "timeout_scale": 1.0,
            "stall_scale": 1.0,
            "tool_iterations_delta": 0,
            "browser_call_delta": 0,
            "builder_prewrite_scale": 1.0,
            "builder_repair_scale": 1.0,
            "builder_tool_only_scale": 1.0,
            "agentic_iteration_delta": 0,
            "agentic_tool_call_delta": 0,
        }
        if tier == 1:
            tuning.update({
                "token_scale": 1.15,
                "timeout_scale": 1.15,
                "stall_scale": 1.1,
                "builder_prewrite_scale": 1.1,
                "builder_repair_scale": 1.05,
                "builder_tool_only_scale": 1.05,
            })
            if normalized_node_type in {"builder", "merger", "debugger", "polisher"}:
                tuning["tool_iterations_delta"] = 2
                tuning["agentic_iteration_delta"] = 3
                tuning["agentic_tool_call_delta"] = 8
            else:
                tuning["tool_iterations_delta"] = 1
                tuning["agentic_iteration_delta"] = 1
                tuning["agentic_tool_call_delta"] = 4
            if normalized_node_type == "analyst":
                tuning["browser_call_delta"] = 2
            elif normalized_node_type == "polisher":
                tuning["browser_call_delta"] = 1
        elif tier == 3:
            tuning.update({
                "token_scale": 0.85,
                "timeout_scale": 0.85,
                "stall_scale": 0.8,
                "builder_prewrite_scale": 0.7,
                "builder_repair_scale": 0.8,
                "builder_tool_only_scale": 0.7,
            })
            if normalized_node_type in {"builder", "merger", "debugger", "polisher"}:
                tuning["tool_iterations_delta"] = -2
                tuning["agentic_iteration_delta"] = -3
                tuning["agentic_tool_call_delta"] = -8
            else:
                tuning["tool_iterations_delta"] = -1
                tuning["agentic_iteration_delta"] = -1
                tuning["agentic_tool_call_delta"] = -4
            if normalized_node_type == "analyst":
                tuning["browser_call_delta"] = -3
            elif normalized_node_type == "polisher":
                tuning["browser_call_delta"] = -1
        return tuning

    def _scale_budget_int(self, value: int, scale: float, *, minimum: int, maximum: int) -> int:
        scaled = int(round(float(value or 0) * float(scale or 1.0)))
        return max(minimum, min(maximum, scaled))

    def _delta_budget_int(self, value: int, delta: int, *, minimum: int, maximum: int) -> int:
        updated = int(value or 0) + int(delta or 0)
        return max(minimum, min(maximum, updated))

    def _is_ultra_mode(self) -> bool:
        """v7.1 (maintainer 2026-04-24): Ultra Mode = 顶级玩家模式。
        放宽所有 timeout / iter cap / rejection budget，支持长任务（3-4h ~ 1 day）
        + 多文件项目 + 图片/爬取工具。只要 cli_mode.enabled 且 cli_mode.ultra_mode
        同时 True 才算 ULTRA（ultra 依赖 CLI 的长运行能力）。
        """
        try:
            cfg = getattr(self, "config", {}) or {}
            cli_mode = cfg.get("cli_mode") or {}
            if not isinstance(cli_mode, dict):
                return False
            # ultra 必须同时有 cli_mode.enabled 和 cli_mode.ultra_mode 才生效
            # （避免不熟悉 CLI 的用户误开 ULTRA 导致 API 模式 timeout 爆炸）
            return bool(cli_mode.get("enabled")) and bool(cli_mode.get("ultra_mode"))
        except Exception:
            return False

    def _ultra_multiplier(self, default: float = 1.0) -> float:
        """Ultra mode multiplier for timeout / iter budgets. Default 10×."""
        if self._is_ultra_mode():
            return 10.0
        return default

    def _ultra_iter_multiplier(self) -> int:
        """For integer iter caps: 4× in ultra mode, 1× normally."""
        return 4 if self._is_ultra_mode() else 1

    def _agentic_loop_limits(self, node_type: str, node: Optional[Dict[str, Any]] = None) -> tuple[int, int]:
        """
        v5.8.6 REDESIGN: "trust the agent" — iteration caps used to hard-stop
        nodes mid-work (reviewer at 6, spritesheet at 2, imagegen at 6). This
        caused empty-output failures when the model legitimately needed more
        rounds on complex tasks. New philosophy: give generous caps as SAFETY
        FLOOR, but let the agent's own `finish_reason=stop` (or our content-
        activity detectors) decide when it's really done. The no-activity
        watchdog is the true exit condition, not arbitrary iteration count.
        """
        normalized_node_type = normalize_node_role(node_type)
        # v6.1.5 (maintainer 2026-04-19): node-type dispatch by "agentic vs
        # generative" classes — research showed Cursor/MetaGPT/Smol keep
        # generative paths single-pass (imagegen/spritesheet/assetimport
        # all pre-structured, no exploration), while debug/merge paths need
        # multi-round. Builder has its own direct_text fast path (see
        # _builder_execution_direct_text_mode) that rides on top of this cap.
        if normalized_node_type == "builder":
            max_iterations = 40
            max_tool_calls = 80
        elif normalized_node_type == "merger":
            # v6.4 (maintainer 2026-04-21): merger's job is read both builder
            # outputs + write one merged file. 30/60 let kimi over-explore
            # (7m12s observed vs 3-5min expected). 18/30 is plenty for
            # read-read-write + 1-2 corrective edits.
            max_iterations = 18
            max_tool_calls = 30
        elif normalized_node_type in {"debugger", "polisher"}:
            max_iterations = 25
            max_tool_calls = 50
        elif normalized_node_type == "patcher":
            # v6.4 (maintainer 2026-04-21): patcher now drives repairs via
            # file_ops read+edit (one pair per blocker), so allow enough
            # loop budget for 4-6 issues (2 tool calls each = 8-12 calls).
            # Keep it below builder so a failed patch still escalates
            # reasonably fast, but not below the file_ops surgical minimum.
            max_iterations = 8
            max_tool_calls = 16
        elif normalized_node_type == "imagegen":
            # Generative: prompt-pack production; 1-2 rounds enough.
            # v6.1.14h.2 (maintainer 2026-04-20): observed imagegen running 10+
            # rounds × 60-120s each (source_fetch exploration loop) → 10min
            # total. Tighten to 4 iterations. It's a manifest producer, not
            # a researcher — analyst already did the research upstream.
            max_iterations = 4
            max_tool_calls = 6
        elif normalized_node_type in {"spritesheet", "assetimport"}:
            # Generative: manifest/naming rules; 1-2 rounds enough.
            max_iterations = 6
            max_tool_calls = 10
        elif normalized_node_type == "analyst":
            # v6.1.3 (maintainer 2026-04-19): analyst needs hard converge; it's
            # research not building. 20→10 forces synthesis quickly.
            # v6.1.14 (maintainer 2026-04-20): deep mode needs more research room.
            # v6.3 (maintainer 2026-04-20): post-mortem run_85ef3b62fcd3 — analyst did
            # 10 source_fetch calls then hung 200s before hard-ceiling. tutorial
            # search is naturally divergent; cap deep 16→10, fast 10→6. Pair with
            # the "pick 3 sources" prompt rule in _planner_prompt_for_difficulty.
            if self._configured_thinking_depth() == "deep":
                max_iterations = 10
                max_tool_calls = 20
            else:
                max_iterations = 6
                max_tool_calls = 12
        elif normalized_node_type == "uidesign":
            # uidesign is a compact builder-brief node, not a research crawler.
            max_iterations = 6
            max_tool_calls = 8
        elif normalized_node_type == "reviewer":
            # v6.1.4 (maintainer 2026-04-18): "trust the agent" — don't hard-cap
            # tool budget, a mature reviewer knows when it's done. But the
            # runaway-loop pattern (18min re-screenshotting same page) means
            # the real fix is at the PROMPT level: explicit stop criterion +
            # dedup watchdog. Cap is a safety floor only.
            # v6.7 (maintainer 2026-04-23): observed run_69495533723c — reviewer
            # burned 5+ minutes doing redundant browser probes on gpt-5.4.
            # Tighten 20/30 → 12/18 — plenty for 1 page + 1 interaction
            # sweep + JSON report; forces convergence instead of thrashing.
            max_iterations = 12
            max_tool_calls = 18
        elif normalized_node_type == "tester":
            # v6.4 (maintainer 2026-04-21): previously fell through to else (25/50)
            # which let kimi burn 12 min on a single tester node doing
            # redundant browser screenshots. 15/25 is plenty for a 3D game
            # smoke test (start screen → spawn → input → HUD → game-over),
            # forcing earlier synthesis while still covering the core states.
            max_iterations = 15
            max_tool_calls = 25
        elif normalized_node_type == "debugger":
            # v6.4: debugger shouldn't need more than 8-10 edit cycles on
            # a small set of reported bugs. Tighten from else-branch (25/50).
            max_iterations = 15
            max_tool_calls = 30
        else:
            max_iterations = 25
            max_tool_calls = 50

        tuning = self._node_budget_tuning(node_type, node=node)
        max_iterations = self._delta_budget_int(
            max_iterations,
            int(tuning.get("agentic_iteration_delta", 0) or 0),
            minimum=4,
            maximum=100,
        )
        max_tool_calls = self._delta_budget_int(
            max_tool_calls,
            int(tuning.get("agentic_tool_call_delta", 0) or 0),
            minimum=max(8, max_iterations),
            maximum=200,
        )
        override_iterations = self._node_int_override(
            node,
            "agentic_max_iterations_override",
            minimum=4,
            maximum=100,
        )
        if override_iterations is not None:
            max_iterations = override_iterations
        override_tool_calls = self._node_int_override(
            node,
            "agentic_max_tool_calls_override",
            minimum=max(8, max_iterations),
            maximum=200,
        )
        if override_tool_calls is not None:
            max_tool_calls = override_tool_calls
        # v6.1.5 (Opus A R1): REMOVED direct_text clamp here. `_agentic_eligible`
        # (line 11511) excludes `force_builder_direct_text`/`direct_multifile`
        # so this code path NEVER runs for direct_text. direct_text throughput
        # is governed by `EVERMIND_DIRECT_TEXT_MAX_CONTINUATIONS` (default 6)
        # in `_execute_openai_compatible_chat` / `_execute_litellm_chat`.
        return max_iterations, max_tool_calls

    def _max_tokens_for_node(
        self,
        node_type: str,
        *,
        retry_attempt: int = 0,
        node: Optional[Dict[str, Any]] = None,
    ) -> int:
        normalized_node_type = normalize_node_role(node_type)
        # Builder often returns full HTML/CSS/JS; keep a higher budget.
        # P0 FIX: Escalated base from 24576→32768 to avoid finish=length death
        # chain on complex game/website tasks (Kimi K2.5 regularly needs 40K+ chars).
        # Escalate on retry: retry 0 → 32768, retry 1 → 40960, retry 2 → 49152
        if normalized_node_type == "builder":
            # v5.8.3: per-mode max_tokens budget.
            #  - direct_text (single-shot HTML): 20480  → Kimi ~80K-char full page fits
            # v5.8.6 FIX: tool_call 8192 → 16384. Original rationale was "tool_call
            # args rarely exceed 6K tokens", but real-world Kimi builders routinely
            # stuff 30-40K-char HTML into file_ops write's `content` arg = 10-14K
            # tokens. 8192 hit finish=length → 2x truncation → loop break → retry
            # with same params → double death. Observed in 4 consecutive runs.
            # 16384 ≈ 160s per turn @ ~100 tok/s decode (Kimi) — still fast,
            # and covers 95% of file_ops write payloads.
            builder_delivery = ""
            if node:
                builder_delivery = str(node.get("builder_delivery_mode") or "").strip().lower()
            is_direct_mode = builder_delivery in {"direct_text", "direct_multifile"}
            # v5.8.6: merger-like builders write a single MASSIVE integrated HTML
            # (80-100K chars combining two builder outputs). Post-mortem showed
            # tool_call mode hitting finish=length at 8192 tokens → invalid HTML
            # → preview validation fails → merger retry. Give merger-like builders
            # a 3x tool_call budget so the unified HTML fits in one shot.
            is_merger_like = bool((node or {}).get("builder_merger_like")) if node else False
            if is_direct_mode and is_merger_like:
                # v5.8.6: merger direct_text must fit the combined 80-100K-char
                # integration. 40960 tokens ≈ 160K chars — quality-first headroom
                # so complex 3D game merges (two 90K+ builder outputs) fit cleanly.
                # Raised from 32768 after recognizing that Kimi occasionally writes
                # 120K-char unified HTML for premium shooter games. 32768 was
                # cutting close to the decode ceiling; 40960 gives safety margin.
                base = self._read_int_env("EVERMIND_BUILDER_MERGER_DIRECT_MAX_TOKENS", 40960, 16384, 65536)
            elif is_direct_mode:
                # v5.8.6 FIX: 20480 → 28672 (was 20480). Real-world observation:
                # builder direct_text stream emitted content_chars=53776 then
                # finish=length — HTML is dense (~2.6 chars/token), so 20480
                # tokens = ~53K chars which is exactly where the model hit the
                # ceiling. 28672 tokens ≈ 75K chars, enough for typical 3D
                # game pages without hitting the ceiling.
                base = self._read_int_env("EVERMIND_BUILDER_DIRECT_MAX_TOKENS", 28672, 4096, 65536)
            elif is_merger_like:
                # v6.1.10 (maintainer 2026-04-19): merger combines 2 builder outputs
                # into 80-120KB integrated HTML. 24576 tokens ≈ 62KB — tight.
                # Bump to 32768 default (~82KB) so merger rarely hits
                # finish=length on 3D game merges.
                base = self._read_int_env("EVERMIND_BUILDER_MERGER_TOOLCALL_MAX_TOKENS", 32768, 8192, 65536)
            else:
                # v6.1.10 (maintainer 2026-04-19): peer builders writing 50KB HTML
                # in tool_call JSON args consistently hit finish=length at
                # 16384 tokens (~40KB). Raised to 24576 (~60KB) default so
                # kimi/minimax one-shot big files don't get truncated.
                # Retry still escalates +8192 per attempt (24→32→40→48).
                base = self._read_int_env("EVERMIND_BUILDER_TOOLCALL_MAX_TOKENS", 24576, 4096, 49152)
            escalated = base + retry_attempt * 8192
            value = min(escalated, 65536)
        elif normalized_node_type == "polisher":
            # v5.8: 16384 → 10240 base. Polisher makes surgical edits; rarely
            # needs >8K tokens of new output. Retries still escalate for safety.
            base = self._read_int_env("EVERMIND_POLISHER_MAX_TOKENS", 10240, 4096, 49152)
            value = min(base + retry_attempt * 6144, 32768)
        elif normalized_node_type == "imagegen":
            # v5.8.1 ROLLBACK: 8192 proved too tight — imagegen emits tool_call
            # arguments with full asset-pack manifests that routinely hit
            # 10-12K output tokens. Restored to 12288 base which still saves
            # 25% over the original 16384 without triggering finish=length loops.
            base = self._read_int_env("EVERMIND_IMAGEGEN_MAX_TOKENS", 12288, 4096, 32768)
            value = min(base + retry_attempt * 4096, 24576)
        elif normalized_node_type in ("spritesheet", "assetimport"):
            # v5.8.1 ROLLBACK: 7168 truncated assetimport tool_calls at ~26K
            # chars (observed in prod). Raised to 10240 — still smaller than
            # the original 12288 but safely above the typical tool_call payload.
            value = self._read_int_env("EVERMIND_ASSET_PLAN_MAX_TOKENS", 10240, 2048, 24576)
        elif normalized_node_type in ("planner", "planner_degraded"):
            # v4.0: Planner produces structured markdown (9 sections) + JSON appendix.
            # v5.8.4: 8192 → 12288. Post-mortem: 3D TPS planner consistently hits
            # finish=length at ~19900 chars (8000+ tokens) → handoff synthesizer
            # fires for 7 missing sections → ~30s overhead. 12288 gives safe headroom
            # for complex game/website blueprints without triggering runaway prose.
            value = self._read_int_env("EVERMIND_PLANNER_MAX_TOKENS", 12288, 2048, 24576)
        elif normalized_node_type == "analyst":
            # v5.8.4: Analyst was falling through to the 4096-token default, causing
            # finish=length after tool-loop synthesis (16196 chars observed). Bumped
            # to 12288 — matches planner headroom so the synthesizer rarely fires.
            # v7.15 (maintainer 2026-04-28): bumped 12288→18432. Observed multiple
            # runs with finish=length truncating 4-5 TIER-1 sections (deliverables_
            # contract / implementation_blueprint / critical_algorithms /
            # builder_1_handoff / builder_2_handoff) leaving builder blind. v7.7
            # added game_balance_spec + test_plan_for_reviewer + task_scope_resolution
            # ≈ 1.9K extra chars; analyst now needs 50%+ more headroom to land all
            # MUST-LAND sections before truncation.
            value = self._read_int_env("EVERMIND_ANALYST_MAX_TOKENS", 26624, 2048, 32768)
        elif normalized_node_type == "router":
            # V4.3: Router only generates a JSON routing table — 2K tokens is
            # more than enough.  4K encouraged verbose reasoning that pushed
            # response time past the 120s ceiling.
            # v5.8.3: 2048 → 6144. For 11-node pipelines (game + asset pack
            # + parallel builders), kimi's JSON routing table routinely exceeds
            # 8K chars → finish=length truncation → JSON parsing error → full
            # router retry. 6144 tokens ≈ 24K chars safely fits.
            # v6.3 (maintainer 2026-04-21): 6144 → 2048. Observed router streaming
            # 12KB of JSON in 80-114s on kimi-k2.6-code-preview — blocking the
            # entire pipeline for 2 minutes before planner can start. The
            # extended 6144 allowance encouraged verbose output the router
            # prompt explicitly forbids ("≤80 char description", "3-5
            # subtasks"). Downstream already uses _build_pro_template's
            # Python-side classification and reconciles drift, so a tight
            # ceiling + occasional finish=length is safer than multi-minute
            # startup stall. Users who need 11-node parallel routing tables
            # can override via EVERMIND_ROUTER_MAX_TOKENS.
            # v6.3.4 (maintainer 2026-04-21): 2048 → 1024. Post-mortem of latest
            # run: router still took 44s producing 8786 chars (finish=length
            # exactly at 2048 tokens).
            # v7.7 (2026-04-27): 1024 → 4096. Real-world data on Kimi
            # k2.6-code-preview shows 1024 hits finish=length on every
            # 13-node game/asset task (chunks=1025 reproducibly), AND the
            # router has 2 candidate models so a length truncation triggers
            # a SECOND full retry (max_retries=2). Observed pattern:
            #   - attempt 1: 62s, finish=length, content_chars=1746
            #   - attempt 2: 49s, finish=length, content_chars=4230
            #   = 110s burned on output that orchestrator discards anyway
            #     (it falls back to the default plan after parse error).
            # 4096 tokens ≈ 16KB chars — fits the 13-node skeleton in one
            # shot, finishes naturally with finish=stop, no retry. Net win:
            # ~80 seconds shaved off cold startup. Override via env var if
            # needed.
            value = self._read_int_env("EVERMIND_ROUTER_MAX_TOKENS", 4096, 384, 16384)
        elif normalized_node_type == "reviewer":
            # v5.8.4: CRITICAL BUG FIX. Reviewer was falling through to the
            # 4096-token default — but the harness requires zone-by-zone prose
            # + 8-dimension scoring + blocking issues + strengths + JSON verdict.
            # v5.8.6: 12288 → 20480. Real-world 3D TPS review produced 56K chars
            # of prose and was truncated at finish=length before emitting the
            # JSON verdict, forcing a full retry (+3-5 min). 20480 tokens ≈ 80K
            # chars which fits even extensive zone-by-zone reviews with the
            # mandatory JSON verdict intact at the end.
            value = self._read_int_env("EVERMIND_REVIEWER_MAX_TOKENS", 20480, 4096, 32768)
        elif normalized_node_type == "merger":
            # v5.8.4: Standalone-merger path (not builder-merger-like). Merger
            # writes one full index.html + possibly module files (~40K chars).
            # Default 4096 truncates at ~15K chars. 16384 gives full headroom.
            value = self._read_int_env("EVERMIND_MERGER_MAX_TOKENS", 16384, 4096, 49152)
        elif normalized_node_type == "debugger":
            # v5.8.4: Debugger writes a full-file patch or surgical edit. Similar
            # to polisher in output shape — 10240 gives a real fix budget.
            value = self._read_int_env("EVERMIND_DEBUGGER_MAX_TOKENS", 10240, 4096, 32768)
        elif normalized_node_type == "tester":
            # v5.8.4: Tester produces a structured QA report (pass/fail per
            # feature + evidence). ~6K chars. 6144 is tight headroom.
            value = self._read_int_env("EVERMIND_TESTER_MAX_TOKENS", 6144, 2048, 16384)
        elif normalized_node_type == "deployer":
            # v5.8.4: Deployer output is a short file listing + preview URL.
            # 4096 is plenty.
            value = self._read_int_env("EVERMIND_DEPLOYER_MAX_TOKENS", 4096, 1024, 8192)
        elif normalized_node_type == "scribe":
            # v5.8.4: Documentation / design brief can be long prose. 8192 handles
            # typical cases; escalate via env if longer manuals needed.
            value = self._read_int_env("EVERMIND_DOC_MAX_TOKENS", 8192, 2048, 24576)
        elif normalized_node_type == "uidesign":
            value = self._read_int_env("EVERMIND_UIDESIGN_MAX_TOKENS", 6144, 2048, 16384)
        else:
            value = self._read_int_env("EVERMIND_MAX_TOKENS", 4096, 1024, 16384)

        override = self._node_int_override(node, "max_tokens_override", minimum=1024, maximum=65536)
        if override is not None:
            return override
        tuning = self._node_budget_tuning(node_type, node=node)
        return self._scale_budget_int(value, float(tuning.get("token_scale", 1.0) or 1.0), minimum=1024, maximum=65536)

    def _timeout_for_node(self, node_type: str, node: Optional[Dict[str, Any]] = None) -> int:
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type == "builder":
            # v5.8.6: merger-like builders get a tight 5-minute budget. A merger
            # that takes longer is not merging — it's regenerating from scratch.
            # With direct_text (40K tokens ≈ 160K chars @ Kimi ~100 tok/s decode):
            # - Typical merged game HTML is 100-120K chars → 250-300s stream time
            # - 300s (5min) budget leaves headroom without wasting the retry cycle
            # - The prior 240s ceiling killed streams mid-write on complex merges
            # Two attempts × 300s = 10min max merger wall time, vs the 30+min
            # tool_call spiral observed in v5.8.5 prod runs.
            if bool((node or {}).get("builder_merger_like")):
                value = self._read_int_env("EVERMIND_BUILDER_MERGER_TIMEOUT_SEC", 300, 90, 540)
            else:
                # v6.1.2: raised cap 960→7200 so the deep-mode floor added in
                # _effective_timeout_for_node (1800s) isn't clipped back down.
                # Default still 600s for fast/normal modes; deep explicitly asks
                # for longer budgets so we must let the envelope open up.
                value = self._read_int_env("EVERMIND_BUILDER_TIMEOUT_SEC", 600, 30, 7200)
        elif normalized_node_type == "polisher":
            value = self._read_int_env("EVERMIND_POLISHER_TIMEOUT_SEC", 540, 60, 900)
        elif normalized_node_type == "imagegen":
            # v4.0: Reduced from 420→240. ImageGen writes briefs/manifests, not heavy code.
            # 420s was letting it idle excessively on retry loops.
            # v6.1.15 (maintainer 2026-04-20): observed imagegen 15 min total on
            # kimi-k2.5 source_fetch loop + model fallback chain. Tightened
            # 240→180. With max_iterations=4 and each ≤45s, this is a hard wall.
            value = self._read_int_env("EVERMIND_IMAGEGEN_TIMEOUT_SEC", 180, 45, 360)
        elif normalized_node_type in ("spritesheet", "assetimport"):
            # v5.8.2: 180 → 240.
            # v5.8.6: 240 → 540. Real-world 3D asset manifest took 763s with
            # 188s + 146s on first-two tool_calls (each a ~15-25K char JSON args
            # payload at Kimi ~100 tok/s). 240s was only covering one turn, so
            # the second polish turn always timed out. 540s fits two full
            # turns with margin, and the agentic iteration cap (3) still
            # bounds the work.
            value = self._read_int_env("EVERMIND_ASSET_PLAN_TIMEOUT_SEC", 540, 30, 900)
        elif normalized_node_type in ("planner", "planner_degraded"):
            # v3.1: Raised from 60s to 180s. v4.2: Raised to 270s.
            # gpt-5.4 produces more detailed blueprints (~9000+ chars for complex
            # game tasks) which takes ~250s at typical streaming rates. 180s caused
            # timeout → fallback to weaker model, losing planning quality.
            value = self._read_int_env("EVERMIND_PLANNER_TIMEOUT_SEC", 270, 30, 480)
        elif normalized_node_type == "analyst":
            # v3.1: Raised from 120s to 180s. Analyst with web research tools needs
            # time to fetch references and synthesize findings. Previous timeout caused
            # tool_iterations_exhausted → 8 critical handoff fields lost.
            # v6.1.13 (maintainer 2026-04-20): deep mode gets 360s (was 180s same as
            # fast). Observed real run where analyst was hard-capped at 180s with
            # only 1 URL visited, `research shallow` warning, downstream builder
            # had insufficient reference code. Fast mode keeps 180s.
            _analyst_default = 360 if self._configured_thinking_depth() == "deep" else 180
            value = self._read_int_env("EVERMIND_ANALYST_TIMEOUT_SEC", _analyst_default, 45, 480)
        elif normalized_node_type == "merger":
            # v5.1: With module-assembly architecture, Merger reads pre-built modules
            # and glues them together — much less work than full rewrite. Reduced from 720→480s.
            # v5.8.2: 480 → 300. Merger post-mortem showed wall-time >8min on
            # trivial 2-file merges. Efficiency contract + 5-min cap forces
            # commit; if merger can't finish in 5min something else is wrong.
            value = self._read_int_env("EVERMIND_MERGER_TIMEOUT_SEC", 300, 60, 900)
        elif normalized_node_type == "router":
            # v5.8: 240 → 120. Router only emits a ~2K-token JSON routing table;
            # no deep thinking required. 240s encouraged relay stalls to sit idle.
            # v6.3 (maintainer 2026-04-21): 120 → 45. Observed router on
            # kimi-k2.6-code-preview taking 80-114s streaming an over-verbose
            # 12KB JSON (prompt says ≤80-char / 3-5 subtasks but model over-
            # generates). With max_tokens now capped at 2048 (≈ 8KB chars),
            # 45s is the realistic ceiling.
            # v6.3.2 (maintainer 2026-04-21): 45 → 60. Post-mortem of new run:
            # first call hit 45s exactly and timed out, forcing a retry.
            # Second attempt finished at 44.35s (finish=length, 8786 chars).
            # 45s is one second too tight — kimi-k2.6-code-preview streams
            # ~40 tok/s so 2048 tokens needs ~50s. 60s eliminates the retry
            # waste while still being 2× faster than the old 120s wall.
            # v7.7 (maintainer 2026-04-28): 60 → 120. Observed kimi.com peak-hour
            # latency repeatedly hitting 60s exactly with first-chunk delay
            # 35-50s + content burst — entire DAG stalled because router
            # blocked all 13 NEs for 60s × 3 retries = 3min before fallback.
            # 120s absorbs the latency spike while still hard-bounded; the
            # stream_stall watchdog (30s) still catches a truly dead relay.
            value = self._read_int_env("EVERMIND_ROUTER_TIMEOUT_SEC", 120, 20, 480)
        elif normalized_node_type == "reviewer":
            # v5.8.4: Reviewer runs ≤8 tool calls — mostly browser navigation,
            # screenshot, scroll, act — plus a detailed prose report. Previously
            # fell through to the 120s default which couldn't finish a single
            # visual-review round. 360s covers the full happy path (≤3 min wall
            # time) with a hard 900s cap for retry edge cases.
            value = self._read_int_env("EVERMIND_REVIEWER_TIMEOUT_SEC", 360, 60, 900)
        elif normalized_node_type == "tester":
            # v5.8.4: Tester runs interaction tests on a ready artifact. 240s
            # is generous for a DOM/click/scroll sweep.
            value = self._read_int_env("EVERMIND_TESTER_TIMEOUT_SEC", 240, 45, 600)
        elif normalized_node_type == "debugger":
            # v5.8.4: Debugger reads the failing artifact + patches it. Similar
            # budget to polisher but tighter — a debug loop over 6 min usually
            # means the bug is not isolable and we should fail fast.
            value = self._read_int_env("EVERMIND_DEBUGGER_TIMEOUT_SEC", 360, 60, 900)
        elif normalized_node_type == "deployer":
            # v5.8.4: Deployer lists files + prints preview URL. 120s plenty.
            value = self._read_int_env("EVERMIND_DEPLOYER_TIMEOUT_SEC", 120, 30, 300)
        elif normalized_node_type == "patcher":
            # v6.7 (maintainer 2026-04-23): dedicated patcher timeout. Previously
            # patcher fell through to EVERMIND_TIMEOUT_SEC=120s, hitting a
            # hard-ceiling at 138s when kimi streamed a 20KB edit — triggered
            # a fallback chain to gpt-5.3-codex (which 503s on the current
            # relay) and wasted 8+ min per patcher. patcher.yaml caps its own
            # wall-clock at 5min, so 300s base matches the prompt contract.
            value = self._read_int_env("EVERMIND_PATCHER_TIMEOUT_SEC", 300, 60, 600)
        elif normalized_node_type == "scribe":
            value = self._read_int_env("EVERMIND_DOC_TIMEOUT_SEC", 240, 45, 600)
        elif normalized_node_type == "uidesign":
            # v6.7d (maintainer 2026-04-24): 180 → 360. kimi-k2.6 on deep-mode
            # uidesign regularly streams 200-280s (10K-char system prompt +
            # thinking enabled); 180s triggered hard-ceiling timeout →
            # model fallback → gpt-5.4 on dead relay → 3 min wasted. 360s
            # matches analyst deep-default; enough margin for kimi's
            # natural first-byte latency + full reasoning pass.
            _ui_default = 360 if self._configured_thinking_depth() == "deep" else 240
            value = self._read_int_env("EVERMIND_UIDESIGN_TIMEOUT_SEC", _ui_default, 30, 600)
        else:
            value = self._read_int_env("EVERMIND_TIMEOUT_SEC", 120, 30, 600)

        override = self._node_int_override(node, "timeout_override_sec", minimum=20, maximum=86400)
        if override is not None:
            return override
        tuning = self._node_budget_tuning(node_type, node=node)
        # v7.1 Ultra Mode: 10x timeout for long-task product-grade runs
        _tuning_scale = float(tuning.get("timeout_scale", 1.0) or 1.0)
        if self._is_ultra_mode():
            _tuning_scale = max(_tuning_scale, 1.0) * self._ultra_multiplier(1.0)
            _max = 86400  # 24 hours
        else:
            _max = 7200
        # v6.1.2: raised max 3600→7200 to honor deep-mode floor from _effective_timeout_for_node
        return self._scale_budget_int(value, _tuning_scale, minimum=20, maximum=_max)

    def _stream_stall_timeout_for_node(self, node_type: str, node: Optional[Dict[str, Any]] = None) -> int:
        """
        Max allowed gap between streamed chunks before we treat the call as stalled.
        Builder can reasonably take longer before first meaningful chunk.
        Planner uses a short stall window — if it goes silent, it's stuck.
        """
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type == "builder":
            # v4.0: Reduced from 300→180. 300s stall was masking dead streams.
            # Kimi K2.5 large bursts still fit within 180s (typical burst < 120s).
            value = self._read_int_env("EVERMIND_BUILDER_STREAM_STALL_SEC", 180, 60, 600)
        elif normalized_node_type == "polisher":
            value = self._read_int_env("EVERMIND_POLISHER_STREAM_STALL_SEC", 90, 30, 360)
        elif normalized_node_type == "imagegen":
            # v5.8: 60 → 35. Asset briefs are small; if the stream goes quiet
            # for 35s it's a relay stall, not real thinking — abort fast.
            value = self._read_int_env("EVERMIND_IMAGEGEN_STREAM_STALL_SEC", 35, 15, 180)
        elif normalized_node_type in ("spritesheet", "assetimport"):
            # v5.8: 45 → 25. Tiny planning docs shouldn't need >25s silence
            # between chunks; anything beyond is a slow relay, kill it.
            value = self._read_int_env("EVERMIND_ASSET_PLAN_STREAM_STALL_SEC", 25, 10, 120)
        elif normalized_node_type in ("planner", "planner_degraded"):
            # P0-2: Short stall window for planner — fail fast if stuck.
            value = self._read_int_env("EVERMIND_PLANNER_STREAM_STALL_SEC", 30, 10, 90)
        elif normalized_node_type == "analyst":
            # v4.0: Analyst-specific stall — was falling through to 180s default.
            # Analyst does web research; if stream dies, detect fast and retry.
            value = self._read_int_env("EVERMIND_ANALYST_STREAM_STALL_SEC", 60, 15, 180)
        elif normalized_node_type == "router":
            # v5.8: router previously fell through to 90s default; a bad
            # relay could silently stream tiny chunks for 70s before timing out.
            # 30s matches planner — if router stalls that long, abort and retry.
            value = self._read_int_env("EVERMIND_ROUTER_STREAM_STALL_SEC", 30, 10, 90)
        elif normalized_node_type == "reviewer":
            # v5.8.4: Reviewer uses browser — a single navigate/observe/screenshot
            # can easily take 20-40s without streaming content. 120s accommodates
            # slow page loads without masking real stalls.
            value = self._read_int_env("EVERMIND_REVIEWER_STREAM_STALL_SEC", 120, 30, 360)
        elif normalized_node_type in ("tester", "debugger"):
            # v5.8.4: Same browser + patch workload profile — 90s is balanced.
            value = self._read_int_env("EVERMIND_QA_STREAM_STALL_SEC", 90, 30, 240)
        elif normalized_node_type == "merger":
            # v5.8.4: Merger streams big HTML bodies; 120s allows a deep-think
            # pause between reasoning and write without false alarms.
            value = self._read_int_env("EVERMIND_MERGER_STREAM_STALL_SEC", 120, 30, 360)
        else:
            # v4.0: Reduced default from 180→90 for non-builder nodes.
            value = self._read_int_env("EVERMIND_STREAM_STALL_SEC", 90, 20, 300)

        override = self._node_int_override(node, "stream_stall_timeout_override_sec", minimum=15, maximum=900)
        if override is not None:
            return override
        tuning = self._node_budget_tuning(node_type, node=node)
        return self._scale_budget_int(value, float(tuning.get("stall_scale", 1.0) or 1.0), minimum=15, maximum=900)

    def _effective_timeout_for_node(
        self,
        node_type: str,
        input_data: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> int:
        timeout_sec = self._timeout_for_node(node_type, node=node)
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type != "builder":
            return timeout_sec
        if float(timeout_sec or 0) < 60:
            # Respect explicit tiny overrides used by tests or emergency ops.
            # Auto-boosting a 1-5s override up to 1800s would hide timeout/salvage
            # paths and make it impossible to validate the watchdog chain.
            return timeout_sec
        # v5.8.6: merger-like builders keep their tight 4-minute ceiling. The
        # game/3D/multi-page boosts below are for primary builders that write
        # from scratch; a merger only integrates existing artifacts and must
        # fail fast so the fallback loop can pick a different strategy.
        # v6.1.2: merger-like STILL gets the deep-mode floor — otherwise deep
        # users watch merger time out at 300s while half-written HTML gets
        # truncated. The floor here is smaller (1200s) than primary-builder
        # deep floor (1800s) because merger really should finish fast, but 300s
        # was killing legitimate 3-5 min merger streams.
        # v6.4.7 (maintainer 2026-04-21) — ALSO detect merger via node_key because
        # orchestrator DAG creates merger subtasks with agent_type="builder"
        # + node_key="merger" and sometimes forgets to set the
        # `builder_merger_like` flag → merger fell through to multi-page
        # boost below (up to 7200s=2h!). Observed run_237a7366b039 where
        # merger hit 7251s hard-timeout on 8-page website. The
        # `_builder_is_merger_like_context` below catches both paths.
        _node_key_lower = str((node or {}).get("node_key") or "").strip().lower()
        _is_merger = bool((node or {}).get("builder_merger_like")) or _node_key_lower == "merger"
        if _is_merger:
            # v6.1.3 (Opus review #1-P5): merger-like branch must ALSO consult
            # disk config.json for symmetric behaviour with non-merger branch.
            _merger_depth = ""
            try:
                _merger_depth = str((self.config or {}).get("thinking_depth", "")).strip().lower()
            except Exception:
                pass
            if _merger_depth not in ("fast", "deep"):
                _merger_depth = str(os.getenv("EVERMIND_THINKING_DEPTH", "") or "").strip().lower()
            if _merger_depth not in ("fast", "deep"):
                try:
                    import json as _json
                    _p = os.path.expanduser("~/.evermind/config.json")
                    if os.path.exists(_p):
                        with open(_p, "r", encoding="utf-8") as _fh:
                            _disk = _json.load(_fh) or {}
                        _d = str(_disk.get("thinking_depth") or "").strip().lower()
                        if _d in ("fast", "deep"):
                            _merger_depth = _d
                except Exception:
                    pass
            if _merger_depth == "deep" and timeout_sec < 1200:
                return 1200
            return timeout_sec

        text = str(input_data or "")
        lower = text.lower()
        boosted = timeout_sec
        if text.strip():
            try:
                if task_classifier.classify(text).task_type == "game":
                    boosted = max(
                        boosted,
                        self._read_int_env("EVERMIND_BUILDER_GAME_TIMEOUT_SEC", 1800, 300, 7200),
                    )
            except Exception as _tc_err:
                logger.warning("Task classification failed in _effective_timeout_for_node, using base timeout: %s", _tc_err)
        if self._builder_input_wants_3d(text):
            boosted = max(
                boosted,
                self._read_int_env("EVERMIND_BUILDER_3D_TIMEOUT_SEC", 2400, 600, 7200),
            )
        if task_classifier.wants_multi_page(text):
            boosted = max(
                boosted,
                self._read_int_env("EVERMIND_BUILDER_MULTI_PAGE_TIMEOUT_SEC", 1800, 300, 7200),
            )
        retry_markers = (
            "previous attempt failed",
            "previous attempt timed out",
            "multiple timeouts detected",
            "retry 1/3",
            "retry 2/3",
            "retry 3/3",
            "previous error:",
            "navigation repair only",
        )
        if any(marker in lower for marker in retry_markers):
            boosted = max(
                boosted,
                self._read_int_env("EVERMIND_BUILDER_RETRY_TIMEOUT_SEC", 960, 600, 2400),
            )
        # v6.1.2: deep-mode floor — THREE sources checked (in priority order)
        # so we never regress when one channel is mis-propagated:
        #   1. self.config["thinking_depth"] — set via WebSocket update_config
        #   2. env EVERMIND_THINKING_DEPTH — set by Electron main.js or shell
        #   3. ~/.evermind/config.json on disk (authoritative persistent state)
        # Previously only (1) and (2) were checked, but the running AIBridge
        # instance sometimes missed update_config propagation (class rebind
        # issue across SIGHUP); Builder-2 ended up at 300s and looped 5-min
        # fallbacks for 30+ minutes. Reading from disk is a cheap safety net.
        _cfg_depth = ""
        try:
            _cfg_depth = str((self.config or {}).get("thinking_depth", "")).strip().lower()
        except Exception:
            pass
        if _cfg_depth not in ("fast", "deep"):
            _env_depth = str(os.getenv("EVERMIND_THINKING_DEPTH", "") or "").strip().lower()
            if _env_depth in ("fast", "deep"):
                _cfg_depth = _env_depth
        if _cfg_depth not in ("fast", "deep"):
            try:
                import json as _json
                _disk_cfg_path = os.path.expanduser("~/.evermind/config.json")
                if os.path.exists(_disk_cfg_path):
                    _disk_cfg = _json.load(open(_disk_cfg_path, "r", encoding="utf-8"))
                    _disk_depth = str(_disk_cfg.get("thinking_depth") or "").strip().lower()
                    if _disk_depth in ("fast", "deep"):
                        _cfg_depth = _disk_depth
            except Exception:
                pass
        if _cfg_depth == "deep":
            # v6.1.2 hard minimum — READ default 1800s; do NOT let env
            # EVERMIND_BUILDER_DEEP_MIN_TIMEOUT_SEC go below 1200 so the
            # legacy Electron main.js env cocktail (which ships 150-420s
            # anti-speed-mode overrides) can't accidentally undercut this.
            _deep_floor_raw = str(os.getenv("EVERMIND_BUILDER_DEEP_MIN_TIMEOUT_SEC", "") or "").strip()
            try:
                _deep_floor = int(_deep_floor_raw) if _deep_floor_raw else 1800
            except Exception:
                _deep_floor = 1800
            _deep_floor = max(1200, min(7200, _deep_floor))
            if boosted < _deep_floor:
                boosted = _deep_floor
        # v6.1.2 debug hook — one-shot log per (node_type,depth) so we can
        # confirm in prod which branch a hung builder actually hit.
        try:
            _dbg_key = f"_effective_timeout_dbg_{normalized_node_type}_{_cfg_depth}"
            if not getattr(self, _dbg_key, False):
                setattr(self, _dbg_key, True)
                logger.info(
                    "_effective_timeout_for_node: node=%s depth=%s boosted=%ss merger_like=%s",
                    normalized_node_type, _cfg_depth or "<unknown>", boosted,
                    bool((node or {}).get("builder_merger_like")),
                )
        except Exception:
            pass
        return boosted

    def _effective_stream_stall_timeout(
        self,
        node_type: str,
        input_data: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> int:
        base = self._stream_stall_timeout_for_node(node_type, node=node)
        if normalize_node_role(node_type) != "builder":
            return base

        text = str(input_data or "")
        lower = text.lower()
        is_3d = self._builder_input_wants_3d(text)
        assigned_targets = len(self._builder_assigned_html_targets(text))
        if task_classifier.wants_multi_page(text) and assigned_targets >= 3:
            base = min(
                base,
                self._read_int_env("EVERMIND_BUILDER_MULTI_PAGE_STREAM_STALL_SEC", 180, 120, 600),
            )

        retry_markers = (
            "previous attempt failed",
            "previous attempt timed out",
            "multiple timeouts detected",
            "previous error:",
            "navigation repair only",
            "multi-page delivery incomplete",
            "html ownership / output contract violation",
        )
        if any(marker in lower for marker in retry_markers):
            if is_3d:
                base = max(
                    base,
                    self._read_int_env("EVERMIND_BUILDER_3D_RETRY_STREAM_STALL_SEC", 360, 150, 600),
                )
            else:
                base = min(
                    base,
                    self._read_int_env("EVERMIND_BUILDER_RETRY_STREAM_STALL_SEC", 150, 90, 600),
                )
        return base

    def _compatible_gateway_fail_fast_node_types(self) -> set[str]:
        # v6.3.1 (maintainer 2026-04-21): added merger + patcher. Both were
        # missing before, so they returned initial_activity=0 and would
        # silently wait 300s (merger hard_timeout) / 120s (patcher
        # hard_timeout) when a relay's TTFB silently hung. Adding them
        # gives the same 75s fail-fast behaviour every other node has.
        return {
            "analyst",
            "assetimport",
            "builder",
            "debugger",
            "deployer",
            "imagegen",
            "merger",
            "patcher",
            "planner",
            "planner_degraded",
            "polisher",
            "reviewer",
            "router",
            "scribe",
            "spritesheet",
            "tester",
            "uidesign",
        }

    def _gateway_initial_activity_timeout_for_node(self, node_type: str, input_data: str = "", model_info: Optional[Dict[str, Any]] = None) -> int:
        """
        Compatible gateways can hang before the first usable token/tool-call arrives.
        Use a shorter initial-activity deadline so nodes fail over before the full
        hard ceiling expires.

        v5.8.6: aigate (private-relay) multiplier — MiniMax/Kimi/GLM on private-relay have
        reasoning-mode TTFB 30-60s on large prompts (the relay routes through
        the upstream's thinking step before first chunk). Default 20-28s isn't
        enough and causes premature fail-over. Apply 2.5x multiplier for aigate.
        """
        # v5.2: Conservative defaults — v4.6 SPEED values (14/12/10) were too
        # aggressive for slow providers. External benchmarks (Kimi K2.5 via
        # Together/Fireworks/Clarifai) show TTFT of 8-9s is normal, and the relay
        # first_chunk p95 for gpt-5.4 reaches 15-18s. Doubled the defaults to
        # give p95 enough headroom while keeping env overrides for fast links.
        # v5.8.6 REDESIGN: initial-activity timeouts tripled across the board.
        # Old values (20-28s) were pre-reasoning-model era. Modern Chinese
        # reasoning models (Kimi-K2.5 / MiniMax-M2.7 / Qwen3) legitimately
        # spend 30-90s in internal reasoning before first chunk, especially
        # when routed through relays (relay) that trigger reasoning
        # auto-mode on tool-using requests. Per Cline/Roo conventions.
        normalized_node_type = normalize_node_role(node_type)
        text = str(input_data or "")
        if normalized_node_type == "builder":
            base = self._read_int_env("EVERMIND_COMPAT_GATEWAY_BUILDER_INITIAL_ACTIVITY_SEC", 90, 15, 300)
            if task_classifier.wants_multi_page(text):
                base = max(
                    base,
                    self._read_int_env("EVERMIND_COMPAT_GATEWAY_BUILDER_MULTI_PAGE_INITIAL_SEC", 120, 20, 360),
                )
            result = base
        elif normalized_node_type == "polisher":
            result = self._read_int_env("EVERMIND_COMPAT_GATEWAY_POLISHER_INITIAL_ACTIVITY_SEC", 75, 15, 240)
        elif normalized_node_type == "imagegen":
            result = self._read_int_env("EVERMIND_COMPAT_GATEWAY_IMAGEGEN_INITIAL_ACTIVITY_SEC", 75, 15, 240)
        elif normalized_node_type in ("spritesheet", "assetimport"):
            result = self._read_int_env("EVERMIND_COMPAT_GATEWAY_ASSET_INITIAL_ACTIVITY_SEC", 60, 15, 180)
        elif normalized_node_type in self._compatible_gateway_fail_fast_node_types():
            result = self._read_int_env("EVERMIND_COMPAT_GATEWAY_INITIAL_ACTIVITY_SEC", 75, 15, 240)
        else:
            return 0
        # aigate (private-relay) reasoning-mode gets extra 1.5x on top of the new baseline.
        _provider = str((model_info or {}).get("provider") or "").strip().lower()
        if _provider == "aigate":
            result = int(result * 1.5)
        return result

    def _builder_input_wants_3d(self, input_data: str = "") -> bool:
        """Detect whether the builder input is for a 3D engine game."""
        text = str(input_data or "").lower()
        # Technical markers (from system prompt / retry injections)
        _technical_markers = (
            "three.js", "three.scene", "webglrenderer", "3d_engine", "three.min.js",
            "three.module.js", "perspectivecamera", "webgl",
        )
        if any(marker in text for marker in _technical_markers):
            return True
        # User-facing markers (Chinese + English goal text)
        _goal_markers = (
            "3d射击", "3d游戏", "三维", "第三人称", "3d shooter", "third person",
            "tps", "3d game", "3d engine", "runtime mode is 3d",
            "_evermind_runtime/three",
        )
        if any(marker in text for marker in _goal_markers):
            return True
        # Classify via task_classifier as a fallback
        try:
            if task_classifier.game_runtime_mode(input_data) == "3d_engine":
                return True
        except Exception:
            pass
        return False

    def _builder_prewrite_call_timeout(
        self,
        node_type: str,
        input_data: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> int:
        """
        Absolute cap for a single builder model call before the first real HTML write.
        This guards against long planning / streaming loops that never reach file_ops.

        v6.1.3 (maintainer 2026-04-19): CRITICAL — this value wraps the ENTIRE async
        call with `asyncio.wait_for`, not "idle chunk" detection. Thinking models
        like GLM-5.1 / DeepSeek reasoner spend 150-400s on reasoning_content
        alone (correctly streaming, not stuck) before the first tool_call delta.
        Previous 90-240s base was KILLING legitimate deep thinkers. Raised base
        to 600s (10 min) to give thinking models room. Inner stream-level idle
        detection (stall_timeout) still catches actual deadlock.
        """
        if normalize_node_role(node_type) != "builder":
            return 0
        # v6.1.3: 90 → 600. Deep-thinking models (GLM-5.1 / DeepSeek reasoner /
        # kimi-k2.6-thinking) routinely spend 3-7 min on legitimate reasoning
        # before the first tool_call. The previous 90s cap killed all of them.
        base = self._read_int_env("EVERMIND_BUILDER_FIRST_WRITE_TIMEOUT_SEC", 600, 120, 1800)
        text = str(input_data or "")
        text_lower = text.lower()
        is_3d = self._builder_input_wants_3d(input_data)
        # v5.1: support-lane concept removed; _builder_is_support_lane always returns False
        is_merger = bool((node or {}).get("builder_merger_like")) or bool(
            re.search(r"\b(?:final merger|merger|integrator|integration|assemble|assembly|merge)\b", text_lower)
        )
        if is_merger:
            # v5.1: Reduced from 600→360s — module assembly is faster than full rewrite
            base = max(
                base,
                self._read_int_env("EVERMIND_MERGER_FIRST_WRITE_SEC", 360, 180, 900),
            )
        if task_classifier.wants_multi_page(text):
            base = max(
                base,
                self._read_int_env("EVERMIND_BUILDER_MULTI_PAGE_FIRST_WRITE_SEC", 180, 90, 420),
            )
        # v5.1: All peer builders get equal timeout — no support-lane cap
        # §FIX: 3D engine games need significantly more time — Three.js code is 20K+ chars
        if is_3d:
            # v5.8.3: 420 → 240. 7-minute pre-write deadline let Builder-2
            # spin in 6-10 read/list calls with zero writes (user visible
            # as "one-line stuck for minutes"). 240s is still 4 minutes —
            # plenty for legit planning + first write on 3D tasks.
            base = max(
                base,
                self._read_int_env("EVERMIND_BUILDER_3D_FIRST_WRITE_SEC", 240, 120, 600),
            )
            goal_hint = self._builder_goal_hint_source(input_data=input_data)
            try:
                prefers_direct_text = task_classifier.premium_3d_builder_direct_text_first_pass(goal_hint)
            except Exception:
                prefers_direct_text = False
            if prefers_direct_text:
                # v6.1.3: 210 → 900. Direct-text mode wraps the whole stream
                # — thinking models need minutes before emitting DOCTYPE.
                # Inner stall_timeout still catches real deadlock.
                base = max(
                    base,
                    self._read_int_env("EVERMIND_BUILDER_3D_DIRECT_TEXT_FIRST_WRITE_SEC", 900, 360, 1800),
                )
        retry_markers = (
            "previous attempt failed",
            "previous attempt timed out",
            "retry 1/3",
            "retry 2/3",
            "retry 3/3",
            "multi-page delivery incomplete",
        )
        if any(marker in text_lower for marker in retry_markers):
            # v5.1: Removed support-lane retry branch (is_support_lane always False)
            if is_merger:
                # v4.1: Merger retry timeout reduced from 600→420s. If the first
                # 600s attempt failed, repeating the same wait is wasteful. 420s
                # still covers 120K char streaming (~350s) with margin.
                base = max(
                    base,
                    self._read_int_env("EVERMIND_MERGER_RETRY_FIRST_WRITE_SEC", 420, 300, 900),
                )
            elif is_3d:
                base = max(
                    base,
                    self._read_int_env("EVERMIND_BUILDER_3D_RETRY_FIRST_WRITE_SEC", 420, 180, 600),
                )
            else:
                # v6.1.3: retry budget raised 180 → 600. Retries are where
                # builder is reading existing artifact + doing edits; thinking
                # models still need minutes before first edit fires. Stall
                # timeout catches actual deadlock.
                base = max(
                    base,
                    self._read_int_env("EVERMIND_BUILDER_RETRY_FIRST_WRITE_SEC", 600, 120, 1200),
                )
        override = self._node_int_override(
            node,
            "builder_prewrite_timeout_override_sec",
            minimum=60,
            maximum=1800,  # v6.1.3: raised from 900 for thinking models
        )
        if override is not None:
            return override
        tuning = self._node_budget_tuning(node_type, node=node)
        scaled = self._scale_budget_int(
            base,
            float(tuning.get("builder_prewrite_scale", 1.0) or 1.0),
            minimum=60,
            maximum=1800,
        )
        # v6.1.7 (maintainer 2026-04-19): GLM-5.x + tool_calls has observed 6+ min
        # dead-stream behavior (zero chunks, zero reasoning). LiteLLM retries
        # don't help — the upstream just never produces bytes. Shorten the
        # prewrite cap for this specific provider so the fallback chain
        # (aigate-minimax / kimi) gets invoked faster. Working GLM calls
        # emit the first chunk within 15-30s; 120s is still 4-8x that.
        assigned = str((node or {}).get("assigned_model") or "").lower()
        if "glm" in assigned:
            glm_cap = self._read_int_env("EVERMIND_BUILDER_GLM_FIRST_WRITE_SEC", 120, 60, 600)
            scaled = min(scaled, glm_cap)
        return scaled

    def _builder_repair_write_timeout(
        self,
        node_type: str,
        input_data: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> int:
        """
        Follow-up timeout after a builder tool turn that still produced no write.

        Premium 3D builders frequently spend one model turn listing or reading
        manifests before the actual HTML write turn. If we clamp that follow-up
        call to a short repair budget, the builder times out on the happy path.
        """
        if normalize_node_role(node_type) != "builder":
            return 0
        timeout = self._read_int_env("EVERMIND_BUILDER_REPAIR_WRITE_TIMEOUT_SEC", 60, 10, 360)
        # v4.0 FIX: Merger reads two large builder outputs before writing the
        # merged result. The default 60s repair budget is too tight — raise to
        # 300s so the model has time to process 120K+ chars of context.
        text_lower = str(input_data or "").lower()
        is_merger = bool((node or {}).get("builder_merger_like")) or bool(
            re.search(r"\b(?:final merger|merger|integrator|integration|assemble|assembly|merge)\b", text_lower)
        )
        if is_merger:
            timeout = max(
                timeout,
                self._read_int_env("EVERMIND_MERGER_REPAIR_WRITE_TIMEOUT_SEC", 300, 120, 600),
            )
        if self._builder_input_wants_3d(input_data):
            timeout = max(
                timeout,
                self._read_int_env(
                    "EVERMIND_BUILDER_3D_REPAIR_WRITE_TIMEOUT_SEC",
                    self._builder_prewrite_call_timeout(node_type, input_data, node=node),
                    180,
                    600,
                ),
            )
        override = self._node_int_override(
            node,
            "builder_repair_timeout_override_sec",
            minimum=10,
            maximum=600,
        )
        if override is not None:
            return override
        tuning = self._node_budget_tuning(node_type, node=node)
        return self._scale_budget_int(
            timeout,
            float(tuning.get("builder_repair_scale", 1.0) or 1.0),
            minimum=10,
            maximum=600,
        )

    def _builder_tool_only_call_timeout(
        self,
        node_type: str,
        input_data: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> int:
        """
        Early-abort budget for builder streams that stay stuck in tool-planning mode.

        This is intentionally lower than the full pre-write timeout, but only applies
        when the stream still has neither deliverable text nor a write-like file_ops
        payload in flight.
        """
        if normalize_node_role(node_type) != "builder":
            return 0
        prewrite_timeout = self._builder_prewrite_call_timeout(node_type, input_data, node=node)
        timeout = self._read_int_env("EVERMIND_BUILDER_TOOL_ONLY_TIMEOUT_SEC", 120, 30, 360)
        if self._builder_is_support_lane(input_data):
            timeout = min(
                timeout,
                self._read_int_env("EVERMIND_BUILDER_SUPPORT_TOOL_ONLY_TIMEOUT_SEC", 60, 20, 180),
            )
        elif self._builder_input_wants_3d(input_data):
            timeout = max(
                timeout,
                self._read_int_env("EVERMIND_BUILDER_3D_TOOL_ONLY_TIMEOUT_SEC", 150, 60, 420),
            )
        if prewrite_timeout > 0:
            timeout = min(timeout, prewrite_timeout)
        override = self._node_int_override(
            node,
            "builder_tool_only_timeout_override_sec",
            minimum=20,
            maximum=420,
        )
        if override is not None:
            return override
        tuning = self._node_budget_tuning(node_type, node=node)
        return self._scale_budget_int(
            timeout,
            float(tuning.get("builder_tool_only_scale", 1.0) or 1.0),
            minimum=20,
            maximum=420,
        )

    def _builder_force_text_threshold(self, input_data: str = "") -> int:
        """
        Limit how many non-write tool turns a builder may spend before switching to
        direct final-file delivery. Multi-page builders should write almost
        immediately; repeated list/read loops are usually wasted time.

        Retry attempts are stricter than first-pass execution, but game/creative
        builders still need extra room to assemble a minimally playable slice
        instead of getting forced into a text-only shell after two directory
        listings.
        """
        base = self._read_int_env("EVERMIND_BUILDER_FORCE_TEXT_STREAK", 5, 1, 20)
        text = str(input_data or "")
        lower = text.lower()
        assigned_targets = len(self._builder_assigned_html_targets(text))
        merger_like = bool(re.search(r"\b(?:final merger|merger|integrator|integration|assemble|assembly|merge)\b", lower))
        is_game_or_creative = False

        # Game/creative tasks need more research iterations (3D setup, physics, etc.)
        try:
            task_type = task_classifier.classify(text).task_type
            if task_type in ("game", "creative"):
                is_game_or_creative = True
                base = max(base, self._read_int_env("EVERMIND_BUILDER_GAME_FORCE_TEXT_STREAK", 6, 3, 20))
        except Exception:
            pass
        if self._builder_is_support_lane(input_data) and not is_game_or_creative:
            # v3.1: Support lane needs to read main builder output before writing
            # complementary files. Previous value of 2 was too aggressive.
            base = min(
                base,
                self._read_int_env("EVERMIND_BUILDER_SUPPORT_FORCE_TEXT_STREAK", 5, 2, 10),
            )

        if task_classifier.wants_multi_page(text) and assigned_targets >= 3:
            base = min(
                base,
                self._read_int_env("EVERMIND_BUILDER_MULTI_PAGE_FORCE_TEXT_STREAK", 3, 1, 6),
            )

        if merger_like:
            # V4.3: Merger MUST read artifacts from BOTH builders before merging.
            # Typical read sequence: list dir (1) + read B1 index (1) + read B1
            # support JS (2-3) + read B2 output (1) + read B2 support (2-3) = 7-9.
            # Previous threshold of 10 triggered after reading, forcing text-only
            # mode that produced planning prose instead of merged HTML.
            base = max(
                base,
                self._read_int_env("EVERMIND_MERGER_FORCE_TEXT_STREAK", 16, 8, 25),
            )

        retry_markers = (
            "previous attempt failed",
            "previous attempt timed out",
            "retry 1/3",
            "retry 2/3",
            "retry 3/3",
            "multiple timeouts detected",
            "multi-page delivery incomplete",
            "html ownership / output contract violation",
            "navigation repair only",
        )
        if any(marker in lower for marker in retry_markers):
            retry_threshold = self._read_int_env("EVERMIND_BUILDER_RETRY_FORCE_TEXT_STREAK", 2, 1, 6)
            if is_game_or_creative:
                retry_threshold = self._read_int_env("EVERMIND_BUILDER_GAME_RETRY_FORCE_TEXT_STREAK", 4, 2, 10)
            base = min(base, retry_threshold)
        if merger_like and any(marker in lower for marker in retry_markers):
            # v3.1: Even on retry, merger needs to re-read artifacts before writing.
            # Previous value of 2 caused instant loop guard on every retry attempt.
            # Must use max() here because the general retry check above already set
            # base = min(base, 2) — using min() would keep it at 2, defeating the purpose.
            base = max(
                base,
                self._read_int_env("EVERMIND_MERGER_RETRY_FORCE_TEXT_STREAK", 6, 3, 12),
            )
        return base

    def _polisher_prewrite_call_timeout(self, node_type: str, input_data: str = "") -> int:
        """
        Polisher should inspect briefly, then start editing. Long tool-only calls
        before the first write are usually a stuck browser/read loop.
        """
        if normalize_node_role(node_type) != "polisher":
            return 0
        # v6.4.61-A (maintainer 2026-04-23): raised base 60→90 and multi-page
        # 75→150. Observed Apr 23 16:07 session: polisher needs to read
        # 4-8 pages worth of deliverable before first edit; 75s is
        # insufficient especially on kimi's slower stream. This is the
        # "pre-write" cap — polisher still has other watchdogs downstream,
        # so loosening here only helps initial analysis not runaway.
        # v6.7 (maintainer 2026-04-23 20:09): observed run_69495533723c — gpt-5.4
        # on relay.cn hit the 90s cap before its reasoning chunk landed,
        # so polisher failed on first call with zero writes. Raise base
        # 90→180 so slow-thinking models get one honest reasoning pass.
        # Multi-page 150→240.
        # v6.7b (maintainer 2026-04-23 23:22): observed run_f90b35a5de35 polisher
        # failed at 180s ("no real file write"). kimi streamed 38 chunks
        # then another 42 chunks (just tool_call acks) but never got to
        # write. Raise base 180→300, max 360→480 so kimi's first-write
        # latency fits; POLISHER_MAX_TOOL_ITERS (cap 10) still bounds waste.
        base = self._read_int_env("EVERMIND_POLISHER_FIRST_WRITE_TIMEOUT_SEC", 300, 30, 480)
        text = str(input_data or "")
        lower = text.lower()
        try:
            if task_classifier.wants_multi_page(text):
                base = max(
                    base,
                    self._read_int_env("EVERMIND_POLISHER_MULTI_PAGE_FIRST_WRITE_SEC", 240, 60, 480),
                )
        except Exception:
            pass
        retry_markers = (
            "previous attempt failed",
            "previous attempt timed out",
            "retry 1/3",
            "retry 2/3",
            "retry 3/3",
        )
        if any(marker in lower for marker in retry_markers):
            base = min(
                base,
                self._read_int_env("EVERMIND_POLISHER_RETRY_FIRST_WRITE_SEC", 45, 30, 180),
            )
        return base

    def _polisher_force_write_threshold(self, input_data: str = "") -> int:
        """
        Allow one quick inspection pass, but stop a polisher that keeps calling
        tools without producing a concrete file write.
        v6.1.14f (maintainer 2026-04-20): bumped base 3→6 because polisher is now
        patch-only (file_ops edit). It needs more read rounds to identify the
        target line before editing. It also has the "polish skipped" escape
        hatch so legitimate early termination won't count as failure.
        """
        base = self._read_int_env("EVERMIND_POLISHER_FORCE_WRITE_STREAK", 6, 1, 15)
        lower = str(input_data or "").lower()
        try:
            if task_classifier.wants_multi_page(str(input_data or "")):
                base = min(
                    base,
                    self._read_int_env("EVERMIND_POLISHER_MULTI_PAGE_FORCE_WRITE_STREAK", 3, 1, 8),
                )
        except Exception:
            pass
        retry_markers = (
            "previous attempt failed",
            "previous attempt timed out",
            "retry 1/3",
            "retry 2/3",
            "retry 3/3",
        )
        if any(marker in lower for marker in retry_markers):
            base = min(
                base,
                self._read_int_env("EVERMIND_POLISHER_RETRY_FORCE_WRITE_STREAK", 2, 1, 6),
            )
        return base

    def _polisher_browser_call_limit(self, node: Optional[Dict[str, Any]] = None) -> int:
        value = self._read_int_env("EVERMIND_POLISHER_MAX_BROWSER_CALLS", 1, 0, 8)
        override = self._node_int_override(node, "browser_call_limit", minimum=0, maximum=8)
        if override is not None:
            return override
        tuning = self._node_budget_tuning("polisher", node=node)
        return self._delta_budget_int(
            value,
            int(tuning.get("browser_call_delta", 0) or 0),
            minimum=0,
            maximum=8,
        )

    def _builder_direct_multifile_requested(self, node_type: str, input_data: str = "") -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        text = str(input_data or "")
        if not text:
            return False
        goal_hint = self._builder_goal_hint_source(input_data=text)
        if self._builder_retry_requires_existing_artifact_patch_context(
            node_type,
            input_data=text,
            goal_hint=goal_hint,
        ):
            return False
        return BUILDER_DIRECT_MULTIFILE_MARKER.lower() in text.lower()

    def _builder_goal_classification_candidates(
        self,
        *,
        goal_hint: str = "",
        input_data: str = "",
    ) -> List[str]:
        candidates: List[str] = []

        def _append(value: str) -> None:
            text = str(value or "").strip()
            if not text or text in candidates:
                return
            candidates.append(text)

        explicit = str(goal_hint or "").strip()
        if explicit:
            _append(explicit)

        text = str(input_data or "").strip()
        if text:
            for pattern in _BUILDER_GOAL_HINT_PATTERNS:
                match = pattern.search(text)
                if not match:
                    continue
                _append(str(match.group(1) or "").strip())
            _append(text)
        return candidates

    def _builder_retry_looks_like_premium_3d_game(
        self,
        *,
        goal_hint: str = "",
        input_data: str = "",
    ) -> bool:
        for candidate in self._builder_goal_classification_candidates(
            goal_hint=goal_hint,
            input_data=input_data,
        ):
            try:
                if task_classifier.wants_multi_page(candidate):
                    continue
            except Exception:
                pass
            try:
                if task_classifier.premium_3d_builder_patch_preferred(candidate):
                    return True
            except Exception:
                continue
        return False

    def _builder_has_retry_context(
        self,
        node_type: str,
        *,
        input_data: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        lower = str(input_data or "").lower()
        retry_attempt = int(((node or {}).get("retry_attempt", 0) or 0))
        retry_markers = (
            "retry 1/",
            "retry 2/",
            "retry 3/",
            "previous attempt failed",
            "previous attempt timed out",
            "quality gate failed",
            "builder pre-write timeout",
            "builder first-write timeout",
            "builder direct-text idle timeout",
            "builder execution timeout",
            "reviewer rejected your output",
            "reviewer rejected",
            "reviewer rework",
            "patch mode only",
            "inspect the existing output artifacts first",
            "start from the current files and patch the failing areas only",
        )
        return retry_attempt > 0 or any(marker in lower for marker in retry_markers)

    def _builder_retry_requires_existing_artifact_patch_context(
        self,
        node_type: str,
        *,
        input_data: str = "",
        goal_hint: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        if bool(
            (node or {}).get("builder_existing_artifact_patch_mode")
            or (node or {}).get("existing_artifact_patch_mode")
        ):
            return True
        if not self._builder_has_retry_context(node_type, input_data=input_data, node=node):
            return False
        if self._builder_retry_missing_artifact_context(
            node_type,
            input_data=input_data,
            goal_hint=goal_hint,
            node=node,
        ):
            return False
        return self._builder_retry_looks_like_premium_3d_game(
            goal_hint=goal_hint,
            input_data=input_data,
        )

    def _builder_retry_missing_artifact_context(
        self,
        node_type: str,
        *,
        input_data: str = "",
        goal_hint: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        retry_context = "\n".join(
            str(part or "")
            for part in (
                input_data,
                goal_hint,
                (node or {}).get("error"),
            )
        ).lower()
        if not retry_context:
            return False
        missing_artifact_markers = (
            "tool-planning prose",
            "persistable html deliverable",
            "non-deliverable text",
            "no saved html artifact found",
            "no real file written",
            "no file write produced",
            "builder pre-write timeout",
            "builder first-write timeout",
            # v6.4.9 (maintainer 2026-04-22): extend markers to cover the zero-files
            # demote + unnamed-block + direct-text stall surfaces. Without these,
            # retries after those failures didn't flip into patch_context and
            # the builder kept trying direct_text again on the same goal text.
            "produced zero files on disk",
            "skipping unnamed html block",
            "direct-text no-output timeout",
            "returned empty output",
            "returned empty content",
            "empty output on retry",
        )
        return any(marker in retry_context for marker in missing_artifact_markers)

    def _experiment_force_tool_call_enabled(self) -> bool:
        """v6.4.14 / v6.4.15 (maintainer 2026-04-22) — unified ON-switch for the
        "short-burst tool_call only" experiment. Reads BOTH env and disk
        config so the user can flip it persistently via config.json without
        needing a shell export on every Evermind launch.

        v6.4.16 (maintainer 2026-04-22): server.py constructs AIBridge.config
        from a whitelist dict that does NOT include the experiment flag.
        Cache the resolved value per AIBridge instance so we only read the
        disk config once per session — the file is only ~7KB so the read
        itself is fast, but we avoid hammering it on every builder turn."""
        cached = getattr(self, "_exp_force_tool_call_cache", None)
        if cached is not None:
            return cached
        # Env wins so the shell-based opt-in still works for one-off experiments.
        if str(os.getenv("EVERMIND_BUILDER_FORCE_TOOL_CALL", "0")).strip().lower() in {"1", "true", "yes", "on"}:
            self._exp_force_tool_call_cache = True
            return True
        # 1) bridge.config (set by server.py for whitelisted fields)
        config = getattr(self, "config", {}) or {}
        flag = config.get("experiment_force_tool_call")
        if isinstance(flag, bool) and flag:
            self._exp_force_tool_call_cache = True
            return True
        if isinstance(flag, str) and flag.strip().lower() in {"1", "true", "yes", "on"}:
            self._exp_force_tool_call_cache = True
            return True
        # 2) disk config.json fallback (captures user edits that bypass the
        # server.py whitelist — the typical path for the experiment toggle).
        try:
            import json as _json
            cfg_path = Path.home() / ".evermind" / "config.json"
            if cfg_path.exists():
                with cfg_path.open("r", encoding="utf-8") as _f:
                    disk_cfg = _json.load(_f)
                disk_flag = disk_cfg.get("experiment_force_tool_call") if isinstance(disk_cfg, dict) else None
                if isinstance(disk_flag, bool) and disk_flag:
                    self._exp_force_tool_call_cache = True
                    return True
                if isinstance(disk_flag, str) and disk_flag.strip().lower() in {"1", "true", "yes", "on"}:
                    self._exp_force_tool_call_cache = True
                    return True
        except Exception:
            pass
        self._exp_force_tool_call_cache = False
        return False

    def _builder_should_auto_direct_multifile(
        self,
        node_type: str,
        *,
        model_name: str = "",
        model_info: Optional[Dict[str, Any]] = None,
        input_data: str = "",
    ) -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        # v6.4.14 (maintainer 2026-04-22): short-burst experiment switch.
        # Toggleable via EITHER env var `EVERMIND_BUILDER_FORCE_TOOL_CALL=1`
        # OR `config.json.experiment_force_tool_call=true` (persistent across
        # Evermind restarts without needing shell export). When ON every
        # builder/merger/polisher is forced through the multi-turn tool_call
        # loop (30-70s short requests) instead of single long 200-300s streams.
        if self._experiment_force_tool_call_enabled():
            return False
        # v5.8.2: env kill-switch for direct_multifile mode.
        if str(os.getenv("EVERMIND_BUILDER_DISABLE_DIRECT_MULTIFILE", "0")).strip().lower() in {"1", "true", "yes"}:
            return False
        # v5.8.2 auto-learn: after 2 empty batches in THIS AIBridge instance,
        # disable direct_multifile for the rest of the run.
        if getattr(self, "_builder_direct_multifile_disabled", False):
            return False
        # Retry with "need-patch-existing" context forces tool-call re-entry
        # so the model reads the artifact before modifying it.
        if self._builder_retry_requires_existing_artifact_patch_context(
            node_type,
            input_data=input_data,
            goal_hint=self._builder_goal_hint_source(input_data=input_data),
        ):
            return False
        assigned_targets = len(self._builder_assigned_html_targets(input_data))
        # Single-target tasks route better through direct_text (one fenced block).
        if assigned_targets < 2:
            lower = str(input_data or "").lower()
            if BUILDER_TARGET_OVERRIDE_MARKER.lower() in lower and assigned_targets >= 1:
                return True
            return False

        resolved = model_info or self._resolve_model(model_name or "")
        provider = str((resolved or {}).get("provider") or "").strip().lower()
        model_lower = str(model_name or "").lower()

        # v6.4.10 (maintainer 2026-04-22): known streaming-incompatible models.
        # GLM-5.x has a known tool_stream bug (sglang#11888) that corrupts
        # multi-file batches; other providers stream `<file path="...">`
        # blocks cleanly. Keep the explicit deny list narrow.
        if re.match(r"^(?:openai/|zhipu/)?glm-5(?:\.\d+)?\b", model_lower):
            return False

        # Kimi retains v5.8.6 opt-in gate (observed 100% fail on multifile
        # schema until an upstream fix lands). Override via env if/when a
        # newer Kimi build ships.
        if provider == "kimi":
            if str(os.getenv("EVERMIND_BUILDER_KIMI_ALLOW_DIRECT_MULTIFILE", "0")).strip().lower() not in {"1", "true", "yes"}:
                return False

        # v6.4.10: every other streaming-capable provider (openai / anthropic /
        # deepseek / qwen / doubao / minimax / mistral / aigate …) can stream
        # `<file path="...">` blocks fine. Routing multi-target builders
        # through direct_multifile completes in ~2-4min per builder versus
        # the 10-15min tool_call loop we observed on 2026-04-22.
        try:
            return task_classifier.wants_multi_page(input_data) or assigned_targets >= 2
        except Exception:
            return True

    def _builder_should_auto_direct_text(
        self,
        node_type: str,
        *,
        model_name: str = "",
        model_info: Optional[Dict[str, Any]] = None,
        input_data: str = "",
        goal_hint: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        # v6.4.14 (maintainer 2026-04-22): short-burst experiment switch (mirror
        # of the multifile guard above). When EVERMIND_BUILDER_FORCE_TOOL_CALL=1
        # every builder is forced through the multi-turn tool_call loop.
        if str(os.getenv("EVERMIND_BUILDER_FORCE_TOOL_CALL", "0")).strip().lower() in {"1", "true", "yes", "on"}:
            return False
        # v5.8.3: env kill-switch for anyone who wants to fully disable the
        # direct-text path. Default behaviour preserved — opt-out only.
        if str(os.getenv("EVERMIND_BUILDER_DISABLE_DIRECT_TEXT", "0")).strip().lower() in {"1", "true", "yes"}:
            return False
        # v5.8.6: merger-like builders MUST use direct_text. The merger combines
        # two 80-100K char HTMLs; tool_call mode (8K tokens/turn) needs 6+ turns
        # and breaks JS syntax between turns (observed: "6 <script> opens, 5
        # </script> closes"). direct_text gives one 40K-token shot (~160K chars)
        # that holds the HTML together.
        # Ordering: this check MUST run BEFORE `_builder_direct_multifile_disabled`
        # because the auto-learn multifile kill-switch triggers on primary-builder
        # returned_targets=[] events — but those "empty returned_targets" are a
        # multifile-schema miss, not a content miss. Merger does not use the
        # multifile schema at all, so it must be able to override the kill.
        if bool((node or {}).get("builder_merger_like")):
            if str(os.getenv("EVERMIND_BUILDER_MERGER_DISABLE_DIRECT_TEXT", "0")).strip().lower() not in {"1", "true", "yes"}:
                return True
        # Runtime kill-switch shared with direct_multifile: once we've learned
        # Kimi won't produce valid multi-file batches in this run, also skip
        # direct_text for PRIMARY builders (the failure modes overlap — both
        # produce prose). Merger bypass is handled above.
        if getattr(self, "_builder_direct_multifile_disabled", False):
            return False
        # v4.0 FIX: Support-lane builders MUST use tool/file_ops mode to produce
        # JS/CSS/JSON artifacts. direct_text only outputs single HTML files which
        # is wrong for support lanes.
        if isinstance(node, dict):
            if bool((node or {}).get("builder_is_support_lane_node")):
                return False
        support_lane_hint = "\n".join(
            part for part in (str(input_data or "").strip(), str(goal_hint or "").strip()) if part
        )
        if self._builder_is_support_lane(support_lane_hint):
            return False

        # v5.8.6 SYMMETRIC PEER BUILDER FIX: only applies when the orchestrator
        # explicitly marked this builder as a peer in parallel mode (merger
        # handles the root). In that case both peers must take the SAME
        # direct_text path — otherwise Builder 1 gets dragged back into
        # tool_call by a wants_multi_page false-positive on its task text,
        # while Builder 2 correctly routes to direct_text.
        # Scope is narrow enough that legacy routing decisions for other
        # builder topologies are preserved (keeps all existing tests green).
        # Real-world orchestrator gives parallel peer builders
        # `allowed_html_targets=[]` when the merger owns root index — but those
        # peers STILL write HTML staging artifacts (task_N/index.html). Support
        # lanes were already filtered by the support_lane_hint check above, so
        # any primary peer reaching this point is truly an HTML producer.
        #
        # v6.3.7 (maintainer 2026-04-21) HOTFIX: Observed builder2 hanging for 15+
        # minutes because it fell through to tool_calls mode while builder1
        # ran direct_multifile. Root cause: the strict `is False` check on
        # `can_write_root_index` fails when the orchestrator omits that
        # attribute (None / missing), and the builder silently routes to the
        # unsafe tool_call path. kimi-k2.6-code-preview in tool_call mode
        # regularly truncates long HTML (2 <script> opens, 1 close) then gets
        # stuck in salvage-continuation loops until hard_timeout. Widen the
        # peer definition: any builder node with `builder_merger_like=False`
        # that is NOT a support lane counts as a parallel peer. Net effect —
        # every peer builder gets the same stable direct_text path.
        is_parallel_peer_with_merger = bool(
            isinstance(node, dict)
            and (
                node.get("can_write_root_index") is False
                or node.get("can_write_root_index") is None
            )
            and not bool(node.get("builder_is_support_lane_node"))
            and not bool(node.get("builder_merger_like"))
        )
        # v6.3.9 (maintainer 2026-04-21) HOTFIX: previous `is False` / None check
        # treats ONLY peer builders (merger will own root) as direct_text
        # candidates. But in the 2-builder+merger topology observed this run,
        # ONE builder has `can_write_root_index=True` (the primary) and the
        # other `can_write_root_index=False` (peer). The primary fell through
        # to `premium_3d_builder_direct_text_first_pass(text)` which classifies
        # the INPUT text — and the input is the orchestrator's generic handoff
        # ("ADVANCED MODE — Use analyst notes..."), stripping out every goal
        # keyword the classifier needs. Result: primary silently routed to
        # tool_calls → kimi truncates 50KB HTML → salvage-loop hang → 15min
        # timeout (witnessed 10:05-10:16 run).
        #
        # Fix: treat BOTH root-owning primaries AND peers as "parallel builder
        # with merger downstream" as long as they are not merger themselves
        # and not a pure support lane. They all write one HTML shell →
        # direct_text is the correct payload shape for every one. This makes
        # the two builders' execution paths symmetric, which is what the
        # merger topology always assumed. Gated by env so the original strict
        # path can be restored in regression tests via
        # EVERMIND_BUILDER_PARALLEL_ALL_DIRECT_TEXT=0.
        if not is_parallel_peer_with_merger and isinstance(node, dict):
            _parallel_all = str(
                os.getenv("EVERMIND_BUILDER_PARALLEL_ALL_DIRECT_TEXT", "1") or "1"
            ).strip().lower() not in ("0", "false", "no", "off")
            if (
                _parallel_all
                and not bool(node.get("builder_is_support_lane_node"))
                and not bool(node.get("builder_merger_like"))
                and not bool(node.get("single_builder_mode"))
            ):
                logger.info(
                    "_builder_should_auto_direct_text v6.3.9 fallback: "
                    "primary builder with merger topology → direct_text=True "
                    "(node_type=%s can_write_root_index=%r)",
                    node.get("type"), node.get("can_write_root_index"),
                )
                is_parallel_peer_with_merger = True
        peer_assigned_targets = (
            self._builder_allowed_html_targets_from_node(node)
            if isinstance(node, dict)
            else []
        ) or self._builder_assigned_html_targets(input_data or goal_hint)
        peer_goal_text = self._builder_goal_hint_source(
            goal_hint=goal_hint,
            input_data=input_data,
        )
        try:
            peer_wants_multi_page = bool(
                peer_goal_text and task_classifier.wants_multi_page(peer_goal_text)
            )
        except Exception:
            peer_wants_multi_page = False
        peer_multi_target_delivery = len(peer_assigned_targets) > 1
        # v6.1.3 debug
        if isinstance(node, dict) and str(node.get("type", "")).lower() == "builder":
            logger.info(
                "_builder_should_auto_direct_text peer check: node_type=%s can_write_root_index=%r support_lane=%r merger_like=%r multi_target=%r wants_multi_page=%r → peer=%s",
                node.get("type"),
                node.get("can_write_root_index"),
                node.get("builder_is_support_lane_node"),
                node.get("builder_merger_like"),
                peer_multi_target_delivery,
                peer_wants_multi_page,
                is_parallel_peer_with_merger,
            )
        if is_parallel_peer_with_merger:
            # v6.1.3 (maintainer 2026-04-19): the kimi-only gate caused builder1
            # (tool_call) + builder2 (direct_text) asymmetry on glm-5.1 —
            # same peer class, same task intent, but task text slightly
            # differs ("game" vs "support subsystem") so task_classifier
            # downstream branches picked different modes. Every peer-builder
            # that can't own root index should take the same direct_text
            # path regardless of provider. Peer writes ONE HTML file into
            # staging → direct_text is the correct shape for every model.
            if peer_multi_target_delivery or peer_wants_multi_page:
                return False
            return True

        text = self._builder_goal_hint_source(goal_hint=goal_hint, input_data=input_data)
        if not text or task_classifier.wants_multi_page(text):
            return False
        if isinstance(node, dict):
            allowed_targets = self._builder_allowed_html_targets_from_node(node) or []
            can_write_root = node.get("can_write_root_index")
            if can_write_root is False and (not allowed_targets or "index.html" not in allowed_targets):
                return False
        assigned_targets = self._builder_assigned_html_targets(text)
        if len(assigned_targets) > 1:
            return False
        has_retry_context = self._builder_has_retry_context(
            node_type,
            input_data=input_data,
            node=node,
        )
        resolved = model_info or self._resolve_model(model_name or "")
        provider = str((resolved or {}).get("provider") or "").strip().lower()
        if provider != "kimi":
            return False
        if not has_retry_context and task_classifier.premium_3d_builder_direct_text_first_pass(text):
            return True
        if (
            task_classifier.premium_3d_builder_patch_preferred(text)
            and self._builder_retry_requires_existing_artifact_patch_context(
                node_type,
                input_data=input_data,
                goal_hint=goal_hint,
                node=node,
            )
        ):
            return False
        if task_classifier.game_direct_text_delivery_mode(text):
            return True
        return self._builder_retry_prefers_direct_text(
            node_type,
            input_data=input_data,
            goal_hint=goal_hint,
        )

    def _builder_retry_prefers_direct_text(
        self,
        node_type: str,
        *,
        input_data: str = "",
        goal_hint: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        if normalize_node_role(node_type) != "builder":
            return False
        text = self._builder_goal_hint_source(goal_hint=goal_hint, input_data=input_data)
        if not text or task_classifier.wants_multi_page(text):
            return False
        assigned_targets = self._builder_assigned_html_targets(input_data or text)
        if len(assigned_targets) > 1:
            return False
        try:
            if task_classifier.classify(text).task_type != "game":
                return False
        except Exception:
            return False
        if self._builder_retry_requires_existing_artifact_patch_context(
            node_type,
            input_data=input_data,
            goal_hint=goal_hint,
            node=node,
        ):
            return False
        lower = str(input_data or "").lower()
        retry_attempt = int(((node or {}).get("retry_attempt", 0) or 0))
        retry_markers = (
            "retry 1/",
            "retry 2/",
            "retry 3/",
            "previous attempt failed",
            "previous attempt timed out",
        )
        direct_text_retry_markers = (
            "builder pre-write timeout",
            "builder first-write timeout",
            "builder direct-text idle timeout",
            "no real file written",
            "no file write produced",
            "stalled after scaffold generation",
            "no new meaningful html stream activity",
            "direct single-file delivery mode",
            "quality gate failed",
            "primitive placeholder geometry",
            "placeholder-grade",
            "canvas2d",
            "3d runtime",
            "tool-planning prose",
            "persistable html deliverable",
            "non-deliverable text",
            "no saved html artifact found",
            # v5.8.6: tool_call truncation — if tool_call mode hit finish=length
            # 2+ times, switch delivery to direct_text (single-shot HTML) on retry
            # so the model isn't forced to stream HTML through tool-call arguments.
            "token limit during tool calls",
            "truncated tool loop",
            "finish=length with tool_calls",
        )
        is_retry = retry_attempt > 0 or any(marker in lower for marker in retry_markers)
        return is_retry and any(marker in lower for marker in direct_text_retry_markers)

    def _builder_goal_hint_source(
        self,
        *,
        goal_hint: str = "",
        input_data: str = "",
    ) -> str:
        explicit = str(goal_hint or "").strip()
        if explicit:
            return explicit
        text = str(input_data or "").strip()
        if not text:
            return ""
        for pattern in _BUILDER_GOAL_HINT_PATTERNS:
            match = pattern.search(text)
            if not match:
                continue
            candidate = str(match.group(1) or "").strip()
            if candidate:
                return candidate
        return text

    def _max_tool_iterations_for_node(self, node_type: str, node: Optional[Dict[str, Any]] = None) -> int:
        normalized_node_type = normalize_node_role(node_type)
        # v6.1.3 (maintainer 2026-04-18): significantly raised caps across the
        # board. Previous values were forcing functions that killed
        # legitimate long-running nodes (analyst research, reviewer CoVe).
        # Trust the no-activity watchdog + content-activity detectors to
        # catch real deadlocks; arbitrary iteration counts hurt quality more
        # than they help. Max ceiling raised 30→100.
        if normalized_node_type == "builder":
            # v6.7 (maintainer 2026-04-23): 60 → 15. builder.yaml mandates
            # one-shot file_ops write (architect/editor contract v6.4.23)
            # plus at most 2-3 corrective edits. Observed V6.6 run: kimi
            # burned 6-10 tool-loop rounds × 200-300s each = 30-50min on
            # builder alone, blowing the Fast=10min/Deep=30min budgets.
            # Cap at 15 still allows generous corrective edits but forces
            # early commitment. Override via EVERMIND_BUILDER_MAX_TOOL_ITERS.
            value = self._read_int_env("EVERMIND_BUILDER_MAX_TOOL_ITERS", 15, 1, 100)
        elif normalized_node_type == "imagegen":
            value = self._read_int_env("EVERMIND_IMAGEGEN_MAX_TOOL_ITERS", 40, 2, 80)
        elif normalized_node_type == "polisher":
            # v6.7 (maintainer 2026-04-23): 50 → 10. polisher.yaml V6.4.15
            # mandates ≤1 read + ≤3 writes + ≤3 min wall clock. 50 was
            # a legacy ceiling that let kimi loop 20+ rounds of reads.
            # 10 covers a real polish path (list → read → 3 writes +
            # corrective edit) with comfortable margin.
            value = self._read_int_env("EVERMIND_POLISHER_MAX_TOOL_ITERS", 10, 3, 100)
        elif normalized_node_type in ("reviewer", "tester"):
            # v6.4.59 (maintainer 2026-04-23): QA iter cap 50→15. Observed Apr 23
            # 14:45 session: reviewer burned 9 minutes on 12 tool_call
            # rounds across gpt-5.4. Most audits converge in 5-8 rounds;
            # 15 gives headroom but forces commitment. Still overridable
            # via EVERMIND_QA_MAX_TOOL_ITERS.
            value = self._read_int_env("EVERMIND_QA_MAX_TOOL_ITERS", 15, 4, 100)
        elif normalized_node_type == "analyst":
            # v6.1.3 (maintainer 2026-04-19): analyst is a RESEARCH node, not a
            # build node. 2-3 source_fetch rounds then MUST synthesize a
            # final report. Raising to 30 (previous attempt) made it loop
            # for 14+ min without converging. 8 keeps enough headroom for a
            # real multi-repo research while forcing commitment.
            # v6.3 (maintainer 2026-04-20): 8→6. Tutorial-search prompts keep asking
            # for one more source. Observed 10 fetches → hard-ceiling hang.
            # Cap + prompt "pick 3" convergence rule now carry the load.
            value = self._read_int_env("EVERMIND_ANALYST_MAX_TOOL_ITERS", 6, 2, 12)
        elif normalized_node_type == "planner":
            value = self._read_int_env("EVERMIND_PLANNER_MAX_TOOL_ITERS", 20, 1, 60)
        elif normalized_node_type == "merger":
            # v6.7 (maintainer 2026-04-23): 12 → 6. merger.yaml V6.6 spec:
            # MERGE_NOOP default path (1 tool_call: file_ops list, done),
            # or ≤3 SEARCH/REPLACE blocks. Real merges need 2-4 rounds;
            # 6 gives headroom without letting kimi over-explore.
            value = self._read_int_env("EVERMIND_MERGER_MAX_TOOL_ITERS", 6, 2, 40)
        elif normalized_node_type == "patcher":
            # v6.7 (maintainer 2026-04-23): 10 → 5. patcher.yaml V6.6 mandates
            # ≤4 tool calls total (NO PREAMBLE + snapshot-based). Reviewer
            # rejection budget is now 1 (see orchestrator._configured_max_reviewer_rejections),
            # so patcher gets exactly one attempt — tighten round cap to
            # match. Floor 2 keeps headroom for the rare retry.
            value = self._read_int_env("EVERMIND_PATCHER_MAX_TOOL_ITERS", 5, 2, 30)
        elif normalized_node_type == "debugger":
            value = self._read_int_env("EVERMIND_DEBUGGER_MAX_TOOL_ITERS", 15, 3, 40)
        elif normalized_node_type == "deployer":
            # v6.7d (maintainer 2026-04-24): tight deployer cap. Observed
            # run_3f5d8b0ebe1e: deployer ran 10+ tool_calls across 17 min
            # (kimi read every file to "verify"), then hit 603s watchdog
            # and retried — wasted 10 min. deployer.yaml now hard-limits
            # to ≤3 tool calls; this cap is the last-line enforcement.
            value = self._read_int_env("EVERMIND_DEPLOYER_MAX_TOOL_ITERS", 5, 2, 15)
        else:
            value = self._read_int_env("EVERMIND_DEFAULT_MAX_TOOL_ITERS", 40, 1, 100)

        override = self._node_int_override(node, "max_tool_iterations_override", minimum=1, maximum=100)
        if override is not None:
            return override
        # v7.1 Ultra: quadruple cap in long-task mode
        if self._is_ultra_mode():
            value = min(value * self._ultra_iter_multiplier(), 400)
        tuning = self._node_budget_tuning(node_type, node=node)
        return self._delta_budget_int(
            value,
            int(tuning.get("tool_iterations_delta", 0) or 0),
            minimum=1,
            maximum=100,
        )

    def _analyst_browser_call_limit(self, node: Optional[Dict[str, Any]] = None) -> int:
        # v3.0.3: With up to 5 URLs allowed, each URL may need 1-2 browser actions
        # (navigate + observe/extract). Default 8 supports thorough research without
        # artificial stalls. Override via EVERMIND_ANALYST_MAX_BROWSER_CALLS.
        value = self._read_int_env("EVERMIND_ANALYST_MAX_BROWSER_CALLS", 8, 0, 16)
        override = self._node_int_override(node, "browser_call_limit", minimum=0, maximum=16)
        if override is not None:
            return override
        tuning = self._node_budget_tuning("analyst", node=node)
        return self._delta_budget_int(
            value,
            int(tuning.get("browser_call_delta", 0) or 0),
            minimum=0,
            maximum=16,
        )

    def _analyst_source_fetch_call_limit(self, node: Optional[Dict[str, Any]] = None) -> int:
        # v6.3 (maintainer 2026-04-20): independent per-tool cap for source_fetch.
        # v6.6 (maintainer 2026-04-23): cap raised 5→8.
        # v7.27 (maintainer 2026-04-29): on retry, cap drops to 2 — observed
        # run_1e0b49c06d01 analyst spent 18min because it hit cap=8 on the
        # first attempt (~5min), got hard-gated for word-count, then on
        # retry redid 8 more source_fetch (~5min) instead of just expanding
        # the existing brief. v7.0 hard-gate prompt says "do NOT rewrite
        # from scratch" but kimi ignores it. So enforce it controller-side:
        # any retry past attempt 0 caps source_fetch at 2 (allows 1-2
        # quick lookups for missing details, but not full re-research).
        value = self._read_int_env("EVERMIND_ANALYST_MAX_SOURCE_FETCH", 8, 1, 12)
        retry_value = self._read_int_env("EVERMIND_ANALYST_RETRY_SOURCE_FETCH_CAP", 2, 0, 8)
        override = self._node_int_override(node, "source_fetch_call_limit", minimum=1, maximum=12)
        if override is not None:
            return override
        try:
            retry_count = int((node or {}).get("retry_count") or 0)
        except Exception:
            retry_count = 0
        if retry_count >= 1:
            return retry_value
        return value

    def _should_block_browser_call(
        self,
        node_type: str,
        tool_call_stats: Dict[str, int],
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type == "analyst":
            limit = self._analyst_browser_call_limit(node=node)
        elif normalized_node_type == "polisher":
            limit = self._polisher_browser_call_limit(node=node)
        else:
            return False
        if limit < 0:
            return False
        current = int(tool_call_stats.get("browser", 0) or 0)
        return current >= limit

    def _should_block_source_fetch_call(
        self,
        node_type: str,
        tool_call_stats: Dict[str, int],
        node: Optional[Dict[str, Any]] = None,
    ) -> bool:
        # v6.3 (maintainer 2026-04-20): analyst-only source_fetch per-tool cap,
        # mirrors _should_block_browser_call. Pairs with the prompt-side
        # "pick 3, cap at 5" convergence rule so the LLM can't silently
        # ignore it.
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type != "analyst":
            return False
        limit = self._analyst_source_fetch_call_limit(node=node)
        if limit < 0:
            return False
        current = int(tool_call_stats.get("source_fetch", 0) or 0)
        return current >= limit

    def _desktop_qa_browser_suppressed(self, node_type: str, input_data: Any) -> bool:
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type not in ("reviewer", "tester"):
            return False
        text = str(input_data or "")
        if "DESKTOP_QA_BROWSER_SUPPRESSED=1" not in text:
            return False
        return "[Desktop QA Session Evidence]" in text or "desktop Evermind QA Preview Session" in text

    def _qa_default_preview_url(self, node_type: str) -> str:
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type in ("reviewer", "tester"):
            port = str(os.getenv("PORT", "8765") or "8765").strip() or "8765"
            # v6.4.19 (maintainer 2026-04-22): always emit a cache-buster so the
            # reviewer/tester browser bypasses the preview's 5s Cache-Control
            # window (see server.py:1162) AND any stale state left in the
            # Chromium page from a prior node. Without this, reviewer
            # occasionally observed the builder's pre-merger artifact
            # because the merger-written bytes arrived while Chromium was
            # still showing the cached response from <5s earlier.
            # Per-process time.time() is stable within a single navigate
            # call but moves forward between reviewer turns, giving every
            # navigation a fresh URL hash.
            try:
                buster = int(time.time())
            except Exception:
                buster = 0
            return f"http://127.0.0.1:{port}/preview/?t={buster}"
        return ""

    def _apply_qa_browser_tool_defaults(
        self,
        tool_name: str,
        node_type: str,
        params: Dict[str, Any],
    ) -> Dict[str, Any]:
        if not isinstance(params, dict):
            return params
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type not in ("reviewer", "tester"):
            return params
        preview_url = self._qa_default_preview_url(node_type)
        if not preview_url:
            return params

        normalized_tool = str(tool_name or "").strip().lower()
        patched = dict(params)
        if normalized_tool == "browser":
            action = str(patched.get("action") or "navigate").strip().lower() or "navigate"
            if action == "navigate" and not str(patched.get("url") or "").strip():
                patched["url"] = preview_url
            # v6.4.19: if reviewer/tester supplied a preview URL themselves
            # (common in multi-route sites, e.g. /preview/pricing.html),
            # silently append a cache-buster so the browser never reuses a
            # pre-merger cached response. Applies only to our own preview
            # host — external URLs are left untouched.
            elif action == "navigate":
                patched["url"] = self._ensure_preview_cache_buster(str(patched.get("url") or ""))
        elif normalized_tool == "browser_use":
            if not str(patched.get("url") or "").strip():
                patched["url"] = preview_url
            else:
                patched["url"] = self._ensure_preview_cache_buster(str(patched.get("url") or ""))
        return patched

    def _ensure_preview_cache_buster(self, url: str) -> str:
        """v6.4.19 — append `?t=<epoch>` (or `&t=<epoch>`) to any
        http://127.0.0.1:<port>/preview/... URL that doesn't already carry
        a `t=` query key. Leaves non-preview URLs alone."""
        u = str(url or "").strip()
        if not u:
            return u
        if "127.0.0.1" not in u and "localhost" not in u:
            return u
        if "/preview/" not in u and not u.endswith("/preview"):
            return u
        if re.search(r"[?&]t=\d+", u):
            return u
        try:
            buster = int(time.time())
        except Exception:
            buster = 0
        sep = "&" if "?" in u else "?"
        return f"{u}{sep}t={buster}"

    # v5.8.1 quality guardrails — patterns that MUST survive context
    # compression intact. Reviewer verdicts, file paths, JSON blobs, and
    # fenced code are the load-bearing signals downstream nodes depend on.
    # If compression strips them the pipeline silently produces wrong output.
    _PRESERVE_PATTERNS = [
        re.compile(r'```[\s\S]*?```'),                                # fenced code blocks
        re.compile(r'`[^`\n]{1,200}`'),                               # inline code / paths
        re.compile(r'"verdict"\s*:\s*"(?:APPROVED|REJECTED)"'),        # reviewer verdict
        re.compile(r'\{\s*"verdict"[\s\S]*?\}', re.MULTILINE),         # full verdict JSON
        re.compile(r'<verdict>[\s\S]*?</verdict>', re.IGNORECASE),    # XML-tagged verdict
        re.compile(r'[\w/.-]+\.(tsx?|jsx?|py|html?|css|json|yaml|yml|md)\b'),  # file paths
    ]

    def _contains_protected_content(self, text: str) -> bool:
        """True if the text contains content that must NOT be truncated/compressed
        (verdicts, code fences, file paths, structured contracts).  Callers should
        skip aggressive compression when this returns True."""
        if not text or len(text) < 20:
            return False
        for pat in self._PRESERVE_PATTERNS:
            if pat.search(text):
                return True
        return False

    def _truncate_text(self, text: Any, max_chars: int) -> Any:
        if not isinstance(text, str):
            return text
        if max_chars <= 0:
            return ""
        if len(text) <= max_chars:
            return text
        # v5.8.1 guardrail: if the tail of the text contains a protected
        # pattern (e.g. verdict JSON at the end of a reviewer message), we
        # KEEP THE TAIL and truncate from the middle instead of the end.
        # Otherwise reviewer JSON verdicts would get cut off, downstream
        # orchestrator would fail to parse, and we'd soft-ship degraded.
        suffix = "... [TRUNCATED]"
        tail_probe = text[-2000:] if len(text) > 2000 else text
        if self._contains_protected_content(tail_probe):
            # Keep last 2000 chars intact; chop the front.
            keep_tail = min(2000, max_chars // 2)
            front_budget = max_chars - keep_tail - len(suffix)
            if front_budget > 200:
                return text[:front_budget] + suffix + text[-keep_tail:]
        if max_chars <= len(suffix):
            return text[:max_chars]
        return text[: max_chars - len(suffix)] + suffix

    def _safe_json_object(self, value: Any) -> Dict[str, Any]:
        if isinstance(value, dict):
            return value
        if isinstance(value, str):
            try:
                parsed = json.loads(value)
            except Exception:
                return {}
            if isinstance(parsed, dict):
                return parsed
        return {}

    def _compact_tool_arguments_for_replay(self, function_name: str, raw_args: Any) -> Any:
        if not isinstance(raw_args, str):
            return raw_args

        normalized_name = str(function_name or "").strip().lower()
        if normalized_name != "file_ops":
            return self._truncate_text(raw_args, MAX_TOOL_ARGS_REPLAY_CHARS)

        parsed = self._safe_json_object(raw_args)
        action = str(parsed.get("action", "")).strip().lower()
        if not action and '"action"' in raw_args and '"write"' in raw_args.lower():
            action = "write"
        if action != "write":
            return self._truncate_text(raw_args, MAX_TOOL_ARGS_REPLAY_CHARS)

        path = str(parsed.get("path", "")).strip()
        if not path:
            match = re.search(r'"path"\s*:\s*"([^"]+)"', raw_args)
            if match:
                path = str(match.group(1)).strip()

        content = parsed.get("content")
        content_chars = len(content) if isinstance(content, str) else 0
        content_lines = content.count("\n") + 1 if isinstance(content, str) and content else 0
        replay_stub: Dict[str, Any] = {
            "action": "write",
            "path": path,
            # Do not inject placeholder source text back into the model context.
            # Placeholder strings can be mistakenly copied into real file writes.
            "content": "",
            "content_omitted": True,
        }
        if content_chars:
            replay_stub["content_chars"] = content_chars
        if content_lines:
            replay_stub["content_lines"] = content_lines
        return json.dumps(replay_stub, ensure_ascii=False)

    def _tool_result_has_write(self, result: Any) -> bool:
        if not isinstance(result, dict):
            return False
        if bool(result.get("written")):
            return True
        try:
            if result.get("path") and int(result.get("bytes_written", 0) or 0) > 0:
                return True
        except Exception:
            pass
        data = result.get("data")
        if not isinstance(data, dict):
            return False
        if bool(data.get("written")):
            return True
        try:
            if data.get("path") and int(data.get("bytes_written", 0) or 0) > 0:
                return True
        except Exception:
            pass
        return False

    def _tool_result_write_path(self, result: Any) -> str:
        if not isinstance(result, dict):
            return ""
        path = str(result.get("path") or "").strip()
        if path:
            return path
        data = result.get("data")
        if isinstance(data, dict):
            return str(data.get("path") or "").strip()
        return ""

    def _builder_game_delivery_signals(self, text: str) -> Dict[str, bool]:
        blob = str(text or "")
        flags = re.IGNORECASE
        return {
            "runtime_surface": bool(re.search(
                r"<canvas\b|new\s+THREE\.|THREE\.WebGLRenderer|new\s+Phaser\.Game|PIXI\.Application|"
                r"(?:id|class)=['\"][^'\"]*(game|arena|board|playfield|viewport|stage|scene|battlefield)[^'\"]*['\"]",
                blob,
                flags,
            )),
            "start_flow": bool(re.search(
                r"window\.startgame|function\s+startgame|start[-_ ]btn|play[-_ ]btn|"
                r"startoverlay|start[-_ ]screen|startscreen|"
                r"onclick\s*=\s*['\"][^'\"]*(?:startgame|(?:start|begin|launch|play)[A-Za-z0-9_]*\s*\()|"
                r"(?:function|(?:const|let|var))\s+(?:start|begin|launch|play)[A-Za-z0-9_]*\b|"
                r">\s*(?:start(?:\s+game|\s+mission)?|play|begin|launch|开始(?:游戏|任务|战斗)|进入战斗)\s*<|"
                r"showScreen\(['\"](?:start|level-select)",
                blob,
                flags,
            )),
            "game_loop": bool(re.search(
                r"requestanimationframe|setanimationloop|ticker\.add|runrenderloop|gameLoop|renderLoop|updateLoop",
                blob,
                flags,
            )),
        }

    def _builder_html_persist_rejection_reason(
        self,
        html_content: str,
        *,
        input_data: str = "",
        filename: str = "index.html",
    ) -> str:
        html = str(html_content or "").strip()
        if len(html) < 240:
            return f"{filename} is too short to trust as a final artifact"

        lower = html.lower()
        if "<!doctype" not in lower and "<html" not in lower:
            return f"{filename} is missing the HTML document shell"
        if "<body" not in lower:
            return f"{filename} is missing a <body> tag"

        body_match = re.search(r"<body\b[^>]*>(.*?)</body>", html, re.IGNORECASE | re.DOTALL)
        body_fragment = body_match.group(1) if body_match else html
        cleaned = re.sub(r"<head\b.*?</head\s*>", " ", body_fragment, flags=re.IGNORECASE | re.DOTALL)
        cleaned = re.sub(
            r"<(style|script|noscript|template)\b.*?</\1\s*>",
            " ",
            cleaned,
            flags=re.IGNORECASE | re.DOTALL,
        )
        meaningful_tags = re.findall(
            r"<(?:canvas|main|section|article|header|footer|nav|aside|div|form|button|a|img|picture|video|svg|input|textarea|select|label|ul|ol|li|table|blockquote|h[1-6]|p)\b",
            cleaned,
            re.IGNORECASE,
        )
        visible_text = re.sub(r"<[^>]+>", " ", cleaned)
        visible_text = re.sub(r"\s+", " ", visible_text).strip()
        if len(meaningful_tags) == 0 and len(visible_text) < 40:
            return f"{filename} body lacks meaningful visible content"

        try:
            task_type = task_classifier.classify(input_data).task_type
        except Exception:
            task_type = ""

        if task_type == "game":
            signals = self._builder_game_delivery_signals(html)
            missing: List[str] = []
            if not signals.get("runtime_surface"):
                missing.append("gameplay surface")
            if not signals.get("start_flow"):
                missing.append("start/play flow")
            if not signals.get("game_loop"):
                missing.append("runtime loop")
            if missing:
                return f"{filename} still lacks a usable game slice ({', '.join(missing)})"
            continuation_reason = self._builder_game_text_continuation_reason(html, input_data)
            if continuation_reason:
                return f"{filename} is still incomplete for a game deliverable ({continuation_reason})"

        return ""

    def _builder_text_output_has_persistable_html(self, output_text: str, input_data: str = "") -> bool:
        extracted_files = self._extract_html_files_from_text_output(str(output_text or ""), input_data)
        for filename, html_content in extracted_files.items():
            if not self._builder_html_persist_rejection_reason(
                html_content,
                input_data=input_data,
                filename=filename,
            ):
                return True
        return False

    def _builder_output_looks_like_tool_planning_prose(self, output_text: str, input_data: str = "") -> bool:
        text = str(output_text or "").strip()
        if not text or self._builder_text_output_has_persistable_html(text, input_data):
            return False
        planning_markers = (
            r"\b(?:i(?:'ll| will)\s+first|let\s+me\s+first|let\s+me\s+check|let\s+me\s+inspect|"
            r"i(?:'ll| will)\s+inspect|i(?:'ll| will)\s+read|understand\s+the\s+existing|"
            r"check\s+the\s+existing\s+files|improve\s+it\s+in\s+place)\b"
        )
        tool_read_markers = (
            r"\bfile_ops\s+(?:read|list)\b|"
            r'"action"\s*:\s*"(?:read|list)"|'
            r'"file_path"\s*:\s*"[^"]+"|'
            r'"path"\s*:\s*"[^"]+"'
        )
        return bool(
            re.search(planning_markers, text, re.IGNORECASE)
            and re.search(tool_read_markers, text, re.IGNORECASE)
        )

    def _builder_non_deliverable_output_reason(self, output_text: str, input_data: str = "") -> str:
        text = str(output_text or "").strip()
        if not text:
            return "Builder returned empty content instead of a final HTML deliverable."
        if self._builder_text_output_has_persistable_html(text, input_data):
            return ""
        if self._builder_output_looks_like_tool_planning_prose(text, input_data):
            return "Builder returned tool-planning prose instead of a persistable HTML deliverable."
        return (
            "Builder returned non-deliverable text instead of persistable HTML. "
            "Repair/retry responses must emit final HTML, not process narration."
        )

    async def _finalize_builder_chat_output(
        self,
        *,
        output_text: str,
        input_data: str,
        node: Optional[Dict[str, Any]] = None,
        tool_results: Optional[List[Dict[str, Any]]] = None,
        tool_call_stats: Optional[Dict[str, int]] = None,
        on_progress=None,
    ) -> tuple[List[str], List[Dict[str, Any]], Dict[str, int], str]:
        results = list(tool_results or [])
        stats = dict(tool_call_stats or {})
        saved_paths = await self._auto_save_builder_text_output(
            output_text=output_text,
            input_data=input_data,
            node=node,
            tool_results=results,
            tool_call_stats=stats,
            on_progress=on_progress,
        )
        if saved_paths:
            assigned_targets = (
                self._builder_allowed_html_targets_from_node(node)
                if normalize_node_role(str((node or {}).get("type") or "").strip()) == "builder"
                else []
            )
            if not assigned_targets:
                assigned_targets = self._builder_assigned_html_targets(input_data)
            missing_targets = self._builder_missing_html_targets(input_data, output_text)
            if (
                len(assigned_targets) >= 2
                and "index.html" in assigned_targets
                and "index.html" in missing_targets
            ):
                return (
                    saved_paths,
                    results,
                    stats,
                    "Builder saved secondary pages but still missed the required root index.html. "
                    + "Missing assigned pages: "
                    + ", ".join(missing_targets[:8])
                    + ".",
                )
            return saved_paths, results, stats, ""

        failure_msg = self._builder_non_deliverable_output_reason(output_text, input_data)
        if not failure_msg and self._builder_text_output_has_persistable_html(output_text, input_data):
            failure_msg = (
                "Builder produced persistable HTML text but it could not be saved to disk. "
                "Emit named HTML blocks that match the assigned targets, or save the file explicitly."
            )
        return [], results, stats, failure_msg

    async def _auto_save_builder_text_output(
        self,
        *,
        output_text: str,
        input_data: str,
        node: Optional[Dict[str, Any]] = None,
        tool_results: List[Dict[str, Any]],
        tool_call_stats: Optional[Dict[str, int]] = None,
        on_progress=None,
    ) -> List[str]:
        text = str(output_text or "")
        if len(text) <= 120:
            return []
        normalized_node_type = normalize_node_role(str((node or {}).get("type") or "").strip())
        builder_node = normalized_node_type == "builder"
        peer_staging_output_dir = (
            self._builder_peer_staging_output_dir_from_node(node)
            if builder_node
            else ""
        )
        extracted_files = self._extract_html_files_from_text_output(text, input_data)
        if not extracted_files and builder_node and peer_staging_output_dir:
            stripped = text.strip()
            lower = stripped.lower()
            html_start = -1
            for marker in ("<!doctype", "<!DOCTYPE", "<html", "<HTML"):
                pos = stripped.find(marker)
                if pos >= 0 and (html_start < 0 or pos < html_start):
                    html_start = pos
            if html_start >= 0:
                html_end = stripped.lower().rfind("</html>")
                candidate = stripped[html_start : html_end + 7] if html_end > html_start else stripped[html_start:]
                normalized = self._normalize_builder_text_html(
                    candidate,
                    filename="index.html",
                    input_data=input_data,
                )
                if normalized and len(normalized) >= 120 and ("<html" in lower or "<!doctype" in lower):
                    extracted_files = {"index.html": normalized}
        if not extracted_files:
            return []

        existing_paths = {
            self._tool_result_write_path(item)
            for item in (tool_results or [])
            if self._tool_result_has_write(item)
        }
        output_dir = self._current_output_dir()
        saved_paths: List[str] = []
        allowed_targets = (
            self._builder_allowed_html_targets_from_node(node)
            if builder_node
            else []
        )
        allowed_targets_set = {str(item or "").strip().lower() for item in allowed_targets if str(item or "").strip()}
        can_write_root_raw = (node or {}).get("can_write_root_index")
        if can_write_root_raw is None:
            can_write_root_raw = (node or {}).get("file_ops_can_write_root_index")
        can_write_root_index = True if can_write_root_raw is None else bool(can_write_root_raw)
        if bool((node or {}).get("builder_merger_like")):
            can_write_root_index = True
        support_lane_node = self._builder_is_support_lane_node(node) if builder_node else False
        stage_root_index_only = self._builder_stage_root_index_only_node(node) if builder_node else False
        staging_output_dir = self._builder_staging_output_dir_from_node(node) if builder_node else ""

        for filename, html_content in extracted_files.items():
            if len(html_content) < 120:
                continue
            filename = Path(str(filename or "").strip()).name
            filename_lower = filename.lower()
            if builder_node:
                if support_lane_node and filename_lower == "index.html":
                    logger.info(
                        "Skipping builder text-mode HTML auto-save for %s: support-lane builder cannot write root index.html",
                        filename,
                    )
                    continue
                if allowed_targets_set and filename_lower not in allowed_targets_set:
                    logger.info(
                        "Skipping builder text-mode HTML auto-save for %s: filename not owned by this builder lane (allowed=%s)",
                        filename,
                        sorted(allowed_targets_set),
                    )
                    continue
                if filename_lower == "index.html" and not can_write_root_index and "index.html" not in allowed_targets_set:
                    if not peer_staging_output_dir:
                        logger.info(
                            "Skipping builder text-mode HTML auto-save for %s: root index ownership is disabled for this lane",
                            filename,
                        )
                        continue
            rejection_reason = self._builder_html_persist_rejection_reason(
                html_content,
                input_data=input_data,
                filename=filename,
            )
            if rejection_reason:
                logger.info(
                    "Skipping builder text-mode HTML auto-save for %s: %s",
                    filename,
                    rejection_reason,
                )
                continue
            try:
                target_root = Path(output_dir)
                if stage_root_index_only and filename_lower == "index.html" and staging_output_dir:
                    target_root = Path(staging_output_dir)
                elif filename_lower == "index.html" and peer_staging_output_dir:
                    target_root = Path(peer_staging_output_dir)
                target_path = target_root / filename
                target_path.parent.mkdir(parents=True, exist_ok=True)
                target_path.write_text(html_content, encoding="utf-8")
                normalized_path = str(target_path)
                saved_paths.append(normalized_path)
                if normalized_path not in existing_paths:
                    tool_results.append({
                        "tool": "file_ops",
                        "success": True,
                        "written": True,
                        "path": normalized_path,
                        "started_at": time.time(),
                        "duration_ms": 0,
                        "args": {"action": "write", "path": normalized_path},
                        "data": {
                            "path": normalized_path,
                            "bytes_written": len(html_content.encode("utf-8")),
                            "written": True,
                        },
                        "error": None,
                        "artifacts": [normalized_path],
                    })
                    existing_paths.add(normalized_path)
                if on_progress:
                    metrics = self._written_file_code_metrics(normalized_path)
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "builder_write",
                        "plugin": "text_output_auto_save",
                        "path": normalized_path,
                        **metrics,
                    })
                logger.info(
                    "Auto-saved builder text-mode HTML: %s (%s chars)",
                    filename,
                    len(html_content),
                )
            except Exception as save_exc:
                logger.warning(
                    "Failed to auto-save builder text-mode HTML %s: %s",
                    filename,
                    str(save_exc)[:200],
                )

        if saved_paths and tool_call_stats is not None:
            tool_call_stats["file_ops"] = tool_call_stats.get("file_ops", 0) + len(saved_paths)
            logger.info(
                "Builder text-mode auto-save complete: %s files written to %s",
                len(saved_paths),
                output_dir,
            )
        return saved_paths

    def _infer_file_ops_action(self, raw_args: Any, result: Any) -> str:
        """
        Infer file_ops action robustly even when tool args are malformed/non-JSON.
        """
        parsed = self._safe_json_object(raw_args)
        action = str(parsed.get("action", "")).strip().lower()
        if action:
            return action

        if isinstance(raw_args, str):
            m = re.search(r'"action"\s*:\s*"([a-zA-Z_]+)"', raw_args)
            if m:
                return str(m.group(1)).strip().lower()

        if self._tool_result_has_write(result):
            return "write"
        if isinstance(result, dict):
            data = result.get("data")
            if isinstance(data, dict):
                if "entries" in data:
                    return "list"
                if "content" in data:
                    return "read"
                if "deleted" in data:
                    return "delete"
        return ""

    def _builder_needs_forced_text(self, node_type: str, output_text: str, tool_results: List[Dict[str, Any]]) -> bool:
        if node_type != "builder":
            return False
        lower = (output_text or "").lower()
        has_html = "<!doctype" in lower or "<html" in lower
        has_file_write = any(self._tool_result_has_write(tr) for tr in (tool_results or []))
        return (not has_html) and (not has_file_write)

    def _current_output_dir(self) -> str:
        current = str((self.config or {}).get("output_dir") or "").strip()
        return current or "/tmp/evermind_output"

    def _current_scratchpad_dir(self) -> str:
        output_dir = Path(self._current_output_dir().rstrip("/") or "/tmp/evermind_output")
        return str(output_dir.parent / "_evermind_scratch")

    def _builder_allowed_html_targets_from_node(self, node: Optional[Dict[str, Any]]) -> List[str]:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return []
        raw_targets = (
            (node or {}).get("allowed_html_targets")
            or (node or {}).get("file_ops_allowed_html_targets")
            or []
        )
        if isinstance(raw_targets, str):
            raw_targets = [raw_targets]
        targets: List[str] = []
        seen: set[str] = set()
        for raw_name in raw_targets or []:
            name = Path(str(raw_name or "").strip()).name
            if not name or name in seen:
                continue
            if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._-]*\.html?", name, re.IGNORECASE):
                continue
            seen.add(name)
            targets.append(name)
        return targets

    def _builder_is_support_lane_node(self, node: Optional[Dict[str, Any]]) -> bool:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return False
        if bool((node or {}).get("builder_merger_like")):
            return False
        explicit = (node or {}).get("builder_is_support_lane_node")
        if explicit is not None:
            return bool(explicit)
        support_targets = (node or {}).get("builder_support_targets")
        if isinstance(support_targets, (list, tuple, set)):
            return any(str(item or "").strip() for item in support_targets)
        return False

    def _builder_stage_root_index_only_node(self, node: Optional[Dict[str, Any]]) -> bool:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return False
        return bool((node or {}).get("builder_stage_root_index_only"))

    def _builder_staging_output_dir_from_node(self, node: Optional[Dict[str, Any]]) -> str:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return ""
        return str((node or {}).get("builder_staging_output_dir") or "").strip()

    def _builder_peer_staging_output_dir_from_node(self, node: Optional[Dict[str, Any]]) -> str:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return ""
        explicit = self._builder_staging_output_dir_from_node(node)
        if explicit:
            return explicit
        if self._builder_is_support_lane_node(node) or bool((node or {}).get("builder_merger_like")):
            return ""
        if (node or {}).get("can_write_root_index") is not False:
            return ""
        if self._builder_allowed_html_targets_from_node(node):
            return ""
        subtask_id = str((node or {}).get("subtask_id") or (node or {}).get("task_id") or "").strip()
        if not subtask_id:
            return ""
        output_root = str((node or {}).get("output_dir") or self._current_output_dir()).strip() or "/tmp/evermind_output"
        return str(Path(output_root) / f"task_{subtask_id}")

    def _builder_support_snapshot_payload(self, path: Path) -> Optional[Dict[str, Any]]:
        suffix = path.suffix.lower()
        if suffix not in {".js", ".mjs", ".css", ".json"}:
            return None
        if not path.exists() or not path.is_file():
            return None
        try:
            text = path.read_text(encoding="utf-8", errors="ignore")
            size = int(path.stat().st_size)
        except Exception:
            return None
        compact = len(re.sub(r"\s+", "", text))
        if suffix == ".json":
            min_chars = 8
        elif suffix == ".css":
            min_chars = 40
        else:
            min_chars = 64
        if size <= 0 or compact < min_chars:
            return None
        return {
            "content": text,
            "size": size,
        }

    def _builder_output_root_for_node(self, node: Optional[Dict[str, Any]]) -> Path:
        output_root = Path(str((node or {}).get("output_dir") or self._current_output_dir()).strip() or "/tmp/evermind_output")
        try:
            return output_root.resolve()
        except Exception:
            return output_root

    def _builder_resolved_output_path(self, node: Optional[Dict[str, Any]], raw_path: str) -> Optional[Path]:
        path_text = str(raw_path or "").strip()
        if not path_text:
            return None
        output_root = self._builder_output_root_for_node(node)
        target_path = Path(path_text)
        if not target_path.is_absolute():
            target_path = output_root / target_path
        try:
            target_path = target_path.resolve()
        except Exception:
            target_path = target_path
        try:
            target_path.relative_to(output_root)
        except Exception:
            return None
        return target_path

    def _builder_prewrite_snapshot_payload(
        self,
        path: Path,
        *,
        input_data: str = "",
    ) -> Optional[Dict[str, Any]]:
        suffix = path.suffix.lower()
        if suffix in {".js", ".mjs", ".css", ".json"}:
            return self._builder_support_snapshot_payload(path)
        if suffix not in {".html", ".htm"}:
            return None
        if not path.exists() or not path.is_file():
            return None
        try:
            text = path.read_text(encoding="utf-8", errors="ignore")
            size = int(path.stat().st_size)
        except Exception:
            return None
        if size <= 0 or not text.strip():
            return None
        rejection_reason = self._builder_html_write_rejection_reason(
            text,
            input_data=input_data,
            filename=path.name,
        )
        if rejection_reason:
            return None
        return {
            "content": text,
            "size": size,
        }

    def _builder_capture_prewrite_snapshot(
        self,
        *,
        node: Optional[Dict[str, Any]],
        input_data: str,
        tool_action: str,
        parsed_args: Dict[str, Any],
        snapshot_cache: Dict[str, Dict[str, Any]],
    ) -> None:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return
        if str(tool_action or "").strip().lower() != "write":
            return
        raw_path = (
            str(parsed_args.get("path") or "").strip()
            or str(parsed_args.get("file_path") or "").strip()
        )
        target_path = self._builder_resolved_output_path(node, raw_path)
        if not target_path:
            return
        snapshot_payload = self._builder_prewrite_snapshot_payload(
            target_path,
            input_data=input_data,
        )
        if snapshot_payload:
            snapshot_cache[str(target_path)] = snapshot_payload

    def _builder_html_write_rejection_reason(
        self,
        html_content: str,
        *,
        input_data: str = "",
        filename: str = "index.html",
    ) -> str:
        rejection_reason = self._builder_html_persist_rejection_reason(
            html_content,
            input_data=input_data,
            filename=filename,
        )
        if not rejection_reason:
            return ""

        try:
            task_type = task_classifier.classify(input_data).task_type
        except Exception:
            task_type = ""
        if task_type != "game":
            return rejection_reason

        html = str(html_content or "")
        lower = html.lower()
        html_bytes = len(html.encode("utf-8"))
        signals = self._builder_game_delivery_signals(html)
        local_script_ref = bool(re.search(
            r"<script\b[^>]*\bsrc\s*=\s*['\"](?!https?:|//|data:)[^'\"]+\.(?:js|mjs)(?:\?[^'\"]*)?['\"]",
            lower,
            re.IGNORECASE,
        ))
        marketing_stub = bool(re.search(
            r"(studio home|about studio|brand storytelling|interactive campaigns|premium brands|launch systems|crafted campaigns)",
            lower,
            re.IGNORECASE,
        ))

        if (
            ("still lacks a usable game slice" in rejection_reason or "incomplete for a game deliverable" in rejection_reason)
            and local_script_ref
            and (signals.get("runtime_surface") or signals.get("start_flow") or html_bytes >= 900)
            and not marketing_stub
        ):
            return ""

        if marketing_stub and html_bytes < 4000:
            return rejection_reason

        if html_bytes < 1200 and not local_script_ref:
            return rejection_reason

        if not signals.get("runtime_surface") and not signals.get("start_flow") and not local_script_ref:
            return rejection_reason

        return ""

    def _builder_guard_support_lane_write_result(
        self,
        *,
        node: Optional[Dict[str, Any]],
        tool_action: str,
        result: Any,
        snapshot_cache: Dict[str, Dict[str, Any]],
    ) -> Any:
        if tool_action != "write" or not isinstance(result, dict):
            return result
        if not bool(result.get("success")) or not self._builder_is_support_lane_node(node):
            return result

        data = result.get("data") if isinstance(result.get("data"), dict) else {}
        raw_path = str(data.get("path") or result.get("path") or "").strip()
        if not raw_path:
            return result

        target_path = self._builder_resolved_output_path(node, raw_path)
        if not target_path:
            return result
        is_support_lane = self._builder_is_support_lane_node(node) or (
            target_path.suffix.lower() not in {".html", ".htm"}
            and (node or {}).get("can_write_root_index") is False
            and not self._builder_allowed_html_targets_from_node(node)
        )
        if not is_support_lane:
            return result
        if target_path.name == "index.html":
            return result

        snapshot_key = str(target_path)
        snapshot_payload = self._builder_support_snapshot_payload(target_path)
        if snapshot_payload:
            snapshot_cache[snapshot_key] = snapshot_payload
            return result

        cached = snapshot_cache.get(snapshot_key)
        if not cached:
            return result

        restored_text = str(cached.get("content") or "")
        if not restored_text.strip():
            return result
        try:
            target_path.parent.mkdir(parents=True, exist_ok=True)
            target_path.write_text(restored_text, encoding="utf-8")
            restored_size = int(target_path.stat().st_size)
        except Exception:
            return result

        snapshot_cache[snapshot_key] = {
            "content": restored_text,
            "size": restored_size,
        }
        if isinstance(result.get("data"), dict):
            result["data"]["path"] = str(target_path)
            result["data"]["written"] = True
            result["data"]["size"] = restored_size
            result["data"]["restored_meaningful_snapshot"] = True
        else:
            result["path"] = str(target_path)
            result["written"] = True
            result["size"] = restored_size
        result["restored_meaningful_snapshot"] = True
        result["warning"] = (
            "Support-lane file_ops write would have truncated a meaningful support artifact; "
            "restored the latest non-empty snapshot instead."
        )
        return result

    def _builder_guard_html_write_result(
        self,
        *,
        node: Optional[Dict[str, Any]],
        input_data: str,
        tool_action: str,
        result: Any,
        snapshot_cache: Dict[str, Dict[str, Any]],
    ) -> Any:
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return result
        if str(tool_action or "").strip().lower() != "write" or not isinstance(result, dict):
            return result
        if not bool(result.get("success")):
            return result
        if not self._tool_result_has_write(result):
            return result

        data = result.get("data") if isinstance(result.get("data"), dict) else {}
        raw_path = str(data.get("path") or result.get("path") or "").strip()
        target_path = self._builder_resolved_output_path(node, raw_path)
        if not target_path or target_path.suffix.lower() not in {".html", ".htm"}:
            return result
        if not target_path.exists() or not target_path.is_file():
            return result

        try:
            html = target_path.read_text(encoding="utf-8", errors="ignore")
        except Exception:
            return result

        rejection_reason = self._builder_html_write_rejection_reason(
            html,
            input_data=input_data,
            filename=target_path.name,
        )
        if not rejection_reason:
            snapshot_cache[str(target_path)] = {
                "content": html,
                "size": len(html.encode("utf-8")),
            }
            return result

        cache_key = str(target_path)
        cached = snapshot_cache.get(cache_key) or {}
        restored_snapshot = False
        removed_rejected_file = False
        restored_size = 0
        restored_text = str(cached.get("content") or "")
        if restored_text.strip():
            try:
                target_path.parent.mkdir(parents=True, exist_ok=True)
                target_path.write_text(restored_text, encoding="utf-8")
                restored_size = int(target_path.stat().st_size)
                snapshot_cache[cache_key] = {
                    "content": restored_text,
                    "size": restored_size,
                }
                restored_snapshot = True
            except Exception:
                restored_snapshot = False
        if not restored_snapshot:
            try:
                target_path.unlink(missing_ok=True)
                removed_rejected_file = True
            except Exception:
                removed_rejected_file = False

        error = f"Shipped HTML write rejected: {rejection_reason}."
        if restored_snapshot:
            error += " Restored the last accepted snapshot instead of keeping contamination."
        elif removed_rejected_file:
            error += " Removed the rejected HTML file so it cannot contaminate downstream nodes."
        else:
            error += " Overwrite the same assigned file immediately with a valid artifact."

        result["success"] = False
        result["written"] = False
        result["error"] = error
        result["rejected_html_write"] = True
        result["html_rejection_reason"] = rejection_reason
        if isinstance(result.get("data"), dict):
            result["data"]["written"] = False
            result["data"]["rejected_html_write"] = True
            result["data"]["html_rejection_reason"] = rejection_reason
            result["data"]["restored_meaningful_snapshot"] = restored_snapshot
            result["data"]["removed_rejected_file"] = removed_rejected_file
            result["data"]["size"] = restored_size if restored_snapshot else 0
        logger.warning(
            "Rejected builder HTML write for %s: %s (restored=%s removed=%s)",
            target_path.name,
            rejection_reason,
            restored_snapshot,
            removed_rejected_file,
        )
        return result

    def _apply_runtime_node_contracts(self, node: Optional[Dict[str, Any]], input_data: str) -> str:
        text = str(input_data or "")
        if normalize_node_role(str((node or {}).get("type") or "").strip()) != "builder":
            return text

        allowed_targets = self._builder_allowed_html_targets_from_node(node)
        stage_root_index_only = self._builder_stage_root_index_only_node(node)
        staging_output_dir = self._builder_staging_output_dir_from_node(node)
        if not allowed_targets:
            if self._builder_is_support_lane_node(node) or self._builder_is_support_lane(text):
                contract = "\n".join(
                    [
                        "[BUILDER RUNTIME SUPPORT CONTRACT]",
                        "This builder is a support lane for the current run.",
                        "Do NOT emit or overwrite /tmp/evermind_output/index.html in this run.",
                        "Write browser-native support artifacts only under /tmp/evermind_output/, such as /tmp/evermind_output/js/weaponSystem.js, /tmp/evermind_output/css/hud.css, or /tmp/evermind_output/data/encounters.json.",
                        "Support JS must be browser-native and must not use CommonJS exports or require(...).",
                    ]
                )
                if contract not in text:
                    return f"{text.rstrip()}\n\n{contract}".strip()
            peer_staging_output_dir = self._builder_peer_staging_output_dir_from_node(node)
            if peer_staging_output_dir:
                contract = "\n".join(
                    [
                        "[BUILDER PEER STAGING CONTRACT]",
                        "This builder is a parallel peer lane for the current run.",
                        "The upstream task text may describe the FULL site-wide deliverable, but in THIS pass you must output only one merger-ready HTML artifact.",
                        "Do NOT attempt multi-file file_ops delivery in this lane, and do NOT emit multiple HTML filenames here.",
                        f"Return exactly ONE complete HTML document from <!DOCTYPE html> to </html>. The runtime will stage your raw response to {peer_staging_output_dir}/index.html for merger.",
                        "Do NOT emit prose, markdown fences, or planning narration before the DOCTYPE.",
                    ]
                )
                if contract not in text:
                    return f"{text.rstrip()}\n\n{contract}".strip()
            return text

        if stage_root_index_only and "index.html" in allowed_targets and staging_output_dir:
            staging_contract = "\n".join(
                [
                    "[BUILDER ROOT STAGING CONTRACT]",
                    "This builder owns the primary root shell for an upstream parallel pass, but the live preview must wait for merger.",
                    f"Do NOT overwrite the live root artifact at {self._current_output_dir().rstrip('/')}/index.html in this pass.",
                    f"Write or patch your full root-shell files under {staging_output_dir}/ instead, with {staging_output_dir}/index.html as the staged entry.",
                    "Merger will publish the final live root only after all parallel builder lanes finish.",
                ]
            )
            if staging_contract not in text:
                text = f"{text.rstrip()}\n\n{staging_contract}".strip()

        existing_targets = self._builder_assigned_html_targets(text)
        if existing_targets == allowed_targets:
            return text

        contract_lines = [
            "[BUILDER RUNTIME TARGET CONTRACT]",
            f"{BUILDER_TARGET_OVERRIDE_MARKER} {', '.join(allowed_targets)}",
            "Assigned HTML filenames for this builder: " + ", ".join(allowed_targets) + ".",
        ]
        if len(allowed_targets) >= 2:
            contract_lines.append("Shared asset filenames for this run: styles.css, app.js.")
        if not bool((node or {}).get("can_write_root_index")) and "index.html" not in allowed_targets:
            contract_lines.append("Do NOT emit index.html or any unassigned HTML filename in this run.")
        contract = "\n".join(contract_lines)
        if contract in text:
            return text
        return f"{text.rstrip()}\n\n{contract}".strip()

    def _builder_is_support_lane(self, input_data: str) -> bool:
        text = str(input_data or "").strip().lower()
        if not text:
            return False
        markers = (
            "support subsystem",
            "support lane",
            "support artifacts only",
            "support js/css/json modules",
            "do not overwrite /tmp/evermind_output/index.html",
            "browser-native support artifacts",
        )
        return any(marker in text for marker in markers)

    def _builder_support_lane_targets(self, input_data: str) -> List[str]:
        text = str(input_data or "")
        targets: List[str] = []

        def _add(raw_name: str) -> None:
            raw = str(raw_name or "").strip().strip("\"'`")
            if not raw:
                return
            cleaned = raw.replace("\\", "/").lstrip("/")
            if cleaned.startswith("tmp/evermind_output/"):
                cleaned = cleaned[len("tmp/evermind_output/") :]
            elif cleaned.startswith("/tmp/evermind_output/"):
                cleaned = cleaned[len("/tmp/evermind_output/") :]
            parts = [part for part in cleaned.split("/") if part not in ("", ".", "..")]
            if not parts:
                return
            suffix = Path(parts[-1]).suffix.lower()
            if suffix not in {".js", ".mjs", ".css", ".json"}:
                return
            candidate = "/".join(parts)
            if candidate not in targets:
                targets.append(candidate)

        for match in re.findall(r"([A-Za-z0-9_./-]+\.(?:js|mjs|css|json))", text, re.IGNORECASE):
            _add(match)

        if targets:
            return targets[:8]

        try:
            task_type = task_classifier.classify(text).task_type
        except Exception:
            task_type = ""

        fallback = (
            [
                "js/weaponSystem.js",
                "js/enemyAI.js",
                "js/effectsManager.js",
                "js/hudController.js",
                "css/hud.css",
                "assets/manifest.json",
            ]
            if task_type == "game"
            else [
                "js/support.js",
                "css/support.css",
                "data/support.json",
            ]
        )
        return fallback

    def _builder_support_lane_write_prompt(
        self,
        input_data: str,
        *,
        opener: str,
        note: str = "",
    ) -> str:
        output_dir = self._current_output_dir().rstrip("/")
        targets = self._builder_support_lane_targets(input_data)
        absolute_targets = ", ".join(f"{output_dir}/{name}" for name in targets[:6])
        first_target = f"{output_dir}/{targets[0]}" if targets else f"{output_dir}/js/support.js"
        note_line = f"{note.strip()} " if str(note or "").strip() else ""
        return (
            f"{opener} "
            f"{note_line}"
            "This builder lane owns browser-native JS/CSS/JSON support artifacts, not the shipped root HTML. "
            f"Do NOT write or overwrite {output_dir}/index.html in this lane. "
            f"Your VERY NEXT response must be one or more file_ops write calls that create or patch non-empty support files under {output_dir}/, for example: {absolute_targets}. "
            "Patch existing support modules in place when they already exist, preserve browser-facing APIs/symbols when possible, "
            "and never replace a meaningful support file with an empty stub. "
            f"If you need a concrete first target, start with {first_target}. "
            "Do not return prose before the file writes are saved."
        )

    def _builder_assigned_html_targets(self, input_data: str) -> List[str]:
        text = str(input_data or "")
        targets: List[str] = []

        def _add(raw_name: str) -> None:
            name = Path(str(raw_name or "").strip()).name
            if not name:
                return
            if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._-]*\.html?", name, re.IGNORECASE):
                return
            if name.lower().startswith("index_part"):
                return
            if name not in targets:
                targets.append(name)

        override_targets: List[str] = []
        for block in re.findall(
            r"html target override(?:[^\n:]*)?:\s*([^\n]+)",
            text,
            re.IGNORECASE,
        ):
            for match in re.findall(r"([A-Za-z0-9][A-Za-z0-9._/-]*\.html?)", block, re.IGNORECASE):
                name = Path(str(match or "").strip()).name
                if name and name not in override_targets:
                    override_targets.append(name)
        if override_targets:
            return override_targets

        positive_index_patterns = [
            r"must create\s+/tmp/evermind_output/index\.html",
            r"save to\s+/tmp/evermind_output/index\.html\s+via file_ops write",
            r"save final html via file_ops write to\s+/tmp/evermind_output/index\.html",
        ]
        if any(re.search(pattern, text, re.IGNORECASE) for pattern in positive_index_patterns):
            _add("index.html")

        for block in re.findall(
            r"fallback set(?:[^\n:]*)?:\s*([^\n]+)",
            text,
            re.IGNORECASE,
        ):
            for match in re.findall(r"([A-Za-z0-9][A-Za-z0-9._/-]*\.html?)", block, re.IGNORECASE):
                _add(match)

        for block in re.findall(
            r"assigned html filenames?(?:[^\n:]*)?:\s*([^\n]+)",
            text,
            re.IGNORECASE,
        ):
            for match in re.findall(r"([A-Za-z0-9][A-Za-z0-9._/-]*\.html?)", block, re.IGNORECASE):
                _add(match)

        for match in re.findall(r"for example\s+([A-Za-z0-9][A-Za-z0-9._/-]*\.html?)", text, re.IGNORECASE):
            _add(match)

        return targets

    def _builder_effective_multifile_target_count(self, input_data: str) -> int:
        assigned_targets = len(self._builder_assigned_html_targets(input_data))
        if assigned_targets > 0:
            return max(1, assigned_targets)
        try:
            requested_pages = task_classifier.requested_page_count(str(input_data or ""))
        except Exception:
            requested_pages = 0
        return max(1, requested_pages)

    def _builder_direct_multifile_budget(self, input_data: str, *, max_tokens: int, timeout_sec: int) -> tuple[int, int]:
        text = str(input_data or "")
        assigned_targets = len(self._builder_assigned_html_targets(text))
        try:
            wants_multi_page = task_classifier.wants_multi_page(text)
        except Exception:
            wants_multi_page = False
        retryish_single_target = (
            assigned_targets == 1
            and not wants_multi_page
            and any(
                marker in text.lower()
                for marker in (
                    "retry 1/",
                    "retry 2/",
                    "retry 3/",
                    "previous attempt failed",
                    "previous attempt timed out",
                    "quality gate failed",
                    "pitch appears inverted",
                    "yaw appears mirrored",
                )
            )
        )
        if retryish_single_target:
            boosted_tokens = max(
                max_tokens,
                self._read_int_env(
                    "EVERMIND_BUILDER_SINGLE_FILE_REPAIR_MAX_TOKENS",
                    49152,
                    16384,
                    65536,
                ),
            )
            return boosted_tokens, timeout_sec
        if not wants_multi_page and assigned_targets < 3:
            return max_tokens, timeout_sec

        requested_pages = self._builder_effective_multifile_target_count(text)
        boosted_tokens = max_tokens
        boosted_timeout = timeout_sec

        if requested_pages >= 6:
            boosted_tokens = max(
                boosted_tokens,
                self._read_int_env(
                    "EVERMIND_BUILDER_DIRECT_MULTIFILE_LARGE_MAX_TOKENS",
                    14336,
                    4096,
                    16384,
                ),
            )
            boosted_timeout = max(
                boosted_timeout,
                self._read_int_env(
                    "EVERMIND_BUILDER_DIRECT_MULTIFILE_LARGE_TIMEOUT_SEC",
                    420,
                    180,
                    720,
                ),
            )
        elif requested_pages >= 3:
            # v6.4.12 (maintainer 2026-04-22): raise default tokens 12288 → 24576.
            # Observation 2026-04-22 15:00:
            #   - gpt-5.4 per-page HTML ≈ 25 KB = ~6300 tokens → 4 pages = 25K
            #   - kimi     per-page HTML ≈ 14.5 KB = ~3600 tokens → 4 pages = 14K
            # Old 12288 cap couldn't fit a 4-page batch for gpt-5.4, forcing
            # a 2+2 split that cost an extra 5-min streaming round. 24576
            # fits the gpt-5.4 4-page worst case with headroom, and kimi is
            # well under. Hard cap raised to 32768 for 8-page single-pass.
            boosted_tokens = max(
                boosted_tokens,
                self._read_int_env(
                    "EVERMIND_BUILDER_DIRECT_MULTIFILE_MAX_TOKENS",
                    24576,
                    4096,
                    32768,
                ),
            )
            boosted_timeout = max(
                boosted_timeout,
                self._read_int_env(
                    "EVERMIND_BUILDER_DIRECT_MULTIFILE_TIMEOUT_SEC",
                    480,
                    120,
                    900,
                ),
            )

        # v6.4.12: raise final cap 16384 → 32768 so env override can really
        # push past the old ceiling on big builds (8+ page sites, single
        # streaming pass).
        builder_timeout_cap = max(self._timeout_for_node("builder"), timeout_sec)
        return min(boosted_tokens, 32768), min(boosted_timeout, builder_timeout_cap)

    def _builder_direct_multifile_initial_batch_size(self, input_data: str) -> int:
        text = str(input_data or "")
        requested_pages = self._builder_effective_multifile_target_count(text)
        if requested_pages >= 6:
            return self._read_int_env(
                "EVERMIND_BUILDER_DIRECT_MULTIFILE_LARGE_INITIAL_BATCH_SIZE",
                1,
                1,
                2,
            )
        if requested_pages >= 3:
            # v6.4.12 (maintainer 2026-04-22): default 2 → 4 for 3-5 page builders.
            # With `DIRECT_MULTIFILE_MAX_TOKENS` raised to 16384, a single
            # streaming call fits all 4 target pages for gpt-5.4 / kimi. The
            # previous default 2 meant gpt-5.4 had to do two sequential
            # 5-minute calls (49KB each) = 10+ min total. 4 pages in one
            # stream completes in ~5-6 min (single setup cost amortised).
            return self._read_int_env(
                "EVERMIND_BUILDER_DIRECT_MULTIFILE_INITIAL_BATCH_SIZE",
                4,
                1,
                4,
            )
        return max(1, min(4, requested_pages))

    def _builder_direct_multifile_batch_size(self, input_data: str) -> int:
        text = str(input_data or "")
        requested_pages = self._builder_effective_multifile_target_count(text)
        if requested_pages >= 6:
            return self._read_int_env(
                "EVERMIND_BUILDER_DIRECT_MULTIFILE_LARGE_BATCH_SIZE",
                2,
                1,
                3,
            )
        if requested_pages >= 3:
            # v6.4.12: continuation batch also 4 — covers the edge case where
            # the initial call only returned partial pages (e.g. 2 of 4) and
            # needs to deliver the remainder in one follow-up rather than two.
            return self._read_int_env(
                "EVERMIND_BUILDER_DIRECT_MULTIFILE_BATCH_SIZE",
                4,
                1,
                4,
            )
        return max(1, min(4, requested_pages))

    def _builder_direct_multifile_continuation_limit(self, input_data: str) -> int:
        base_limit = self._read_int_env(
            "EVERMIND_BUILDER_DIRECT_MULTIFILE_CONTINUATIONS",
            3,
            0,
            10,
        )
        assigned_targets = len(self._builder_assigned_html_targets(input_data))
        if assigned_targets <= 0:
            return base_limit
        initial_batch_size = max(1, self._builder_direct_multifile_initial_batch_size(input_data))
        continuation_batch_size = max(1, self._builder_direct_multifile_batch_size(input_data))
        remaining = max(0, assigned_targets - initial_batch_size)
        needed = (
            (remaining + continuation_batch_size - 1) // continuation_batch_size
            if remaining else 0
        )
        return min(10, max(base_limit, needed))

    def _builder_returned_html_targets(self, output_text: str) -> List[str]:
        targets: List[str] = []
        for block in self._builder_named_code_blocks(output_text):
            candidate = str(block.get("filename") or "").strip()
            if not candidate.lower().endswith((".html", ".htm")):
                continue
            if candidate not in targets:
                targets.append(candidate)
        return targets

    def _builder_named_code_blocks(self, output_text: str) -> List[Dict[str, Any]]:
        text = str(output_text or "")
        if not text:
            return []

        closed_pattern = re.compile(
            r"```(?P<lang>html|htm|css|js|javascript)\s+(?P<name>[^\n`]+)\n(?P<code>.*?)(?:\n```)",
            re.IGNORECASE | re.DOTALL,
        )
        open_pattern = re.compile(
            r"```(?P<lang>html|htm|css|js|javascript)\s+(?P<name>[^\n`]+)\n",
            re.IGNORECASE,
        )

        blocks: List[Dict[str, Any]] = []
        closed_spans: List[tuple[int, int]] = []
        for match in closed_pattern.finditer(text):
            header_name = str(match.group("name") or "").strip()
            filename = Path(header_name.split()[0].strip().strip("\"'`")).name
            lang = str(match.group("lang") or "").strip().lower()
            if lang == "javascript":
                lang = "js"
            blocks.append({
                "lang": lang,
                "filename": filename,
                "code": str(match.group("code") or ""),
                "closed": True,
            })
            closed_spans.append(match.span())

        last_closed_end = max((end for _, end in closed_spans), default=0)
        trailing_open = None
        for match in open_pattern.finditer(text):
            start = match.start()
            if any(span_start <= start < span_end for span_start, span_end in closed_spans):
                continue
            if start >= last_closed_end:
                trailing_open = match

        if trailing_open is not None:
            header_name = str(trailing_open.group("name") or "").strip()
            filename = Path(header_name.split()[0].strip().strip("\"'`")).name
            lang = str(trailing_open.group("lang") or "").strip().lower()
            if lang == "javascript":
                lang = "js"
            blocks.append({
                "lang": lang,
                "filename": filename,
                "code": text[trailing_open.end():],
                "closed": False,
            })

        return blocks

    def _builder_html_block_looks_complete(self, code: str, *, closed: bool) -> bool:
        if not closed:
            return False
        lower = str(code or "").lower()
        if "</html>" in lower:
            return True
        if "<html" not in lower and "<!doctype" not in lower:
            return False
        return "</body>" in lower

    def _builder_response_looks_like_narration_only(self, content: str) -> bool:
        """v5.8.7: detect pure-prose batches before they burn continuation budget.

        Diagnosed from the minimax-m2.7 run that emitted 2202→1619→1066→572 chars
        of planning narrative with returned_targets=[], never producing a fenced
        HTML block. The loop still consumed all continuations because each batch
        had non-empty `content` and the existing `is_truly_empty_batch` check only
        fired when targets were empty AND content was under threshold.

        A narration-only batch looks like: short-ish, with no DOCTYPE/<html prefix,
        no fenced named blocks, and angle-bracket density close to zero. We never
        want such a batch to satisfy "success"; return True so callers can break.
        """
        text = str(content or "")
        stripped = text.strip()
        if not stripped:
            return True
        if self._builder_named_code_blocks(stripped):
            return False
        lower = stripped.lower()
        has_html_skeleton = (
            "<!doctype" in lower
            or "<html" in lower
            or "</html>" in lower
            or "</body>" in lower
        )
        if has_html_skeleton and len(stripped) >= 600:
            return False
        angle_density = (stripped.count("<") + stripped.count(">")) / max(1, len(stripped))
        if angle_density >= 0.02 and len(stripped) >= 4096:
            return False
        return True

    def _builder_completed_html_targets(self, output_text: str) -> List[str]:
        targets: List[str] = []
        for block in self._builder_named_code_blocks(output_text):
            candidate = str(block.get("filename") or "").strip()
            if not candidate.lower().endswith((".html", ".htm")):
                continue
            if not self._builder_html_block_looks_complete(
                str(block.get("code") or ""),
                closed=bool(block.get("closed")),
            ):
                continue
            if candidate not in targets:
                targets.append(candidate)
        return targets

    def _builder_persistable_named_html_targets(self, output_text: str, input_data: str) -> List[str]:
        targets: List[str] = []
        assigned_targets = self._builder_assigned_html_targets(input_data)
        assigned_set = {name for name in assigned_targets if str(name or "").strip()}
        for block in self._builder_named_code_blocks(output_text):
            candidate = Path(str(block.get("filename") or "").strip()).name
            if not candidate.lower().endswith((".html", ".htm")):
                continue
            if assigned_set and candidate not in assigned_set:
                continue
            code = str(block.get("code") or "").strip()
            if len(code) < 120:
                continue
            lower = code.lower()
            if "<!doctype" not in lower and "<html" not in lower:
                continue
            normalized = self._normalize_builder_text_html(
                code,
                filename=candidate,
                input_data=input_data,
            )
            if not normalized or len(normalized) < 120:
                continue
            if self._builder_html_persist_rejection_reason(
                normalized,
                input_data=input_data,
                filename=candidate,
            ):
                continue
            if candidate not in targets:
                targets.append(candidate)
        return targets

    def _builder_missing_html_targets(self, input_data: str, output_text: str) -> List[str]:
        assigned = self._builder_assigned_html_targets(input_data)
        if not assigned:
            return []
        if len(assigned) == 1 and self._builder_text_output_has_persistable_html(output_text, input_data):
            return []
        returned = set(self._builder_persistable_named_html_targets(output_text, input_data))
        return [name for name in assigned if name not in returned]

    def _builder_requires_shared_assets(self, input_data: str) -> bool:
        assigned_targets = self._builder_assigned_html_targets(input_data)
        if "index.html" not in assigned_targets:
            return False
        assigned_count = len(assigned_targets)
        try:
            wants_multi_page = task_classifier.wants_multi_page(input_data)
        except Exception:
            wants_multi_page = False
        return assigned_count >= 2 and (wants_multi_page or assigned_count >= 3)

    def _builder_returned_named_assets(self, output_text: str) -> List[str]:
        text = str(output_text or "")
        assets: List[str] = []
        for match in re.finditer(r"```(?:css|js|javascript)\s+([^\n`]+)", text, re.IGNORECASE):
            header = str(match.group(1) or "").strip()
            if not header:
                continue
            candidate = Path(header.split()[0].strip().strip("\"'`")).name
            normalized = candidate.lower()
            if normalized not in {"styles.css", "app.js"}:
                continue
            if normalized not in assets:
                assets.append(normalized)
        return assets

    def _builder_missing_shared_assets(self, input_data: str, output_text: str) -> List[str]:
        if not self._builder_requires_shared_assets(input_data):
            return []
        returned = set(self._builder_returned_named_assets(output_text))
        return [name for name in ("styles.css", "app.js") if name not in returned]

    def _builder_direct_multifile_initial_messages(
        self,
        system_prompt: str,
        input_data: str,
    ) -> List[Dict[str, str]]:
        assigned_targets = self._builder_assigned_html_targets(input_data)
        if not assigned_targets:
            return [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": input_data},
            ]
        if len(assigned_targets) == 1:
            target = assigned_targets[0]
            output_dir = self._current_output_dir().rstrip("/")
            prompt = (
                "[DIRECT SINGLE-FILE DELIVERY]\n"
                f"{BUILDER_TARGET_OVERRIDE_MARKER} {target}\n"
                f"Return ONLY one fenced ```html {target}``` block.\n"
                "This is a single-file builder delivery or repair pass, not a multi-page batch.\n"
                "Treat the current output as the source of truth and patch in place instead of re-planning the whole game/site.\n"
                "Preserve working systems and change only what is required by the retry notes or current brief.\n"
                "Keep the file compact enough to finish in one response: remove dead comments, duplicate helper branches, repeated geometry boilerplate, and unused fallback code.\n"
                "Do NOT output prose, planning text, or extra filenames.\n"
                f"Use the exact runtime path under {output_dir}/{target}.\n"
                f"Output ONLY:\n```html {target}\n<!DOCTYPE html>...\n```"
            )
            return [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": f"{str(input_data or '').strip()}\n\n{prompt}"},
            ]
        batch_size = self._builder_direct_multifile_initial_batch_size(input_data)
        first_batch = assigned_targets[:batch_size]
        remaining = assigned_targets[batch_size:]
        output_dir = self._current_output_dir().rstrip("/")
        batch_line = ", ".join(first_batch)
        allowed_route_line = ", ".join(assigned_targets)
        target_override_line = f"{BUILDER_TARGET_OVERRIDE_MARKER} {batch_line}"
        shared_assets_required = self._builder_requires_shared_assets(input_data)
        remaining_note = (
            "If more assigned files remain after this batch, another continuation will request them immediately."
            if remaining else
            "This batch covers the full assignment."
        )
        root_batch_contract = ""
        if "index.html" in first_batch:
            root_batch_contract = (
                "ROOT PAGE CONTRACT:\n"
                "- index.html is part of this batch and is MANDATORY.\n"
                "- Return one COMPLETE fenced ```html index.html``` block in this response before any secondary page.\n"
                "- If index.html is omitted, thin, or replaced with prose, the batch is a failure and will be retried.\n"
            )
        example_blocks_parts: List[str] = []
        if shared_assets_required:
            example_blocks_parts.extend([
                "```css styles.css\n:root { --bg: #08111f; --accent: #d9b36c; }\n```",
                "```js app.js\ndocument.addEventListener('DOMContentLoaded', () => {\n  document.querySelectorAll('[data-reveal]').forEach((el) => el.classList.add('is-ready'));\n});\n```",
            ])
        for name in first_batch[: max(1, min(2, len(first_batch)))]:
            example_blocks_parts.append(
                f"```html {name}\n<!DOCTYPE html>...\n<link rel=\"stylesheet\" href=\"styles.css\">\n<script src=\"app.js\" defer></script>\n```"
            )
        example_blocks = "\n".join(example_blocks_parts)
        shared_asset_contract = ""
        if shared_assets_required:
            shared_asset_contract = (
                "FIRST-BATCH ASSET CONTRACT:\n"
                "- You MUST return ```css styles.css``` and ```js app.js``` in this response before the HTML block(s).\n"
                "- Every HTML page in this batch must link the shared local assets with rel=stylesheet href=\"styles.css\" and script src=\"app.js\" defer.\n"
                "- styles.css must contain the core layout, color, spacing, responsive, and motion system.\n"
                "- app.js must be route-safe: every optional selector must be null-guarded before addEventListener/classList/style access.\n"
            )
        shared_asset_delivery = (
            "Prefer one shared ```css styles.css``` block and one shared ```js app.js``` block in this first batch if the site reuses the same design system or motion logic.\n"
            "Link those shared assets from the HTML pages instead of duplicating the same CSS/JS inside every page.\n"
            "Do NOT inline large CSS or JS blobs into the HTML when shared assets are available.\n"
            "If you use shared app.js, it MUST be route-safe: every queried element needs a null guard before classList/addEventListener/style access, unless every linked page contains the same DOM structure.\n"
            if shared_assets_required else
            "Builder 1 owns the root shared assets for this site. Do NOT invent or overwrite root-level styles.css/app.js in this batch.\n"
        )
        prompt = (
            "[DIRECT MULTI-FILE INITIAL DELIVERY]\n"
            f"{target_override_line}\n"
            "Deliver the assigned HTML files in small batches to reduce stream stalls.\n"
            f"Return ONLY this first batch now: {batch_line}.\n"
            f"The ONLY valid local HTML route set for this site is: {allowed_route_line}.\n"
            "Every internal href that points to a local .html page MUST use one of those exact filenames.\n"
            "Do NOT invent new local routes such as destinations.html, collections.html, services.html, or planning.html unless they are explicitly in that allowed route set.\n"
            "If you need more navigation items than routes, point them to existing assigned pages or same-page #anchors instead of creating new HTML filenames.\n"
            "Any extra HTML filename outside this batch will be discarded and counted as failure.\n"
            "Do NOT try to emit every assigned page in one response.\n"
            "Do NOT output prose, planning text, or explanations.\n"
            f"{root_batch_contract}"
            f"{shared_asset_contract}"
            f"{shared_asset_delivery}"
            "Keep each page compact and shippable: use concise copy, semantic sections, and avoid giant repeated markup.\n"
            "Do not fill destination, package, gallery, or story modules with a single oversized outline icon; use real media or a rich finished composition instead.\n"
            "Avoid base64 assets, giant SVG path dumps, or repeating the entire site content inside one page.\n"
            "Overwrite the assigned scaffold files by returning final HTML for these exact filenames.\n"
            f"Use runtime paths under {output_dir}/.\n"
            f"{remaining_note}\n"
            "Output ONLY fenced HTML code blocks, for example:\n"
            f"{example_blocks}"
        )
        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": f"{str(input_data or '').strip()}\n\n{prompt}"},
        ]

    def _builder_direct_multifile_continuation_messages(
        self,
        system_prompt: str,
        input_data: str,
        accumulated_output: str,
        remaining_targets: List[str],
    ) -> List[Dict[str, str]]:
        assigned_targets = self._builder_assigned_html_targets(input_data)
        if len(assigned_targets) == 1:
            target = assigned_targets[0]
            output_dir = self._current_output_dir().rstrip("/")
            prompt = (
                "[DIRECT SINGLE-FILE CONTINUATION]\n"
                f"{BUILDER_TARGET_OVERRIDE_MARKER} {target}\n"
                "The previous response for this single file was truncated by the model token limit.\n"
                f"Return ONE complete replacement ```html {target}``` block only.\n"
                "Do NOT restart the architecture from zero. Preserve the working gameplay/site shell and apply only the targeted repair.\n"
                "Keep the file compact enough to finish in one response: trim duplicate sections, dead helper code, repeated geometry comments, and unused fallback branches.\n"
                "Do NOT emit prose, planning text, or any extra filename.\n"
                f"Use the exact runtime path under {output_dir}/{target}.\n"
                f"Output ONLY:\n```html {target}\n<!DOCTYPE html>...\n```"
            )
            return [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": f"{str(input_data or '').strip()}\n\n{prompt}"},
            ]
        delivered_targets = self._builder_returned_html_targets(accumulated_output)
        batch_size = self._builder_direct_multifile_batch_size(input_data)
        next_batch = remaining_targets[:batch_size]
        output_dir = self._current_output_dir().rstrip("/")
        remaining_line = ", ".join(next_batch[:12])
        allowed_route_line = ", ".join(assigned_targets)
        target_override_line = f"{BUILDER_TARGET_OVERRIDE_MARKER} {remaining_line}" if remaining_line else ""
        delivered_line = ", ".join(delivered_targets[:12]) if delivered_targets else "none"
        missing_shared_assets = self._builder_missing_shared_assets(input_data, accumulated_output)
        root_retry_contract = ""
        if "index.html" in next_batch:
            root_retry_contract = (
                "CRITICAL ROOT RETRY:\n"
                "- index.html is still missing from the delivered output set.\n"
                "- Return a COMPLETE fenced ```html index.html``` block first in this response, then any remaining secondary page in this batch.\n"
                "- Do NOT defer index.html to a later batch.\n"
            )
        example_blocks_parts: List[str] = []
        if missing_shared_assets:
            if "styles.css" in missing_shared_assets:
                example_blocks_parts.append("```css styles.css\n:root { --bg: #08111f; --accent: #d9b36c; }\n```")
            if "app.js" in missing_shared_assets:
                example_blocks_parts.append("```js app.js\ndocument.addEventListener('DOMContentLoaded', () => {\n  document.querySelectorAll('[data-reveal]').forEach((el) => el.classList.add('is-ready'));\n});\n```")
        for name in next_batch[: max(1, min(2, len(next_batch)))]:
            example_blocks_parts.append(
                f"```html {name}\n<!DOCTYPE html>...\n<link rel=\"stylesheet\" href=\"styles.css\">\n<script src=\"app.js\" defer></script>\n```"
            )
        example_blocks = "\n".join(example_blocks_parts)
        shared_asset_note = (
            "Shared assets are still missing from earlier batches: "
            + ", ".join(missing_shared_assets)
            + ". Return those named asset blocks first in this response, then return the HTML batch below.\n"
            if missing_shared_assets else
            ""
        )
        continuation_prompt = (
            "[DIRECT MULTI-FILE CONTINUATION]\n"
            f"{target_override_line}\n"
            "The previous response stopped before all assigned HTML files were delivered.\n"
            f"Already returned: {delivered_line}.\n"
            f"Continue now with ONLY this next batch of HTML files: {remaining_line}.\n"
            f"The ONLY valid local HTML route set for this site is: {allowed_route_line}.\n"
            "Rewrite or remove any local href that points to a non-assigned HTML filename; use an existing assigned page or a same-page #anchor instead.\n"
            f"{root_retry_contract}"
            f"{shared_asset_note}"
            "Do NOT restart from index.html unless index.html is still in the remaining list.\n"
            "Do NOT repeat files that were already returned.\n"
            "Do NOT skip ahead to future batches.\n"
            "Any extra HTML filename outside this batch will be discarded and counted as failure.\n"
            "Return ONLY the next HTML file(s) in this batch.\n"
            "Do NOT re-emit styles.css or app.js unless you are intentionally revising those shared assets.\n"
            "Do NOT inline large CSS or JS into this continuation page; rely on the shared assets already delivered.\n"
            "Maintain route-safe shared JS across all pages; do not assume a selector exists on every page unless the markup is truly consistent.\n"
            "Keep the continuation compact: avoid giant repeated sections, base64 assets, long placeholder essays, or duplicated site-wide markup.\n"
            "Do not leave media-led sections as icon-only cards or thin decorative shells; repair them with real imagery or a finished visual composition.\n"
            "If one page starts becoming excessively long, simplify the copy and section count before returning it.\n"
            "Keep the same design system, content direction, navigation, and motion language.\n"
            "Output ONLY fenced code blocks, one per remaining file, for example:\n"
            f"{example_blocks}\n"
            f"Use the exact runtime paths under {output_dir}/ and no extra prose."
        )
        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": f"{str(input_data or '').strip()}\n\n{continuation_prompt}"},
        ]

    def _response_finish_reason(self, response: Any) -> str:
        try:
            choice = response.choices[0]
        except Exception:
            return ""
        if isinstance(choice, dict):
            return str(choice.get("finish_reason") or "")
        return str(getattr(choice, "finish_reason", "") or "")

    def _runtime_output_prompt_block(self) -> str:
        current = self._current_output_dir()
        scratch = self._current_scratchpad_dir()
        return (
            "\n\nRUNTIME OUTPUT CONTRACT:\n"
            f"- Current output directory: {current}\n"
            "- /tmp/evermind_output may be a compatibility alias, but you must treat the current output directory as the source of truth.\n"
            "- Do not inherit stale placeholder files from any other directory.\n"
            f"\nSCRATCHPAD DIRECTORY: {scratch}\n"
            "- Use this for temporary or intermediate files (draft CSS, test data, asset manifests) that should NOT be in the final deliverables.\n"
            "- Create this directory with file_ops if it does not exist yet.\n"
            "- Only use /tmp if you explicitly need system-level temp storage.\n"
        )

    def _builder_forced_text_prompt(self, input_data: str) -> str:
        assigned_targets = self._builder_assigned_html_targets(input_data)
        support_lane = self._builder_is_support_lane(input_data) and not assigned_targets
        assigned_line = ""
        exact_paths_line = ""
        forbidden_index_line = ""
        example_blocks = ""
        game_contract = ""
        try:
            if task_classifier.classify(input_data).task_type == "game":
                game_contract = (
                    "GAME FINAL DELIVERY CONTRACT: "
                    "include a visible start/play flow, gameplay surface (canvas/arena/viewport), "
                    "requestAnimationFrame loop, keyboard/pointer/touch bindings, HUD/progression UI, "
                    "and a fail/win/restart path. "
                    "Bind gameplay input in script with addEventListener or an equivalent runtime hook; "
                    "do not output a visually polished but non-playable shell. "
                )
        except Exception:
            game_contract = ""
        if assigned_targets:
            assigned_line = (
                "Your assigned HTML filenames are: "
                + ", ".join(assigned_targets)
                + ". "
            )
            output_dir = self._current_output_dir().rstrip("/")
            exact_paths_line = (
                "Use these exact runtime output paths: "
                + ", ".join(f"{output_dir}/{name}" for name in assigned_targets[:8])
                + ". "
            )
            if "index.html" not in assigned_targets:
                forbidden_index_line = (
                    "Do NOT emit ```html index.html``` or any other unassigned filename; "
                    "those blocks will be discarded and counted as failure. "
                )
            example_targets = assigned_targets[: max(1, min(2, len(assigned_targets)))]
            example_blocks = "\n".join(
                f"```html {name}\n<!DOCTYPE html>...\n```"
                for name in example_targets
            )
        if task_classifier.wants_multi_page(input_data):
            if assigned_targets:
                delivery_line = (
                    "Return ONLY the assigned HTML files listed above. "
                    "Do not invent extra slugs and do not omit any assigned file."
                )
            else:
                count = task_classifier.requested_page_count(input_data)
                if count > 1:
                    delivery_line = f"Return index.html plus at least {count - 1} additional linked HTML files."
                else:
                    delivery_line = "Return index.html plus the additional linked HTML files required by the brief."
                example_blocks = (
                    "```html index.html\n<!DOCTYPE html>...\n```\n"
                    "```html page-2.html\n<!DOCTYPE html>...\n```"
                )
            return (
                "You have used all your tool calls. Now output ONLY the final files as text. "
                "This is a MULTI-PAGE website request, so do NOT collapse it into one long page. "
                f"{game_contract}"
                f"{assigned_line}"
                f"{exact_paths_line}"
                f"{forbidden_index_line}"
                f"{delivery_line} "
                "Use EXACTLY one fenced code block per file with the filename in the fence header, for example:\n"
                f"{example_blocks}\n"
                "Unnamed ```html``` blocks are invalid and will be discarded. "
                "If you need shared assets, you may also output blocks like ```css styles.css``` or ```js app.js```. "
                "Every HTML file must be full, standalone, and linked by working navigation. "
                "Do NOT add explanations before or after the file blocks."
            )
        if support_lane:
            support_targets = self._builder_support_lane_targets(input_data)
            output_dir = self._current_output_dir().rstrip("/")
            example_blocks = "\n".join(
                (
                    f"```{('css' if name.endswith('.css') else 'json' if name.endswith('.json') else 'js')} {name}\n"
                    + ("{ \"status\": \"ready\" }\n" if name.endswith(".json") else "/* implementation */\n")
                    + "```"
                )
                for name in support_targets[:3]
            )
            return (
                "You have used all your tool calls. Now output ONLY the final support files as text. "
                "This is a support-lane builder pass for a single-entry app/game, so do NOT emit a root index.html rewrite. "
                f"{game_contract}"
                f"Use runtime paths under {output_dir}/ such as: "
                + ", ".join(f"{output_dir}/{name}" for name in support_targets[:6])
                + ". "
                "Return ONLY non-empty browser-native JS/CSS/JSON files that deepen the assigned subsystem. "
                "Use EXACTLY one fenced code block per file with the filename in the fence header, for example:\n"
                f"{example_blocks}\n"
                "Do NOT output prose, unnamed blocks, or any ```html index.html``` block."
            )
        return (
            "You have used all your tool calls. Now output the COMPLETE HTML code directly as text. "
            f"{game_contract}"
            "If you are repairing or continuing an existing partial page, output the FULL merged file from <!DOCTYPE html> to </html>, not only the tail fragment or patch chunk. "
            "Start with <!DOCTYPE html> and end with </html>. "
            "Put it inside a ```html code block. Do NOT describe it — output the full code NOW."
        )

    def _builder_tool_results_summary(self, tool_results: List[Dict[str, Any]]) -> str:
        lines: List[str] = []
        for result in (tool_results or [])[-8:]:
            if not isinstance(result, dict):
                continue
            data = result.get("data")
            error = str(result.get("error") or "").strip()
            if isinstance(data, dict):
                path = str(data.get("path") or "").strip()
                label = Path(path).name if path else ""
                if bool(data.get("written")):
                    lines.append(f"- Wrote file: {label or path or 'unknown file'}")
                    continue
                if "content" in data and path:
                    lines.append(f"- Read file: {label}")
                    continue
                entries = data.get("entries")
                if isinstance(entries, list) and path:
                    sample = [
                        str(item.get("name") or "").strip()
                        for item in entries[:8]
                        if isinstance(item, dict) and str(item.get("name") or "").strip()
                    ]
                    if sample:
                        lines.append(f"- Listed {label or path}: {', '.join(sample)}")
                        continue
            if error:
                lines.append(f"- Tool error: {error[:180]}")
        return "\n".join(lines[:8]).strip()

    def _builder_forced_text_messages(
        self,
        system_prompt: str,
        input_data: str,
        tool_results: List[Dict[str, Any]],
        output_text: str,
        force_text_reason: str,
    ) -> List[Dict[str, str]]:
        context_parts: List[str] = []
        reason = str(force_text_reason or "").strip()
        if reason:
            context_parts.append(f"Forced final delivery reason: {reason}.")
        tool_summary = self._builder_tool_results_summary(tool_results)
        if tool_summary:
            context_parts.append("Workspace/tool summary:\n" + tool_summary)
        partial = self._truncate_text(str(output_text or "").strip(), 1600)
        if partial:
            context_parts.append(
                "Incomplete prior draft for salvage only. Reuse any good ideas, but output the final files directly now:\n"
                + partial
            )

        user_content = str(input_data or "").strip()
        if context_parts:
            user_content += "\n\n[FORCED FINAL DELIVERY CONTEXT]\n" + "\n\n".join(context_parts)
        user_content += "\n\n" + self._builder_forced_text_prompt(input_data)
        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_content},
        ]

    def _plain_text_node_write_guard_error(self, node_type: str) -> str:
        normalized = normalize_node_role(node_type)
        if normalized == "analyst":
            return (
                "Analyst nodes must NOT write code files. "
                "Produce your research report as plain text content in your response using the required XML tags. "
                "Do NOT use file_ops write."
            )
        if normalized == "scribe":
            return (
                "Scribe nodes must NOT write files in this workflow stage. "
                "Produce your documentation or content handoff as plain text in your response. "
                "Do NOT use file_ops write."
            )
        if normalized == "uidesign":
            return (
                "UIDesign nodes must NOT write production code files. "
                "Produce your design brief as plain text in your response. "
                "Do NOT use file_ops write."
            )
        return "This node must produce plain text in its response instead of file_ops write."

    def _plain_text_node_final_prompt(self, node_type: str) -> str:
        normalized = normalize_node_role(node_type)
        if normalized == "analyst":
            return (
                "Output ONLY the final analyst handoff as plain text using ALL required XML tags.\n"
                "Do NOT call any tools.\n"
                "Use ONLY the sources already gathered. If the collected sources are insufficient, state that explicitly in <risk_register> instead of inventing citations.\n"
                "Do NOT write HTML, CSS, or JavaScript."
            )
        if normalized == "scribe":
            return (
                "Output ONLY the final scribe handoff as plain text.\n"
                "Do NOT call any tools.\n"
                "Do NOT invent XML tags unless the prompt already required them.\n"
                "Do NOT write files or source code in this response."
            )
        if normalized == "uidesign":
            return (
                "Output ONLY the final UI design brief as plain text.\n"
                "Do NOT call any tools.\n"
                "Do NOT write production HTML, CSS, JavaScript, or files."
            )
        return "Output ONLY the final plain-text handoff. Do NOT call any tools."

    def _plain_text_node_output_is_sufficient(self, node_type: str, output_text: str) -> bool:
        text = str(output_text or "").strip()
        if len(text) < 80:
            return False
        normalized = normalize_node_role(node_type)
        if normalized != "analyst":
            return True
        lower = text.lower()
        required_tags = (
            "<reference_sites>",
            "<design_direction>",
            "<non_negotiables>",
            "<deliverables_contract>",
            "<risk_register>",
            "<builder_1_handoff>",
            "<builder_2_handoff>",
            "<reviewer_handoff>",
            "<tester_handoff>",
            "<debugger_handoff>",
        )
        return all(tag in lower for tag in required_tags)

    def _plain_text_node_output_is_materializable(self, node_type: str, output_text: str) -> bool:
        text = str(output_text or "").strip()
        if not text:
            return False
        if self._plain_text_node_output_is_sufficient(node_type, text):
            return True
        normalized = normalize_node_role(node_type)
        if normalized != "analyst":
            return False
        lower = text.lower()
        essential_tags = (
            "<reference_sites>",
            "<design_direction>",
            "<non_negotiables>",
            "<deliverables_contract>",
            "<risk_register>",
        )
        downstream_tags = (
            "<builder_1_handoff>",
            "<builder_2_handoff>",
            "<reviewer_handoff>",
            "<tester_handoff>",
            "<debugger_handoff>",
        )
        essential_hits = sum(1 for tag in essential_tags if tag in lower)
        downstream_hits = sum(1 for tag in downstream_tags if tag in lower)
        if essential_hits == len(essential_tags):
            return True
        if len(text) >= 900 and essential_hits >= 4 and downstream_hits >= 2:
            return True
        if len(text) >= 1600 and essential_hits >= 3 and downstream_hits >= 4:
            return True
        # v7.4.1: large-output salvage. Without this, kimi frequently produces
        # 20K+ chars of solid analysis but uses Markdown (## Reference Sites)
        # or non-canonical tag spelling, and the previous strict checks fall
        # through → orchestrator forces a 3-5 min forced-synthesis re-roll
        # that often shrinks content. If the output is genuinely large AND
        # has SOME structural anchor (XML, Markdown headers, or numbered
        # sections), trust it and pass to downstream.
        if len(text) >= 15000:
            md_headings = sum(1 for token in (
                "## reference", "## design", "## non-negot", "## deliverable",
                "## risk", "## builder 1", "## builder 2", "## reviewer", "## tester",
                "### reference", "### design", "### deliverable",
                "# reference", "# design", "# deliverable",
            ) if token in lower)
            xml_anchors = essential_hits + downstream_hits
            structural_anchor = (xml_anchors >= 2) or (md_headings >= 3) or (xml_anchors >= 1 and md_headings >= 2)
            if structural_anchor:
                return True
        # Even-longer truly-huge body: accept anything ≥18K with at least one
        # anchor of any kind. Re-rolling kimi to "obey the schema better" on
        # an output this big is almost always worse than just accepting it.
        if len(text) >= 18000 and (essential_hits >= 1 or downstream_hits >= 1 or "##" in text or "===" in text):
            return True
        return False

    def _plain_text_node_needs_forced_output(
        self,
        node_type: str,
        output_text: str,
        tool_results: List[Dict[str, Any]],
    ) -> bool:
        normalized = normalize_node_role(node_type)
        if normalized not in {"analyst", "scribe", "uidesign"}:
            return False
        if self._plain_text_node_output_is_materializable(node_type, output_text):
            return False
        return bool(tool_results or str(output_text or "").strip())

    def _plain_text_final_timeout_for_node(
        self,
        node_type: str,
        force_text_reason: str = "",
    ) -> int:
        normalized = normalize_node_role(node_type)
        reason = str(force_text_reason or "").strip().lower()
        if normalized == "analyst":
            # v5.8.1: 60 → 120. Post-mortem showed analyst hit the 60s ceiling
            # on a game-planning task with rich research (report was still
            # being synthesized when we killed the stream).
            # v5.8.5: 120 → 200. Observed analyst forced-synthesis call time-out
            # at exactly 120s while the API was still streaming the final
            # handoff; we were killing the call mid-synthesis and losing the
            # whole section set. 200s fits a real 12K-token multi-section
            # reply at Kimi's ~100 tok/s decode rate with safety margin.
            base = self._read_int_env("EVERMIND_ANALYST_FINAL_SYNTH_TIMEOUT_SEC", 200, 30, 360)
            if reason in {"tool_iterations_exhausted", "missing_final_handoff", "blocked_file_write"}:
                return base
        if normalized in {"scribe", "uidesign"}:
            return self._read_int_env("EVERMIND_PLAIN_TEXT_FINAL_SYNTH_TIMEOUT_SEC", 25, 10, 90)
        return 0

    def _plain_text_node_forced_messages(
        self,
        system_prompt: str,
        input_data: str,
        tool_results: List[Dict[str, Any]],
        output_text: str,
        node_type: str,
        force_text_reason: str,
    ) -> List[Dict[str, str]]:
        context_parts: List[str] = []
        reason = str(force_text_reason or "").strip()
        if reason:
            context_parts.append(f"Forced final handoff reason: {reason}.")
        tool_summary = self._builder_tool_results_summary(tool_results)
        if tool_summary:
            context_parts.append("Workspace/tool summary:\n" + tool_summary)
        partial = self._truncate_text(str(output_text or "").strip(), 1600)
        if partial:
            context_parts.append(
                "Incomplete prior draft for salvage only. Reuse any valid findings, but output the final plain-text handoff now:\n"
                + partial
            )

        user_content = str(input_data or "").strip()
        if context_parts:
            user_content += "\n\n[FORCED FINAL HANDOFF CONTEXT]\n" + "\n\n".join(context_parts)
        user_content += "\n\n" + self._plain_text_node_final_prompt(node_type)
        return [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_content},
        ]

    def _reviewer_needs_forced_verdict(
        self,
        node_type: str,
        output_text: str,
        tool_results: List[Dict[str, Any]],
    ) -> bool:
        if normalize_node_role(node_type) != "reviewer":
            return False
        if not str(output_text or "").strip() and not tool_results:
            return False
        return self._review_output_format_followup_reason(node_type, output_text) is not None

    def _reviewer_forced_verdict_messages(
        self,
        system_prompt: str,
        input_data: str,
        tool_results: List[Dict[str, Any]],
        output_text: str,
        force_reason: str,
    ) -> List[Dict[str, str]]:
        # v5.8.6: do NOT reuse the reviewer.yaml system prompt here. The YAML
        # commands "DETAILED natural-language report" + zone-by-zone prose;
        # the model obeys the strongest system instruction and writes 90K+
        # chars of prose, hitting finish=length (observed 95883 chars / 183s
        # before truncation) and emitting zero usable verdict. A short,
        # single-purpose system prompt here prevents the clash.
        tight_system_prompt = (
            "You are the reviewer VERDICT-SYNTHESIZER. Your ONLY job is to "
            "emit exactly one JSON object matching the required shape. "
            "No prose. No markdown. No explanation. No preamble. JSON only. "
            "If evidence is incomplete or uncertain, verdict is REJECTED.\n"
            "[v7.19b] EMPTY OUTPUT IS NOT ALLOWED. If you return empty content, "
            "the entire run fails and the user gets nothing. You MUST emit the JSON now. "
            "When uncertain, emit REJECTED with concrete blocking_issues drawn from the tool evidence (console errors, click failures, missing DOM elements, runtime exceptions) — NEVER use empty arrays or generic placeholders. "
            "Example minimal valid output (one line, no fences):\n"
            '{"verdict":"REJECTED","scores":{"layout":6,"color":6,"typography":6,"animation":4,"responsive":5,"functionality":3,"completeness":4,"originality":5},"ship_readiness":4,"average":4.9,"issues":[],"blocking_issues":["start button click_start preflight timeout","missing canvas/Three.js render loop","keydown WASD listeners not bound"],"missing_deliverables":["working 3D scene"],"required_changes":["wire pointerlockchange handler","add THREE.WebGLRenderer initialization"],"acceptance_criteria":["pressing W moves camera forward in 3D space"],"strengths":["start screen renders","button styling acceptable"]}'
        )
        context_parts: List[str] = []
        reason = str(force_reason or "").strip()
        if reason:
            context_parts.append(f"Forced reviewer verdict reason: {reason}.")
        tool_summary = self._builder_tool_results_summary(tool_results)
        if tool_summary:
            # v5.8.6: cap tool summary — a 10K-char tool log just eats context
            # without helping the synth pick a verdict.
            context_parts.append(
                "QA/tool evidence summary:\n"
                + self._truncate_text(tool_summary, 3000)
            )
        partial = self._truncate_text(str(output_text or "").strip(), 1800)
        if partial:
            context_parts.append(
                "Malformed prior reviewer draft for salvage only. Reuse its concrete findings, but DO NOT repeat the prose:\n"
                + partial
            )

        user_content = self._truncate_text(str(input_data or "").strip(), 4000)
        if context_parts:
            user_content += "\n\n[FORCED REVIEWER VERDICT CONTEXT]\n" + "\n\n".join(context_parts)
        user_content += (
            "\n\nReturn ONLY one strict JSON object. No markdown fences. No prose before or after.\n"
            'Required shape (emit ONE line, no formatting):\n'
            '{"verdict":"APPROVED" or "REJECTED","scores":{"layout":N,"color":N,"typography":N,"animation":N,"responsive":N,"functionality":N,"completeness":N,"originality":N},"ship_readiness":N,"average":N.N,"issues":[],"blocking_issues":[],"missing_deliverables":[],"required_changes":[],"acceptance_criteria":[],"strengths":[]}\n'
            'If the evidence is mixed, incomplete, or uncertain, set "verdict" to "REJECTED" rather than "APPROVED".'
        )
        return [
            {"role": "system", "content": tight_system_prompt},
            {"role": "user", "content": user_content},
        ]

    def _reviewer_empty_output_fallback_verdict(
        self,
        *,
        tool_results: List[Dict[str, Any]],
        original_reason: str,
    ) -> str:
        """Deterministic reviewer verdict for the empty-output last-resort path.

        v5.8.6: When kimi reviewer returns empty content twice (tool-loop +
        forced no-tool synthesis), this builds a parseable REJECTED verdict
        so the orchestrator can proceed with its soft-pass / debugger logic
        instead of marking the subtask failed and burning a rejection round
        with no usable output. The verdict is intentionally conservative —
        REJECTED with generic blocking_issues — because we lack concrete
        evidence from the model.
        """
        tool_count = len(tool_results or [])
        browser_used = any(
            isinstance(r, dict) and r.get("tool") == "browser"
            for r in (tool_results or [])
        )
        notes: List[str] = []
        if original_reason:
            notes.append(f"empty-output guard: {original_reason}")
        if tool_count:
            notes.append(
                f"model ran {tool_count} tool calls"
                + (" (incl. browser QA)" if browser_used else "")
                + " but produced no prose"
            )
        note_text = "; ".join(notes) or "reviewer emitted empty output twice"

        diagnostic_issues_v719b: List[str] = []
        diagnostic_changes_v719b: List[str] = []
        try:
            for tr_v719b in (tool_results or [])[:30]:
                if not isinstance(tr_v719b, dict):
                    continue
                data_v719b = tr_v719b.get("data") if isinstance(tr_v719b.get("data"), dict) else {}
                err_v719b = str(tr_v719b.get("error") or data_v719b.get("error") or "").strip()
                action_v719b = str(tr_v719b.get("args", {}).get("action") if isinstance(tr_v719b.get("args"), dict) else "") or str(data_v719b.get("action") or "")
                if err_v719b and len(err_v719b) > 5:
                    short_err = err_v719b[:140]
                    if action_v719b:
                        diagnostic_issues_v719b.append(f"{action_v719b} failed: {short_err}")
                    else:
                        diagnostic_issues_v719b.append(f"tool error: {short_err}")
                console_errs = data_v719b.get("console_errors") or data_v719b.get("recent_console_errors") or []
                if isinstance(console_errs, list):
                    for ce in console_errs[:3]:
                        ce_str = str(ce)[:120]
                        if ce_str:
                            diagnostic_issues_v719b.append(f"console error: {ce_str}")
                if "click_start" in str(tr_v719b.get("name", "")) and tr_v719b.get("success") is False:
                    diagnostic_changes_v719b.append("Wire start button so reviewer click_start preflight succeeds within 12s")
        except Exception:
            pass

        try:
            import os as _os_v720b
            import re as _re_v720b
            _output_dir_v720b = (
                _os_v720b.environ.get("EVERMIND_OUTPUT_DIR", "")
                or _os_v720b.path.join(_os_v720b.environ.get("TMPDIR", "/tmp"), "evermind_output")
            )
            _root_path_v720b = _os_v720b.path.join(_output_dir_v720b, "index.html")
            _root_size_v720b = 0
            _total_html_size_v720b = 0
            _html_file_count_v720b = 0
            _root_quality_v720b = 0
            _has_click_start_failure = any(
                isinstance(tr, dict) and tr.get("success") is False and "click_start" in str(tr.get("name", ""))
                for tr in (tool_results or [])
            )
            if _os_v720b.path.exists(_root_path_v720b):
                _root_html_v720b = open(_root_path_v720b, "r", encoding="utf-8", errors="replace").read()
                _root_size_v720b = len(_root_html_v720b)
                _root_quality_v720b += len(_re_v720b.findall(r"\bTHREE\.[A-Z]", _root_html_v720b)) * 3
                _root_quality_v720b += len(_re_v720b.findall(r"<canvas\b", _root_html_v720b)) * 5
                _root_quality_v720b += len(_re_v720b.findall(r"requestAnimationFrame", _root_html_v720b))
                _root_quality_v720b += len(_re_v720b.findall(r"requestPointerLock|movementX|movementY", _root_html_v720b)) * 2
                _root_quality_v720b += len(_re_v720b.findall(r"WebGLRenderer|PerspectiveCamera|Scene\(", _root_html_v720b)) * 2
            try:
                for _f_v720b in _os_v720b.listdir(_output_dir_v720b):
                    if _f_v720b.endswith((".html", ".htm")) and not _f_v720b.startswith("_"):
                        _fp_v720b = _os_v720b.path.join(_output_dir_v720b, _f_v720b)
                        if _os_v720b.path.isfile(_fp_v720b):
                            _total_html_size_v720b += _os_v720b.path.getsize(_fp_v720b)
                            _html_file_count_v720b += 1
            except Exception:
                pass
            _multi_page_v724a = _html_file_count_v720b >= 3 and _total_html_size_v720b >= 25_000
            _single_page_healthy_v724a = _root_size_v720b >= 8000 and _root_quality_v720b >= 30
            _legacy_3d_healthy_v720b = _root_size_v720b >= 30_000 and _root_quality_v720b >= 100
            if (
                (_legacy_3d_healthy_v720b or _multi_page_v724a or _single_page_healthy_v724a)
                and not _has_click_start_failure
                and not any("console error" in s.lower() for s in diagnostic_issues_v719b)
            ):
                logger.warning(
                    "[v7.20b] Reviewer fallback SOFT-PASS: root index.html (%d bytes, quality_score=%d) is healthy + no console errors + click_start succeeded — emitting APPROVED instead of REJECTED so deployer can ship.",
                    _root_size_v720b, _root_quality_v720b,
                )
                import json as _json_v720b
                soft_pass_obj = {
                    "verdict": "APPROVED",
                    "scores": {"layout": 7, "color": 7, "typography": 7, "animation": 7,
                                "responsive": 7, "functionality": 7, "completeness": 7, "originality": 7},
                    "ship_readiness": 7,
                    "average": 7.0,
                    "issues": [],
                    "blocking_issues": [],
                    "missing_deliverables": [],
                    "required_changes": [],
                    "acceptance_criteria": [],
                    "strengths": [
                        f"Root artifact size={_root_size_v720b}B, quality_score={_root_quality_v720b} indicates substantive 3D implementation",
                        "click_start preflight succeeded — interactive entry point works",
                        "No runtime console errors detected in tool evidence",
                    ],
                    "runtime_errors": [],
                }
                soft_prose = (
                    "### Reviewer Fallback Verdict (v7.20b — healthy-product SOFT-PASS)\n"
                    "The reviewer model did not emit prose, but tool evidence shows a "
                    "substantive Three.js artifact with successful click_start interaction "
                    "and no console errors. Defaulting to APPROVED so deployer can ship; "
                    "user can manually request a debugger pass if visual issues surface.\n"
                    f"_Diagnostic: root_size={_root_size_v720b}B, quality_score={_root_quality_v720b}, "
                    f"click_start={'OK' if not _has_click_start_failure else 'FAILED'}._\n\n"
                )
                return soft_prose + "```json\n" + _json_v720b.dumps(soft_pass_obj, ensure_ascii=False) + "\n```"
        except Exception as _v720b_err:
            logger.debug("[v7.20b] healthy-product SOFT-PASS check failed: %s", _v720b_err)

        seen = set()
        unique_issues = []
        for it in diagnostic_issues_v719b:
            if it and it not in seen:
                seen.add(it)
                unique_issues.append(it)
        if not unique_issues:
            unique_issues = [
                "reviewer_empty_output_fallback (no concrete tool errors visible)",
                "verify root index.html has functional event listeners + render loop",
            ]
        if not diagnostic_changes_v719b:
            diagnostic_changes_v719b = [
                "Read root index.html and patch any inline-script syntax errors with file_ops edit",
                "Ensure 3D game tasks have <canvas> + THREE.WebGLRenderer + requestAnimationFrame loop",
            ]

        prose = (
            "### Reviewer Fallback Verdict (v7.19b — tool-evidence-driven)\n"
            "The reviewer model returned no natural-language review despite "
            "attempting tool-based QA and a forced no-tool synthesis pass. "
            "Defaulting to REJECTED with concrete blocking_issues extracted "
            "from tool evidence so the patcher can act surgically instead of "
            "spinning on read-only iterations.\n"
            f"_Diagnostic: {note_text}._\n\n"
        )
        import json as _json_v719b
        verdict_obj = {
            "verdict": "REJECTED",
            "scores": {"layout": 5, "color": 5, "typography": 5, "animation": 5,
                        "responsive": 5, "functionality": 5, "completeness": 5, "originality": 5},
            "ship_readiness": 5,
            "average": 5.0,
            "issues": [],
            "blocking_issues": unique_issues[:6],
            "missing_deliverables": [],
            "required_changes": diagnostic_changes_v719b[:4],
            "acceptance_criteria": [],
            "strengths": [],
        }
        verdict_json = _json_v719b.dumps(verdict_obj, ensure_ascii=False)
        return prose + "```json\n" + verdict_json + "\n```"

    def _builder_partial_text_is_salvageable(self, input_data: str, output_text: str) -> bool:
        text = str(output_text or "").strip()
        if len(text) < 120:
            return False
        lower = text.lower()
        if re.search(r"```(?:html|htm)(?:\s+[^\n`]+\.html?)?", text, re.IGNORECASE):
            return True
        if "<!doctype" in lower or "<html" in lower:
            return True
        if task_classifier.wants_multi_page(input_data):
            return bool(re.search(r"[A-Za-z0-9._/-]+\.html?", text, re.IGNORECASE))
        return False

    def _builder_streaming_tool_call_looks_like_write(self, fn_name: str, args_str: str) -> bool:
        name = str(fn_name or "").strip().lower()
        if name not in {"file_ops", "write_file", "write"}:
            return False

        raw = str(args_str or "")
        if len(raw) < 24:
            return False
        lower = raw.lower()

        if any(
            marker in lower
            for marker in (
                '"action":"list"',
                '"action": "list"',
                '"action":"read"',
                '"action": "read"',
                '"action":"exists"',
                '"action": "exists"',
                '"action":"stat"',
                '"action": "stat"',
                '"action":"mkdir"',
                '"action": "mkdir"',
                '"action":"delete"',
                '"action": "delete"',
            )
        ):
            return False

        recovered_html = self._extract_html_from_truncated_tool_args(raw)
        if recovered_html and len(recovered_html) >= 200:
            return True

        parsed = self._safe_json_object(raw)
        action = str(parsed.get("action", "") or "").strip().lower()
        if action and action != "write":
            return False

        content = str(parsed.get("content", "") or "")
        path = str(parsed.get("path", "") or "")
        if content and self._builder_partial_text_is_salvageable("", content):
            return True
        if (
            path.lower().endswith((".html", ".htm", ".css", ".js", ".mjs"))
            and (content or '"content"' in lower)
        ):
            return True

        return bool(
            any(marker in lower for marker in ('"action":"write"', '"action": "write"'))
            and any(marker in lower for marker in ('"content"', '"path"', ".html"))
        )

    def _prewrite_activity_grace_seconds(self, stall_timeout: float) -> float:
        try:
            stall = float(stall_timeout or 0.0)
        except Exception:
            stall = 0.0
        return max(12.0, min(stall / 4.0, 45.0))

    def _builder_pending_write_stream_cap_seconds(
        self,
        prewrite_timeout: float,
        hard_timeout: float,
    ) -> float:
        try:
            prewrite = max(0.0, float(prewrite_timeout or 0.0))
        except Exception:
            prewrite = 0.0
        try:
            hard = max(0.0, float(hard_timeout or 0.0))
        except Exception:
            hard = 0.0
        cap = min(
            max(prewrite * 1.5, 0.5),
            max(0.5, hard / 8.0) if hard > 0 else 180.0,
            180.0,
        )
        return max(0.5, cap)

    def _forcing_text_progress_payload(self, node_type: str, reason: str) -> Dict[str, Any]:
        payload: Dict[str, Any] = {
            "stage": "forcing_text_output",
            "reason": reason,
        }
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type == "builder":
            payload["builder_delivery_mode"] = "direct_text"
            payload["builder_direct_text"] = True
        return payload

    def _extract_html_from_truncated_tool_args(self, args_str: str) -> Optional[str]:
        """Extract HTML content from a truncated file_ops tool call JSON string.

        When the model calls file_ops with action=write and content=<html>... but
        the JSON is truncated mid-stream (finish=length), the standard json.loads()
        fails. This method uses regex to locate the "content" field in the raw JSON
        string and un-escapes the value to recover usable HTML.

        Returns the extracted HTML or None if extraction failed.
        """
        raw = str(args_str or "")
        if len(raw) < 200:
            return None

        # Look for "content": "..." pattern in the truncated JSON
        # The JSON string has escaped quotes, newlines, etc.
        match = re.search(r'"content"\s*:\s*"', raw)
        if not match:
            return None

        html_start = match.end()
        # Everything after "content": " is the HTML (still JSON-escaped)
        json_escaped_html = raw[html_start:]

        # Remove trailing incomplete JSON (may end with \", unfinished tag, etc.)
        # Strip any trailing unescaped quote + JSON structure
        if json_escaped_html.endswith('"'):
            json_escaped_html = json_escaped_html[:-1]

        # Un-escape JSON string encoding
        try:
            # Wrap in quotes and parse as a JSON string to properly un-escape
            # Add closing quote since the original was truncated
            unescaped = json.loads('"' + json_escaped_html + '"')
        except (json.JSONDecodeError, ValueError):
            # Manual fallback for common escape sequences
            unescaped = json_escaped_html
            unescaped = unescaped.replace('\\"', '"')
            unescaped = unescaped.replace('\\n', '\n')
            unescaped = unescaped.replace('\\t', '\t')
            unescaped = unescaped.replace('\\\\', '\\')

        # Validate it looks like HTML
        lower = unescaped.lower()
        if '<html' not in lower and '<!doctype' not in lower and '<head' not in lower:
            return None

        return unescaped

    def _script_tag_balance_issues(self, text: str) -> tuple[int, int]:
        blob = str(text or "")
        if not blob:
            return 0, 0
        depth = 0
        stray_closers = 0
        token_re = re.compile(r"<script\b[^>]*>|</script\s*>", re.IGNORECASE)
        for match in token_re.finditer(blob):
            token = str(match.group(0) or "").lower()
            if token.startswith("</script"):
                if depth <= 0:
                    stray_closers += 1
                else:
                    depth -= 1
            else:
                depth += 1
        return stray_closers, depth

    def _normalize_builder_text_html(
        self,
        html_content: str,
        *,
        filename: str = "index.html",
        input_data: str = "",
    ) -> str:
        normalized = str(html_content or "").strip()
        if not normalized:
            return ""

        lower = normalized.lower()
        starts = [idx for idx in (lower.find("<!doctype"), lower.find("<html")) if idx >= 0]
        if starts:
            start = min(starts)
            if start > 0:
                normalized = normalized[start:].lstrip()

        try:
            task_type = task_classifier.classify(input_data).task_type if str(input_data or "").strip() else "website"
        except Exception:
            task_type = "website"

        try:
            normalized = postprocess_generated_text(
                normalized,
                filename=filename,
                task_type=task_type,
            )
        except Exception as exc:
            logger.warning("Failed to normalize extracted builder HTML %s: %s", filename, str(exc)[:200])
        return str(normalized or "").strip()

    def _builder_game_text_continuation_reason(self, output_text: str, input_data: str = "") -> str:
        text = str(output_text or "")
        lower = text.lower()
        if len(text) < 1000:
            return ""
        try:
            task_type = task_classifier.classify(input_data).task_type
        except Exception:
            task_type = ""
        if task_type not in ("game", "creative"):
            return ""

        has_runtime_surface = bool(re.search(
            r"<canvas\b|new\s+three\.|three\.webglrenderer|phaser\.game|pixi\.application|gamecanvas",
            lower,
            re.IGNORECASE,
        ))

        has_runtime_loop = bool(re.search(
            r"requestanimationframe|setanimationloop|ticker\.add|runrenderloop|gameloop|renderloop|updateloop|animate\s*\(",
            lower,
            re.IGNORECASE,
        ))

        body_match = re.search(r"<body\b[^>]*>(.*?)</body>", text, re.IGNORECASE | re.DOTALL)
        body_markup = body_match.group(1) if body_match else ""
        body_lower = body_markup.lower()
        has_body_tag = "<body" in lower
        body_signal_markup = bool(re.search(
            r"<canvas\b|<button\b|<main\b|<section\b|<div\b|id\s*=\s*['\"][^'\"]*(?:game|canvas|hud|menu|overlay|screen|crosshair|weapon|ammo|health|wave|score)",
            body_lower,
            re.IGNORECASE,
        ))
        if (
            not has_body_tag
            or len(body_markup.strip()) < 80
            or (not body_signal_markup and not has_runtime_loop)
        ):
            return "missing_game_shell"
        if not has_runtime_surface and bool(re.search(
            r"startgame|startbtn|playbtn|startoverlay|start-screen|startscreen|hud|weapon|ammo|health|wave|score|enemy|monster|boss|第三人称|射击|shooter|tps|fps",
            lower,
            re.IGNORECASE,
        )):
            return "missing_runtime_surface"

        stray_script_closers, missing_script_closers = self._script_tag_balance_issues(text)
        if stray_script_closers > 0 or missing_script_closers > 0:
            return "unfinished_script_block"

        inline_start_handler = bool(re.search(
            r"onclick\s*=\s*['\"][^'\"]*startgame\s*\(",
            lower,
            re.IGNORECASE,
        ))
        start_handler_defined = bool(re.search(
            r"(?:function\s+startgame\b|window\.startgame\s*=|globalthis\.startgame\s*=|self\.startgame\s*=|(?:const|let|var)\s+startgame\s*=)",
            lower,
            re.IGNORECASE,
        ))
        if inline_start_handler and not start_handler_defined:
            return "missing_start_handler"

        has_start_flow = bool(re.search(
            r"startgame|startbtn|playbtn|startoverlay|start-screen|startscreen",
            lower,
            re.IGNORECASE,
        ))
        if has_start_flow and not has_runtime_loop:
            return "missing_game_loop"

        return ""

    def _builder_game_text_continuation_prompt(self, reason: str) -> str:
        if reason == "missing_game_shell":
            return (
                "The game page shell started but the playable body markup is still incomplete. "
                "Reconstruct and output the COMPLETE merged HTML document from <!DOCTYPE html> to </html>. "
                "Reuse the existing shell as needed instead of returning only a tail fragment. "
                "The finished file must include a visible start screen, gameplay viewport/canvas, HUD, control hints, "
                "the missing runtime JavaScript, and valid closing tags. "
                "Output ONLY the HTML document, no markdown fences, no explanation."
            )
        if reason == "missing_runtime_surface":
            return (
                "The page currently has menu/style scaffolding, but the playable runtime surface is still missing. "
                "Reconstruct and output the COMPLETE merged HTML document from <!DOCTYPE html> to </html>. "
                "Keep the strongest existing menu/HUD shell, then add the gameplay viewport/canvas, runtime JavaScript, "
                "start handler, controls, requestAnimationFrame loop, and valid closing tags. "
                "Do NOT return only a CSS block or JS tail fragment. "
                "Output ONLY the HTML document, no markdown fences, no explanation."
            )
        if reason == "missing_start_handler":
            return (
                "Continue from EXACTLY where you stopped. Do NOT repeat any previous content. "
                "The HTML already references startGame()/restartGame(), but the handler code is still missing. "
                "Write the remaining JavaScript runtime, define the missing gameplay entry handlers, and finish the game loop/input logic. "
                "Output ONLY the continuation code, no markdown fences, no explanation."
            )
        if reason == "missing_game_loop":
            return (
                "Continue from EXACTLY where you stopped. Do NOT repeat any previous content. "
                "The game UI/runtime shell is present, but the gameplay loop/runtime code is still incomplete. "
                "Write the remaining JavaScript loop, state updates, and input-driven gameplay code, then finish any missing closing tags if needed. "
                "Output ONLY the continuation code, no markdown fences, no explanation."
            )
        return (
            "Continue from EXACTLY where you stopped. Do NOT repeat any previous content. "
            "You were mid-JavaScript inside a game HTML document. Continue writing the remaining "
            "runtime code and properly close any open </script>, </body>, and </html> tags. "
            "Output ONLY the continuation code, no markdown fences, no explanation."
        )

    async def _attempt_builder_game_text_continuation(
        self,
        *,
        output_text: str,
        input_data: str,
        system_prompt: str,
        continuation_count: int,
        max_continuations: int,
        request_continuation: Callable[[List[Dict[str, str]]], Any],
        on_progress,
        log_prefix: str = "Builder text-mode",
    ) -> tuple[str, int, Any]:
        text = str(output_text or "")
        if len(text) <= 1000 or continuation_count >= max_continuations:
            return text, continuation_count, None

        continuation_reason = self._builder_game_text_continuation_reason(text, input_data)
        if not continuation_reason:
            return text, continuation_count, None

        continuation_count += 1
        lower = text.lower()
        logger.info(
            "%s incomplete game runtime detected (%s): %d <script> opens, %d </script> closes — attempting continuation (attempt %d)",
            log_prefix,
            continuation_reason,
            lower.count("<script"),
            lower.count("</script>"),
            continuation_count,
        )

        cont_messages = [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": self._builder_game_text_continuation_prompt(continuation_reason)},
            {"role": "assistant", "content": text[-3000:]},
        ]
        try:
            cont_resp = await request_continuation(cont_messages)
        except Exception as cont_exc:
            logger.warning("%s continuation failed: %s", log_prefix, str(cont_exc)[:200])
            return text, continuation_count, None

        cont_content = str(getattr(cont_resp.choices[0].message, "content", "") or "").strip()
        if not cont_content or len(cont_content) <= 200:
            return text, continuation_count, cont_resp

        cont_lower = cont_content.lower()
        if "```html" in cont_lower or "<!doctype" in cont_lower or "<html" in cont_lower:
            text = cont_content
        else:
            if text and not text.endswith("\n"):
                text += "\n"
            text += cont_content
        logger.info(
            "%s continuation succeeded: +%d chars (total: %d)",
            log_prefix,
            len(cont_content),
            len(text),
        )
        await self._publish_partial_output(on_progress, text, phase="finalizing")
        return text, continuation_count, cont_resp

    def _strip_builder_plan_block(self, text: str) -> str:
        """v7.16 (maintainer 2026-04-28): strip leading <plan>...</plan> block
        from builder output before HTML extraction. Per the new
        thinking_gate_v7_16 contract, builder MUST emit a ≤220-char plan
        block grounding tech / files / controls / risk before the actual
        HTML. The orchestrator removes it from saved artifacts so the
        plan is reasoning-only metadata, not content. Hard cap: if the
        block exceeds 320 chars it's clearly narration abuse — strip and
        log a warning."""
        if not text:
            return text
        import re as _re_v716
        m = _re_v716.match(r"\s*<plan>(.{0,3000}?)</plan>\s*", text, _re_v716.DOTALL)
        if not m:
            return text
        plan_body = m.group(1) or ""
        if len(plan_body) > 320:
            logger.warning(
                "[v7.16] builder <plan> block exceeded 320 chars (%d) — likely narration abuse",
                len(plan_body),
            )
        # Drop the matched prefix (whole `<plan>...</plan>` + surrounding whitespace).
        return text[m.end():]

    def _extract_html_files_from_text_output(
        self, output_text: str, input_data: str = ""
    ) -> Dict[str, str]:
        """Extract HTML files from builder text output (markdown code blocks).

        When Kimi K2.5 outputs HTML as markdown instead of calling file_ops,
        the output_text contains code blocks like:

            ```html index.html
            <!DOCTYPE html>
            <html>...
            ```

        This method parses all such blocks and returns {filename: html_content}.
        """
        # v7.16: strip <plan> block before extracting HTML.
        text = self._strip_builder_plan_block(str(output_text or ""))
        if len(text) < 120:
            return {}

        files: Dict[str, str] = {}
        assigned_targets = self._builder_assigned_html_targets(input_data)
        default_filename = assigned_targets[0] if assigned_targets else ""
        input_lower = str(input_data or "").lower()
        forbid_implicit_root_html = any(
            marker in input_lower
            for marker in (
                "do not overwrite /tmp/evermind_output/index.html",
                "do not write /tmp/evermind_output/index.html",
                "do not emit index.html",
                "if index.html is not in your assigned list, do not touch it",
                "your lane owns support js/css/json modules first, not a root index.html rewrite",
            )
        )

        # Pattern 1: ```html filename.html\n...\n```
        # Pattern 2: ```html\n...\n``` (no filename → default to index.html)
        pattern = re.compile(
            r"```(?:html?|htm)\s*([A-Za-z0-9._/-]*\.html?)?\s*\n(.*?)```",
            re.DOTALL | re.IGNORECASE,
        )
        for match in pattern.finditer(text):
            filename = (match.group(1) or "").strip()
            content = match.group(2).strip()
            if not content or len(content) < 120:
                continue
            content_lower = content.lower()
            if '<html' not in content_lower and '<!doctype' not in content_lower:
                continue
            if not filename:
                if forbid_implicit_root_html or not default_filename:
                    continue
                filename = default_filename
            # Sanitize filename
            filename = Path(filename).name
            if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._-]*\.html?", filename, re.IGNORECASE):
                if forbid_implicit_root_html or not default_filename:
                    continue
                filename = default_filename
            normalized = self._normalize_builder_text_html(
                content,
                filename=filename,
                input_data=input_data,
            )
            if normalized and len(normalized) >= 120:
                files[filename] = normalized

        # Also accept a trailing open named block when the stream was cut off
        # after starting ```html index.html but before the closing fence.
        for block in self._builder_named_code_blocks(text):
            lang = str(block.get("lang") or "").strip().lower()
            if lang not in {"html", "htm"}:
                continue
            filename = Path(str(block.get("filename") or "index.html").strip() or "index.html").name
            content = str(block.get("code") or "").strip()
            if not content or len(content) < 120:
                continue
            content_lower = content.lower()
            if "<html" not in content_lower and "<!doctype" not in content_lower:
                continue
            if not re.fullmatch(r"[A-Za-z0-9][A-Za-z0-9._-]*\.html?", filename, re.IGNORECASE):
                if forbid_implicit_root_html or not default_filename:
                    continue
                filename = default_filename
            normalized = self._normalize_builder_text_html(
                content,
                filename=filename,
                input_data=input_data,
            )
            if normalized and len(normalized) >= 120:
                existing = files.get(filename, "")
                if len(normalized) > len(existing):
                    files[filename] = normalized

        # Fallback: if no code blocks found but text itself looks like raw HTML
        if not files:
            stripped = text.strip()
            stripped_lower = stripped.lower()
            # v6.1.3 (maintainer 2026-04-18 builder2 zero-files bug): peer builder
            # in direct_text mode sometimes emits 58K chars with <!DOCTYPE> /
            # <html> but without an explicit <body> tag (HTML5 makes <body>
            # implicit; models occasionally skip it when dumping pure
            # <canvas> + <script> games). Previously rejected → 0 files.
            # Relax the body requirement for very long HTML-ish outputs.
            has_html_marker = '<html' in stripped_lower or '<!doctype' in stripped_lower
            has_body = '<body' in stripped_lower
            has_substantive_content = has_body or (
                len(stripped) > 5000
                and ('<canvas' in stripped_lower
                     or '<div' in stripped_lower
                     or '<main' in stripped_lower
                     or '<script' in stripped_lower)
            )
            if has_html_marker and has_substantive_content and len(stripped) > 1000:
                fallback_filename = default_filename
                if not fallback_filename and not forbid_implicit_root_html:
                    fallback_filename = "index.html"
                # P1 FIX (Opus): Trim any leading non-HTML text (e.g. system prompt
                # leakage, markdown preamble) before the actual HTML starts.
                html_start = -1
                for marker in ('<!doctype', '<!DOCTYPE', '<html', '<HTML'):
                    pos = stripped.find(marker)
                    if pos >= 0 and (html_start < 0 or pos < html_start):
                        html_start = pos
                if html_start > 0:
                    stripped = stripped[html_start:]
                if forbid_implicit_root_html or not fallback_filename:
                    return files
                normalized = self._normalize_builder_text_html(
                    stripped,
                    filename=fallback_filename,
                    input_data=input_data,
                )
                if normalized and len(normalized) >= 120:
                    files[fallback_filename] = normalized

        if files:
            logger.info(
                "Extracted %s HTML files from builder text output: %s",
                len(files),
                {k: len(v) for k, v in files.items()},
            )
        return files

    def _builder_tool_result_salvage_text(
        self,
        tool_results: List[Dict[str, Any]],
        input_data: str = "",
    ) -> str:
        """Recover HTML from file_ops read results when the builder never lands a real write."""
        if not tool_results:
            return ""

        assigned_targets = self._builder_assigned_html_targets(input_data)
        html_by_name: Dict[str, str] = {}

        for result in tool_results[-12:]:
            if not isinstance(result, dict):
                continue
            data = result.get("data")
            if not isinstance(data, dict):
                continue
            path = str(data.get("path") or "").strip()
            content = str(data.get("content") or "").strip()
            if not path or not content or len(content) < 80:
                continue
            normalized_path = path.replace("\\", "/")
            if "evermind_output" not in normalized_path:
                continue
            filename = Path(path).name
            if Path(filename).suffix.lower() not in (".html", ".htm"):
                continue
            lower = content.lower()
            if "<!doctype" not in lower and "<html" not in lower:
                continue
            existing = html_by_name.get(filename, "")
            if len(content) > len(existing):
                html_by_name[filename] = content

        if not html_by_name:
            return ""

        ordered_names: List[str] = []
        for name in assigned_targets:
            if name in html_by_name and name not in ordered_names:
                ordered_names.append(name)
        for name in sorted(html_by_name):
            if name not in ordered_names:
                ordered_names.append(name)

        return "\n\n".join(
            f"```html {name}\n{html_by_name[name].strip()}\n```"
            for name in ordered_names
            if str(html_by_name.get(name) or "").strip()
        )

    def _builder_stream_tool_call_salvage_text(
        self,
        tool_calls_map: Dict[Any, Dict[str, Any]],
        input_data: str = "",
    ) -> str:
        if not tool_calls_map:
            return ""

        assigned_targets = self._builder_assigned_html_targets(input_data)
        html_by_name: Dict[str, str] = {}

        for key in sorted(tool_calls_map.keys(), key=lambda item: str(item)):
            tc_data = tool_calls_map.get(key) or {}
            fn = tc_data.get("function") if isinstance(tc_data, dict) else {}
            fn_name = str((fn or {}).get("name") or "").strip().lower()
            if fn_name not in {"file_ops", "write_file", "write"}:
                continue
            raw_args = str((fn or {}).get("arguments") or "")
            if len(raw_args) < 24:
                continue

            parsed = self._safe_json_object(raw_args)
            path = str(parsed.get("path") or "").strip()
            content = str(parsed.get("content") or "").strip()
            html = ""
            if path.lower().endswith((".html", ".htm")) and self._builder_partial_text_is_salvageable(input_data, content):
                html = content
            else:
                extracted = self._extract_html_from_truncated_tool_args(raw_args)
                if extracted and self._builder_partial_text_is_salvageable(input_data, extracted):
                    html = extracted
            if not html:
                continue

            filename = Path(path).name if path else ""
            if not filename.lower().endswith((".html", ".htm")):
                filename = assigned_targets[0] if len(assigned_targets) == 1 else "index.html"
            existing = html_by_name.get(filename, "")
            if len(html) > len(existing):
                html_by_name[filename] = html.strip()

        if not html_by_name:
            return ""

        ordered_names: List[str] = []
        for name in assigned_targets:
            if name in html_by_name and name not in ordered_names:
                ordered_names.append(name)
        for name in sorted(html_by_name):
            if name not in ordered_names:
                ordered_names.append(name)

        return "\n\n".join(
            f"```html {name}\n{html_by_name[name].strip()}\n```"
            for name in ordered_names
            if str(html_by_name.get(name) or "").strip()
        )

    def _builder_fragment_looks_incremental(self, output_text: str) -> bool:
        text = str(output_text or "").strip()
        if len(text) < 120:
            return False
        lower = text.lower()
        if "```html" in lower or "<!doctype" in lower or "<html" in lower:
            return False
        return bool(re.search(
            r"<(?:section|div|main|canvas|button|script|style)\b|"
            r"(?:background|color|font-size|font-weight|letter-spacing|position|display|padding|margin|transition|text-transform)\s*:"
            r"|requestanimationframe|function\s+\w+\s*\(|const\s+\w+\s*=",
            text,
            re.IGNORECASE,
        ))

    def _merge_builder_fragment_with_base_html(self, base_html: str, fragment: str) -> str:
        base = str(base_html or "").strip()
        tail = str(fragment or "").strip()
        if len(base) < 200 or not self._builder_fragment_looks_incremental(tail):
            return ""
        base_lower = base.lower()
        if "<!doctype" not in base_lower and "<html" not in base_lower:
            return ""

        merged = base
        if re.search(r"</style>\s*</head>\s*<body\b[^>]*>\s*</body>\s*</html>\s*$", merged, re.IGNORECASE | re.DOTALL):
            merged = re.sub(
                r"</style>\s*</head>\s*<body\b[^>]*>\s*</body>\s*</html>\s*$",
                "",
                merged,
                flags=re.IGNORECASE | re.DOTALL,
            )
        elif re.search(r"</script>\s*</body>\s*</html>\s*$", merged, re.IGNORECASE | re.DOTALL):
            merged = re.sub(
                r"</script>\s*</body>\s*</html>\s*$",
                "",
                merged,
                flags=re.IGNORECASE | re.DOTALL,
            )
        elif (
            re.search(r"<body\b[^>]*>\s*</body>\s*</html>\s*$", merged, re.IGNORECASE | re.DOTALL)
            and re.search(r"<(?:section|div|main|canvas|button|script)\b", tail, re.IGNORECASE)
        ):
            merged = re.sub(r"</body>\s*</html>\s*$", "", merged, flags=re.IGNORECASE | re.DOTALL)
        elif re.search(r"</html>\s*$", merged, re.IGNORECASE):
            merged = re.sub(r"</html>\s*$", "", merged, flags=re.IGNORECASE)

        if merged and not merged.endswith("\n"):
            merged += "\n"
        return merged + tail

    def _builder_disk_salvage_text(
        self,
        input_data: str = "",
        *,
        incremental_text: str = "",
    ) -> str:
        if not self._builder_fragment_looks_incremental(incremental_text):
            return ""

        output_dir = Path(self._current_output_dir())
        if not output_dir.exists():
            return ""

        assigned_targets = self._builder_assigned_html_targets(input_data)
        candidate_names: List[str] = []
        for name in assigned_targets:
            if name not in candidate_names:
                candidate_names.append(name)
        if not candidate_names:
            for path in sorted(output_dir.glob("*.htm*")):
                if path.is_file() and not path.name.startswith("_") and path.name not in candidate_names:
                    candidate_names.append(path.name)

        if not candidate_names:
            return ""

        html_by_name: Dict[str, str] = {}
        for name in candidate_names[:4]:
            path = output_dir / name
            if not path.exists() or not path.is_file():
                continue
            try:
                content = path.read_text(encoding="utf-8")
            except Exception:
                continue
            if len(content.strip()) < 80:
                continue
            merged = self._merge_builder_fragment_with_base_html(content, incremental_text)
            candidate = merged
            if not candidate:
                continue
            lower = candidate.lower()
            if "<!doctype" not in lower and "<html" not in lower:
                continue
            existing = html_by_name.get(name, "")
            if len(candidate) > len(existing):
                html_by_name[name] = candidate

        if not html_by_name:
            return ""

        ordered_names = [name for name in candidate_names if name in html_by_name]
        return "\n\n".join(
            f"```html {name}\n{html_by_name[name].strip()}\n```"
            for name in ordered_names
            if str(html_by_name.get(name) or "").strip()
        )

    def _select_builder_salvage_text(
        self,
        latest_stream_text: str,
        output_text: str,
        recovered_html: Optional[str] = None,
        tool_result_text: str = "",
    ) -> str:
        """Prefer the fullest salvage candidate, especially recovered HTML from truncated tool calls."""
        latest = str(latest_stream_text or "").strip()
        output = str(output_text or "").strip()
        recovered = str(recovered_html or "").strip()
        tool_result = str(tool_result_text or "").strip()

        def _looks_like_html(text: str) -> bool:
            lower = text.lower()
            return "<!doctype" in lower or "<html" in lower or "<body" in lower or "```html" in lower

        def _body_signal_score(text: str) -> int:
            lower = text.lower()
            score = 0
            for token in ("<body", "<main", "<canvas", "<section", "<button", "<h1", "hud", "start", "play"):
                if token in lower:
                    score += 1
            return score

        best = ""
        best_rank = (-1, -1, -1, -1)
        for candidate in (latest, output, recovered, tool_result):
            if not candidate:
                continue
            lower = candidate.lower()
            rank = (
                1 if _looks_like_html(candidate) else 0,
                _body_signal_score(candidate),
                1 if "</html>" in lower else 0,
                len(candidate),
            )
            if rank > best_rank:
                best = candidate
                best_rank = rank
        return best

    async def _builder_partial_text_salvage_result(
        self,
        *,
        node: Optional[Dict[str, Any]] = None,
        input_data: str,
        output_text: str,
        reason: str,
        on_progress,
        tool_results: List[Dict[str, Any]],
        model_name: str,
        mode: str,
        usage: Any = None,
        cost: Optional[float] = None,
        tool_call_stats: Optional[Dict[str, int]] = None,
    ) -> Optional[Dict[str, Any]]:
        tool_result_text = self._builder_tool_result_salvage_text(tool_results, input_data)
        enriched_output = self._select_builder_salvage_text(
            "",
            output_text,
            tool_result_text=tool_result_text,
        )
        if not self._builder_partial_text_is_salvageable(input_data, enriched_output):
            return None
        if not self._builder_text_output_has_persistable_html(enriched_output, input_data):
            logger.info(
                "Skipping builder partial text salvage promotion: recovered HTML is still too thin/incomplete",
            )
            return None
        if on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "builder_timeout_salvage",
                "reason": str(reason or "partial_text_timeout"),
            })
        await self._publish_partial_output(on_progress, enriched_output, phase="finalizing")
        logger.info(
            "Salvaging builder partial text after timeout/fallback failure (%s chars, reason=%s)",
            len(str(enriched_output or "")),
            _sanitize_error(str(reason or ""))[:160],
        )
        await self._auto_save_builder_text_output(
            output_text=enriched_output,
            input_data=input_data,
            node=node,
            tool_results=tool_results,
            tool_call_stats=tool_call_stats,
            on_progress=on_progress,
        )
        payload: Dict[str, Any] = {
            "success": True,
            "output": enriched_output,
            "tool_results": tool_results,
            "model": model_name,
            "mode": mode,
            "tool_call_stats": dict(tool_call_stats or {}),
        }
        if usage is not None:
            payload["usage"] = usage
        if cost is not None:
            payload["cost"] = cost
        return payload

    def _builder_tool_repair_prompt(self, input_data: str, tool_action: str, result: Any) -> Optional[str]:
        if not isinstance(result, dict) or bool(result.get("success")):
            return None
        error = str(result.get("error") or "").strip()
        if not error:
            return None

        output_dir = self._current_output_dir().rstrip("/")
        assigned_targets = self._builder_assigned_html_targets(input_data)
        support_lane = self._builder_is_support_lane(input_data) and not assigned_targets
        assigned_line = (
            "Assigned HTML filenames: " + ", ".join(assigned_targets) + ". "
            if assigned_targets else
            ""
        )
        output_path_line = ""
        if assigned_targets:
            output_path_line = (
                "Exact runtime output paths: "
                + ", ".join(f"{output_dir}/{name}" for name in assigned_targets[:8])
                + ". "
            )

        if support_lane:
            if "html target not assigned" in error.lower():
                return self._builder_support_lane_write_prompt(
                    input_data,
                    opener="Your previous write targeted an HTML file that is not assigned to this lane and not in your assigned list.",
                    note="Stay on support files only.",
                )
            if (
                "shipped html write rejected" in error.lower()
                or "lacks a usable game slice" in error.lower()
                or "incomplete for a game deliverable" in error.lower()
                or "too short to trust as a final artifact" in error.lower()
                or "body lacks meaningful visible content" in error.lower()
            ):
                return self._builder_support_lane_write_prompt(
                    input_data,
                    opener="Stop attempting a playable root HTML rewrite in this lane.",
                    note="Repair the assigned subsystem through support files instead.",
                )
            if "Path not allowed by security policy" in error or "blank path is not allowed" in error.lower():
                return self._builder_support_lane_write_prompt(
                    input_data,
                    opener="Your previous file_ops call failed because the path was blank or invalid.",
                    note="Retry immediately with explicit absolute support-file paths.",
                )
            if tool_action == "read" and error.startswith("File not found:"):
                return self._builder_support_lane_write_prompt(
                    input_data,
                    opener="The support file you tried to read does not exist yet.",
                    note="Create it now instead of probing missing files.",
                )

        if "html target not assigned" in error.lower():
            return (
                "Your previous file_ops write targeted an HTML file that is not assigned to you. "
                f"{assigned_line}"
                f"{output_path_line}"
                f"Write ONLY those exact HTML filenames under {output_dir}/. "
                "If index.html is not in your assigned list, do not touch it. "
                "Retry immediately with file_ops write for the missing assigned pages only."
            )

        if (
            "shipped html write rejected" in error.lower()
            or "lacks a usable game slice" in error.lower()
            or "incomplete for a game deliverable" in error.lower()
            or "too short to trust as a final artifact" in error.lower()
            or "body lacks meaningful visible content" in error.lower()
        ):
            primary_target = assigned_targets[0] if assigned_targets else "index.html"
            try:
                task_type = task_classifier.classify(input_data).task_type
            except Exception:
                task_type = ""
            delivery_note = (
                "Write a complete playable game slice now: include a visible start/play flow, a gameplay surface "
                "(canvas/scene/viewport), live input binding, and a running requestAnimationFrame loop or equivalent runtime hook. "
                if task_type == "game" else
                "Overwrite the same assigned page with a complete standalone final page, not a thin shell or off-topic placeholder. "
            )
            return (
                "Your previous HTML write was rejected by the runtime guard. "
                f"{assigned_line}"
                f"{output_path_line}"
                f"Overwrite {output_dir}/{primary_target} immediately via file_ops write. "
                f"{delivery_note}"
                "Do not inspect again. Do not return prose before the corrected write."
            )

        if "Path not allowed by security policy" in error or "blank path is not allowed" in error.lower():
            # Dynamically discover existing HTML files on disk to give the model concrete targets
            disk_hint = ""
            try:
                from pathlib import Path as _P
                output_path = _P(output_dir)
                if output_path.exists():
                    existing = sorted(
                        f.name for f in output_path.glob("*.htm*")
                        if f.is_file() and not f.name.startswith("_")
                    )
                    if existing:
                        disk_hint = (
                            "Existing HTML files on disk: "
                            + ", ".join(f"{output_dir}/{name}" for name in existing[:10])
                            + ". "
                        )
            except Exception:
                pass
            return (
                "Your previous file_ops call failed because the path was blank or invalid. "
                "STOP reading or listing. You MUST write HTML files NOW. "
                f"Retry IMMEDIATELY with file_ops write using explicit absolute paths under {output_dir}/. "
                f"{assigned_line}"
                f"{output_path_line}"
                f"{disk_hint}"
                f"Example: {{\"action\": \"write\", \"path\": \"{output_dir}/index.html\", \"content\": \"<!DOCTYPE html>...\"}}. "
                "Do not output prose or explanations. Save the real HTML files now."
            )

        if tool_action == "read" and error.startswith("File not found:"):
            create_target = assigned_targets[0] if assigned_targets else "index.html"
            return (
                "The file you tried to read does not exist yet. "
                f"Create it now with file_ops write at {output_dir}/{create_target}. "
                f"{assigned_line}"
                f"{output_path_line}"
                "For multi-page work, also create the remaining assigned HTML pages in the same directory. "
                "Do not keep probing missing files."
            )

        return None

    def _register_edit_failure(
        self,
        edit_failures: Dict[str, int],
        tool_action: str,
        parsed_args: Any,
        result: Any,
    ) -> tuple:
        """v6.1.12 (maintainer 2026-04-20): track consecutive file_ops edit failures.

        Returns ``(total_failures, per_path_failures, path)`` so callers can
        decide whether to:
          - inject a one-shot "abandon edit, do full write" prompt (per-path ≥ 2)
          - break the tool loop and fall through to direct_text (total ≥ 3)

        Design note: merger was observed shrinking a 73 KB Three.js HTML to
        48 KB by cycling on file_ops edit with drifted SEARCH blocks. This
        tracker lets us escape the loop without waiting for the wall-clock
        timeout. The check is conservative — only real edit-miss errors
        count, not write/permission errors.
        """
        if str(tool_action or "").strip().lower() != "edit":
            return 0, 0, ""
        if not isinstance(result, dict) or bool(result.get("success")):
            return 0, 0, ""
        err = str(result.get("error") or "").lower()
        if not err:
            return 0, 0, ""
        edit_miss = (
            "string to replace not found" in err
            or "old_string not found" in err
            or "found 0 matches" in err
            or "no match" in err
        )
        if not edit_miss:
            return 0, 0, ""
        parsed = parsed_args if isinstance(parsed_args, dict) else {}
        path = str(
            parsed.get("path")
            or parsed.get("file_path")
            or parsed.get("filename")
            or ""
        ).strip() or "<unknown>"
        try:
            edit_failures[path] = int(edit_failures.get(path, 0)) + 1
        except Exception:
            edit_failures[path] = 1
        per_path = int(edit_failures.get(path, 0))
        total = sum(int(v or 0) for v in edit_failures.values())
        return total, per_path, path

    def _edit_rewrite_escalation_prompt(self, path: str, per_path: int, total: int) -> str:
        """v6.1.12: prompt telling the model to abandon edit and do full write."""
        path_line = f"`{path}`" if path and path != "<unknown>" else "the target file"
        return (
            "Your last file_ops edit on "
            f"{path_line} missed its SEARCH block (attempt {per_path}; "
            f"{total} failed edits total this turn). STOP retrying edit — the "
            "file content no longer matches your SEARCH string. Your VERY NEXT "
            "response MUST be a single file_ops write (action=\"write\") that "
            "replaces the ENTIRE file content with the merged / patched result, "
            "reconstructed from memory + any prior successful reads. Do NOT "
            "emit another edit call. Do NOT ship a truncated or shrunken file."
        )

    def _builder_non_write_followup_prompt(
        self,
        input_data: str,
        tool_action: str,
        result: Any,
        non_write_streak: int,
    ) -> Optional[str]:
        if tool_action not in {"list", "read"}:
            return None
        if not isinstance(result, dict) or not bool(result.get("success")):
            return None
        if int(non_write_streak or 0) <= 0:
            return None

        output_dir = self._current_output_dir().rstrip("/")
        assigned_targets = self._builder_assigned_html_targets(input_data)
        merger_like = bool(re.search(r"\b(?:final merger|merger|integrator|integration|assemble|assembly|merge)\b", str(input_data or "").lower()))
        support_lane = self._builder_is_support_lane(input_data) and not assigned_targets and not merger_like
        assigned_line = (
            "Assigned HTML filenames: " + ", ".join(assigned_targets) + ". "
            if assigned_targets else
            ""
        )
        output_path_line = ""
        if assigned_targets:
            output_path_line = (
                "Exact runtime output paths: "
                + ", ".join(f"{output_dir}/{name}" for name in assigned_targets[:8])
                + ". "
            )
        if task_classifier.wants_multi_page(input_data):
            targets_line = ""
            if assigned_targets:
                targets_line = (
                    "Your next response must emit a batch of file_ops write calls that covers EVERY assigned HTML filename, "
                    "not just a single page. A one-page retry is still a failure. "
                )
            return (
                "You have already inspected the workspace. Stop listing or reading files now. "
                f"{assigned_line}"
                f"{output_path_line}"
                f"{targets_line}"
                f"Your VERY NEXT response must be one or more file_ops write calls that overwrite the final HTML pages directly under {output_dir}/. "
                "Do not browse. Do not probe more directories. Do not return prose. "
                "Overwrite the bootstrap draft files with the final routed pages now."
            )
        if support_lane:
            return self._builder_support_lane_write_prompt(
                input_data,
                opener="You have already inspected the workspace. Stop listing or reading now.",
            )
        if merger_like:
            primary_target = assigned_targets[0] if assigned_targets else "index.html"
            return (
                "You already inspected enough merger context. Stop reading now. "
                f"{assigned_line}"
                f"{output_path_line}"
                "Read the live root artifact plus each non-empty local JS/CSS/JSON support file at most once, then merge immediately. "
                f"Your VERY NEXT response must be a file_ops write that patches {output_dir}/{primary_target} and wires the retained subsystems into the shipped root. "
                "If a support subsystem is worth keeping, either wire it with browser-native <script>/<link> tags or inline the needed code into the root artifact now. "
                "Do not leave meaningful support files beside the root artifact unwired, and do not keep Node/CommonJS footers like module.exports or exports.* in shipped browser files. "
                "Do not list more directories. Do not re-read files you already inspected. Do not return prose before the merge write is saved."
            )
        primary_target = assigned_targets[0] if assigned_targets else "index.html"
        return (
            "You have already inspected the workspace. Stop reading and write the deliverable now. "
            f"{assigned_line}"
            f"{output_path_line}"
            f"Your VERY NEXT response must be a file_ops write to {output_dir}/{primary_target}. "
            "Do not return prose before the file is saved."
        )

    def _polisher_non_write_followup_prompt(
        self,
        tool_name: str,
        tool_action: str,
        result: Any,
        non_write_streak: int,
    ) -> Optional[str]:
        tool_name = str(tool_name or "").strip().lower()
        tool_action = str(tool_action or "").strip().lower()
        streak = int(non_write_streak or 0)
        if streak < 1:
            return None
        inspection_note = ""
        if tool_name == "browser":
            inspection_note = "You already have enough visual evidence from the browser. "
        elif tool_name == "file_ops" and tool_action in {"list", "read"}:
            if not isinstance(result, dict) or not bool(result.get("success")):
                return None
            inspection_note = "You have already inspected the artifact on disk. "
        elif tool_name == "file_ops" and tool_action and tool_action != "write" and streak >= 2:
            inspection_note = "Stop spending more tool turns on inspection. "
        else:
            return None

        output_dir = self._current_output_dir().rstrip("/")
        current_pages = self._current_output_html_pages()
        page_hint = (
            "Current HTML pages on disk: " + ", ".join(current_pages[:10]) + ". "
            if current_pages else
            ""
        )
        return (
            f"{inspection_note}Stop inspecting and start polishing now. "
            f"Your VERY NEXT response must contain one or more file_ops write calls to files under {output_dir}/. "
            "Start with shared files such as styles.css or app.js when possible, then patch only the specifically affected routed pages. "
            f"{page_hint}"
            "Patch the current files in place instead of re-reading the whole site. "
            "Replace blank media placeholders, gradient-only image stand-ins, empty map/location blocks, [Collection Image]-style placeholder copy, and thin motion with finished premium visuals and interactions now without rewriting strong sections. "
            "Do not browse again. Do not return prose before writing files."
        )

    def _normalize_review_preview_path(self, raw: str) -> str:
        text = str(raw or "").strip()
        if not text:
            return ""
        parsed = urlparse(text)
        path = parsed.path or text
        if "/preview/" in path:
            path = path.split("/preview/", 1)[1]
        path = path.split("#", 1)[0].split("?", 1)[0].strip()
        path = path.lstrip("/")
        if not path:
            return "index.html"
        if path.endswith("/"):
            return f"{path}index.html"
        last_segment = path.rsplit("/", 1)[-1]
        if "." not in last_segment:
            return f"{path}/index.html"
        return path

    def _current_output_html_pages(self) -> List[str]:
        output_dir = Path(self._current_output_dir())
        if not output_dir.exists():
            return []
        try:
            output_root = output_dir.resolve()
        except Exception:
            output_root = output_dir
        pages: List[str] = []
        seen: set[str] = set()
        for path in sorted(output_dir.rglob("*")):
            if not path.is_file() or path.suffix.lower() not in {".html", ".htm"}:
                continue
            try:
                rel_path = path.resolve().relative_to(output_root)
            except Exception:
                rel_path = Path(path.name)
            if rel_path.parts and rel_path.parts[0] == "_stable_previews":
                continue
            normalized = self._normalize_review_preview_path(str(rel_path))
            name = Path(normalized).name
            if (
                not normalized
                or normalized in seen
                or name.startswith("_")
                or re.fullmatch(r"index_part\d+\.html?", name, re.IGNORECASE)
            ):
                continue
            seen.add(normalized)
            pages.append(normalized)
        pages.sort(key=lambda item: (item != "index.html", item))
        return pages

    def _classify_task_type(self, prompt_source: str) -> str:
        source = str(prompt_source or "").strip()
        if not source:
            return "website"
        # v6.0 FIX: builder's input_data concatenates the user goal with
        # harness reference blocks ("GAME/INTERACTIVE section...", "Game-tier
        # polish..."). Those harness blocks contain the literal word "game"
        # / "Game" / "interactive", which triggers task_classifier's game
        # pattern (case-insensitive) and mis-classifies a "Hello landing
        # page" as a game task. Quality gate then rejects the output because
        # it "lacks a usable game slice". Root cause: harness template words
        # leak into classification.
        # Strip everything after a reference-material separator so we only
        # classify the user's actual ask.
        import re as _re
        _separators = (
            r"\n*===\s*REFERENCE\b",
            r"\n*===\s*HARNESS\b",
            r"\n*\n---\s+HARNESS\b",
            r"\n*\[BUILDER_",
            r"\n*GAME/INTERACTIVE",
            r"\n*=== BUILDER",
        )
        trimmed = source
        for sep in _separators:
            m = _re.search(sep, trimmed, _re.IGNORECASE)
            if m:
                trimmed = trimmed[: m.start()].strip() or trimmed
        # Keep only the first ~800 chars of the user intent — enough for
        # pattern matching, small enough that stray harness keywords in a
        # big injection can't leak in.
        trimmed = trimmed[:800] if trimmed else source[:800]
        try:
            return task_classifier.classify(trimmed).task_type
        except Exception:
            return "website"

    def _tool_names_from_defs(self, tools: Any) -> set[str]:
        names: set[str] = set()
        for tool in tools or []:
            name = ""
            if isinstance(tool, dict):
                if str(tool.get("type") or "").strip().lower() == "function":
                    fn = tool.get("function")
                    if isinstance(fn, dict):
                        name = str(fn.get("name") or "").strip().lower()
                else:
                    name = str(tool.get("name") or "").strip().lower()
            else:
                fn = getattr(tool, "function", None)
                if fn is not None:
                    name = str(getattr(fn, "name", "") or "").strip().lower()
                if not name:
                    name = str(getattr(tool, "name", "") or "").strip().lower()
            if name:
                names.add(name)
        return names

    def _tool_results_reference_urls(self, tool_results: Any) -> List[str]:
        urls: List[str] = []
        for result in tool_results or []:
            if not isinstance(result, dict):
                continue
            data = result.get("data")
            if not isinstance(data, dict):
                continue
            candidates: List[str] = []
            for key in ("url", "final_url"):
                value = str(data.get(key) or "").strip()
                if value:
                    candidates.append(value)
            for key in ("urls", "visited_urls"):
                raw = data.get(key)
                if isinstance(raw, list):
                    candidates.extend(str(item).strip() for item in raw if str(item).strip())
            for candidate in candidates:
                if self._is_local_preview_or_nonweb_url(candidate):
                    continue
                if candidate and candidate not in urls:
                    urls.append(candidate)
        return urls

    def _node_execution_strategy_prompt_block(self, node: Optional[Dict[str, Any]]) -> str:
        block = str((node or {}).get("model_execution_strategy_block") or "").strip()
        if not block:
            return ""
        return f"\n\nMODEL-CAPABILITY EXECUTION STRATEGY:\n{block}"

    def _is_local_preview_or_nonweb_url(self, candidate: str) -> bool:
        text = str(candidate or "").strip()
        if not text:
            return True
        parsed = urlparse(text)
        scheme = str(parsed.scheme or "").strip().lower()
        host = str(parsed.hostname or "").strip().lower()
        path = str(parsed.path or "").strip().lower()
        if scheme and scheme not in {"http", "https"}:
            return True
        if host in {"127.0.0.1", "localhost", "0.0.0.0", "::1"}:
            return True
        return path.startswith("/preview") or "/preview/" in path

    def _analyst_browser_followup_reason(
        self,
        node_type: str,
        tool_call_stats: Dict[str, int],
        tool_results: List[Dict[str, Any]],
        available_tool_names: Optional[set[str]] = None,
    ) -> Optional[str]:
        if normalize_node_role(node_type) != "analyst":
            return None
        available_names = {
            str(item or "").strip()
            for item in (available_tool_names or set())
            if str(item or "").strip()
        }
        research_tools = {"browser", "source_fetch"} & available_names
        if not research_tools:
            return None
        research_calls = sum(int(tool_call_stats.get(tool_name, 0) or 0) for tool_name in research_tools)
        visited_urls = self._tool_results_reference_urls(tool_results)
        if research_calls < 1 or not visited_urls:
            return "You must use source_fetch or browser on at least 2 different source URLs before final report."
        if len(visited_urls) < 2:
            return (
                "You have only visited 1 source URL. "
                "Use source_fetch or browser on one more distinct GitHub/doc/tutorial/source page before final report."
            )
        return None

    def _analyst_browser_followup_message(self, reason: str) -> str:
        reason_text = str(reason or "").strip()
        lower = reason_text.lower()
        action_hint = (
            'Call source_fetch now on an implementation-grade source such as a GitHub repo README/blob file, docs page, '
            'tutorial, or postmortem; use browser only if the page needs interaction. Visit 2 distinct URLs total before finalizing. '
            'Do NOT open localhost or /preview/ pages for analyst research.'
        )
        if "1 source url" in lower or "one more distinct" in lower:
            action_hint = (
                'Call source_fetch or browser on one more distinct URL now, preferably a GitHub repo, official docs page, '
                'or technical tutorial that materially informs implementation. '
                'Do NOT open localhost or /preview/ pages.'
            )
        return (
            "Your research pass is incomplete.\n"
            f"Missing requirement: {reason_text}\n"
            f"{action_hint}\n"
            "Do not output the final analyst report yet. Browse first, then finalize with the visited URLs listed."
        )

    def _asset_plan_output_complete(self, node_type: str, output_text: str) -> bool:
        normalized = normalize_node_role(node_type)
        text = str(output_text or "").strip()
        if normalized not in {"spritesheet", "assetimport"} or len(text) < 80:
            return False

        candidate_chunks: List[str] = []
        json_start = text.find("{")
        json_end = text.rfind("}") + 1
        if json_start >= 0 and json_end > json_start:
            candidate_chunks.append(text[json_start:json_end])
        candidate_chunks.append(text)

        parsed_obj: Optional[Dict[str, Any]] = None
        for candidate in candidate_chunks:
            try:
                parsed = json.loads(candidate)
            except Exception:
                parsed = None
                if _json_repair_fn:
                    try:
                        repaired = _json_repair_fn(candidate)
                        if isinstance(repaired, str):
                            repaired = json.loads(repaired)
                        parsed = repaired
                    except Exception:
                        parsed = None
            if isinstance(parsed, dict):
                parsed_obj = parsed
                break

        if not isinstance(parsed_obj, dict):
            return False

        non_empty_keys = {
            str(key).strip()
            for key, value in parsed_obj.items()
            if str(key).strip() and value not in (None, "", [], {})
        }
        if len(non_empty_keys) < 4:
            return False

        if normalized == "spritesheet":
            has_targets = bool({"asset_families", "model_targets"} & non_empty_keys)
            has_rules = bool({"builder_replacement_rules", "style_lock_tokens"} & non_empty_keys)
            has_material = bool({"material_constraints", "material_rules"} & non_empty_keys)
            return has_targets and has_rules and has_material

        has_mapping = bool({"runtime_mapping", "manifest_fields"} & non_empty_keys)
        has_replacements = bool({"replacement_keys", "builder_integration_notes"} & non_empty_keys)
        has_fallbacks = bool({"placeholder_fallbacks", "folder_structure", "naming_rules"} & non_empty_keys)
        return has_mapping and has_replacements and has_fallbacks

    def _browser_use_enabled_for_qa(self) -> bool:
        raw = self.config.get("qa_enable_browser_use", os.getenv("EVERMIND_QA_ENABLE_BROWSER_USE", "0"))
        return str(raw or "").strip().lower() in {"1", "true", "yes", "on"}

    def _browser_use_force_for_games(self) -> bool:
        raw = self.config.get(
            "qa_force_browser_use_for_games",
            os.getenv("EVERMIND_QA_FORCE_BROWSER_USE_FOR_GAMES", "0"),
        )
        return str(raw or "").strip().lower() in {"1", "true", "yes", "on"}

    def _qa_browser_use_available(self, node_type: str, available_tool_names: set[str]) -> bool:
        normalized = normalize_node_role(node_type)
        return (
            normalized in {"reviewer", "tester"}
            and is_qa_browser_use_enabled(config=self.config)
            and "browser_use" in (available_tool_names or set())
        )

    def _qa_browser_use_required(
        self,
        node_type: str,
        task_type: str,
        available_tool_names: set[str],
    ) -> bool:
        return (
            self._qa_browser_use_available(node_type, available_tool_names)
            and task_type == "game"
            and self._browser_use_force_for_games()
        )

    def _qa_browser_prefetch_allowed(
        self,
        node_type: str,
        available_tool_names: set[str],
    ) -> bool:
        normalized = normalize_node_role(node_type)
        return normalized in {"reviewer", "tester"} and "browser" in (available_tool_names or set())

    def _browser_action_event_from_result(
        self,
        result: Dict[str, Any],
        *,
        action_name: str,
    ) -> Dict[str, Any]:
        browser_data = result.get("data", {}) if isinstance(result.get("data"), dict) else {}
        if not isinstance(browser_data, dict):
            browser_data = {}
        return {
            "action": action_name or browser_data.get("action") or "unknown",
            "subaction": browser_data.get("subaction"),
            "intent": browser_data.get("intent"),
            "ok": bool(result.get("success", False)) if isinstance(result, dict) else False,
            "url": browser_data.get("url"),
            "target": browser_data.get("target"),
            "observation": browser_data.get("observation"),
            "snapshot_refs_preview": browser_data.get("snapshot_refs_preview", []),
            "snapshot_ref_count": browser_data.get("snapshot_ref_count", 0),
            "state_hash": browser_data.get("state_hash"),
            "previous_state_hash": browser_data.get("previous_state_hash"),
            "state_changed": bool(browser_data.get("state_changed", False)),
            "scroll_y": browser_data.get("scroll_y", 0),
            "viewport_height": browser_data.get("viewport_height", 0),
            "page_height": browser_data.get("page_height", 0),
            "at_page_top": bool(browser_data.get("at_page_top", False)),
            "at_page_bottom": bool(browser_data.get("at_page_bottom", False)),
            "keys_count": browser_data.get("keys_count", 0),
            "console_error_count": browser_data.get("console_error_count", 0),
            "page_error_count": browser_data.get("page_error_count", 0),
            "failed_request_count": browser_data.get("failed_request_count", 0),
            "recent_console_errors": browser_data.get("recent_console_errors", []),
            "recent_page_errors": browser_data.get("recent_page_errors", []),
            "browser_mode": browser_data.get("browser_mode"),
            "requested_mode": browser_data.get("requested_mode"),
            "launch_note": browser_data.get("launch_note"),
            "recording_path": browser_data.get("recording_path"),
            "capture_path": browser_data.get("capture_path"),
            "error": (result.get("error") if isinstance(result, dict) else "") or "",
        }

    def _tool_execution_progress_payload(self, fn_name: str, parsed_args: Dict[str, Any]) -> Dict[str, Any]:
        payload: Dict[str, Any] = {"stage": "executing_plugin", "plugin": fn_name}
        args = parsed_args if isinstance(parsed_args, dict) else {}
        if fn_name == "file_ops":
            action = str(args.get("action", "")).strip().lower()
            if action:
                payload["tool_action"] = action
            path = (
                args.get("path")
                or args.get("target")
                or args.get("dest")
                or args.get("output_path")
            )
            if str(path or "").strip():
                payload["path"] = str(path).strip()
            else:
                raw_paths = args.get("paths")
                if isinstance(raw_paths, list):
                    payload["paths"] = [str(item).strip() for item in raw_paths[:6] if str(item or "").strip()]
        elif fn_name == "source_fetch":
            mode = str(args.get("mode", "")).strip().lower()
            if mode:
                payload["tool_action"] = mode
            query = str(args.get("query", "")).strip()
            if query:
                payload["query"] = query[:200]
            url = str(args.get("url", "")).strip()
            if url:
                payload["url"] = url
            raw_urls = args.get("urls")
            if isinstance(raw_urls, list):
                payload["urls"] = [str(item).strip() for item in raw_urls[:6] if str(item or "").strip()]
        else:
            action = str(args.get("action", "")).strip().lower()
            if action:
                payload["tool_action"] = action
            url = str(args.get("url", "")).strip()
            if url:
                payload["url"] = url
            target = str(args.get("target", "")).strip()
            if target:
                payload["target"] = target[:200]
        return payload

    def _normalize_browser_use_action_name(self, raw: Any) -> str:
        lowered = str(raw or "").strip().lower().replace("-", "_")
        if not lowered:
            return ""
        mapping = {
            "click_element": "click",
            "click": "click",
            "input_text": "fill",
            "fill": "fill",
            "send_keys": "press_sequence",
            "press_keys": "press_sequence",
            "keyboard": "press_sequence",
            "scroll": "scroll",
            "navigate": "navigate",
            "open_tab": "navigate",
            "go_to_url": "navigate",
            "extract_content": "observe",
            "wait": "wait_for",
            "done": "done",
        }
        return mapping.get(lowered, lowered)

    def _browser_use_state_hash(self, url: str, capture_path: str, step: int) -> str:
        payload = f"{url}|{capture_path}|{step}"
        return hashlib.md5(payload.encode("utf-8", errors="ignore")).hexdigest()

    def _browser_use_action_events(self, result: Dict[str, Any]) -> List[Dict[str, Any]]:
        if not isinstance(result, dict):
            return []
        browser_data = result.get("data", {}) if isinstance(result.get("data"), dict) else {}
        if not isinstance(browser_data, dict):
            browser_data = {}
        history_items = browser_data.get("history_items")
        if not isinstance(history_items, list):
            history_items = []
        screenshot_paths = [
            str(item).strip()
            for item in (browser_data.get("screenshot_paths") or [])
            if str(item).strip()
        ]
        urls = [
            str(item).strip()
            for item in (browser_data.get("urls") or [])
            if str(item).strip()
        ]
        base_url = str(browser_data.get("final_url") or browser_data.get("url") or "").strip()
        capture_path = str(browser_data.get("capture_path") or "").strip()
        recording_path = str(browser_data.get("recording_path") or "").strip()
        browser_mode = browser_data.get("browser_mode")
        requested_mode = browser_data.get("requested_mode")
        action_names = [
            str(item).strip()
            for item in (browser_data.get("action_names") or [])
            if str(item).strip()
        ]

        events: List[Dict[str, Any]] = []
        first_snapshot_path = (
            str((history_items[0] or {}).get("screenshot_path") or "").strip()
            if history_items and isinstance(history_items[0], dict)
            else ""
        ) or (screenshot_paths[0] if screenshot_paths else capture_path)
        first_url = (
            str((history_items[0] or {}).get("url") or "").strip()
            if history_items and isinstance(history_items[0], dict)
            else ""
        ) or (urls[0] if urls else base_url)
        previous_state_hash = ""
        if first_snapshot_path or first_url:
            previous_state_hash = self._browser_use_state_hash(first_url, first_snapshot_path, 0)
            events.append({
                "action": "snapshot",
                "subaction": "",
                "intent": "observe",
                "ok": True,
                "url": first_url,
                "target": "",
                "observation": "",
                "snapshot_refs_preview": [],
                "snapshot_ref_count": 0,
                "state_hash": previous_state_hash,
                "previous_state_hash": "",
                "state_changed": False,
                "scroll_y": 0,
                "viewport_height": 0,
                "page_height": 0,
                "at_page_top": False,
                "at_page_bottom": False,
                "keys_count": 0,
                "console_error_count": 0,
                "page_error_count": 0,
                "failed_request_count": 0,
                "recent_console_errors": [],
                "recent_page_errors": [],
                "browser_mode": browser_mode,
                "requested_mode": requested_mode,
                "recording_path": recording_path,
                "capture_path": first_snapshot_path,
                "error": "",
                "plugin": "browser_use",
            })

        if not history_items and action_names:
            history_items = [
                {
                    "step": idx + 1,
                    "action_names": [name],
                    "url": urls[idx] if idx < len(urls) else (urls[-1] if urls else base_url),
                    "screenshot_path": screenshot_paths[idx] if idx < len(screenshot_paths) else (screenshot_paths[-1] if screenshot_paths else capture_path),
                    "interacted_element": None,
                    "errors": browser_data.get("errors") or [],
                }
                for idx, name in enumerate(action_names)
            ]

        for idx, item in enumerate(history_items):
            if not isinstance(item, dict):
                continue
            raw_actions = item.get("action_names") if isinstance(item.get("action_names"), list) else []
            normalized_actions = [
                self._normalize_browser_use_action_name(name)
                for name in raw_actions
                if self._normalize_browser_use_action_name(name)
            ]
            if not normalized_actions:
                continue
            item_url = str(item.get("url") or "").strip() or (urls[idx] if idx < len(urls) else "") or base_url
            item_capture = str(item.get("screenshot_path") or "").strip() or (screenshot_paths[idx] if idx < len(screenshot_paths) else "") or capture_path
            state_hash = self._browser_use_state_hash(item_url, item_capture, idx + 1)
            target = item.get("interacted_element")
            if isinstance(target, dict):
                target = json.dumps(target, ensure_ascii=False)[:240]
            elif target is None:
                target = ""
            else:
                target = str(target)[:240]
            item_errors = [
                str(entry).strip()[:240]
                for entry in (item.get("errors") or [])
                if str(entry).strip()
            ]
            state_changed = bool(previous_state_hash and state_hash != previous_state_hash)
            for action_name in normalized_actions:
                if action_name == "done":
                    continue
                effective_state_changed = state_changed or action_name in {
                    "click", "fill", "press", "press_sequence", "scroll", "navigate",
                }
                events.append({
                    "action": action_name,
                    "subaction": "",
                    "intent": action_name,
                    "ok": not bool(item_errors),
                    "url": item_url,
                    "target": target,
                    "observation": "",
                    "snapshot_refs_preview": [],
                    "snapshot_ref_count": 0,
                    "state_hash": state_hash,
                    "previous_state_hash": previous_state_hash,
                    "state_changed": effective_state_changed,
                    "scroll_y": 0,
                    "viewport_height": 0,
                    "page_height": 0,
                    "at_page_top": False,
                    "at_page_bottom": False,
                    "keys_count": 4 if action_name == "press_sequence" else (1 if action_name == "press" else 0),
                    "console_error_count": 0,
                    "page_error_count": 0,
                    "failed_request_count": 0,
                    "recent_console_errors": [],
                    "recent_page_errors": [],
                    "browser_mode": browser_mode,
                    "requested_mode": requested_mode,
                    "recording_path": recording_path,
                    "capture_path": item_capture,
                    "error": "; ".join(item_errors[:2]),
                    "plugin": "browser_use",
                })
            previous_state_hash = state_hash or previous_state_hash

        if not events and (capture_path or base_url):
            events.append({
                "action": "snapshot",
                "subaction": "",
                "intent": "observe",
                "ok": bool(result.get("success", False)),
                "url": base_url,
                "target": "",
                "observation": "",
                "snapshot_refs_preview": [],
                "snapshot_ref_count": 0,
                "state_hash": self._browser_use_state_hash(base_url, capture_path, 0),
                "previous_state_hash": "",
                "state_changed": False,
                "scroll_y": 0,
                "viewport_height": 0,
                "page_height": 0,
                "at_page_top": False,
                "at_page_bottom": False,
                "keys_count": 0,
                "console_error_count": 0,
                "page_error_count": 0,
                "failed_request_count": 0,
                "recent_console_errors": [],
                "recent_page_errors": [],
                "browser_mode": browser_mode,
                "requested_mode": requested_mode,
                "recording_path": recording_path,
                "capture_path": capture_path,
                "error": str(result.get("error") or "").strip(),
                "plugin": "browser_use",
            })
        return events

    def _qa_browser_use_prefetch_task(self, node_type: str, task_type: str, goal: str) -> str:
        normalized = normalize_node_role(node_type)
        if task_type == "game":
            qa_role = "reviewer" if normalized == "reviewer" else "tester"
            return (
                f"You are running an automated {qa_role} gameplay preflight for Evermind. "
                "Open the local preview first, inspect the visible title screen, HUD, and start controls, "
                "click the visible Start / Play / Begin control, then perform a short real gameplay session. "
                "Use Arrow keys or WASD plus Space or Enter when relevant. "
                "Verify that the visible state changes after input by checking the HUD, score, camera, scene, "
                "player position, enemy state, or restart/death state. Keep screenshots and recording evidence. "
                f"Goal context: {str(goal or '')[:220]}"
            )
        return (
            "Open the local preview, interact with the primary controls, and keep screenshot/recording evidence "
            "for downstream QA."
        )

    def _qa_browser_use_prefetch_summary(
        self,
        result: Dict[str, Any],
        browser_use_events: List[Dict[str, Any]],
        task_type: str,
    ) -> str:
        success = bool((result or {}).get("success"))
        data = result.get("data", {}) if isinstance(result.get("data"), dict) else {}
        preview_url = self._qa_default_preview_url("tester") or "http://127.0.0.1:8765/preview/"
        action_names: List[str] = []
        for event in browser_use_events or []:
            action = str(event.get("action") or "").strip()
            if action and action not in action_names:
                action_names.append(action)
        if not action_names:
            action_names = [
                str(item).strip()
                for item in (data.get("action_names") or [])
                if str(item).strip()
            ][:8]
        final_url = str(data.get("final_url") or data.get("url") or "").strip() or preview_url
        recording_path = str(data.get("recording_path") or "").strip()
        capture_path = str(data.get("capture_path") or "").strip()
        if success:
            lines = [
                "System note: a deterministic browser_use QA preflight already ran before your verdict.",
                f"- task_type: {task_type}",
                f"- final_url: {final_url}",
            ]
            if action_names:
                lines.append(f"- captured_actions: {', '.join(action_names[:8])}")
            if recording_path:
                lines.append(f"- recording_path: {recording_path}")
            if capture_path:
                lines.append(f"- capture_path: {capture_path}")
            lines.append(
                "Treat this as real interaction evidence. Use it in your scoring, and only add extra browser checks where the evidence is still incomplete."
            )
            return "\n".join(lines)

        error_text = str((result or {}).get("error") or "").strip()[:240]
        return (
            "System note: the deterministic browser_use QA preflight was attempted but did not complete cleanly.\n"
            f"- task_type: {task_type}\n"
            f"- error: {error_text or 'unknown browser_use preflight failure'}\n"
            "Continue with browser-based QA, but do not assume gameplay quality without visible evidence."
        )

    def _qa_browser_prefetch_summary(
        self,
        results: List[Dict[str, Any]],
        browser_events: List[Dict[str, Any]],
        task_type: str,
    ) -> str:
        successful_events = [item for item in (browser_events or []) if bool(item.get("ok"))]
        preview_url = self._qa_default_preview_url("tester") or "http://127.0.0.1:8765/preview/"
        final_url = ""
        capture_path = ""
        for event in successful_events:
            final_url = final_url or str(event.get("url") or "").strip()
            capture_path = capture_path or str(event.get("capture_path") or "").strip()
        if successful_events:
            action_names: List[str] = []
            for event in successful_events:
                action = str(event.get("action") or "").strip()
                if action and action not in action_names:
                    action_names.append(action)
            # v7.7 (maintainer 2026-04-28): inject the actual DOM-diff / console-
            # error / failed-request evidence the reviewer needs to enforce
            # HARD GATES A and B from reviewer.yaml. Was leaking only action
            # names + capture_path — reviewer had to guess whether the click
            # actually changed anything, and approved broken games (PvZ "点
            # 植物放不上草坪" passed reviewer with zero diff). Now reviewer
            # can read pre-vs-post state hashes, count of console errors,
            # count of failed network requests, and recent error messages.
            pre_hash = ""
            post_hash = ""
            state_changed_observed = False
            console_err_total = 0
            failed_req_total = 0
            recent_console_errors: List[str] = []
            click_actions = ("click", "click_start", "drag_and_drop", "press", "type")
            click_event = None
            for event in successful_events:
                ph = str(event.get("previous_state_hash") or "").strip()
                cur = str(event.get("state_hash") or "").strip()
                if ph and not pre_hash:
                    pre_hash = ph
                if cur:
                    post_hash = cur  # last successful hash wins
                if bool(event.get("state_changed")):
                    state_changed_observed = True
                try:
                    console_err_total += int(event.get("console_error_count") or 0)
                except Exception:
                    pass
                try:
                    failed_req_total += int(event.get("failed_request_count") or 0)
                except Exception:
                    pass
                rce = event.get("recent_console_errors")
                if isinstance(rce, list):
                    for entry in rce:
                        text = str(entry).strip()
                        if text and text not in recent_console_errors:
                            recent_console_errors.append(text)
                if click_event is None and str(event.get("action") or "").strip() in click_actions:
                    click_event = event
            lines = [
                "System note: a deterministic browser QA preflight already ran before your verdict.",
                f"- task_type: {task_type}",
                f"- final_url: {final_url or preview_url}",
            ]
            if action_names:
                lines.append(f"- captured_actions: {', '.join(action_names[:8])}")
            if capture_path:
                lines.append(f"- capture_path: {capture_path}")
            if pre_hash or post_hash:
                lines.append(
                    f"- state_signatures: pre={pre_hash[:12] or 'n/a'} post={post_hash[:12] or 'n/a'} "
                    f"changed={'YES' if state_changed_observed else 'NO'}"
                )
            if click_event is not None:
                cph = str(click_event.get("previous_state_hash") or "").strip()
                cpost = str(click_event.get("state_hash") or "").strip()
                cchg = bool(click_event.get("state_changed"))
                lines.append(
                    f"- click_dom_diff: pre={cph[:12] or 'n/a'} post={cpost[:12] or 'n/a'} "
                    f"changed={'YES' if cchg else 'NO (HARD GATE A: reject if click did nothing)'}"
                )
            lines.append(
                f"- console_error_total: {console_err_total} | failed_request_total: {failed_req_total}"
            )
            if recent_console_errors:
                joined = " | ".join(s[:160] for s in recent_console_errors[:5])
                lines.append(f"- recent_console_errors: {joined}")
            if failed_req_total > 0:
                lines.append(
                    "- HARD GATE B note: any local 404 in failed_request_total = BLOCKER REJECT per reviewer.yaml."
                )
            if click_event is not None and not bool(click_event.get("state_changed")):
                lines.append(
                    "- HARD GATE A note: pre-click DOM signature equals post-click DOM signature — "
                    "treat the artefact as non-interactive (reject)."
                )
            lines.append(
                "Treat this as real visual evidence. Use it in your scoring, and only add extra browser steps where interaction proof is still incomplete."
            )
            return "\n".join(lines)

        first_error = ""
        for result in results or []:
            first_error = str((result or {}).get("error") or "").strip()
            if first_error:
                break
        return (
            "System note: the deterministic browser QA preflight was attempted but did not complete cleanly.\n"
            f"- task_type: {task_type}\n"
            f"- error: {(first_error or 'unknown browser preflight failure')[:240]}\n"
            "Continue with manual browser-based QA if the tool is still available."
        )

    async def _maybe_seed_qa_browser(
        self,
        *,
        node: Dict[str, Any],
        node_type: str,
        task_type: str,
        input_data: str,
        plugins: Optional[List[Any]],
        available_tool_names: set[str],
        tool_results: List[Dict[str, Any]],
        tool_call_stats: Dict[str, int],
        browser_action_events: List[Dict[str, Any]],
        messages: Optional[List[Dict[str, Any]]] = None,
        on_progress=None,
    ) -> Optional[List[Dict[str, Any]]]:
        if not self._qa_browser_prefetch_allowed(node_type, available_tool_names):
            normalized_role = normalize_node_role(node_type) or node_type
            reason = "node_type_not_qa_role"
            if normalized_role in {"reviewer", "tester"} and "browser" not in (available_tool_names or set()):
                reason = "browser_tool_unavailable"
            logger.info(
                "qa_browser_prefetch skipped: node=%s reason=%s tools=%s",
                normalized_role,
                reason,
                sorted(available_tool_names or set()),
            )
            return None
        if (
            task_type == "game"
            and self._qa_browser_use_required(node_type, task_type, available_tool_names)
            and "browser_use" in available_tool_names
        ):
            logger.info(
                "qa_browser_prefetch skipped: node=%s reason=browser_use_forced_for_game",
                normalize_node_role(node_type) or node_type,
            )
            return None
        if int(tool_call_stats.get("browser", 0) or 0) >= 1:
            logger.info(
                "qa_browser_prefetch skipped: node=%s reason=browser_already_used count=%s",
                normalize_node_role(node_type) or node_type,
                int(tool_call_stats.get("browser", 0) or 0),
            )
            return None
        if not plugins or "browser" not in available_tool_names:
            logger.info(
                "qa_browser_prefetch skipped: node=%s reason=browser_plugin_missing",
                normalize_node_role(node_type) or node_type,
            )
            return None
        if self._desktop_qa_browser_suppressed(node_type, input_data):
            logger.info(
                "qa_browser_prefetch skipped: node=%s reason=desktop_qa_evidence_present",
                normalize_node_role(node_type) or node_type,
            )
            return None

        preflight_results: List[Dict[str, Any]] = []
        preflight_events: List[Dict[str, Any]] = []
        logger.info(
            "deterministic browser QA preflight: node=%s task_type=%s tools=%s",
            normalize_node_role(node_type) or node_type,
            task_type,
            sorted(available_tool_names or set()),
        )
        preview_url = self._qa_default_preview_url(node_type) or "http://127.0.0.1:8765/preview/"
        preflight_steps = [
            (
                "observe",
                {
                    "action": "observe",
                    "url": preview_url,
                    "goal": (
                        "Inspect the loaded preview, visible title, primary CTA, key content blocks, and obvious interaction affordances."
                        if task_type != "game" else
                        "Inspect the loaded game preview, title screen, HUD, and visible start/play controls."
                    ),
                    "screenshot": True,
                    "limit": 36,
                },
            ),
            (
                "record_scroll" if task_type != "game" else "snapshot",
                {
                    "action": "record_scroll" if task_type != "game" else "snapshot",
                    "amount": 420,
                    "max_steps": 4,
                    "full_page": False,
                    "screenshot": True,
                } if task_type != "game" else {
                    "action": "snapshot",
                    "screenshot": True,
                    "limit": 36,
                },
            ),
        ]
        # v7.7 quality-fix: actively click the primary CTA / 开始游戏 button
        # so reviewer can detect "click does nothing" failures (broken event
        # listeners, 404 sprites blocking init, missing handler bindings).
        # Static observe+snapshot only validates the title screen renders;
        # most user-facing breakage hides behind the first interaction.
        if task_type == "game":
            preflight_steps.append((
                "click_start",
                {
                    "action": "click",
                    "text": "开始游戏",
                    "fallback_texts": ["开始", "START", "Start", "Play", "Begin", "进入", "进入游戏", "开局", "开战", "GO"],
                    "wait_after_ms": 1500,
                    "screenshot": True,
                    "tolerate_failure": True,
                    "timeout_ms": 12000,
                },
            ))
            preflight_steps.append((
                "post_interaction_snapshot",
                {
                    "action": "snapshot",
                    "screenshot": True,
                    "limit": 36,
                    "include_console": True,
                },
            ))
        else:
            preflight_steps.append((
                "click_cta",
                {
                    "action": "click",
                    "fallback_texts": ["了解更多", "Learn More", "Get Started", "Start", "登录", "Sign In", "立即体验"],
                    "wait_after_ms": 1200,
                    "screenshot": True,
                    "tolerate_failure": True,
                },
            ))
        if on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "qa_browser_prefetch",
                "node_type": normalize_node_role(node_type) or node_type,
                "task_type": task_type,
                "url": preview_url,
            })

        for action_name, params in preflight_steps:
            try:
                result = await asyncio.wait_for(
                    self._run_plugin(
                        "browser",
                        params,
                        plugins,
                        node_type=node_type,
                        node=node,
                    ),
                    timeout=25,
                )
            except asyncio.TimeoutError:
                result = {
                    "success": False,
                    "error": f"browser QA preflight timed out during {action_name}",
                    "data": {},
                }
            preflight_results.append(result)
            tool_results.append(result)
            tool_call_stats["browser"] = tool_call_stats.get("browser", 0) + 1
            event = self._browser_action_event_from_result(result, action_name=action_name)
            preflight_events.append(event)
            browser_action_events.append(event)
            logger.info(
                "qa_browser_prefetch step: node=%s action=%s success=%s url=%s capture=%s error=%s",
                normalize_node_role(node_type) or node_type,
                action_name,
                bool(result.get("success")),
                str(event.get("url") or "").strip(),
                str(event.get("capture_path") or "").strip(),
                str(result.get("error") or "").strip()[:160],
            )
            if on_progress:
                await self._emit_noncritical_progress(on_progress, {
                    "stage": "browser_action",
                    "plugin": "browser",
                    **event,
                })
            if not result.get("success"):
                break

        if messages is not None:
            messages.append({
                "role": "user",
                "content": self._qa_browser_prefetch_summary(preflight_results, preflight_events, task_type),
            })
        return preflight_results

    async def _maybe_seed_qa_browser_use(
        self,
        *,
        node: Dict[str, Any],
        node_type: str,
        task_type: str,
        input_data: str,
        plugins: Optional[List[Any]],
        available_tool_names: set[str],
        tool_results: List[Dict[str, Any]],
        tool_call_stats: Dict[str, int],
        browser_action_events: List[Dict[str, Any]],
        messages: Optional[List[Dict[str, Any]]] = None,
        on_progress=None,
    ) -> Optional[Dict[str, Any]]:
        if not self._qa_browser_use_required(node_type, task_type, available_tool_names):
            logger.info(
                "qa_browser_use_prefetch skipped: node=%s reason=not_required task_type=%s tools=%s",
                normalize_node_role(node_type) or node_type,
                task_type,
                sorted(available_tool_names or set()),
            )
            return None
        if int(tool_call_stats.get("browser_use", 0) or 0) >= 1:
            logger.info(
                "qa_browser_use_prefetch skipped: node=%s reason=browser_use_already_used count=%s",
                normalize_node_role(node_type) or node_type,
                int(tool_call_stats.get("browser_use", 0) or 0),
            )
            return None
        if not plugins or "browser_use" not in available_tool_names:
            logger.info(
                "qa_browser_use_prefetch skipped: node=%s reason=browser_use_plugin_missing",
                normalize_node_role(node_type) or node_type,
            )
            return None

        preview_url = self._qa_default_preview_url(node_type) or "http://127.0.0.1:8765/preview/"
        params = {
            "url": preview_url,
            "task": self._qa_browser_use_prefetch_task(node_type, task_type, input_data),
            "max_steps": 10 if task_type == "game" else 8,
            "timeout_sec": 150 if task_type == "game" else 120,
            "use_vision": True,
            "model": str(
                self.config.get("browser_use_model")
                or self.config.get("default_model")
                or "gpt-5.4"
            ).strip() or "gpt-5.4",
        }
        if on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "qa_browser_use_prefetch",
                "node_type": normalize_node_role(node_type) or node_type,
                "task_type": task_type,
                "url": params["url"],
            })

        # P0 FIX (Opus): Wrap prefetch with independent timeout to avoid consuming
        # the reviewer/tester node's full timeout budget if browser_use hangs.
        _PREFETCH_TIMEOUT = 60
        try:
            result = await asyncio.wait_for(
                self._run_plugin(
                    "browser_use",
                    params,
                    plugins,
                    node_type=node_type,
                    node=node,
                ),
                timeout=_PREFETCH_TIMEOUT,
            )
        except asyncio.TimeoutError:
            logger.warning(
                "browser_use QA prefetch timed out after %ss — continuing without preflight evidence",
                _PREFETCH_TIMEOUT,
            )
            result = {
                "success": False,
                "error": f"browser_use QA prefetch timed out after {_PREFETCH_TIMEOUT}s",
                "data": {},
            }
        tool_results.append(result)
        tool_call_stats["browser_use"] = tool_call_stats.get("browser_use", 0) + 1

        preflight_events = self._browser_use_action_events(result)
        for browser_event in preflight_events:
            browser_action_events.append(browser_event)
            if on_progress:
                await self._emit_noncritical_progress(on_progress, {
                    "stage": "browser_action",
                    "plugin": "browser_use",
                    **browser_event,
                })

        if messages is not None:
            messages.append({
                "role": "user",
                "content": self._qa_browser_use_prefetch_summary(result, preflight_events, task_type),
            })
        return result

    def _review_browser_followup_reason(
        self,
        node_type: str,
        task_type: str,
        browser_actions: List[Dict[str, Any]],
        goal: str = "",
        tool_call_stats: Optional[Dict[str, int]] = None,
        available_tool_names: Optional[set[str]] = None,
    ) -> Optional[str]:
        if node_type not in {"reviewer", "tester"}:
            return None

        tool_stats = tool_call_stats or {}
        available_names = available_tool_names or set()
        if self._qa_browser_use_required(node_type, task_type, available_names):
            if int(tool_stats.get("browser_use", 0) or 0) < 1:
                return "You must use browser_use for a real gameplay session before final verdict."

        successful = [
            item for item in (browser_actions or [])
            if item.get("ok")
        ]
        if not successful:
            return "You have not used the browser tool yet."

        def _normalized_action(item: Dict[str, Any]) -> str:
            action = str(item.get("action") or "").strip().lower()
            subaction = str(item.get("subaction") or item.get("intent") or "").strip().lower()
            if action == "observe":
                return "snapshot"
            if action == "record_scroll":
                return "scroll"
            if action == "act" and subaction:
                return subaction
            return action

        def _is_verification_action(item: Dict[str, Any]) -> bool:
            action = str(item.get("action") or "").strip().lower()
            normalized = _normalized_action(item)
            return normalized in {"snapshot", "wait_for"} or action == "record_scroll"

        actions = [_normalized_action(item) for item in successful]
        if "snapshot" not in actions:
            return "You must inspect the page with browser.observe or browser.snapshot before final verdict."

        scroll_actions = [item for item in successful if _normalized_action(item) == "scroll"]
        scroll_boundary_known = any(
            bool(item.get("at_bottom"))
            or bool(item.get("at_top"))
            or item.get("is_scrollable") is not None
            for item in scroll_actions
        )
        reached_scroll_boundary = any(
            bool(item.get("at_bottom"))
            or bool(item.get("at_top"))
            or item.get("is_scrollable") is False
            for item in scroll_actions
        )

        seen_interaction = False
        has_post_verify = False
        seen_gameplay_input = False
        has_post_gameplay_verify = False
        for item in successful:
            action = _normalized_action(item)
            if action in {"click", "fill", "press", "press_sequence"}:
                seen_interaction = True
                if action in {"press", "press_sequence"}:
                    seen_gameplay_input = True
                continue
            if seen_interaction and _is_verification_action(item):
                has_post_verify = True
            if seen_gameplay_input and _is_verification_action(item):
                has_post_gameplay_verify = True

        if task_type == "game":
            if "click" not in actions:
                return "You must click the start/play control before final verdict."
            if not any(action in {"press", "press_sequence"} for action in actions):
                return "You must test gameplay controls with press_sequence or press before final verdict."
            if not has_post_gameplay_verify:
                return (
                    "You must verify gameplay controls with browser.observe, browser.snapshot, "
                    "wait_for, or record_scroll after gameplay input before final verdict."
                )
            return None

        if task_type == "dashboard":
            if "click" not in actions:
                return "You must click at least one dashboard control before final verdict."
            if not has_post_verify:
                return (
                    "After clicking a dashboard control, you must call browser.observe, "
                    "browser.snapshot, wait_for, or record_scroll to verify the changed state."
                )
            return None

        if task_type == "website":
            if node_type == "reviewer" and "scroll" not in actions:
                return "Website reviews must scroll the page before final verdict."
            if node_type == "reviewer" and scroll_actions and scroll_boundary_known and not reached_scroll_boundary:
                return "You must keep scrolling until you reach the bottom of the page or confirm the page is non-scrollable."
            if node_type == "tester" and "scroll" not in actions:
                return "Website tests must scroll the page before final verdict."
            if node_type == "tester" and scroll_actions and scroll_boundary_known and not reached_scroll_boundary:
                return "You must keep scrolling until you reach the bottom of the page or confirm the page is non-scrollable."
            if task_classifier.wants_multi_page(goal):
                requested_pages = max(task_classifier.requested_page_count(goal), 2)
                artifact_pages = self._current_output_html_pages()
                use_artifact_pages = 2 <= len(artifact_pages) <= requested_pages
                expected_pages = len(artifact_pages) if use_artifact_pages else requested_pages
                visited_pages = {
                    self._normalize_review_preview_path(item.get("url", ""))
                    for item in successful
                    if self._normalize_review_preview_path(item.get("url", ""))
                }
                missing_pages = [
                    page for page in artifact_pages
                    if page and page not in visited_pages
                ] if use_artifact_pages else []
                if len(visited_pages) < expected_pages:
                    missing_suffix = ""
                    if missing_pages:
                        missing_suffix = " Remaining missing pages: " + ", ".join(missing_pages[:8]) + "."
                    return (
                        "You must cover every requested page/route before final verdict. "
                        "Validate at least one internal navigation action first; after that, direct visits to the remaining known preview paths are acceptable. "
                        f"Current distinct pages visited: {len(visited_pages)}/{expected_pages}."
                        f"{missing_suffix}"
                    )
            if not any(action in {"click", "fill"} for action in actions):
                return "You must click or fill at least one interactive element before final verdict."
            if not has_post_verify:
                return (
                    "After interacting with the website, you must call browser.observe, "
                    "browser.snapshot, wait_for, or record_scroll to verify the changed state."
                )
            return None

        if not any(action in {"click", "fill", "press", "press_sequence"} for action in actions):
            return "You must test at least one interactive control before final verdict."
        if not has_post_verify:
            return (
                "After interaction, you must call browser.observe, browser.snapshot, "
                "wait_for, or record_scroll to verify the changed state."
            )
        return None

    def _review_browser_followup_message(self, reason: str, task_type: str) -> str:
        reason_text = str(reason or "").strip()
        lower = reason_text.lower()
        missing_pages: List[str] = []
        missing_match = re.search(r"Remaining missing pages:\s*([^.]*)", reason_text, re.IGNORECASE)
        if missing_match:
            missing_pages = [
                item.strip().strip(",")
                for item in missing_match.group(1).split(",")
                if item.strip()
            ]
        action_hint = 'Call browser with {"action":"observe"} now.'
        if "scroll" in lower:
            action_hint = (
                'Prefer calling browser with {"action":"record_scroll","amount":500} now. '
                'If that is unavailable, call browser with {"action":"scroll","direction":"down","amount":500} repeatedly '
                'until the browser reports the bottom of the page or the page is clearly non-scrollable.'
            )
        elif "bottom of the page" in lower or "non-scrollable" in lower:
            action_hint = (
                'Prefer calling browser with {"action":"record_scroll","amount":500} now. '
                'If that is unavailable, call browser with {"action":"scroll","direction":"down","amount":500} repeatedly '
                'until the browser reports at_bottom=true or the page is clearly non-scrollable.'
            )
        elif missing_pages or "every requested page" in lower or "page/route" in lower:
            if missing_pages:
                first_missing = missing_pages[0]
                remaining = ", ".join(missing_pages[:6])
                action_hint = (
                    "After proving one real internal navigation path, directly open the remaining preview routes. "
                    f'Call browser with {{"action":"navigate","url":"http://127.0.0.1:8765/preview/{first_missing}"}} '
                    'and then {"action":"observe"}; repeat for the remaining missing pages: '
                    f"{remaining}."
                )
            else:
                action_hint = (
                    'Use the real navigation links/buttons to open each requested page, then inspect every page before '
                    'finalizing your verdict.'
                )
        elif "start/play" in lower:
            action_hint = 'Call browser with {"action":"act","intent":"click","target":"Start Game"} or the visible play control now.'
        elif "browser_use" in lower and "gameplay session" in lower:
            action_hint = (
                'Call browser_use with {"url":"http://127.0.0.1:8765/preview/","task":"Open the preview, click the visible '
                'Start/Play control, play for several moves with Arrow keys or WASD plus Space/Enter, and verify the HUD, '
                'camera, or scene changes while keeping recorded evidence."} now.'
            )
        elif "gameplay controls" in lower:
            action_hint = (
                'Call browser with {"action":"act","intent":"press_sequence","keys":["ArrowRight","ArrowRight","Space","ArrowLeft"],'
                '"repeat":2,"interval_ms":150} now.'
            )
        elif (
            "wait_for or snapshot" in lower
            or "browser.observe" in lower
            or "record_scroll" in lower
            or "changed state" in lower
        ):
            if task_type == "game":
                action_hint = 'Call browser with {"action":"observe"} now to verify the post-gameplay state changed.'
            else:
                action_hint = 'Call browser with {"action":"observe"} now to verify the post-action state changed.'
        elif "browser.snapshot" in lower or "snapshot" in lower or "browser.observe" in lower:
            action_hint = 'Call browser with {"action":"observe"} now before final verdict.'
        return (
            "Your browser-based review/test is incomplete.\n"
            f"Missing requirement: {reason_text}\n"
            f"{action_hint}\n"
            "Do not output a final verdict yet. Use the browser tool immediately and only finalize after the missing step is complete."
        )

    def _review_output_format_followup_reason(self, node_type: str, output_text: str) -> Optional[str]:
        if normalize_node_role(node_type) != "reviewer":
            return None
        text = str(output_text or "").strip()
        if not text:
            return "Your final reviewer answer is empty. Write a detailed review and end with a JSON verdict."
        # V4.6: Accept natural language with embedded JSON verdict anywhere in the text.
        # Search for the LAST JSON object (most likely the verdict appendix).
        json_end = text.rfind("}")
        if json_end >= 0:
            # Walk backwards to find the matching opening brace
            depth = 0
            json_start = -1
            for i in range(json_end, -1, -1):
                if text[i] == "}":
                    depth += 1
                elif text[i] == "{":
                    depth -= 1
                    if depth == 0:
                        json_start = i
                        break
            if json_start >= 0:
                try:
                    parsed = json.loads(text[json_start:json_end + 1])
                    verdict = str(parsed.get("verdict") or "").strip().upper()
                    if verdict in {"APPROVED", "REJECTED"}:
                        return None
                except Exception:
                    pass
        # V4.6: Also accept plain text with clear verdict keywords
        lower = text.lower()
        if ("verdict" in lower or "conclusion" in lower) and ('"approved"' in lower or '"rejected"' in lower or "approved" in lower[-500:] or "rejected" in lower[-500:]):
            return None
        return (
            "Your review is missing a clear verdict. End your report with a JSON verdict block:\n"
            '{"verdict":"APPROVED" or "REJECTED","scores":{...},"blocking_issues":[...],"strengths":[...]}'
        )

    def _review_output_format_followup_message(self, reason: str) -> str:
        reason_text = str(reason or "").strip()
        return (
            "Your reviewer output format is incomplete.\n"
            f"Missing requirement: {reason_text}\n"
            "Return ONLY one JSON object. No markdown fences. No bullet lists. No commentary before or after.\n"
            "Required shape:\n"
            '{"verdict":"APPROVED" or "REJECTED","scores":{"layout":N,"color":N,"typography":N,"animation":N,"responsive":N,"functionality":N,"completeness":N,"originality":N},"ship_readiness":N,"average":N.N,"issues":[],"blocking_issues":[],"missing_deliverables":[],"required_changes":[],"acceptance_criteria":[],"strengths":[]}'
        )

    def _message_char_count(self, msg: Dict[str, Any]) -> int:
        total = 0
        content = msg.get("content")
        if isinstance(content, str):
            total += len(content)
        reasoning = msg.get("reasoning_content")
        if isinstance(reasoning, str):
            total += len(reasoning)
        for tc in msg.get("tool_calls") or []:
            if not isinstance(tc, dict):
                continue
            fn = tc.get("function")
            if isinstance(fn, dict):
                args = fn.get("arguments")
                if isinstance(args, str):
                    total += len(args)
        return total

    def _messages_char_count(self, messages: List[Dict[str, Any]]) -> int:
        total = 0
        for msg in messages or []:
            if isinstance(msg, dict):
                total += self._message_char_count(msg)
        return total

    def _tool_names_for_log(self, tools: List[Dict[str, Any]]) -> List[str]:
        names: List[str] = []
        for tool in tools or []:
            if not isinstance(tool, dict):
                continue
            fn = tool.get("function")
            if isinstance(fn, dict):
                name = str(fn.get("name") or "").strip()
                if name:
                    names.append(name)
        return names

    def _format_latency_for_log(self, value: Optional[float]) -> str:
        if value is None or value < 0:
            return "none"
        return f"{value:.2f}s"

    # ── V4.4 + v5.8.2: Cross-provider prompt caching ─────────
    def _merge_with_overlap_dedup(
        self,
        prior: str,
        continuation: str,
        max_overlap: int = 400,
    ) -> str:
        """Concatenate continuation, cutting any overlap where the model
        accidentally repeats the tail of the prior chunk.

        v6.1.10 (maintainer 2026-04-19) — research found that GPT/Gemini
        semantic-continue mode causes 20-200 char repetition in 40-50% of
        code/JSON scenarios (OpenAI forum #806445). Even with our anchor
        prompt, models sometimes emit "...</body>" twice. This O(n) scan
        finds the longest suffix of `prior` that equals a prefix of
        `continuation` and drops the duplicate half.

        Safe: prior and continuation are typed str, max_overlap caps work.
        """
        if not prior or not continuation:
            return prior + continuation
        # Longest suffix/prefix match up to max_overlap
        scan_len = min(len(prior), len(continuation), max_overlap)
        # Search from longest possible overlap down to 10 chars (smaller
        # random coincidences aren't worth fixing and may false-positive).
        for n in range(scan_len, 9, -1):
            if prior.endswith(continuation[:n]):
                logger.info(
                    "continuation overlap deduped: removed %d duplicate chars", n,
                )
                return prior + continuation[n:]
        return prior + continuation

    def _maybe_route_to_fast_write_model(
        self,
        model_info: Dict[str, Any],
        node: Optional[Dict[str, Any]] = None,
    ) -> Dict[str, Any]:
        """Cursor Fast Apply pattern: when builder enters direct_text mode,
        optionally route the WRITE-only call to a cheap/fast apply model.

        Config precedence:
        1. node-level `fast_write_model_override`
        2. config.fast_write_model (global)
        3. EVERMIND_FAST_WRITE_MODEL env var
        4. None → no override (current behavior, default safe)

        Returns potentially-swapped model_info. Only swaps when the override
        resolves to a known model; otherwise passes through untouched.
        """
        override = None
        if node:
            override = str(node.get("fast_write_model_override") or "").strip()
        if not override:
            cfg_val = self.config.get("fast_write_model") if isinstance(self.config, dict) else None
            override = str(cfg_val or "").strip()
        if not override:
            override = str(os.getenv("EVERMIND_FAST_WRITE_MODEL", "") or "").strip()
        if not override:
            return model_info
        try:
            resolved = self._resolve_model(override)
        except Exception:
            logger.warning("fast_write_model override %r failed to resolve; keeping primary", override)
            return model_info
        if not resolved:
            return model_info
        logger.info(
            "Fast Apply routing: direct_text builder swapped to %r (was %r)",
            override, model_info.get("name") or model_info.get("id") or "?",
        )
        return resolved

    def _provider_supports_assistant_prefill(
        self,
        model_info: Optional[Dict[str, Any]],
        model_name: str = "",
    ) -> bool:
        """Whether the provider supports assistant-message prefill.

        v6.1.8 Wave B + research 2026-04-19 expanded matrix:
        - Anthropic / Bedrock Claude / Vertex Claude — bare assistant-as-last
        - DeepSeek (beta endpoint) — `prefix: true`
        - Moonshot/Kimi direct — `partial: true` (LiteLLM translates)
        - Qwen (DashScope) — `partial: true` (qwen3-max/plus/flash/coder/turbo)
        - Mistral AI — `prefix: true`

        Confirmed NO:
        - OpenAI gpt-4o/gpt-5/o1/o3 — rejects assistant-last
        - Gemini — no prefill API
        - Grok (xAI) — no prefix field in docs
        - Together/Fireworks/Groq — OpenAI-compat, no prefix
        - Relay gateways (private-relay/aigate/private-relay) — strip unknown fields
        """
        return self._assistant_prefill_field(model_info, model_name) is not None

    def _assistant_prefill_field(
        self,
        model_info: Optional[Dict[str, Any]],
        model_name: str = "",
    ) -> Optional[str]:
        """Return the prefill field name for this provider, or None if unsupported.

        Used by the continuation path to stamp the correct flag on the
        trailing assistant message. Mapping by official docs:
          - anthropic/bedrock/vertex → ""   (empty string = no flag needed)
          - deepseek / mistral        → "prefix"
          - moonshot / kimi / qwen    → "partial"
        """
        info = model_info or {}
        provider = str(info.get("provider") or "").strip().lower()
        lid = str(info.get("litellm_id") or model_name or "").strip().lower()
        base = str(info.get("api_base") or "").lower()
        routes_through_relay = any(
            tok in lid or tok in base
            for tok in ("relay", "aigate", "private-relay", "relay", "llm.private-relay.example")
        )
        if routes_through_relay:
            return None
        # Native Claude protocol — just put assistant as last, no flag
        if provider in ("anthropic", "bedrock", "vertex_ai-anthropic"):
            return ""
        if lid.startswith("anthropic/") or lid.startswith("claude"):
            return ""
        # v6.1.9 research: Doubao/Volcengine Ark supports bare assistant-as-last
        # (https://www.volcengine.com/docs/82379/1359497 "续写模式-Prefill
        # Response 最佳实践"). Same semantics as Anthropic, no extra flag.
        if provider in ("doubao", "volcengine", "ark", "byteplus"):
            return ""
        if "volces.com" in base or "ark.cn-beijing" in base or "byteplus" in base:
            return ""
        # DeepSeek + Mistral use `prefix`
        if provider in ("deepseek", "mistral"):
            return "prefix"
        if lid.startswith("deepseek/") or "deepseek-" in lid or lid.startswith("mistral/"):
            return "prefix"
        # Moonshot + Qwen use `partial`
        if provider in ("moonshot", "kimi", "qwen", "dashscope"):
            return "partial"
        if "qwen" in lid or "dashscope" in lid:
            return "partial"
        return None

    def _maybe_make_incremental_stream_parser(
        self,
        node: Optional[Dict[str, Any]],
        node_type: str,
        direct_multifile: bool,
    ) -> Optional[Any]:
        """Return a Bolt.new-style IncrementalStreamParser when conditions are met.

        v6.1.8 Wave A: activates only for builder nodes in direct_text
        single-root mode (NOT direct_multifile — that needs separate
        file-splitting handling). Writes to a ``.streaming`` staging file
        beside the final index.html so concurrent postprocess won't race.
        No-op when gated off by env var EVERMIND_STREAM_TO_DISK=0.
        """
        if str(os.getenv("EVERMIND_STREAM_TO_DISK", "1") or "1").strip() in ("0", "false", "no"):
            return None
        if normalize_node_role(node_type) != "builder":
            return None
        # direct_multifile has its own parser path; don't double-write
        if direct_multifile:
            return None
        node_meta = node if isinstance(node, dict) else {}
        # Find a target path candidate
        output_dir = str(
            node_meta.get("output_dir") or node_meta.get("file_ops_output_dir") or ""
        ).strip()
        task_id = str(node_meta.get("subtask_id") or node_meta.get("task_id") or "").strip()
        if not output_dir:
            output_dir = "/tmp/evermind_output"
        if not task_id:
            return None  # only enable when we can infer task_N folder
        staging_path = str(Path(output_dir) / f"task_{task_id}" / "index.html.streaming")
        try:
            from incremental_stream_parser import IncrementalStreamParser
        except Exception:
            return None
        try:
            return IncrementalStreamParser(target_path=staging_path)
        except Exception:
            logger.debug("incremental parser init failed", exc_info=True)
            return None

    def _stamp_builder_handoff_cache(
        self,
        messages: List[Dict[str, Any]],
        model: str = "",
    ) -> List[Dict[str, Any]]:
        """v6.5 Phase 2 (#9): mark the large builder payload for Anthropic
        prompt caching so the Merger's re-read hits a 5-min TTL ephemeral
        cache (Claude 4 extends to 1h on select tiers). Saves ~90% read cost
        and 83% TTFT on the builder->merger handoff.

        Scans the last 5 messages; any text block >= 8000 chars gets a
        cache_control:ephemeral marker. String-valued content is promoted
        into a single-block list so the marker survives the Anthropic
        message pipeline. No-op on non-Anthropic models.
        """
        if not messages:
            return messages
        model_lower = str(model or "").lower()
        is_anthropic = (
            "anthropic/" in model_lower
            or "claude-" in model_lower
            or model_lower.startswith("claude")
        )
        if not is_anthropic:
            return messages

        THRESHOLD = 8000
        tail_start = max(0, len(messages) - 5)
        stamped = 0
        for idx in range(tail_start, len(messages)):
            msg = messages[idx]
            if not isinstance(msg, dict):
                continue
            content = msg.get("content")
            if isinstance(content, list):
                for block in content:
                    if not isinstance(block, dict):
                        continue
                    if block.get("type") == "text" and len(str(block.get("text") or "")) > THRESHOLD:
                        if "cache_control" not in block:
                            block["cache_control"] = {"type": "ephemeral"}
                            stamped += 1
            elif isinstance(content, str) and len(content) > THRESHOLD:
                msg["content"] = [{
                    "type": "text",
                    "text": content,
                    "cache_control": {"type": "ephemeral"},
                }]
                stamped += 1
        if stamped:
            logger.debug(
                "Builder-handoff cache stamped: %d blocks marked (model=%s)",
                stamped, model_lower[:30],
            )
        return messages

    def _apply_tools_cache_breakpoint(
        self,
        tools: Optional[List[Dict[str, Any]]],
        model: str = "",
    ) -> Optional[List[Dict[str, Any]]]:
        """Stamp the last tool with cache_control:ephemeral for Anthropic.

        v6.1.6 (maintainer 2026-04-19): Claims the 4th of 4 Anthropic cache
        breakpoints on the tools array. Tools are stable across turns in a
        single agent run so this is free compute savings (Cline
        src/core/api/providers/anthropic.ts:L125-L133 comments document this
        exact pattern: "cache breakpoints go from tools > system > messages").
        For non-Anthropic providers, returns tools unchanged.
        """
        if not tools:
            return tools
        model_lower = str(model or "").lower()
        is_anthropic = (
            "anthropic/" in model_lower
            or "claude-" in model_lower
            or model_lower.startswith("claude")
        )
        if not is_anthropic:
            return tools
        # Only mutate a shallow copy so the caller's list stays pristine.
        tagged = [dict(t) if isinstance(t, dict) else t for t in tools]
        last = tagged[-1]
        if isinstance(last, dict):
            # Works for both function-schema style (name/input_schema) and the
            # OpenAI-compat {"type": "function", "function": {...}} envelope.
            if "function" in last and isinstance(last["function"], dict):
                last["function"]["cache_control"] = {"type": "ephemeral"}
            else:
                last["cache_control"] = {"type": "ephemeral"}
        return tagged

    def _inject_prompt_cache_breakpoints(self, messages: List[Dict[str, Any]], model: str = "") -> List[Dict[str, Any]]:
        """Prepare messages for cross-provider prompt caching.

        Different providers cache differently:

        - **Anthropic (Claude)**: requires explicit ``cache_control: {type:"ephemeral"}``
          markers on each message part. Up to 4 cache breakpoints allowed per call.
          Saves 90% on read, costs 25% extra on write. 5-min TTL (1h on Claude 4).
        - **OpenAI (gpt-4o, gpt-5.x)**: automatic prefix cache on prompts ≥1024 tokens.
          No marker needed — just keep the prefix byte-identical. 50% discount.
        - **Kimi (via OpenAI-compatible)**: automatic prefix cache. 75% discount,
          83% TTFT reduction. No marker needed.
        - **Gemini**: explicit context caching (not supported via this path yet).

        v5.8.2: we now ONLY inject cache_control markers for Anthropic models,
        because list-of-dicts content with unknown fields gets mangled by some
        OpenAI-compat gateways. Other providers still benefit from the prefix
        stability of the rest of our pipeline (sorted set iteration, cached
        React Bits block, etc.) — they just don't need the explicit marker.
        """
        model_lower = str(model or "").lower()
        is_anthropic = (
            "anthropic/" in model_lower
            or "claude-" in model_lower
            or model_lower.startswith("claude")
        )
        if not is_anthropic:
            # Other providers: keep messages as-is. Their prefix cache works
            # automatically as long as the message prefix stays byte-stable,
            # which our sorted-set + cached-catalog fixes preserve.
            return messages

        # v6.1.5 (maintainer 2026-04-19): upgrade to Cline v3.5.0 multi-breakpoint
        # pattern (src/api/providers/anthropic.ts:L37-L86). Keep system +
        # LAST TWO user messages tagged so multi-turn history still hits cache.
        # Anthropic caps at 4 cache_control breakpoints per request; we use 3
        # and reserve 1 for future tools-cache extension.

        def _already_tagged(content_val: Any) -> bool:
            if not isinstance(content_val, list):
                return False
            for part in content_val:
                if isinstance(part, dict) and "cache_control" in part:
                    return True
            return False

        # Identify indices of user messages
        user_msg_indices = [
            i for i, m in enumerate(messages)
            if isinstance(m, dict) and str(m.get("role") or "") == "user"
        ]
        last_user_idx = user_msg_indices[-1] if user_msg_indices else -1
        second_last_user_idx = user_msg_indices[-2] if len(user_msg_indices) >= 2 else -1

        result: List[Dict[str, Any]] = []
        system_tagged = False
        user_tag_count = 0

        for i, msg in enumerate(messages):
            if not isinstance(msg, dict):
                result.append(msg)
                continue

            msg_copy = dict(msg)
            role = str(msg_copy.get("role") or "")
            content = msg_copy.get("content")

            if role == "system" and not system_tagged:
                if isinstance(content, str):
                    msg_copy["content"] = [
                        {"type": "text", "text": content,
                         "cache_control": {"type": "ephemeral"}}
                    ]
                    system_tagged = True
                elif _already_tagged(content):
                    system_tagged = True
            elif role == "user" and i in (last_user_idx, second_last_user_idx):
                if isinstance(content, str):
                    msg_copy["content"] = [
                        {"type": "text", "text": content,
                         "cache_control": {"type": "ephemeral"}}
                    ]
                    user_tag_count += 1
                elif _already_tagged(content):
                    user_tag_count += 1
                elif isinstance(content, list):
                    # v6.1.5 (Opus Y4): agentic loops emit tool_result list
                    # content. Attach cache_control to the LAST text-typed
                    # part so we still get cache hits across multi-turn runs.
                    new_content = []
                    tagged_in_list = False
                    for part in reversed(content):
                        if (not tagged_in_list
                            and isinstance(part, dict)
                            and part.get("type") == "text"):
                            new_part = dict(part)
                            new_part["cache_control"] = {"type": "ephemeral"}
                            new_content.insert(0, new_part)
                            tagged_in_list = True
                        else:
                            new_content.insert(0, part)
                    if tagged_in_list:
                        msg_copy["content"] = new_content
                        user_tag_count += 1

            result.append(msg_copy)

        if system_tagged or user_tag_count:
            logger.debug(
                "Anthropic cache breakpoints: system=%s user_msgs=%d model=%s",
                system_tagged, user_tag_count, model_lower[:30],
            )
        return result

    # ── V4.4: Tool Call Dedup ────────────────────────────────
    # Inspired by Opencode-DCP: when the same tool is called with identical
    # name+args multiple times, older results are redundant.  Replace them
    # with a tiny placeholder to free token budget for fresh context.
    TOOL_DEDUP_PLACEHOLDER = "[DEDUP: identical call repeated later — see latest result]"

    def _dedup_tool_calls_in_history(self, messages: List[Dict[str, Any]]) -> int:
        """Deduplicate identical tool calls in message history (in-place).

        Scans backwards: the *last* occurrence of a (name, args) pair keeps
        its full result; earlier occurrences get their tool-result content
        replaced with a short placeholder.

        Returns the number of results deduplicated.
        """
        # Build a map:  (tool_name, args_hash) → list of (tool_call_id)
        # ordered by position (earliest first).
        from hashlib import md5 as _md5

        # Phase 1: collect all tool_call signatures
        sig_to_tc_ids: Dict[str, List[str]] = {}   # sig → [tc_id, ...]
        for msg in messages:
            if not isinstance(msg, dict) or msg.get("role") != "assistant":
                continue
            for tc in msg.get("tool_calls") or []:
                if not isinstance(tc, dict):
                    continue
                fn = tc.get("function")
                if not isinstance(fn, dict):
                    continue
                tc_id = str(tc.get("id") or "")
                fn_name = str(fn.get("name") or "")
                fn_args = str(fn.get("arguments") or "")
                if not tc_id or not fn_name:
                    continue
                # Skip write/edit — those are side-effecting, not idempotent
                if fn_name == "file_ops":
                    try:
                        _parsed = json.loads(fn_args)
                        _action = str(_parsed.get("action", "")).lower()
                        if _action in ("write", "edit", "delete"):
                            continue
                    except Exception:
                        continue
                sig = _md5(f"{fn_name}:{fn_args}".encode()).hexdigest()
                sig_to_tc_ids.setdefault(sig, []).append(tc_id)

        # Phase 2: for sigs with ≥2 calls, mark all-but-last for dedup
        dedup_tc_ids: set = set()
        for sig, tc_ids in sig_to_tc_ids.items():
            if len(tc_ids) >= 2:
                # Keep only the last occurrence
                for tc_id in tc_ids[:-1]:
                    dedup_tc_ids.add(tc_id)

        if not dedup_tc_ids:
            return 0

        # Phase 3: replace tool-result content for deduped tc_ids
        deduped = 0
        for msg in messages:
            if not isinstance(msg, dict) or msg.get("role") != "tool":
                continue
            tc_id = msg.get("tool_call_id")
            if tc_id and tc_id in dedup_tc_ids:
                msg["content"] = self.TOOL_DEDUP_PLACEHOLDER
                deduped += 1

        if deduped:
            logger.info("Tool call dedup: replaced %d redundant tool results", deduped)
        return deduped

    def _prepare_messages_for_request(self, messages: List[Dict[str, Any]], model_name: str) -> List[Dict[str, Any]]:
        """
        V4.5: 5-layer compaction pipeline (Claude Code + SWE-agent style).

        Layer 0 — OBSERVATION MASK: Replace old tool results (>3 turns back) with
                  short summaries. Based on SWE-agent research showing tool results
                  are ~84% of context; masking reduces cost >50% with no perf loss.
        Layer 1 — SNIP: Per-message truncation (role-based char limits)
        Layer 2 — MICROCOMPACT: Tool call dedup + read-result summarization
        Layer 3 — CONTEXT COLLAPSE: Drop older context, keep recent turns
        Layer 4 — AUTOCOMPACT: Semantic sentence-level compression

        Each layer only activates when the previous layer leaves the total
        above MAX_REQUEST_TOTAL_CHARS.  This avoids over-compacting short
        conversations while aggressively shrinking long tool-loop sessions.
        """
        # ── Layer 0: OBSERVATION MASK — mask old tool results ──────
        # v5.8.1 upgrade: JetBrains/SWE-agent research (arXiv:2508.21433) on
        # SWE-bench Verified showed M=6-10 window MATCHES full-context solve
        # rate at 52% lower cost. Our previous M=2 was over-aggressive — it
        # cost builder coherence on iterative fixes (model couldn't see what
        # it had just read 3 turns ago). Bumped to 6, plus content-hash dedup:
        # if an older tool_result has the SAME (fn, args) as a newer one, it
        # gets masked even inside the "recent" window (the newer is strictly
        # more up-to-date).
        messages = [dict(m) if isinstance(m, dict) else m for m in messages]
        _MASK_KEEP_RECENT = int(os.getenv("EVERMIND_OBSMASK_KEEP_RECENT", "6"))
        _MASK_PLACEHOLDER = "[TOOL_RESULT_MASKED: older copy replaced by later call with same signature]"
        _tool_msg_indices = [
            i for i, m in enumerate(messages)
            if isinstance(m, dict) and str(m.get("role") or "") == "tool"
        ]
        # Content-hash dedup: build tool_call_id → (fn_name, canonical_args) map
        # from the preceding assistant messages, then mask older tool_results
        # whose signature also appears in a newer tool_result.
        from hashlib import md5 as _md5
        _sig_by_tc_id: Dict[str, str] = {}
        for msg in messages:
            if isinstance(msg, dict) and msg.get("role") == "assistant":
                for tc in msg.get("tool_calls") or []:
                    if isinstance(tc, dict):
                        fn = tc.get("function") or {}
                        tc_id = str(tc.get("id") or "")
                        if tc_id and isinstance(fn, dict):
                            sig = _md5(f"{fn.get('name','')}:{fn.get('arguments','')}".encode()).hexdigest()
                            _sig_by_tc_id[tc_id] = sig
        # Scan tool msgs oldest→newest; if a later msg has the same sig, mask older.
        _seen_sigs_future: Dict[str, int] = {}  # sig → latest index that has it
        for idx in _tool_msg_indices:
            msg = messages[idx]
            if isinstance(msg, dict):
                sig = _sig_by_tc_id.get(str(msg.get("tool_call_id") or ""), "")
                if sig:
                    _seen_sigs_future[sig] = idx
        _mask_cutoff = len(_tool_msg_indices) - _MASK_KEEP_RECENT
        _indices_to_mask: set = set()
        if _mask_cutoff > 0:
            _indices_to_mask.update(_tool_msg_indices[:_mask_cutoff])
        # Also mask older-but-within-window msgs whose signature has a newer twin.
        for idx in _tool_msg_indices:
            msg = messages[idx]
            if not isinstance(msg, dict):
                continue
            sig = _sig_by_tc_id.get(str(msg.get("tool_call_id") or ""), "")
            if sig and _seen_sigs_future.get(sig, idx) > idx:
                _indices_to_mask.add(idx)
        for idx in _indices_to_mask:
            msg = messages[idx]
            content = msg.get("content")
            if isinstance(content, str) and len(content) > 200:
                messages[idx] = dict(msg)
                messages[idx]["content"] = _MASK_PLACEHOLDER

        # ── Layer 0.5: PROVIDER-AWARE REASONING STRIP (v6.1.2) ────────
        # Different vendors disagree on whether `reasoning_content` must / must
        # NOT be replayed. Getting this wrong causes 400 errors in long tool
        # loops. Rules (verified 2026-04 via official docs + GitHub issues):
        #   DeepSeek Reasoner      → MUST NOT include reasoning_content
        #   DeepSeek V3.2          → MUST NOT include reasoning_content (non-reasoner)
        #   Anthropic Claude       → MUST include last-turn thinking block only
        #                            (earlier turns may be dropped)
        #   OpenAI o1/o3/o4        → do NOT echo reasoning; server manages via IDs
        #   Kimi K2.5 thinking     → MUST include for tool-call branch
        #   Kimi K2.5 non-thinking → drop
        #   Qwen-thinking / Doubao-thinking / GLM-thinking → keep
        # Env kill-switch EVERMIND_REASONING_STRICT=0 reverts to legacy behaviour.
        _reasoning_strict = str(os.getenv("EVERMIND_REASONING_STRICT", "1")).strip().lower() not in ("0", "false", "off", "no")
        if _reasoning_strict:
            _model_info_for_reasoning = self._resolve_model(model_name) or {}
            _provider_for_reasoning = str(_model_info_for_reasoning.get("provider") or "").strip().lower()
            _mn_lower = str(model_name or "").lower()
            # Fallback: infer provider from the bare model name when registry
            # lookup returns no provider (happens for raw litellm IDs like
            # "deepseek-chat" not in MODEL_REGISTRY).
            if not _provider_for_reasoning:
                if "deepseek" in _mn_lower:
                    _provider_for_reasoning = "deepseek"
                elif "claude" in _mn_lower or _mn_lower.startswith("anthropic"):
                    _provider_for_reasoning = "anthropic"
                elif _mn_lower.startswith("gpt-") or any(tag in _mn_lower for tag in ("o1-", "o3-", "o4-")):
                    _provider_for_reasoning = "openai"
                elif "kimi" in _mn_lower or "moonshot" in _mn_lower:
                    _provider_for_reasoning = "kimi"
                elif "qwen" in _mn_lower or "dashscope" in _mn_lower:
                    _provider_for_reasoning = "qwen"
            _drop_all_reasoning = False
            _keep_last_only = False
            if _provider_for_reasoning in ("deepseek",):
                _drop_all_reasoning = True
            elif _provider_for_reasoning == "anthropic" or "claude" in _mn_lower:
                _keep_last_only = True
            elif _provider_for_reasoning == "openai" and any(tag in _mn_lower for tag in ("o1", "o3", "o4", "gpt-5")):
                _drop_all_reasoning = True
            elif _provider_for_reasoning == "kimi":
                # keep only if thinking was requested (best-effort detection
                # from configured depth)
                _depth = self._configured_thinking_depth()
                if _depth != "deep":
                    _drop_all_reasoning = True
            # Other providers (qwen / zhipu / doubao / minimax / aigate / relay)
            # → keep as-is; their native thinking streams are fine to replay.
            if _drop_all_reasoning:
                for _m in messages:
                    if isinstance(_m, dict) and "reasoning_content" in _m:
                        _m.pop("reasoning_content", None)
            elif _keep_last_only:
                _last_assistant_idx = -1
                for _i, _m in enumerate(messages):
                    if isinstance(_m, dict) and _m.get("role") == "assistant":
                        _last_assistant_idx = _i
                for _i, _m in enumerate(messages):
                    if isinstance(_m, dict) and _i != _last_assistant_idx:
                        _m.pop("reasoning_content", None)

            # v6.1.3 → v6.1.14 (maintainer 2026-04-20): UNIVERSAL reasoning_content
            # synthesis. History: private-relay/aigate first hit this 400 (first tool
            # call round has no reasoning). Then kimi-k2.6-code-preview direct
            # hit it too. maintainer asked to make this universal so ANY relay + ANY
            # direct provider + ANY model works in deep mode.
            #
            # Contract: if we've decided to KEEP reasoning_content (i.e.
            # _drop_all_reasoning=False AND not Anthropic keep-last-only), AND
            # thinking is enabled (deep mode), then every assistant message MUST
            # carry `reasoning_content`. Upstream providers (OpenAI-compat API)
            # either ignore the extra field or require it — never reject. So
            # synthesizing empty string is the safe default that prevents 400s
            # across private-relay / aigate / openrouter / kimi direct / moonshot /
            # qwen / doubao / glm / minimax / any future relay.
            #
            # Exclusions already handled above:
            #   _drop_all_reasoning=True  → DeepSeek / o-series / gpt-5-thinking
            #   _keep_last_only=True      → Anthropic (only last turn retained)
            # Both those paths have already normalized the messages; no synth.
            _needs_empty_reasoning_synth = (
                not _drop_all_reasoning
                and not _keep_last_only
                and self._configured_thinking_depth() == "deep"
            )
            if _needs_empty_reasoning_synth:
                # v6.1.14b (maintainer 2026-04-20): Kimi Coding endpoint validator
                # treats `""` as "missing" — still 400s. Use a non-empty
                # placeholder so any strict validator sees a truthy value.
                # Plain text, no special syntax — safe for all OpenAI-compat
                # relays (they either use it or ignore it).
                _synth_placeholder = os.getenv(
                    "EVERMIND_REASONING_SYNTH_PLACEHOLDER",
                    "(no reasoning emitted by model this turn)",
                )
                _synth_count = 0
                for _m in messages:
                    if not isinstance(_m, dict):
                        continue
                    if _m.get("role") != "assistant":
                        continue
                    _cur = _m.get("reasoning_content")
                    if "reasoning_content" not in _m or _cur is None or _cur == "":
                        _m["reasoning_content"] = _synth_placeholder
                        _synth_count += 1
                if _synth_count and os.getenv("EVERMIND_DEBUG_REASONING_SYNTH"):
                    logger.info(
                        "reasoning_content synth: injected placeholder into %s assistant msg(s) for %s",
                        _synth_count, model_name,
                    )

        # ── Layer 1: SNIP — per-message truncation ──────────────────
        prepared: List[Dict[str, Any]] = []
        for msg in messages:
            if not isinstance(msg, dict):
                try:
                    prepared.append(self._serialize_assistant_message(msg))
                except Exception:
                    continue
                continue

            normalized = dict(msg)
            role = str(normalized.get("role") or "")
            content = normalized.get("content")
            if isinstance(content, str):
                if role == "tool":
                    normalized["content"] = self._truncate_text(content, MAX_TOOL_RESULT_CHARS)
                elif role == "assistant":
                    normalized["content"] = self._truncate_text(content, MAX_ASSISTANT_REPLAY_CHARS)
                else:
                    normalized["content"] = self._truncate_text(content, MAX_MESSAGE_CONTENT_CHARS)

            reasoning = normalized.get("reasoning_content")
            if isinstance(reasoning, str):
                normalized["reasoning_content"] = self._truncate_text(reasoning, MAX_REASONING_REPLAY_CHARS)

            tool_calls = normalized.get("tool_calls")
            if isinstance(tool_calls, list):
                compact_calls = []
                for tc in tool_calls:
                    if not isinstance(tc, dict):
                        compact_calls.append(tc)
                        continue
                    tc_copy = dict(tc)
                    fn = tc_copy.get("function")
                    if isinstance(fn, dict):
                        fn_copy = dict(fn)
                        function_name = str(fn_copy.get("name") or "")
                        args = fn_copy.get("arguments")
                        if isinstance(args, str):
                            fn_copy["arguments"] = self._compact_tool_arguments_for_replay(function_name, args)
                        tc_copy["function"] = fn_copy
                    compact_calls.append(tc_copy)
                normalized["tool_calls"] = compact_calls

            prepared.append(normalized)

        original_total = sum(self._message_char_count(m) for m in prepared)
        if original_total <= MAX_REQUEST_TOTAL_CHARS:
            return self._inject_prompt_cache_breakpoints(
                self._fix_orphaned_tool_call_ids(prepared),
                model=model_name,
            )

        # ── Layer 2: MICROCOMPACT — tool call dedup + read summarization ─
        dedup_count = self._dedup_tool_calls_in_history(prepared)
        # Summarize verbose read-only tool results (list/read actions)
        self._summarize_read_tool_results(prepared)

        l2_total = sum(self._message_char_count(m) for m in prepared)
        if l2_total <= MAX_REQUEST_TOTAL_CHARS:
            logger.info(
                "Microcompact sufficient: model=%s chars=%s->%s dedup=%s",
                model_name, original_total, l2_total, dedup_count,
            )
            return self._inject_prompt_cache_breakpoints(
                self._fix_orphaned_tool_call_ids(prepared),
                model=model_name,
            )

        # ── Layer 3: CONTEXT COLLAPSE — drop older message content ───
        keep_last = max(4, MAX_CONTEXT_KEEP_LAST_MESSAGES)
        compact_upto = max(2, len(prepared) - keep_last)
        # v6.1.14d (maintainer 2026-04-20): preserve reasoning_content placeholder
        # through compaction — Kimi Coding / any strict thinking validator
        # treats "" as missing and 400s. Use the same placeholder the earlier
        # synth block uses so the contract is consistent.
        _collapsed_reasoning_placeholder = os.getenv(
            "EVERMIND_REASONING_SYNTH_PLACEHOLDER",
            "(no reasoning emitted by model this turn)",
        )
        for idx, msg in enumerate(prepared):
            if idx >= compact_upto:
                continue
            role = str(msg.get("role") or "")
            if role in ("assistant", "tool", "user"):
                if isinstance(msg.get("content"), str) and msg.get("content"):
                    msg["content"] = CONTEXT_OMITTED_MARKER
                if isinstance(msg.get("reasoning_content"), str):
                    # v6.1.14d: never blank out reasoning_content — keep
                    # placeholder so the thinking validator stays satisfied.
                    msg["reasoning_content"] = (
                        _collapsed_reasoning_placeholder if role == "assistant" else ""
                    )
                # Keep tool_call structure but drop large historical args.
                if role == "assistant" and isinstance(msg.get("tool_calls"), list):
                    trimmed_calls = []
                    for tc in msg["tool_calls"]:
                        if not isinstance(tc, dict):
                            trimmed_calls.append(tc)
                            continue
                        tc_copy = dict(tc)
                        fn = tc_copy.get("function")
                        if isinstance(fn, dict):
                            fn_copy = dict(fn)
                            if isinstance(fn_copy.get("arguments"), str):
                                fn_copy["arguments"] = "{}"
                            tc_copy["function"] = fn_copy
                        trimmed_calls.append(tc_copy)
                    msg["tool_calls"] = trimmed_calls

        l3_total = sum(self._message_char_count(m) for m in prepared)
        if l3_total > MAX_REQUEST_TOTAL_CHARS:
            # Safety clamp: shrink non-critical messages proportionally.
            per_msg_budget = max(256, MAX_REQUEST_TOTAL_CHARS // max(1, len(prepared)))
            for idx, msg in enumerate(prepared):
                if idx < 2:
                    continue
                if isinstance(msg.get("content"), str):
                    msg["content"] = self._truncate_text(msg["content"], per_msg_budget)
                if isinstance(msg.get("reasoning_content"), str):
                    msg["reasoning_content"] = self._truncate_text(msg["reasoning_content"], min(512, per_msg_budget // 2))
            l3_total = sum(self._message_char_count(m) for m in prepared)

        logger.warning(
            "Context compacted L1→L3: model=%s chars=%s->%s->%s messages=%s dedup=%s",
            model_name,
            original_total,
            l2_total,
            l3_total,
            len(prepared),
            dedup_count,
        )

        # ── Layer 4: AUTOCOMPACT — semantic compression ──────────────
        # After structural compaction, apply sentence-level compression
        # to remaining verbose messages to further reduce token count.
        try:
            _pre_compress_chars = sum(len(str(m.get("content") or "")) for m in prepared)
            # V4.4: More aggressive compression ratio for long tool-loops
            _target_ratio = 0.50 if l3_total > MAX_REQUEST_TOTAL_CHARS * 0.8 else 0.65
            prepared = _compress_messages(
                prepared,
                target_ratio=_target_ratio,
                preserve_last_n=max(4, MAX_CONTEXT_KEEP_LAST_MESSAGES),
            )
            _post_compress_chars = sum(len(str(m.get("content") or "")) for m in prepared)
            _saved_pct = round((1 - _post_compress_chars / max(_pre_compress_chars, 1)) * 100)
            if _saved_pct > 0:
                logger.info(
                    "Autocompact L4: %d→%d chars (-%d%%, ratio=%.2f)",
                    _pre_compress_chars, _post_compress_chars, _saved_pct, _target_ratio,
                )
        except Exception as _comp_exc:
            logger.info("Autocompact L4 skipped: %s", str(_comp_exc)[:120])

        # ── Fix: Validate tool_call_id sequencing after compaction ──
        prepared = self._fix_orphaned_tool_call_ids(prepared)

        # v5.7 + v5.8.2: cross-provider prompt-cache preparation.
        # - Anthropic: injects explicit cache_control markers (90% cost cut on read).
        # - OpenAI / Kimi / others: returns messages unchanged — they have
        #   automatic prefix cache that fires as long as the prefix stays
        #   byte-identical, which our sorted-set and cached-catalog fixes
        #   above now guarantee.
        prepared = self._inject_prompt_cache_breakpoints(prepared, model=model_name)
        # v6.5 Phase 2 (#9): stamp large builder-handoff blocks (>=8KB text)
        # with cache_control:ephemeral. Idempotent — skips blocks already
        # stamped by the system/user breakpoint pass above.
        prepared = self._stamp_builder_handoff_cache(prepared, model=model_name)
        return prepared

    def _summarize_read_tool_results(self, messages: List[Dict[str, Any]]) -> None:
        """Microcompact helper: shrink verbose read/list tool results.

        For file_ops read results over 2000 chars, replace content with
        a byte-count summary.  For list results, cap at 30 entries.
        This runs in-place.
        """
        _READ_SUMMARY_THRESHOLD = 2000
        _LIST_MAX_ENTRIES = 30

        for msg in messages:
            if not isinstance(msg, dict) or msg.get("role") != "tool":
                continue
            content = msg.get("content")
            if not isinstance(content, str) or len(content) < _READ_SUMMARY_THRESHOLD:
                continue

            # Try to detect read results with file content
            try:
                parsed = json.loads(content)
                if not isinstance(parsed, dict):
                    continue
                data = parsed.get("data") or parsed
                if not isinstance(data, dict):
                    continue

                # Opus review #2 P5: summarise any large textual payload, not
                # just data.content. Real-world tool results use different
                # field names per plugin: file_ops→content, browser
                # observe/snapshot→snapshot, shell→stdout/output, source_fetch
                # →text/html. Summarising all of them keeps the prompt
                # window bounded in multi-tool loops.
                _LARGE_TEXT_FIELDS = ("content", "text", "html", "output",
                                      "stdout", "snapshot", "body")
                compacted_any = False
                for _field in _LARGE_TEXT_FIELDS:
                    _value = data.get(_field)
                    if not isinstance(_value, str) or len(_value) <= _READ_SUMMARY_THRESHOLD:
                        continue
                    lines = _value.split("\n")
                    keep_head = min(10, len(lines))
                    keep_tail = min(5, max(0, len(lines) - keep_head))
                    summary_lines = lines[:keep_head]
                    if keep_tail:
                        summary_lines.append(
                            f"... [{len(lines) - keep_head - keep_tail} lines omitted, field={_field}] ..."
                        )
                        summary_lines.extend(lines[-keep_tail:])
                    data[_field] = "\n".join(summary_lines)
                    compacted_any = True
                # Opus review #8 P2: fall through to list-cap even when text
                # fields already compacted. A single tool result can have both
                # a huge `content` AND a large `entries` list (file_ops list on
                # a folder with big file previews).
                if compacted_any:
                    data["_compacted"] = True

                # Summarize list results: cap entries
                entries = data.get("entries") or data.get("files") or data.get("items")
                if isinstance(entries, list) and len(entries) > _LIST_MAX_ENTRIES:
                    key = "entries" if "entries" in data else ("files" if "files" in data else "items")
                    data[key] = entries[:_LIST_MAX_ENTRIES]
                    data["_truncated_from"] = len(entries)
                    compacted_any = True

                if compacted_any:
                    msg["content"] = json.dumps(parsed, ensure_ascii=False)
            except (json.JSONDecodeError, ValueError):
                continue

    def _fix_orphaned_tool_call_ids(self, messages: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        """
        Validate tool_call_id sequencing: every assistant message with tool_calls
        must be followed by tool messages responding to each tool_call_id.
        Inject synthetic error responses for orphaned tool_call_ids.
        """
        # Collect all tool_call_ids that have responses
        responded_ids: set = set()
        for msg in messages:
            if isinstance(msg, dict) and msg.get("role") == "tool":
                tc_id = msg.get("tool_call_id")
                if tc_id:
                    responded_ids.add(tc_id)

        # Find orphaned tool_call_ids from assistant messages
        orphaned: List[tuple] = []  # (insert_after_idx, tc_id, fn_name)
        for idx, msg in enumerate(messages):
            if not isinstance(msg, dict) or msg.get("role") != "assistant":
                continue
            tool_calls = msg.get("tool_calls")
            if not isinstance(tool_calls, list):
                continue
            for tc in tool_calls:
                if not isinstance(tc, dict):
                    continue
                tc_id = tc.get("id", "")
                fn = tc.get("function") or {}
                fn_name = fn.get("name", "unknown") if isinstance(fn, dict) else "unknown"
                if tc_id and tc_id not in responded_ids:
                    orphaned.append((idx, tc_id, fn_name))

        if not orphaned:
            return messages

        logger.warning(
            "Fixing %s orphaned tool_call_ids in message history: %s",
            len(orphaned),
            [(tc_id, fn_name) for _, tc_id, fn_name in orphaned[:8]],
        )

        # Group orphans by their assistant message index
        orphan_by_idx: Dict[int, List[tuple]] = {}
        for assistant_idx, tc_id, fn_name in orphaned:
            orphan_by_idx.setdefault(assistant_idx, []).append((tc_id, fn_name))

        # Build result with injected synthetic tool responses
        result: List[Dict[str, Any]] = []
        for idx, msg in enumerate(messages):
            result.append(msg)
            if idx in orphan_by_idx:
                # Find the correct insertion point: after the last existing tool
                # response for this assistant message, or immediately after it.
                for tc_id, fn_name in orphan_by_idx[idx]:
                    result.append({
                        "role": "tool",
                        "tool_call_id": tc_id,
                        "content": json.dumps({
                            "success": False,
                            "error": f"Tool call '{fn_name}' was truncated or interrupted. Context was compacted.",
                            "data": {},
                            "artifacts": [],
                        }),
                    })

        return result

    def _builder_web_research_enabled(self) -> bool:
        return is_builder_browser_enabled(config=self.config)

    def _compose_system_prompt(
        self,
        node: Dict[str, Any],
        plugins: Optional[List[Plugin]] = None,
        input_data: str = "",
    ) -> str:
        """Compose and compress the system prompt for a node."""
        raw = self._compose_system_prompt_raw(node, plugins=plugins, input_data=input_data)
        return compress_system_prompt(raw)

    def _compose_system_prompt_raw(
        self,
        node: Dict[str, Any],
        plugins: Optional[List[Plugin]] = None,
        input_data: str = "",
    ) -> str:
        node_type = node.get("type", "builder")
        normalized_node_type = normalize_node_role(node_type) or str(node_type or "builder")
        preset = AGENT_PRESETS.get(str(node_type or ""), AGENT_PRESETS.get(normalized_node_type, {}))
        base_prompt = node.get("prompt") or preset.get("instructions", "You are a helpful assistant.")
        prompt_source = str(input_data or node.get("goal") or node.get("task") or "").strip()
        # v6.1.3 (maintainer 2026-04-19): lightweight fast-path for pure classifier
        # nodes (router). Router outputs a 100-byte JSON — it does NOT need
        # skill directives, execution report templates, scratchpad rules or
        # strategy blocks. Industry norm (Kiro/Cline/Cursor) is <4KB router.
        # Previously Evermind router ballooned to 9KB from cross-node harness
        # injection, taking 30s+ for what should be a 3s classification.
        if normalized_node_type == "router":
            return base_prompt
        # V4.3: Language-aware reports for ALL node types (was only 5).
        # Without this, builder/merger/tester execution_report sections
        # ignore the user's language setting.
        # v6.1.14e (maintainer 2026-04-20): prefer the DEDICATED walkthrough_language
        # setting, so maintainer can run the UI in English but still receive Chinese
        # analyst handoffs and builder copy (he reported walkthrough stuck in
        # English despite walkthrough_language=zh).
        _walk_lang = str(self.config.get("walkthrough_language", "") or "").strip().lower()
        ui_language = _walk_lang if _walk_lang in ("zh", "en") else str(self.config.get("ui_language", "") or "").strip().lower()
        if ui_language:
            lang_name = "Chinese (简体中文)" if ui_language == "zh" else "English"
            language_directive = (
                f"\n\nREPORT LANGUAGE: Write your entire report, analysis, execution_report, AND any user-facing UI copy/text you generate in {lang_name}. "
                f"Use natural {lang_name} for all headings, descriptions, analysis content, page titles, section headers, hero copy, button labels, and body text. "
                "Technical terms (function names, file paths, library names, variable names) should keep their English form.\n"
            )
            base_prompt = base_prompt + language_directive
        # v6.1.14e (maintainer 2026-04-20): hard rule against Evermind brand
        # pollution. Observed real run where builder produced
        # `<title>Evermind — Unlock Your Mind's Potential</title>` while the
        # user's goal was a Chinese artisan/craft website. The model keyed
        # off `/tmp/evermind_output/` in the system prompt and inferred
        # "Evermind" was the product brand. Reinforce that the output is
        # for the USER's goal, not the pipeline's internal name.
        if normalized_node_type in {"builder", "polisher", "debugger", "merger", "uidesign", "scribe"}:
            base_prompt = base_prompt + (
                "\n\n## NAMING / BRAND RULES (v6.1.14e)\n"
                "- NEVER use 'Evermind' as a product name, brand, title, tagline, or copy text. "
                "`evermind_output` is the INTERNAL pipeline scratchpad path — the product you build belongs to the USER, not to the pipeline.\n"
                "- Derive the product name, title, and brand voice STRICTLY from the user's goal. "
                "If the user's goal doesn't name a brand, invent a neutral name that fits the topic "
                "(e.g. for a craft showcase, pick a word evoking craftsmanship, materials, or heritage).\n"
                "- Keep the goal's original language for the title and all user-facing copy. "
                "Chinese goal → Chinese copy; English goal → English copy. Mixing is a reject.\n"
            )
        # v4.0: Inject universal execution protocol for all node types
        base_prompt = base_prompt + BASE_HARNESS_PREAMBLE

        # v5.2: Reviewer/Tester browser tool downgrade.
        # If the Playwright runtime is unavailable (user hasn't enabled visual
        # smoke-test / chromium not installed), the reviewer preset's MANDATORY
        # browser-steps cause a tool-call loop because `browser`/`browser_use`
        # plugins were filtered out of the tool list. We handle two tiers:
        #   (a) both browser + browser_use missing → full read-only review
        #   (b) browser_use missing (game review would demand it) → keep browser,
        #       drop browser_use directives so the model doesn't hallucinate the tool
        if normalized_node_type in ("reviewer", "tester"):
            # v5.8.1: sort plugin names for deterministic iteration so Kimi's
            # prefix cache doesn't miss between calls whose plugin set has the
            # same membership but different set-iteration order.
            _plugin_names_sorted = sorted({getattr(p, "name", "") or "" for p in (plugins or [])})
            _plugin_names = set(_plugin_names_sorted)
            _has_browser = "browser" in _plugin_names
            _has_browser_use = "browser_use" in _plugin_names
            if not _has_browser and not _has_browser_use:
                base_prompt += (
                    "\n\n## BROWSER DISABLED — READ-ONLY REVIEW MODE (OVERRIDES VISUAL REVIEW PROTOCOL)\n"
                    "The runtime does NOT have Playwright / browser_use available on this host. "
                    "DO NOT attempt to call any browser tool — it is NOT in your tool list and any "
                    "`browser`/`browser_use` call will trigger a tool-loop guard and block your "
                    "verdict. Ignore every `browser ...` / `browser_use ...` instruction in the "
                    "VISUAL REVIEW PROTOCOL section above.\n"
                    "Perform the review via file_ops only:\n"
                    "1. `file_ops list` /tmp/evermind_output/ — enumerate deliverables.\n"
                    "2. `file_ops read` each HTML / JS / CSS file — inspect structure, code quality, "
                    "accessibility markup, and content completeness directly from source.\n"
                    "3. For games: confirm index.html contains THREE.Scene / WebGLRenderer / "
                    "requestAnimationFrame + input listeners (keydown, mousedown, pointerlockchange). "
                    "Structural presence is sufficient evidence for functionality/completeness scoring "
                    "(award ≥6 when the markers exist) because you cannot perform live interaction.\n"
                    "4. Skip zone-by-zone screenshots/scrolling — use HTML section hierarchy + CSS "
                    "rules as evidence for layout/color/typography scoring.\n"
                    "5. The MANDATORY JSON Verdict block at the end of your report is still required "
                    "and must be valid JSON on a single line.\n"
                )
            elif not _has_browser_use:
                # browser is available but browser_use is not (EVERMIND_QA_ENABLE_BROWSER_USE=0
                # by default). Preset demands browser_use for games — strip that requirement.
                base_prompt += (
                    "\n\n## browser_use DISABLED — USE internal browser ONLY\n"
                    "The `browser_use` higher-level agent tool is NOT enabled on this host. "
                    "DO NOT call `browser_use ...` — it is NOT in your tool list and any such "
                    "call will trigger a tool-loop guard and block your verdict. For GAMES, "
                    "ignore the 'MUST use browser_use' line in the VISUAL REVIEW PROTOCOL and "
                    "instead drive review with the internal `browser` tool: navigate, observe, "
                    "screenshot, record_scroll, act. For games specifically, trigger "
                    "start/restart via `browser act` clicking on the visible control, then "
                    "`browser observe` to confirm state change. Do NOT require browser_use "
                    "evidence in your verdict — structural + internal-browser evidence is "
                    "sufficient to score functionality/completeness.\n"
                )

        # v6.1.14f (maintainer 2026-04-20): extend react-bits injection to polisher
        # and merger. Originally only builder got this catalog. Polisher needs
        # it to know which animation/transition components to micro-edit into
        # the existing artifact. Merger needs it when consolidating peer
        # builder outputs that reference react-bits components.
        # v6.4.11 (maintainer 2026-04-22): extend to uidesign and analyst. uidesign
        # designs the brief → it must know which components builder can call
        # on ("use Magnet hover buttons here, Aurora background in hero, Bento
        # grid for features") instead of inventing visuals from scratch.
        # analyst researches frontend references → knowing the catalog lets it
        # link concrete component names into reference_sites / implementation
        # notes instead of describing effects abstractly. Cost: ~2KB prompt.
        if normalized_node_type in {"builder", "polisher", "merger", "uidesign", "analyst"}:
            if normalized_node_type == "builder":
                prompt_source = self._builder_goal_hint_source(
                    goal_hint=str(node.get("goal") or ""),
                    input_data=prompt_source,
                ) or prompt_source
            # v5.5: Inject React Bits component catalog.
            # v5.8.1: cached once on self — rebuilding every request was a
            # Kimi prefix-cache killer because the dict iteration + slicing
            # could drift byte-for-byte between calls. Cached value is
            # recomputed only if ui_language changes at runtime (rare).
            try:
                cached_block = getattr(self, "_react_bits_block_cache", None)
                cached_lang = getattr(self, "_react_bits_block_cache_lang", None)
                _ui_lang = str((getattr(self, "config", {}) or {}).get("ui_language", "zh") or "zh").lower()
                if cached_block is None or cached_lang != _ui_lang:
                    import react_bits_catalog
                    if react_bits_catalog.is_enabled(getattr(self, "config", {}) or {}):
                        cached_block = react_bits_catalog.build_prompt_block(
                            lang=_ui_lang, max_per_category=8,
                        )
                    else:
                        cached_block = ""
                    self._react_bits_block_cache = cached_block
                    self._react_bits_block_cache_lang = _ui_lang
                if cached_block:
                    base_prompt = base_prompt + cached_block
            except Exception as _rbc_err:
                logger.debug("React Bits catalog inject skipped: %s", _rbc_err)
        skill_block = build_skill_context(normalized_node_type, prompt_source)
        skill_names = resolve_skill_names_for_goal(normalized_node_type, prompt_source)
        builder_delivery_mode = ""
        if normalized_node_type == "builder":
            builder_delivery_mode = str(node.get("builder_delivery_mode") or "").strip().lower()
        repo_context = None
        # Direct preview-delivery builders own /tmp output artifacts, not the shared repo.
        # Keep repo-edit guidance out even if upstream retry text mentions repo-ish paths.
        if not (
            normalized_node_type == "builder"
            and builder_delivery_mode in {"direct_text", "direct_multifile"}
        ):
            repo_context = build_repo_context(normalized_node_type, prompt_source, self.config)
        runtime_output_block = self._runtime_output_prompt_block()
        skill_contract = ""
        if skill_names:
            skill_contract = (
                "\n═══ MANDATORY SKILL DIRECTIVES ═══\n"
                "The following skills are loaded as MANDATORY operational directives for this execution.\n"
                "You MUST follow every instruction in each skill section below.\n"
                "Ignoring a skill directive is treated as a task failure by the reviewer.\n\n"
                "ACTIVE SKILLS:\n"
                + "\n".join(f"  [OK] {name}" for name in skill_names)
                + "\n\nSKILL COMPLIANCE CHECKLIST (verify before finishing):\n"
                + "\n".join(f"  - [{name}] Applied its core directives? YES/NO" for name in skill_names[:6])
                + "\n═══ END SKILL DIRECTIVES ═══\n"
            )
        strategy_block = self._node_execution_strategy_prompt_block(node)
        repo_block = ""
        if repo_context:
            repo_root = str(repo_context.get("repo_root") or "").strip()
            repo_map_prompt = str(repo_context.get("prompt_block") or "").strip()
            repo_block = (
                "\n\nEXISTING REPOSITORY EDIT MODE:\n"
                f"- Work inside the existing repository at {repo_root}\n"
                "- This is NOT a greenfield one-file HTML task unless the user explicitly asks for that\n"
                "- Start from the repo map, inspect only the relevant files, then make the smallest coherent edits\n"
                "- Preserve the repo's architecture, naming, build system, and existing conventions\n"
                "- Prefer editing existing files over creating parallel replacements or shadow copies\n"
                "- If shell-based verification is available, run the smallest relevant verification command before finishing\n"
            )
            if repo_map_prompt:
                repo_block += f"\nAIDER-STYLE REPO MAP:\n{repo_map_prompt}"
        if node_type != "builder":
            backend_hint = ""
            if node_type == "imagegen":
                asset_mode = task_classifier.game_asset_pipeline_mode(prompt_source)
                if is_image_generation_available(config=self.config):
                    backend_hint = (
                        "\nIMAGE BACKEND STATUS:\n"
                        "- Configured image backend detected\n"
                        "- Health-check the comfyui plugin first, then generate concrete assets if the run requires final art files\n"
                    )
                else:
                    if asset_mode == "3d":
                        backend_hint = (
                            "\nIMAGE BACKEND STATUS:\n"
                            "- No configured image backend detected in runtime settings\n"
                            "- Do NOT pretend to have raster generation\n"
                            "- For this 3D game goal, switch to modeling-design mode: produce character / monster / weapon / environment briefs, silhouette rules, material notes, rig-or-animation requirements, and builder-ready replacement guidance\n"
                            "- Land the minimum viable replacement pack first: 00_visual_target.md, 01_style_lock.md, manifest.json, character_hero_brief.md, monster_primary_brief.md, weapon_primary_brief.md, and environment_kit_brief.md\n"
                            "- Do NOT create optional orthographic/material/shortlist companion docs until that core pack is already complete and substantive\n"
                            "- If source_fetch or browser is available, use source_fetch first on a small set of permissive asset/model libraries or technical docs when the analyst handoff still lacks a critical reference; otherwise write the core pack immediately\n"
                            "- If you gather external asset references, keep them clearly licensed and limited to the most relevant sources (for example Kenney, Poly Pizza, Quaternius, ambientCG, or clearly licensed OpenGameArt entries)\n"
                            "- After the core pack is stable, you may add asset_sources.md or asset_license_matrix.md with replacement candidates and license notes\n"
                        )
                    else:
                        backend_hint = (
                            "\nIMAGE BACKEND STATUS:\n"
                            "- No configured image backend detected in runtime settings\n"
                            "- Do NOT pretend to have raster generation\n"
                            "- Return production-ready prompt packs, negative prompts, style locks, and replacement guidance instead\n"
                        )
            if skill_block:
                return f"{base_prompt}{strategy_block}{backend_hint}{runtime_output_block}\n\nLOADED NODE SKILLS:\n{skill_block}{skill_contract}{repo_block}" + EXECUTION_REPORT_TEMPLATE
            return base_prompt + strategy_block + backend_hint + runtime_output_block + repo_block + EXECUTION_REPORT_TEMPLATE

        # Builder system prompt is task-adaptive so game/dashboard/tool goals don't get
        # constrained by website-only guidance.
        # V4.6 SPEED: Use split_deferred=True to move large reference blocks (CSS,
        # design system, topic images) out of the system prompt. They get injected
        # into the user message instead, keeping the system prefix small and stable
        # for prompt caching. Saves ~10K chars from system prompt per request.
        adaptive_source = prompt_source
        if adaptive_source:
            try:
                result = task_classifier.builder_system_prompt(
                    adaptive_source, split_deferred=True,
                )
                if isinstance(result, tuple):
                    base_prompt, deferred_ctx = result
                    self._builder_deferred_context = deferred_ctx or ""
                else:
                    base_prompt = result
            except Exception:
                # Keep execution resilient if classifier has an unexpected runtime issue.
                pass

        if repo_block:
            if skill_block:
                return f"{base_prompt}{strategy_block}{runtime_output_block}\n\nLOADED NODE SKILLS:\n{skill_block}{skill_contract}{repo_block}" + EXECUTION_REPORT_TEMPLATE
            return base_prompt + strategy_block + runtime_output_block + repo_block + EXECUTION_REPORT_TEMPLATE

        # V4.6 SPEED: When builder staging is active, tell the model its ACTUAL
        # output directory so it doesn't try to write to /tmp/evermind_output/ root
        # (which gets blocked and wastes 130-180s on path escape retries).
        builder_staging_dir = str(node.get("builder_file_ops_output_dir") or node.get("builder_staging_output_dir") or "").strip()
        if builder_staging_dir:
            runtime_output_block += (
                f"\n[警告] IMPORTANT: Your output directory is {builder_staging_dir}/ (NOT the root output directory).\n"
                f"All file_ops writes MUST target {builder_staging_dir}/. "
                "Writing to the parent directory will be rejected.\n"
            )

        has_browser_plugin = any(p and getattr(p, "name", "") == "browser" for p in (plugins or []))
        web_research_enabled = self._builder_web_research_enabled() and has_browser_plugin
        if web_research_enabled:
            mode_hint = (
                "\n\nWEB RESEARCH MODE (ENABLED):\n"
                "- Use browser observe / extract for quick style research (max 2 pages)\n"
                "- Use browser act only when a site requires one interaction to reveal important content\n"
                "- Extract structure/tone/color intent only; never copy site code\n"
                "- After research, produce a fresh implementation locally in one HTML file\n"
            )
        else:
            mode_hint = (
                "\n\nWEB RESEARCH MODE (DISABLED):\n"
                "- Do not rely on live web browsing\n"
                "- Achieve premium look using inline SVG icons, gradients, and robust layout system\n"
            )
        # v6.1.3 (direct_text narration hotfix): when no tools are attached,
        # kimi-k2.5 / k2.6-code-preview have been observed stopping after
        # 100-300 chars of "I'll inspect existing files first" planning prose
        # because their training assumes file_ops is always available. The
        # narration guard correctly rejects that output, but it wastes the
        # entire builder retry budget. An explicit NO-TOOLS directive forces
        # them to emit `<!DOCTYPE html>` as the first token.
        direct_text_override = ""
        if builder_delivery_mode == "direct_text":
            direct_text_override = (
                "\n\n═══ DIRECT-TEXT DELIVERY MODE (NO TOOLS AVAILABLE) ═══\n"
                "You have NO tools in this request. There is no `file_ops`, no "
                "`shell`, no `browser`. Any reference in the preset above to "
                "`file_ops write`, `first tool call`, or `read existing files` "
                "DOES NOT APPLY to this call — ignore those sections.\n\n"
                "YOUR ONLY OUTPUT: the complete HTML file content starting with "
                "`<!DOCTYPE html>` and ending with `</html>`. The runtime will "
                "save your raw response as index.html automatically.\n\n"
                "FORBIDDEN OUTPUTS (will be auto-rejected by narration guard):\n"
                "- 'I'll inspect existing files...'\n"
                "- 'Let me check the current project state...'\n"
                "- 'I need to read...'\n"
                "- Any markdown fence, JSON wrapper, or prose before the DOCTYPE.\n\n"
                "Start your reply with `<!DOCTYPE html>` — no preamble.\n"
                "═══ END DIRECT-TEXT DIRECTIVE ═══\n"
            )
        # v6.1.3 (Opus P0 #2): direct_text mode MUST NOT append the execution
        # report template. The report block tells the model to emit "##
        # EXECUTION REPORT" prose AFTER its output; combined with our DOCTYPE-
        # first directive this creates a contradiction that Kimi resolves by
        # appending the report after `</html>` (breaks raw-save path) or by
        # emitting the report in place of HTML (triggers narration guard).
        _report_tail = "" if builder_delivery_mode == "direct_text" else EXECUTION_REPORT_TEMPLATE
        if skill_block:
            return f"{base_prompt}{strategy_block}{runtime_output_block}\n\nLOADED NODE SKILLS:\n{skill_block}{skill_contract}{mode_hint}{direct_text_override}" + _report_tail
        return base_prompt + strategy_block + runtime_output_block + mode_hint + direct_text_override + _report_tail

    def _serialize_assistant_message(self, msg: Any) -> Dict[str, Any]:
        # Keep provider-specific fields (e.g. reasoning_content) if available.
        payload: Dict[str, Any] = {}
        if hasattr(msg, "model_dump"):
            try:
                dumped = msg.model_dump(exclude_none=True)
                if isinstance(dumped, dict):
                    payload.update(dumped)
            except Exception:
                pass
        elif hasattr(msg, "dict"):
            try:
                dumped = msg.dict(exclude_none=True)
                if isinstance(dumped, dict):
                    payload.update(dumped)
            except Exception:
                pass

        payload["role"] = "assistant"
        if "content" not in payload:
            payload["content"] = getattr(msg, "content", "") or ""

        # P0 FIX: Prevent empty assistant messages that trigger API 400 errors.
        # When finish=length strips tool calls, both content and tool_calls can be empty.
        # Inject a safe fallback to avoid "message must not be empty" from providers.
        tool_calls_raw = payload.get("tool_calls") or getattr(msg, "tool_calls", None) or []
        if not payload.get("content") and not tool_calls_raw:
            payload["content"] = "(output truncated by token limit — continuing)"

        reasoning_content = getattr(msg, "reasoning_content", None)
        if reasoning_content is not None and "reasoning_content" not in payload:
            payload["reasoning_content"] = reasoning_content

        tool_calls = payload.get("tool_calls")
        if tool_calls is None:
            tool_calls = getattr(msg, "tool_calls", None) or []
        normalized_tool_calls = []
        for tc in tool_calls:
            if isinstance(tc, dict):
                normalized_tool_calls.append(tc)
                continue
            fn = getattr(tc, "function", None)
            normalized_tool_calls.append({
                "id": getattr(tc, "id", ""),
                "type": getattr(tc, "type", "function"),
                "function": {
                    "name": getattr(fn, "name", ""),
                    "arguments": getattr(fn, "arguments", "{}"),
                },
            })
        if normalized_tool_calls:
            payload["tool_calls"] = normalized_tool_calls
        return payload

    def _debug_log_tool_messages(self, messages: List[Dict[str, Any]], model_name: str):
        if not os.getenv("EVERMIND_DEBUG_KIMI_MESSAGES"):
            return
        try:
            for idx, m in enumerate(messages):
                if not isinstance(m, dict):
                    continue
                if m.get("role") != "assistant":
                    continue
                if not m.get("tool_calls"):
                    continue
                has_reasoning = "reasoning_content" in m and bool(m.get("reasoning_content"))
                logger.warning(
                    "Kimi debug msg[%s] model=%s tool_calls=%s has_reasoning_content=%s keys=%s",
                    idx,
                    model_name,
                    len(m.get("tool_calls") or []),
                    has_reasoning,
                    sorted(list(m.keys())),
                )
                if os.getenv("EVERMIND_DEBUG_KIMI_CALLS"):
                    print(
                        f"KIMI_DEBUG_MSG idx={idx} model={model_name} tool_calls={len(m.get('tool_calls') or [])} "
                        f"has_reasoning={has_reasoning} keys={sorted(list(m.keys()))}",
                        flush=True,
                    )
        except Exception:
            pass

    # ─────────────────────────────────────────
    # Pre-flight: check API key availability
    # ─────────────────────────────────────────
    def _check_api_key(self, model_name: str, model_info: Dict) -> Optional[str]:
        """Check if the required API key for a model is configured. Returns error string or None."""
        provider = model_info.get("provider", "")

        # Relay and ollama don't need API keys from us
        if provider in ("relay", "ollama", ""):
            return None

        recent_auth_failure = self._provider_recent_auth_failure_reason(model_info)
        if recent_auth_failure:
            return recent_auth_failure

        env_key = PROVIDER_ENV_KEY_MAP.get(provider)
        if not env_key:
            return None  # Unknown provider, let it try

        # Check config dict (from WS update_config) and env var
        config_key = env_key.lower()  # e.g. "openai_api_key"
        has_key = bool(self.config.get(config_key)) or bool(os.getenv(env_key))

        if not has_key:
            provider_names = {
                "openai": "OpenAI", "anthropic": "Anthropic/Claude",
                "google": "Google/Gemini", "deepseek": "DeepSeek",
                "kimi": "Kimi/Moonshot", "qwen": "Qwen/通义千问",
            }
            name = provider_names.get(provider, provider)
            return (
                f"未配置 {name} 的 API Key。"
                f"请在「设置 → 连接 → API 密钥」中填入 {name} 的 Key，"
                f"然后点击「保存到后端」。\n"
                f"The {name} API key is not configured. "
                f"Please go to Settings → Connection → API Keys and enter your {name} key."
            )
        return None

    def _should_retry_same_model(
        self,
        error_message: str,
        *,
        node_type: str = "",
        model_name: str = "",
        model_info: Optional[Dict[str, Any]] = None,
    ) -> bool:
        error_lower = str(error_message or "").lower()
        if not error_lower:
            return True
        non_retryable_markers = (
            "api key",
            "api_key",
            "invalid key",
            "not configured",
            "unauthorized",
            "forbidden",
            "401",
            "403",
            "authentication",
            "auth failed",
            "permission",
            "empty or invalid response from llm endpoint",
            "invalid response from llm endpoint",
            "received: '<!doctype html",
            "relay - ai api gateway",
            "your request was blocked",
            "request was blocked",
            "content policy",
            "safety system",
            "model not found",
            "does not exist",
            "unsupported model",
            "invalid request",
            "invalid_request_error",
            "unsupported input",
            "builder pre-write timeout",
            "polisher pre-write timeout",
            "polisher loop guard",
            "initial-activity timeout",
            "compatible gateway circuit open",
            "compatible gateway rejection cooldown",
            "returned empty content for builder node",
            "empty content for builder node",
        )
        if any(marker in error_lower for marker in non_retryable_markers):
            return False
        normalized_node_type = normalize_node_role(node_type)
        relay_fast_fail_markers = (
            "timeout",
            "timed out",
            "bad gateway",
            "gateway timeout",
            "remoteprotocolerror",
            "connection",
            "network",
            "socket",
            "dns",
            "service unavailable",
            "temporarily unavailable",
            "502",
            "503",
            "504",
        )
        if normalized_node_type in self._compatible_gateway_fail_fast_node_types() and any(
            marker in error_lower for marker in relay_fast_fail_markers
        ):
            if self._relay_model_candidates_for(model_name):
                return False
        if self._custom_compatible_gateway_base(model_info):
            gateway_fast_fail_markers = (
                "timeout",
                "timed out",
                "bad gateway",
                "gateway timeout",
                "remoteprotocolerror",
                "connection",
                "network",
                "socket",
                "dns",
                "provider",
                "service unavailable",
                "temporarily unavailable",
                "502",
                "503",
                "504",
            )
            if normalized_node_type in self._compatible_gateway_fail_fast_node_types() and any(
                marker in error_lower for marker in gateway_fast_fail_markers
            ):
                return False
        return True

    def _should_fallback_to_next_model(self, error_message: str, *, node_type: str = "") -> bool:
        error_lower = str(error_message or "").lower()
        if not error_lower:
            return False
        normalized_node_type = normalize_node_role(node_type)
        if normalized_node_type == "polisher" and any(
            marker in error_lower
            for marker in (
                "polisher pre-write timeout",
                "polisher loop guard",
                "polisher deterministic gap gate failed",
                "polisher regression guard failed",
            )
        ):
            # Polisher is a refinement stage. If it fails before landing a safe write,
            # do not bounce into a slower fallback model and stall the full workflow.
            return False
        fallback_markers = (
            "api key",
            "api_key",
            "invalid key",
            "not configured",
            "unauthorized",
            "forbidden",
            "401",
            "403",
            "authentication",
            "auth failed",
            "permission",
            "rate limit",
            "too many requests",
            "quota",
            "overloaded",
            "temporarily unavailable",
            "service unavailable",
            "bad gateway",
            "gateway timeout",
            "timeout",
            "timed out",
            "connection",
            "network",
            "socket",
            "dns",
            "remoteprotocolerror",
            "provider",
            "litellm",
            "model not found",
            "does not exist",
            "unsupported model",
            "invalid request",
            "your request was blocked",
            "request was blocked",
            "content policy",
            "safety system",
            "builder first-write timeout",
            "builder pre-write timeout",
            "polisher pre-write timeout",
            "polisher loop guard",
            "initial-activity timeout",
            "stalled",
            "502",
            "503",
            "504",
            "429",
            "compatible gateway circuit open",
            "compatible gateway rejection cooldown",
            "returned empty content for builder node",
            "empty content for builder node",
        )
        return any(marker in error_lower for marker in fallback_markers)

    # ─────────────────────────────────────────
    # V4.6 SPEED: Speculative Execution
    # Race requests to different providers in parallel.
    # Uses first successful response, cancels the rest.
    # ─────────────────────────────────────────
    # V4.6 SPEED: Only worker nodes use speculative execution.
    # Orchestrator nodes (planner, analyst) need strict structured output
    # that kimi-k2.5 can't reliably produce — kimi wins the race but fails
    # structure validation, causing infinite retry loops.
    _SPECULATIVE_NODE_TYPES = frozenset({
        "builder", "merger",
        "assetimport", "imagegen", "spritesheet",
    })

    def _pick_speculative_pair(
        self, node_type: str, candidates: List[str],
    ) -> Optional[Tuple[str, str]]:
        """Pick 2 candidates from different providers for parallel racing.
        v5.3++: must be DIFFERENT PROVIDERS (not just different api_base). Racing
        two Kimi models hits the same per-account concurrency limit — combined
        with parallel builders that's 4 concurrent calls, triggering 401.
        Requiring cross-provider avoids this class of failure entirely.
        v5.8: master kill-switch via EVERMIND_DISABLE_SPECULATIVE=1 — speculative
        is pure upside only when ALL providers have credit. When one provider is
        quota-exhausted (e.g. relay GPT), speculative burns latency + request
        slots for no wins. Users with single-provider budgets should disable it."""
        # v5.8.6: default OFF for speculative racing. Racing two models costs
        # 2x prompt_tokens on every worker-node call (builder/merger/imagegen/
        # spritesheet/assetimport) while typically only saving a few seconds
        # when both providers have headroom. Users on single-provider budgets
        # (e.g. Kimi-only) gain ZERO speed and pay latency for an extra leg
        # that 401s/403s. Opt in via EVERMIND_ENABLE_SPECULATIVE=1.
        _spec_env = str(os.getenv("EVERMIND_ENABLE_SPECULATIVE", "0")).strip().lower()
        if _spec_env not in {"1", "true", "yes"}:
            return None
        if str(os.getenv("EVERMIND_DISABLE_SPECULATIVE", "0")).strip().lower() in {"1", "true", "yes"}:
            return None
        normalized = normalize_node_role(node_type)
        if normalized not in self._SPECULATIVE_NODE_TYPES:
            return None
        if len(candidates) < 2:
            return None
        first = candidates[0]
        first_info = self._resolve_model(first)
        first_provider = str(first_info.get("provider") or "").strip().lower()
        # v5.8: also skip candidates currently under auth-failure cooldown —
        # launching a 2nd leg we know will 401/403 is pure waste.
        cooldown_until = getattr(self, "_provider_auth_cooldown_until", {}) or {}
        now = time.time()
        for other in candidates[1:]:
            other_info = self._resolve_model(other)
            other_provider = str(other_info.get("provider") or "").strip().lower()
            if not other_provider or not first_provider or other_provider == first_provider:
                continue
            if float(cooldown_until.get(other_provider, 0)) > now:
                continue
            return (first, other)
        return None

    async def _execute_speculative_race(
        self,
        node: Dict,
        plugins: List[Plugin],
        masked_input: str,
        model_a: str,
        model_b: str,
        on_progress: Callable,
        total_candidates: int,
    ) -> Optional[Dict]:
        """Race two models from different providers. Return first success or None."""
        info_a = self._resolve_model(model_a)
        info_b = self._resolve_model(model_b)
        node_type = node.get("type", "")

        logger.info(
            "Speculative execution: node=%s racing %s(%s) vs %s(%s)",
            node_type, model_a, info_a.get("api_base", "")[:30],
            model_b, info_b.get("api_base", "")[:30],
        )
        if on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "speculative_start",
                "message": f"[闪电] 并行竞速: {model_a} vs {model_b}",
                "model_a": model_a,
                "model_b": model_b,
            })

        task_a = asyncio.create_task(
            self._execute_single_model(
                node, plugins, masked_input,
                model_name=model_a, model_info=info_a,
                on_progress=on_progress,
                total_candidate_count=total_candidates,
            ),
            name=f"spec_{model_a}",
        )
        task_b = asyncio.create_task(
            self._execute_single_model(
                node, plugins, masked_input,
                model_name=model_b, model_info=info_b,
                on_progress=None,  # secondary stays silent
                total_candidate_count=total_candidates,
            ),
            name=f"spec_{model_b}",
        )

        try:
            done, pending = await asyncio.wait(
                {task_a, task_b}, return_when=asyncio.FIRST_COMPLETED,
            )
        except Exception as exc:
            logger.warning("Speculative race wait error: %s", str(exc)[:200])
            for t in (task_a, task_b):
                t.cancel()
            return None

        winner_task = done.pop()
        try:
            result = winner_task.result()
        except Exception as exc:
            logger.warning("Speculative winner exception: %s", str(exc)[:200])
            result = {"success": False, "error": str(exc)[:200]}

        winner_model = model_a if winner_task is task_a else model_b
        loser_model = model_b if winner_task is task_a else model_a

        if result.get("success"):
            for p in pending:
                p.cancel()
                try:
                    await p
                except (asyncio.CancelledError, Exception):
                    pass
            logger.info(
                "Speculative winner: node=%s model=%s (cancelled %s)",
                node_type, winner_model, loser_model,
            )
            if on_progress:
                await self._emit_noncritical_progress(on_progress, {
                    "stage": "speculative_winner",
                    "message": f"[闪电] {winner_model} 胜出 (取消 {loser_model})",
                    "winner": winner_model,
                    "cancelled": loser_model,
                })
            result["speculative_winner"] = winner_model
            result["speculative_cancelled"] = loser_model
            return result

        # First finished but failed — wait for the second
        if pending:
            loser_task = pending.pop()
            try:
                result_b = await loser_task
            except (asyncio.CancelledError, Exception) as exc:
                logger.warning("Speculative second task error: %s", str(exc)[:200])
                return None
            if result_b.get("success"):
                logger.info(
                    "Speculative fallback: node=%s %s failed, %s succeeded",
                    node_type, winner_model, loser_model,
                )
                result_b["speculative_winner"] = loser_model
                result_b["speculative_first_failed"] = winner_model
                return result_b
        elif done:
            # Both tasks completed simultaneously — asyncio.wait(FIRST_COMPLETED)
            # can put both in 'done' when they finish at the same instant (common
            # in mock/test environments). Check the remaining done task.
            remaining_task = done.pop()
            try:
                result_b = remaining_task.result()
            except Exception as exc:
                logger.warning("Speculative simultaneous second task error: %s", str(exc)[:200])
                return None
            if result_b.get("success"):
                remaining_model = model_b if remaining_task is task_b else model_a
                failed_model = model_a if remaining_task is task_b else model_b
                logger.info(
                    "Speculative fallback (simultaneous): node=%s %s failed, %s succeeded",
                    node_type, failed_model, remaining_model,
                )
                result_b["speculative_winner"] = remaining_model
                result_b["speculative_first_failed"] = failed_model
                return result_b

        return None  # Both failed, fall through to sequential

    # ─────────────────────────────────────────
    # Main dispatch
    # ─────────────────────────────────────────
    async def _execute_single_model(
        self,
        node: Dict,
        plugins: List[Plugin],
        masked_input: str,
        *,
        model_name: str,
        model_info: Dict,
        on_progress: Callable = None,
        total_candidate_count: int = 1,
    ) -> Dict:
        key_error = self._check_api_key(model_name, model_info)
        if key_error:
            logger.warning(f"API key missing for model {model_name}: {key_error[:80]}")
            return {
                "success": False,
                "output": "",
                "error": key_error,
                "model": model_name,
                "assigned_model": model_name,
                "assigned_provider": model_info.get("provider", ""),
            }

        node_type = node.get("type", "")
        normalized_node_type = normalize_node_role(node_type)
        assigned_builder_targets = self._builder_assigned_html_targets(masked_input)
        builder_goal_hint = (
            self._builder_goal_hint_source(
                goal_hint=str(node.get("goal") or ""),
                input_data=masked_input,
            )
            if normalized_node_type == "builder"
            else ""
        )
        builder_retry_context = (
            self._builder_has_retry_context(
                node_type,
                input_data=masked_input,
                node=node,
            )
            if normalized_node_type == "builder"
            else False
        )
        builder_retry_patch_context = (
            self._builder_retry_requires_existing_artifact_patch_context(
                node_type,
                input_data=masked_input,
                goal_hint=builder_goal_hint,
                node=node,
            )
            if normalized_node_type == "builder"
            else False
        )
        auto_builder_direct_multifile = self._builder_should_auto_direct_multifile(
            node_type,
            model_name=model_name,
            model_info=model_info,
            input_data=masked_input,
        )
        auto_builder_direct_text = self._builder_should_auto_direct_text(
            node_type,
            model_name=model_name,
            model_info=model_info,
            input_data=masked_input,
            goal_hint=builder_goal_hint,
            node=node,
        )
        requested_builder_direct_text = (
            normalized_node_type == "builder"
            and str(node.get("builder_delivery_mode") or "").strip().lower() == "direct_text"
        )
        if builder_retry_patch_context:
            auto_builder_direct_multifile = False
            auto_builder_direct_text = False
            requested_builder_direct_text = False
        retry_builder_direct_text = (
            self._builder_retry_prefers_direct_text(
                node_type,
                input_data=masked_input,
                goal_hint=builder_goal_hint,
                node=node,
            )
            if normalized_node_type == "builder"
            else False
        )
        # v5.8.6: parallel peer builders (merger owns root) must BYPASS the
        # classifier-gated safety net. The safety net was designed for the
        # single-builder case where direct_text is only safe for narrow task
        # profiles; peers in a merger pipeline ALWAYS target one HTML staging
        # file per builder, which is the exact shape direct_text handles well.
        # Without this bypass, `auto_builder_direct_text=True` from the peer
        # fix gets AND'd with a False classifier → `force_builder_direct_text=False`
        # and Builder 1/2 fall back to tool_call finish=length loops.
        is_parallel_peer_builder = (
            normalized_node_type == "builder"
            and isinstance(node, dict)
            and node.get("can_write_root_index") is False
            and not bool(node.get("builder_is_support_lane_node"))
            and not bool(node.get("builder_merger_like"))
        )
        safe_builder_direct_text = (
            (
                not builder_retry_patch_context
                and not builder_retry_context
                and (
                    task_classifier.game_direct_text_delivery_mode(builder_goal_hint)
                    or task_classifier.premium_3d_builder_direct_text_first_pass(builder_goal_hint)
                    or is_parallel_peer_builder
                )
            )
            or retry_builder_direct_text
            if normalized_node_type == "builder"
            else False
        )
        force_builder_direct_multifile = (
            self._builder_direct_multifile_requested(node_type, masked_input)
            or (
                normalized_node_type == "builder"
                and str(node.get("builder_delivery_mode") or "").strip().lower() == "direct_multifile"
            )
            or auto_builder_direct_multifile
        )
        # v6.1.11 (maintainer 2026-04-19): retry_patch_context used to kill
        # direct_multifile unconditionally. But for peer builders (can_root
        # =False) in multi-builder game runs, dropping back to tool_call
        # is exactly the path where JSON-args truncation kills us. If the
        # orchestrator flagged this node as direct_multifile on entry, honor
        # it across retries.
        if builder_retry_patch_context:
            _was_orig_multifile = (
                normalized_node_type == "builder"
                and isinstance(node, dict)
                and str(node.get("builder_delivery_mode") or "").strip().lower() == "direct_multifile"
            )
            _is_peer_builder = (
                normalized_node_type == "builder"
                and isinstance(node, dict)
                and node.get("can_write_root_index") is False
                and not bool(node.get("builder_merger_like"))
            )
            if _was_orig_multifile or _is_peer_builder:
                logger.info(
                    "retry_patch_context: preserving direct_multifile for peer/orig-multifile builder (node=%s model=%s)",
                    normalize_node_role(node_type) or node_type, model_name,
                )
                # keep force_builder_direct_multifile as computed above
            else:
                force_builder_direct_multifile = False
        # v5.8.7: respect the auto-learn kill switch even when the orchestrator or
        # input marker forced direct_multifile. Prior behaviour let a run produce 4
        # consecutive empty batches (2.2KB → 572B) because the explicit node setting
        # overrode the session-wide disable flag. When the kill switch fires we
        # fall back to tool_call for the remainder of the run.
        if (
            normalized_node_type == "builder"
            and force_builder_direct_multifile
            and getattr(self, "_builder_direct_multifile_disabled", False)
        ):
            force_builder_direct_multifile = False
            logger.info(
                "builder direct_multifile force override suppressed by auto-learn kill switch: node=%s model=%s",
                normalize_node_role(node_type) or node_type,
                model_name,
            )
        if force_builder_direct_multifile:
            requested_builder_direct_text = False
            auto_builder_direct_text = False
            retry_builder_direct_text = False
        force_builder_direct_text = (requested_builder_direct_text or auto_builder_direct_text) and safe_builder_direct_text
        # v6.4.10 (maintainer 2026-04-22) — v6.4.9 safety net REVERTED.
        # The v6.4.9 safety net routed multi-target builders away from
        # direct_text to tool_call. Empirically (2026-04-22 run 14:00-14:14)
        # tool_call requires 8-15 file_ops.write turns per builder = 12-15min,
        # triggers finish=length token truncation, and the orchestrator's
        # built-in escalator explicitly wants to flip back to direct_text on
        # truncation — which the safety net then blocked, creating a loop.
        # Correct fix moved upstream: ensure direct_multifile is open to every
        # streaming-capable provider (_builder_should_auto_direct_multifile in
        # v6.4.10) so the fast path is always chosen first. direct_text is
        # kept as a legitimate fallback; the orchestrator's per-model prompt
        # enforces named `\`\`\`html filename=xxx\`\`\`` blocks to make the
        # extractor's job easy.
        effective_node = dict(node or {})
        effective_node["model"] = model_name
        if builder_retry_patch_context:
            effective_node.pop("builder_delivery_mode", None)
        if (
            normalized_node_type == "builder"
            and str(effective_node.get("builder_delivery_mode") or "").strip().lower() == "direct_text"
            and not safe_builder_direct_text
        ):
            effective_node.pop("builder_delivery_mode", None)
        if (
            force_builder_direct_multifile
            and normalized_node_type == "builder"
            and str(effective_node.get("builder_delivery_mode") or "").strip().lower() != "direct_multifile"
        ):
            effective_node["builder_delivery_mode"] = "direct_multifile"
        elif (
            force_builder_direct_text
            and normalized_node_type == "builder"
            and str(effective_node.get("builder_delivery_mode") or "").strip().lower() not in ("direct_text", "direct_multifile")
        ):
            effective_node["builder_delivery_mode"] = "direct_text"
        if force_builder_direct_multifile and on_progress:
            message = (
                "Builder retry switched to direct multi-file delivery mode to patch missing pages without tool loops."
                if not auto_builder_direct_multifile
                else "Builder auto-switched to direct multi-file delivery mode for Kimi multi-page delivery to avoid stalled first-write tool loops."
            )
            await self._emit_noncritical_progress(on_progress, {
                "stage": "system_info",
                "message": message,
                "builder_delivery_mode": "direct_multifile",
                "builder_direct_multifile": True,
                "assignedModel": model_name,
                "assignedProvider": model_info.get("provider", ""),
            })
        elif force_builder_direct_text and on_progress:
            message = (
                "Builder switched to direct single-file HTML delivery mode to avoid Kimi tool-call first-write stalls on game generation."
                if auto_builder_direct_text
                else "Builder switched to direct single-file HTML delivery mode."
            )
            await self._emit_noncritical_progress(on_progress, {
                "stage": "system_info",
                "message": message,
                "builder_delivery_mode": "direct_text",
                "builder_direct_text": True,
                "assignedModel": model_name,
                "assignedProvider": model_info.get("provider", ""),
            })
        elif requested_builder_direct_text and not safe_builder_direct_text and on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "system_info",
                "message": (
                    "Builder direct single-file delivery was disabled for this engine/asset-heavy game brief. "
                    "Falling back to normal file_ops delivery for stability."
                ),
                "assignedModel": model_name,
                "assignedProvider": model_info.get("provider", ""),
            })

        max_retries = 2 if total_candidate_count > 1 else 3
        last_error = None
        result: Dict[str, Any] = {
            "success": False,
            "output": "",
            "error": "",
            "model": model_name,
            "assigned_model": model_name,
            "assigned_provider": model_info.get("provider", ""),
        }
        logger.info(
            "execute(): node=%s model=%s direct_multifile=%s direct_text=%s auto_direct=%s extra_headers=%s litellm=%s assigned_targets=%s candidate_count=%s",
            node_type,
            model_name,
            force_builder_direct_multifile,
            force_builder_direct_text,
            auto_builder_direct_multifile or auto_builder_direct_text,
            bool(model_info.get("extra_headers")),
            bool(self._litellm),
            len(assigned_builder_targets),
            total_candidate_count,
        )
        for attempt in range(max_retries):
            preflight_error = self._compatible_gateway_preflight_error(model_info)
            if preflight_error:
                # P0 FIX 2026-04-04: Try fallback gateway bases before giving up.
                # If relay.cn blocks gpt-5.4, try EVERMIND_OPENAI_FALLBACK_API_BASE.
                fallback_used = False
                for fb_base in self._fallback_gateway_bases(model_info):
                    fb_info = {**model_info, "api_base": fb_base}
                    if not self._compatible_gateway_preflight_error(fb_info):
                        model_info = fb_info
                        fallback_used = True
                        logger.info(
                            "Gateway fallback activated: %s -> %s for model=%s",
                            self._compatible_gateway_host(model_info) or "primary",
                            fb_base,
                            model_name,
                        )
                        break
                if not fallback_used:
                    result = {
                        "success": False,
                        "output": "",
                        "error": preflight_error,
                        "model": model_name,
                        "assigned_model": model_name,
                        "assigned_provider": model_info.get("provider", ""),
                    }
                    last_error = preflight_error
                    break
            attempt_started_at = time.time()
            try:
                if attempt > 0:
                    # v3.0: Optimized retry using RetryStrategy (500ms first retry, Retry-After, circuit breaker)
                    is_rate_limit = False  # Default; legacy branch below may override
                    if self._retry_strategy and _AGENTIC_RUNTIME_AVAILABLE:
                        provider = model_info.get("provider", "unknown")
                        # Circuit breaker check: skip immediately if provider is down
                        if self._retry_strategy.is_circuit_open(provider):
                            logger.warning("Circuit breaker OPEN for %s, skipping retry", provider)
                            break
                        wait = self._retry_strategy.get_wait_time(attempt, str(last_error or ""))
                        # Detect rate-limit for progress event even in v3.0 path
                        if last_error and any(
                            kw in str(last_error).lower()
                            for kw in ("429", "rate limit", "too many requests", "quota")
                        ):
                            is_rate_limit = True
                    else:
                        # V4.6 SPEED: Minimal retry delays — we'd rather fire
                        # requests fast and let the fallback chain handle failures
                        # than sit idle waiting for a maybe-recovered gateway.
                        # V4.6 SPEED: Ultra-fast retries — 0.2s/0.5s/0.8s
                        base_wait = 0.2 + 0.3 * attempt
                        jitter = random.uniform(0, 0.15)
                        is_rate_limit = last_error and any(
                            kw in str(last_error).lower()
                            for kw in ("429", "rate limit", "too many requests", "quota")
                        )
                        if is_rate_limit and attempt == 1:
                            base_wait = 1.0  # V4.6: Was 2s — faster rate-limit retry
                        wait = base_wait + jitter
                    logger.info(f"Retry {attempt}/{max_retries} for {model_name}, waiting {wait:.1f}s...")
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "retrying",
                            "attempt": attempt,
                            "wait": round(wait, 1),
                            "assignedModel": model_name,
                            "assignedProvider": model_info.get("provider", ""),
                            "is_rate_limited": bool(is_rate_limit),
                        })
                    await asyncio.sleep(wait)

                custom_gateway = bool(self._custom_compatible_gateway_base(model_info))

                # v3.0: AgenticLoop — Think-Act-Observe cycle for autonomous tool use
                # Only activated when EVERMIND_AGENTIC_LOOP=1 feature flag is set
                _agentic_eligible = (
                    self._agentic_loop_enabled()
                    and normalized_node_type in {"builder", "merger", "debugger", "polisher"}
                    and not force_builder_direct_text
                    and not force_builder_direct_multifile
                    and model_info.get("supports_tools")
                    and self._litellm
                )
                if _agentic_eligible:
                    try:
                        result = await self._execute_agentic_loop(
                            effective_node, plugins, masked_input, model_info, on_progress,
                        )
                    except Exception as agentic_exc:
                        logger.warning(
                            "AgenticLoop failed for node %s, falling back to standard path: %s",
                            effective_node.get("type", "unknown"), _sanitize_error(str(agentic_exc))[:200],
                        )
                        result = None  # Fall through to standard routing below
                elif (force_builder_direct_multifile or force_builder_direct_text) and (model_info.get("extra_headers") or custom_gateway):
                    # v6.1.6 (maintainer 2026-04-19, Cursor Fast Apply pattern):
                    # allow a cheap "apply" model to handle direct text output
                    # while planning stays on the primary model. Opt-in via
                    # config.fast_write_model; no-op if unset.
                    model_info = self._maybe_route_to_fast_write_model(model_info, effective_node)
                    result = await self._execute_openai_compatible_chat(effective_node, masked_input, model_info, on_progress)
                elif (force_builder_direct_multifile or force_builder_direct_text) and self._litellm:
                    model_info = self._maybe_route_to_fast_write_model(model_info, effective_node)
                    result = await self._execute_litellm_chat(effective_node, masked_input, model_info, on_progress)
                elif force_builder_direct_multifile or force_builder_direct_text:
                    result = await self._execute_openai_direct(effective_node, [], masked_input, on_progress)
                elif model_info.get("supports_cua") and any(p.name == "computer_use" for p in plugins):
                    result = await self._execute_cua_loop(effective_node, plugins, masked_input, on_progress)
                elif model_info.get("provider") == "relay":
                    result = await self._execute_relay(effective_node, masked_input, model_info, on_progress)
                elif custom_gateway and plugins:
                    result = await self._execute_openai_compatible(
                        effective_node,
                        masked_input,
                        model_info,
                        on_progress,
                        plugins=plugins,
                    )
                elif custom_gateway:
                    result = await self._execute_openai_compatible_chat(
                        effective_node,
                        masked_input,
                        model_info,
                        on_progress,
                    )
                elif model_info.get("extra_headers"):
                    result = await self._execute_openai_compatible(
                        effective_node,
                        masked_input,
                        model_info,
                        on_progress,
                        plugins=plugins,
                    )
                elif self._litellm and model_info.get("supports_tools") and plugins:
                    result = await self._execute_litellm_tools(effective_node, plugins, masked_input, model_info, on_progress)
                elif self._litellm:
                    result = await self._execute_litellm_chat(effective_node, masked_input, model_info, on_progress)
                else:
                    result = await self._execute_openai_direct(effective_node, plugins, masked_input, on_progress)

                # AgenticLoop fallback: if it set result=None, fall through to standard path
                if result is None:
                    if self._litellm and model_info.get("supports_tools") and plugins:
                        result = await self._execute_litellm_tools(effective_node, plugins, masked_input, model_info, on_progress)
                    elif self._litellm:
                        result = await self._execute_litellm_chat(effective_node, masked_input, model_info, on_progress)
                    else:
                        result = await self._execute_openai_direct(effective_node, plugins, masked_input, on_progress)

                if not isinstance(result, dict):
                    result = {"success": False, "output": "", "error": "Invalid model response payload"}

                result["model"] = model_name
                result["assigned_model"] = model_name
                result["assigned_provider"] = model_info.get("provider", "")

                if result.get("success"):
                    try:
                        from settings import get_usage_tracker
                        tracker = get_usage_tracker()
                        usage = self._normalize_usage(result.get("usage", {}))
                        tracker.record(
                            model=model_name,
                            prompt_tokens=usage.get("prompt_tokens", 0),
                            completion_tokens=usage.get("completion_tokens", 0),
                            cost=float(result.get("cost", 0) or 0),
                            provider=model_info.get("provider", "unknown"),
                            mode=result.get("mode", "unknown"),
                        )
                    except Exception:
                        pass
                    _call_latency_ms = (time.time() - attempt_started_at) * 1000.0
                    self._record_compatible_gateway_success(
                        model_info,
                        latency_ms=_call_latency_ms,
                    )
                    result["latency_ms"] = int(round(_call_latency_ms))
                    self._record_provider_auth_success(model_info)
                    break

                last_error = result.get("error", "Unknown error")
                _fail_latency_ms = (time.time() - attempt_started_at) * 1000.0
                self._record_compatible_gateway_failure(
                    model_info,
                    last_error,
                    latency_ms=_fail_latency_ms,
                )
                # V4.3 FIX: Record timeout in gateway health so orchestrator
                # retries skip this model+gateway combo instead of retrying
                # from the same slow provider.
                if "timeout" in str(last_error).lower():
                    self._record_gateway_timeout(model_info, last_error, node_type=node_type)
                result["latency_ms"] = int(round(_fail_latency_ms))
                if not self._should_retry_same_model(
                    last_error,
                    node_type=node_type,
                    model_name=model_name,
                    model_info=model_info,
                ):
                    break

            except Exception as e:
                last_error = str(e)
                error_lower = last_error.lower()
                _exc_latency_ms = (time.time() - attempt_started_at) * 1000.0
                self._record_compatible_gateway_failure(
                    model_info,
                    last_error,
                    latency_ms=_exc_latency_ms,
                )
                # V4.3 FIX: Also mark timeout exceptions in gateway health
                if "timeout" in error_lower:
                    self._record_gateway_timeout(model_info, last_error, node_type=node_type)
                logger.warning(f"Execute attempt {attempt+1} failed: {_sanitize_error(last_error[:200])}")

                is_auth_error = any(kw in error_lower for kw in [
                    "auth", "api key", "api_key", "invalid key", "permission",
                    "unauthorized", "forbidden", "401", "403",
                ])
                if is_auth_error:
                    self._record_provider_auth_failure(model_info, last_error)
                    friendly = (
                        f"API 密钥无效或已过期，请在「设置」中重新填入正确的密钥。\n"
                        f"API key invalid or expired. Please update it in Settings.\n"
                        f"({_sanitize_error(last_error[:100])})"
                    )
                    result = {
                        "success": False,
                        "output": "",
                        "error": friendly,
                        "model": model_name,
                        "assigned_model": model_name,
                        "assigned_provider": model_info.get("provider", ""),
                        "latency_ms": int(round(_exc_latency_ms)),
                    }
                    break

                result = {
                    "success": False,
                    "output": "",
                    "error": _sanitize_error(last_error),
                    "model": model_name,
                    "assigned_model": model_name,
                    "assigned_provider": model_info.get("provider", ""),
                    "latency_ms": int(round(_exc_latency_ms)),
                }

        return result

    async def execute(self, node: Dict, plugins: List[Plugin], input_data: str,
                      model: str = "kimi-coding", on_progress: Callable = None,
                      privacy_settings: Dict = None) -> Dict:
        node_type = node.get("type", "")

        # ── Privacy: mask PII before sending to AI ──
        masker = get_masker(privacy_settings) if privacy_settings else get_masker()
        masked_input, restore_map = masker.mask(input_data, node_type=node_type)
        masked_input = self._apply_runtime_node_contracts(node, masked_input)
        if restore_map and on_progress:
            await self._emit_noncritical_progress(on_progress, {"stage": "privacy_masked", "pii_count": len(restore_map)})

        # ── CLI Backend Route ──
        # When cli_mode is enabled in settings, route execution to local CLI tools
        # instead of going through API relay endpoints.
        try:
            from cli_backend import is_cli_mode_enabled, get_executor
            _cli_settings = (getattr(self, "config", {}) or {}).get("cli_mode") or {}
            if not isinstance(_cli_settings, dict):
                _cli_settings = {}
            # Fallback: if in-memory config lacks cli_mode details, load from persisted settings
            if not _cli_settings.get("preferred_cli") and not _cli_settings.get("preferred_model"):
                try:
                    from settings import load_settings as _load_cli_settings
                    _persisted = _load_cli_settings().get("cli_mode") or {}
                    if isinstance(_persisted, dict) and _persisted.get("enabled"):
                        _cli_settings = _persisted
                except Exception:
                    pass
            _cli_enabled = _cli_settings.get("enabled", False) or is_cli_mode_enabled()
            # v7.0 (maintainer 2026-04-24): expanded CLI coverage. Previous v6.x
            # limited CLI to only 5 "worker" nodes, arguing that orchestrator
            # nodes like planner/analyst need AGENT_PRESETS structured output.
            # In practice: Claude Code CLI / Codex CLI are fully capable of
            # producing structured tagged output when the task prompt explicitly
            # asks for it (see prompt_templates/*.yaml — they already describe
            # the target schema). Excluding planner/analyst/uidesign/polisher/
            # patcher/deployer/scribe meant a CLI-mode user still paid the full
            # relay cost for half the pipeline. Now every node whose
            # output is *text* is CLI-eligible. Only true asset-plugin nodes
            # (imagegen/spritesheet/assetimport) stay on the backend plugin
            # path because they invoke non-LLM side effects.
            _CLI_ALLOWED_NODES = {
                "planner", "planner_degraded", "analyst", "uidesign", "scribe",
                "builder", "merger", "polisher", "reviewer", "patcher",
                "tester", "debugger", "deployer", "router",
            }
            # v7.1g (maintainer 2026-04-25): reviewer/tester NOW go through CLI too.
            # Previously these auto-routed to API because CLI subprocess had no
            # browser plugin. Since v7.1g registers playwright-mcp in all 3 CLI
            # configs (~/.claude/.mcp.json + ~/.gemini/settings.json + codex
            # config.toml), Claude/Gemini CLI now have full browser automation
            # via MCP — screenshot, click, observe, scroll all available.
            # The hard-coded API bypass is removed; reviewer/tester stay on CLI
            # path unless cli_mode.force_api_for_browser is explicitly set.
            _CLI_BROWSER_REQUIRED = set()
            _early_node_overrides = _cli_settings.get("node_cli_overrides", {}) if isinstance(_cli_settings, dict) else {}
            _cli_override_for_node = (
                isinstance(_early_node_overrides, dict)
                and _early_node_overrides.get(node_type)
            )
            _force_api_browser = bool(_cli_settings.get("force_api_for_browser", False)) if isinstance(_cli_settings, dict) else False
            if _force_api_browser and node_type in {"reviewer", "tester"} and not _cli_override_for_node:
                # Legacy escape hatch — only triggered when user explicitly opts in.
                if _cli_enabled and on_progress:
                    try:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "cli_route_skipped",
                            "node": node_type,
                            "reason": "force_api_for_browser=True (legacy mode)",
                        })
                    except Exception:
                        pass
                _cli_enabled = False  # 仅本次调用关闭；不影响其它节点
            if _cli_enabled and node_type in _CLI_ALLOWED_NODES:
                _cli_executor = get_executor(self.config)
                _preferred_cli = _cli_settings.get("preferred_cli", "")
                _preferred_model = _cli_settings.get("preferred_model", "")
                _node_overrides = _cli_settings.get("node_cli_overrides", {})
                # v7.1d (maintainer 2026-04-24): per-node-key override priority.
                # Lookup order: node_key (e.g. "builder1") → node_type ("builder")
                # → preferred. Lets ultra split frontend builders → gemini and
                # backend builders → claude without changing the workflow.
                _node_key_for_override = str(
                    (node or {}).get("key", "")
                    or (node or {}).get("node_key", "")
                ).strip().lower()
                _override = (
                    (_node_overrides.get(_node_key_for_override) if _node_key_for_override else None)
                    or _node_overrides.get(node_type, "")
                )
                if isinstance(_override, dict):
                    _cli_choice = _override.get("cli", "") or _preferred_cli
                    _model_choice = _override.get("model", "") or _preferred_model
                else:
                    _cli_choice = _override or _preferred_cli
                    _model_choice = _preferred_model
                _workspace = (self.config or {}).get("workspace", "")
                # v7.1c (maintainer 2026-04-24): ULTRA-aware CLI timeouts.
                # Was: builder 600s = 10min — fine for single HTML, way too
                # tight for Claude CLI doing a full multi-file Vite/Electron
                # project (it needs 30-60min to scaffold + write 20+ files).
                # Ultra: ×6 across the board (3600s = 60min for builder).
                _ultra_on_for_cli = bool(_cli_settings.get("ultra_mode")) if isinstance(_cli_settings, dict) else False
                _ULTRA_MULT = 6 if _ultra_on_for_cli else 1
                _CLI_TIMEOUTS = {
                    "builder": 600 * _ULTRA_MULT,
                    "merger": 720 * _ULTRA_MULT,
                    "reviewer": 300 * _ULTRA_MULT,
                    "tester": 300 * _ULTRA_MULT,
                    "debugger": 600 * _ULTRA_MULT,
                    "polisher": 540 * _ULTRA_MULT,
                    "patcher": 360 * _ULTRA_MULT,
                    "deployer": 360 * _ULTRA_MULT,
                    "analyst": 600 * _ULTRA_MULT,
                    "uidesign": 360 * _ULTRA_MULT,
                    "scribe": 600 * _ULTRA_MULT,
                    "planner": 360 * _ULTRA_MULT,
                }
                _cli_timeout = _CLI_TIMEOUTS.get(node_type, 600 * _ULTRA_MULT)
                # v7.0b (maintainer 2026-04-24): inject full system prompt from
                # AGENT_PRESETS / yaml template as a prefix to the task.
                # Without this, claude/codex/gemini CLI treat the prompt as
                # conversational and return terse answers (observed analyst
                # returning 1135 chars vs the required 15000). The prompt
                # template is the source of truth for node schema + quality
                # bar, so passing it verbatim is the only way the CLI
                # subprocess can produce structured output comparable to
                # the API route.
                _cli_task = masked_input
                try:
                    _sys_prompt = self._compose_system_prompt(node, plugins=plugins, input_data=input_data)
                    if _sys_prompt:
                        # v7.0b safety: cap system prompt at 40KB to stay
                        # safely under CLI argv / -p length limits.
                        # Typical limit on macOS is ~256KB for argv; our
                        # prompts can reach 80KB when all skills load.
                        _SYS_CAP = 40_000
                        if len(_sys_prompt) > _SYS_CAP:
                            _sys_prompt = _sys_prompt[:_SYS_CAP] + "\n\n[SYSTEM PROMPT TRUNCATED TO 40KB]"
                        # v7.1d (maintainer 2026-04-24): CLI-specialization header.
                        # Each CLI has different strengths — tell the subprocess
                        # to lean into its native talents. This is the "1+1>2"
                        # layer: claude does backend auth hard, gemini does
                        # visual/SVG hard, codex does algorithmic density hard.
                        _cli_spec_map = {
                            "claude": (
                                "You are running inside Claude Code CLI — your "
                                "strengths: multi-file refactor, agentic "
                                "planning, security reasoning, long-horizon "
                                "code coherence, comprehensive test scaffolding. "
                                "Use Read/Edit/Write/Bash/Glob/Grep tools actively.\n\n"
                                "## v7.1h CAPABILITY DISCOVERY (MANDATORY FIRST STEP)\n"
                                "Before deep work, briefly probe what's available:\n"
                                "- `Task` tool dispatches sub-agents — for research-heavy "
                                "  work, dispatch a `codebase-researcher` (Haiku, fast) or "
                                "  `image-fetcher` (Sonnet, web-fetch) sub-agent in parallel "
                                "  while you focus on integration. Saves 40-50% time.\n"
                                "- `TodoWrite` — track multi-step work as a checklist; "
                                "  forces structured execution and prevents skipping steps.\n"
                                "- `WebFetch` / `WebSearch` — for accuracy-critical assets "
                                "  (real images, references), always WebFetch authoritative "
                                "  sources rather than inventing.\n"
                                "- MCP servers in `~/.claude/.mcp.json`: playwright (browser), "
                                "  fetch (URL→markdown), memory (KG), sequentialthinking. "
                                "  When you need to scrape or browse, use these.\n"
                                "- Skills in `~/.claude/skills/`: invoke `/evermind-builder` "
                                "  or `/accuracy-critical-imagery` when relevant.\n"
                                "- Sub-agents in `~/.claude/agents/`: `codebase-researcher` "
                                "  + `image-fetcher` ready for dispatch.\n"
                                "USE these capabilities — don't hand-roll what's already provided.\n\n"
                                "CRITICAL — FINAL MESSAGE PROTOCOL:\n"
                                "Your FINAL assistant message (the response captured by the "
                                "orchestrator) MUST contain the COMPLETE structured output the "
                                "SYSTEM INSTRUCTIONS asks for. The orchestrator extracts only "
                                "the LAST assistant message; tool-phase content is invisible. "
                                "Inline the entire deliverable verbatim — no 'see above', no "
                                "'I've completed', no truncation."
                            ),
                            "gemini": (
                                "You are running inside Gemini CLI — your "
                                "strengths: rich SVG/illustration crafting, motion "
                                "design (View Transitions API, cubic-bezier), "
                                "typography systems (fluid clamp(), container "
                                "queries), visual-first thinking, ambitiously "
                                "beautiful but accessible UI. Use write_file tool.\n\n"
                                "## v7.1h CAPABILITY DISCOVERY (MANDATORY FIRST STEP)\n"
                                "Probe what's available before deep work:\n"
                                "- MCP servers configured in ~/.gemini/settings.json: "
                                "  `openclaw` (custom tooling) + `playwright` (browser/"
                                "  scraping). Use playwright for image scraping and "
                                "  visual verification.\n"
                                "- `gemini extensions list` shows installed extensions; "
                                "  `gemini skills list` shows skills. Invoke if relevant.\n"
                                "- GEMINI.md / AGENTS.md in workspace cwd — read these "
                                "  for project-specific context.\n"
                                "- Multi-modal vision — Gemini can analyze images. "
                                "  When verifying generated UI, capture screenshot "
                                "  and analyze visually.\n\n"
                                "CRITICAL — FINAL MESSAGE PROTOCOL:\n"
                                "Orchestrator only sees your FINAL message. Inline the "
                                "complete deliverable. No 'see above' / 'I've created'."
                            ),
                            "codex": (
                                "You are running inside Codex CLI with a "
                                "reasoning model — your strengths are: dense "
                                "algorithmic thinking, state machines, "
                                "encoding / parsing, graph traversal, "
                                "numerical accuracy. Lean into those. Emit "
                                "complete file contents via your apply_patch "
                                "tool rather than narrating."
                            ),
                        }
                        _spec_header = _cli_spec_map.get(_cli_choice or "", "")
                        # v7.1i: append the user's REAL installed capabilities
                        # (skills/MCP/agents/plugins) as scanned from disk.
                        # Static spec_map text says what's *typical*; this
                        # block tells the subprocess what's *actually* there.
                        try:
                            _live_caps_block = _get_cli_capability_hint(_cli_choice or "")
                        except Exception:
                            _live_caps_block = ""
                        if _live_caps_block:
                            _spec_header = (
                                (_spec_header + "\n\n" if _spec_header else "")
                                + "## v7.1i LIVE CAPABILITY SCAN (real, installed on this machine)\n"
                                + _live_caps_block
                                + "\n\nIf any of the above directly accelerates your "
                                + "task — invoke it. Don't re-implement what's already installed."
                            )
                            try:
                                _first_line = (_live_caps_block.splitlines() or [""])[1] if "\n" in _live_caps_block else _live_caps_block[:60]
                                logger.info(
                                    "[v7.1i] capability scan injected: cli=%s node=%s caps_chars=%d head=%s",
                                    _cli_choice, node_type, len(_live_caps_block), _first_line[:80],
                                )
                            except Exception:
                                pass
                        # Inject node_key so the builder knows which lane it is
                        # (builder1 vs builder4 have very different handoffs).
                        _node_key_for_hdr = str(
                            (node or {}).get("key", "")
                            or (node or {}).get("node_key", "")
                            or node_type
                        ).strip()
                        _lane_header = ""
                        if _node_key_for_hdr and _node_key_for_hdr != node_type:
                            _lane_header = (
                                f"[LANE IDENTITY]\n"
                                f"You are lane `{_node_key_for_hdr}` in a "
                                f"4-builder Ultra-mode parallel DAG. The "
                                f"analyst's `<builder_N_handoff>` that "
                                f"matches this lane is YOUR handoff; ignore "
                                f"the others. Do NOT attempt to own files "
                                f"assigned to sibling lanes — merger will "
                                f"integrate.\n\n"
                            )
                        # v7.1g cache-friendly split:
                        # • Stable + recurring: SYSTEM INSTRUCTIONS + CLI
                        #   SPECIALIZATION + LANE IDENTITY → goes to
                        #   --append-system-prompt (becomes Claude's stable
                        #   prefix, hits prompt cache on repeated calls).
                        # • Volatile (per-task): USER TASK / INPUT goes to
                        #   the user prompt body. Each retry/iteration
                        #   updates only this variable suffix.
                        _stable_prefix = (
                            f"[SYSTEM INSTRUCTIONS FOR NODE={node_type}]\n"
                            f"{_sys_prompt}\n\n"
                            + (f"[CLI SPECIALIZATION]\n{_spec_header}\n\n" if _spec_header else "")
                            + _lane_header
                            + (
                                "[OUTPUT CONTRACT]\n"
                                "Follow the SYSTEM INSTRUCTIONS above verbatim. "
                                "Produce the required output tags / structure / "
                                "length. DO NOT reply conversationally — treat "
                                "this as a production pipeline task.\n"
                            )
                        )
                        # Volatile body — ONLY the per-call task. Keeps cache hit.
                        _cli_task = (
                            f"[USER TASK / INPUT]\n{masked_input}"
                        )
                        # Stash the stable prefix on the node dict so
                        # cli_backend.executor can pull it for
                        # --append-system-prompt (Claude) / GEMINI.md (gemini)
                        # / shell_environment (codex).
                        try:
                            if isinstance(node, dict):
                                node["_cli_append_system_prompt"] = _stable_prefix
                                # also ensure node_key + run_id are there for
                                # session_seed derivation in cli_backend
                                _run_id_from_self = ""
                                try:
                                    _run_id_from_self = str(
                                        (self.config or {}).get("run_id") or ""
                                    )
                                except Exception:
                                    _run_id_from_self = ""
                                if _run_id_from_self and not node.get("run_id"):
                                    node["run_id"] = _run_id_from_self
                        except Exception:
                            pass
                except Exception as _sp_err:
                    logger.debug("CLI system-prompt injection failed (non-critical): %s", _sp_err)
                try:
                    _cli_result = await _cli_executor.execute(
                        task=_cli_task,
                        node_type=node_type,
                        workspace=_workspace,
                        timeout=_cli_timeout,
                        preferred_cli=_cli_choice or None,
                        preferred_model=_model_choice or None,
                        on_progress=on_progress,
                        node=node,
                        ultra_mode=_ultra_on_for_cli,
                    )
                except Exception as _cli_exc:
                    logger.warning(
                        "CLI subprocess crashed (node=%s): %s — falling back to API route",
                        node_type, str(_cli_exc)[:200],
                    )
                    _cli_result = None
                # v7.1d (maintainer 2026-04-24): DUAL-DELIVERY RECOVERY.
                # If the CLI succeeded but returned a very short message
                # (Claude often does deep tool work then says "Done.") try
                # to recover the FULL deliverable from the file the prompt
                # told the agent to write. This is the analyst.yaml + builder.yaml
                # "DUAL-DELIVERY PROTOCOL": agent writes report.xml AND
                # mirrors it in the final message. If the final message is
                # short, prefer the on-disk file.
                if _cli_result and _cli_result.get("success"):
                    _len_msg = len(str(_cli_result.get("output") or ""))
                    _MIN_FOR_NODE = {
                        "analyst": 8000, "uidesign": 4000, "scribe": 4000,
                        "planner": 1500, "merger": 4000, "polisher": 3000,
                        "reviewer": 2000, "patcher": 2000, "debugger": 1500,
                    }
                    _min_chars = _MIN_FOR_NODE.get(node_type, 1500)
                    if _len_msg < _min_chars:
                        try:
                            _output_dir = (self.config or {}).get(
                                "output_dir", "/tmp/evermind_output"
                            )
                            _handoff_dir = os.path.join(_output_dir, "handoff")
                            _candidate_files = [
                                os.path.join(_handoff_dir, f"{node_type}_report.xml"),
                                os.path.join(_handoff_dir, f"{node_type}_report.txt"),
                                os.path.join(_handoff_dir, f"{node_type}_report.md"),
                                os.path.join(_output_dir, f"{node_type}_report.xml"),
                            ]
                            _disk_text = ""
                            _disk_path = ""
                            for _p in _candidate_files:
                                if os.path.exists(_p) and os.path.getsize(_p) > _len_msg:
                                    try:
                                        with open(_p, "r", encoding="utf-8") as _fh:
                                            _disk_text = _fh.read()
                                            _disk_path = _p
                                            break
                                    except Exception:
                                        continue
                            if _disk_text and len(_disk_text) > _len_msg:
                                logger.info(
                                    "CLI dual-delivery recovery: node=%s msg_len=%d → disk_len=%d (%s)",
                                    node_type, _len_msg, len(_disk_text), _disk_path,
                                )
                                _cli_result["output"] = _disk_text
                                _cli_result["dual_delivery_recovered"] = True
                                _cli_result["dual_delivery_source"] = _disk_path
                        except Exception as _rec_err:
                            logger.debug(
                                "Dual-delivery recovery failed (non-fatal): %s",
                                str(_rec_err)[:200],
                            )

                # v7.1g (maintainer 2026-04-24): STRICT CLI MODE.
                # Per maintainer's directive: "确保 cli 模式下调用的是 cli 不是
                # 用户配置的 api". When cli_mode.enabled = true and the node
                # is in _CLI_ALLOWED_NODES, the result MUST come from CLI.
                # No silent API fallback (which would charge user's API key
                # without their knowledge).
                #
                # Exceptions:
                # 1. Browser-required nodes (reviewer/tester) already routed
                #    to API path EARLIER (see _CLI_BROWSER_REQUIRED check)
                #    via _cli_enabled = False — those won't reach this code.
                # 2. Strict mode can be relaxed via cli_mode.allow_api_fallback.
                # v7.1i (maintainer 2026-04-25): router/classifier 节点天生短输出
                # （返回 "tool" / "code" 这种分类标签），100 字节阈值会把
                # 它误判成 unusable → 整个 ultra plan 退化成 4 节点
                # deterministic fallback。给短输出节点单独宽松阈值。
                _SHORT_OUTPUT_NODES = {"router"}
                _min_ok_chars = 3 if node_type in _SHORT_OUTPUT_NODES else 100
                _cli_ok = (
                    _cli_result
                    and _cli_result.get("success")
                    and len(str(_cli_result.get("output") or "")) >= _min_ok_chars
                )
                _allow_api_fallback = bool(
                    _cli_settings.get("allow_api_fallback", False)
                ) if isinstance(_cli_settings, dict) else False
                # v7.1i (maintainer 2026-04-25): REMOVED merger/patcher/polisher/deployer
                # safety net. Previous behavior silently fell back to API for these
                # 4 nodes — maintainer observed Kimi API being called during CLI runs and
                # rejected this. Strict CLI mode must be **truly strict**: if CLI
                # fails, fail the node and let the orchestrator retry with another
                # CLI candidate (or surface the failure), never silently bill the
                # user's API key. Set cli_mode.allow_api_fallback=true if you
                # explicitly want API fallback for ALL nodes.
                if _cli_ok:
                    if restore_map and _cli_result.get("output"):
                        _cli_result["output"] = masker.unmask(_cli_result["output"], restore_map)
                        _cli_result["privacy_masked"] = len(restore_map)
                    return _cli_result
                elif _allow_api_fallback:
                    # Legacy soft-fall behavior (only if user explicitly opts in)
                    logger.warning(
                        "CLI result unusable (node=%s success=%s len=%d) — "
                        "falling back to API route (allow_api_fallback=True)",
                        node_type,
                        bool(_cli_result and _cli_result.get("success")),
                        len(str((_cli_result or {}).get("output") or "")),
                    )
                    if on_progress:
                        try:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "cli_fallback_to_api",
                                "node": node_type,
                                "reason": "cli output unusable, allow_api_fallback=True",
                            })
                        except Exception:
                            pass
                    # Do NOT return — let execution continue to the API route below.
                else:
                    # STRICT CLI MODE: return the CLI failure verbatim. Do
                    # NOT silently use the user's API key.
                    logger.warning(
                        "CLI result unusable (node=%s success=%s len=%d) — "
                        "STRICT MODE: NOT falling back to API. Returning failure.",
                        node_type,
                        bool(_cli_result and _cli_result.get("success")),
                        len(str((_cli_result or {}).get("output") or "")),
                    )
                    if on_progress:
                        try:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "cli_strict_failure",
                                "node": node_type,
                                "reason": "cli failed and api fallback is disabled (cli_mode.allow_api_fallback=False)",
                            })
                        except Exception:
                            pass
                    # Build a failure result that downstream orchestrator
                    # will see and retry / report. Keep mode tagged as cli
                    # so the orchestrator knows this came from the CLI lane.
                    _strict_failure = {
                        "success": False,
                        "output": str((_cli_result or {}).get("output") or ""),
                        "error": (
                            f"CLI execution unusable for node={node_type}. "
                            f"STRICT mode prevents silent API fallback. "
                            f"CLI error: {str((_cli_result or {}).get('error', ''))[:300]}"
                        ),
                        "mode": "cli:strict_failure",
                        "cli_used": (_cli_result or {}).get("cli_used", ""),
                        "iterations": 1,
                        "files_created": (_cli_result or {}).get("files_created", []),
                        "tool_results": [],
                        "usage": (_cli_result or {}).get("usage", {
                            "prompt_tokens": 0, "completion_tokens": 0, "total_tokens": 0,
                        }),
                        "cost": (_cli_result or {}).get("cost", 0),
                        "assigned_model": f"cli:{(_cli_result or {}).get('cli_used', 'unknown')}",
                    }
                    return _strict_failure
        except ImportError:
            logger.debug("cli_backend module not available, using API route")
        except Exception as _cli_err:
            logger.warning("CLI backend error, falling back to API: %s", str(_cli_err)[:200])

        candidate_models = self.resolve_node_model_candidates(node, model)
        # v6.7d (maintainer 2026-04-24): hard-filter gpt-* / claude-* from the
        # candidate chain when kimi is available. The config scrubs + pre-
        # promotion already try to keep gpt out, but `_augment_candidates_
        # with_matching_relays` can re-add gpt-5.4 siblings of the selected
        # relay (observed run_a84a1998bd55: uidesign Model fallback
        # kimi→gpt-5.4 after 180s hard-ceiling, because gpt-5.4 sat in the
        # candidate list despite config). Do the filter HERE as the last
        # line of defense — this is the call site of real API hits.
        if self._model_provider_has_key("kimi-k2.6-code-preview") and candidate_models:
            _filtered = [
                m for m in candidate_models
                if not (
                    str(m).lower().startswith("gpt-")
                    or str(m).lower() in ("claude-4-sonnet", "claude-4-opus", "claude-3.5-sonnet")
                )
            ]
            if _filtered and _filtered != candidate_models:
                logger.info(
                    "v6.7d candidate filter: dropped gpt/claude from node=%s chain: %s → %s",
                    node_type, candidate_models, _filtered,
                )
                candidate_models = _filtered
        result: Dict[str, Any] = {"success": False, "output": "", "error": "No model candidates available"}
        attempted_models: List[str] = []
        if on_progress and candidate_models:
            first_info = self._resolve_model(candidate_models[0])
            await self._emit_noncritical_progress(on_progress, {
                "stage": "model_chain_resolved",
                "assignedModel": candidate_models[0],
                "assignedProvider": first_info.get("provider", ""),
                "candidateModels": candidate_models[:6],
            })

        # V4.6 SPEED: Speculative execution — race top 2 different-provider candidates
        _all_candidates_backup = candidate_models[:]
        spec_pair = self._pick_speculative_pair(node_type, candidate_models)
        if spec_pair:
            spec_result = await self._execute_speculative_race(
                node, plugins, masked_input,
                model_a=spec_pair[0], model_b=spec_pair[1],
                on_progress=on_progress,
                total_candidates=len(candidate_models),
            )
            if spec_result and spec_result.get("success"):
                spec_result["model_candidates"] = _all_candidates_backup
                spec_result["attempted_models"] = list(spec_pair)
                spec_result["model_chain_applied"] = True
                spec_result["speculative_execution"] = True
                result = spec_result
                candidate_models = []  # skip sequential fallback

        for index, candidate_model in enumerate(candidate_models):
            model_info = self._resolve_model(candidate_model)
            provider = model_info.get("provider", "")
            attempted_models.append(candidate_model)
            if on_progress:
                await self._emit_noncritical_progress(on_progress, {
                    "stage": "model_selected",
                    "assignedModel": candidate_model,
                    "assignedProvider": provider,
                    "modelIndex": index + 1,
                    "modelCount": len(candidate_models),
                })

            result = await self._execute_single_model(
                node,
                plugins,
                masked_input,
                model_name=candidate_model,
                model_info=model_info,
                on_progress=on_progress,
                total_candidate_count=len(candidate_models),
            )
            result["model_candidates"] = candidate_models[:]
            result["attempted_models"] = attempted_models[:]
            result["model_chain_applied"] = len(candidate_models) > 1

            if result.get("success"):
                break

            error_message = str(result.get("error") or "").strip()
            next_model = ""
            next_index = -1
            if index + 1 < len(candidate_models):
                next_model, next_index = self._next_fallback_candidate(node_type, candidate_models, index)
            if next_model and self._should_fallback_to_next_model(error_message, node_type=node_type):
                next_info = self._resolve_model(next_model)
                logger.warning(
                    "Model fallback: node=%s from=%s to=%s error=%s",
                    node_type,
                    candidate_model,
                    next_model,
                    _sanitize_error(error_message[:200]),
                )
                if on_progress:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "model_fallback",
                        "message": f"[重试] 自动切换模型: {candidate_model} -> {next_model}",
                        "from_model": candidate_model,
                        "to_model": next_model,
                        "assignedModel": next_model,
                        "assignedProvider": next_info.get("provider", ""),
                    })
                continue
            if index + 1 < len(candidate_models) and self._should_fallback_to_next_model(error_message, node_type=node_type):
                logger.info(
                    "Suppressing model fallback: node=%s from=%s error=%s",
                    node_type,
                    candidate_model,
                    _sanitize_error(error_message[:200]),
                )
            break

        # ── Privacy: unmask PII in AI response ──
        if restore_map and result.get("output"):
            result["output"] = masker.unmask(result["output"], restore_map)
            result["privacy_masked"] = len(restore_map)

        # v6.1.10 (maintainer 2026-04-19): respect the DEDICATED walkthrough_language
        # setting first — matches orchestrator._report_language() semantics.
        # Lets user run UI in English but receive Chinese walkthroughs (or
        # vice versa). Without this fix, walkthrough language flapped between
        # zh/en depending on which code path generated the report.
        _cfg = getattr(self, "config", {}) or {}
        _walk_lang = str(_cfg.get("walkthrough_language", "") or "").strip().lower()
        if _walk_lang in ("zh", "en"):
            report_lang = _walk_lang
        else:
            report_lang = str(_cfg.get("ui_language", "zh") or "zh").strip().lower()
        if report_lang not in {"zh", "en"}:
            report_lang = "zh"

        # v4.0: Extract AI-written execution report from output
        # V4.5: Search full output (was: last 3000 chars only — missed reports in long outputs)
        _full_raw = str(result.get("output") or "")
        _ai_report_match = re.search(
            r'<execution_report>(.*?)</execution_report>',
            _full_raw,
            re.DOTALL,
        )
        if _ai_report_match:
            _extracted_report = _ai_report_match.group(1).strip()
            # V4.5: Reject JSON-formatted reports — force natural language
            if _extracted_report.startswith('{') or _extracted_report.startswith('['):
                logger.debug("Rejected JSON-formatted execution report, will use fallback")
                _extracted_report = ""
            # V4.5: Strip code fences that wrap the report content
            if _extracted_report.startswith('```'):
                _extracted_report = re.sub(r'^```\w*\n?', '', _extracted_report)
                _extracted_report = re.sub(r'\n?```$', '', _extracted_report).strip()
            if _extracted_report:
                result["ai_execution_report"] = _extracted_report
            # Strip the report from main output to prevent downstream confusion
            _full_output = str(result.get("output") or "")
            _report_start = _full_output.rfind('<execution_report>')
            if _report_start >= 0:
                result["output"] = _full_output[:_report_start].rstrip()

        # ── v3.0: Generate node walkthrough report ──
        # Use the full ReportGenerator.from_agentic_result builder when the result
        # contains agentic-loop data (tool_results, files_created, etc.).
        # Falls back to manual construction for non-agentic results.
        if _REPORT_GENERATOR_AVAILABLE and result.get("success"):
            try:
                if result.get("tool_results") or result.get("files_created"):
                    # Rich agentic result — use the full builder (populates tool timeline,
                    # search queries, reference URLs, file change details)
                    node_report = ReportGenerator.from_agentic_result(
                        result,
                        node_label=node.get("label", node_type),
                        node_type=node_type,
                        node_key=node.get("key", ""),
                        model_used=result.get("assigned_model", model),
                        task_brief=masked_input[:500] if masked_input else "",
                        lang=report_lang,
                    )
                else:
                    # Standard LLM result — manual construction with available fields
                    # V4.5: Use larger limit (6000) to preserve meaningful report content
                    fallback_summary = self._compact_partial_output(str(result.get("output", "")))
                    node_report = NodeReport(
                        node_label=node.get("label", node_type),
                        node_type=node_type,
                        node_key=node.get("key", ""),
                        model_used=result.get("assigned_model", model),
                        task_brief=masked_input[:500] if masked_input else "",
                        outcome_summary=fallback_summary,
                        success=True,
                        tool_call_stats=result.get("tool_call_stats", {}),
                        total_tokens=result.get("usage", {}).get("total_tokens", 0),
                        prompt_tokens=result.get("usage", {}).get("prompt_tokens", 0),
                        completion_tokens=result.get("usage", {}).get("completion_tokens", 0),
                        cost=float(result.get("cost", 0) or 0),
                        iterations=result.get("iterations", 0),
                    )
                report_md = ReportGenerator.generate(node_report, lang=report_lang)
                result["walkthrough_report"] = report_md
                result["node_report"] = node_report.__dict__
            except Exception as report_err:
                logger.debug("Report generation failed (non-critical): %s", str(report_err)[:200])

        # ── v3.0: Attach handoff packet for downstream nodes ──
        # Use HandoffBuilder.from_agentic_result for richer handoff data when available.
        if _TASK_HANDOFF_AVAILABLE and result.get("success"):
            try:
                report_summary = ""
                if isinstance(result.get("node_report"), dict):
                    report_summary = str(result.get("node_report", {}).get("outcome_summary") or "").strip()
                if result.get("tool_results") or result.get("files_created"):
                    packet = HandoffBuilder.from_agentic_result(
                        result,
                        source_node=node.get("key", ""),
                        source_node_type=node_type,
                        output_summary=report_summary,
                        lang=report_lang,
                    )
                else:
                    packet = HandoffPacket(
                        source_node=node.get("key", ""),
                        source_node_type=node_type,
                        context_summary=report_summary or self._compact_partial_output(str(result.get("output", "")), limit=1800),
                        token_usage=result.get("usage", {}),
                        tool_calls_count=sum(result.get("tool_call_stats", {}).values()),
                    )
                result["handoff_packet"] = packet.to_dict()
                result["handoff_context_message"] = packet.to_context_message(lang=report_lang)
            except Exception:
                pass

        return result

    # ─────────────────────────────────────────
    # v7.4: Outbound system-prompt PII mask helper.
    # Was inline-duplicated only in _execute_openai_compatible[_chat]; the
    # other 6 _execute_* paths shipped raw WORKSPACE/HOME/email/PAT strings
    # straight to the relay. Centralising the gate ensures every dispatch
    # path scrubs system_prompt before the first byte goes on the wire.
    # ─────────────────────────────────────────
    def _mask_outbound_system_prompt(self, node: Dict, system_prompt: str) -> str:
        if not system_prompt:
            return system_prompt
        try:
            node_type = node.get("type", "builder") if isinstance(node, dict) else "builder"
            normalized = normalize_node_role(node_type)
            masker = get_masker()
            if not masker or not getattr(masker, "enabled", True):
                return system_prompt
            if node_type in getattr(masker, "exclude_node_types", set()):
                return system_prompt
            masked, restore = masker.mask(system_prompt, node_type=node_type)
            if restore:
                existing = node.setdefault("_outbound_restore_map", {})
                existing.update(restore)
                logger.info(
                    "Outbound PII mask: node=%s system_prompt items=%d (paths/IPs/emails sanitised before relay)",
                    normalized or node_type, len(restore),
                )
                return masked
            return system_prompt
        except Exception as exc:
            logger.warning("Outbound PII mask skipped: %s", str(exc)[:200])
            return system_prompt

    # ─────────────────────────────────────────
    # Path: Relay Endpoint
    # ─────────────────────────────────────────
    async def _execute_relay(self, node, input_data, model_info, on_progress) -> Dict:
        """Execute through a proxy/relay endpoint."""
        relay_mgr = get_relay_manager()
        relay_id = model_info.get("relay_id")
        model_name = str(
            model_info.get("relay_model_name")
            or model_info.get("relay_pool_model")
            or model_info.get("relay_target_model")
            or model_info.get("model_name")
            or ""
        ).strip()
        if not model_name:
            litellm_id = str(model_info.get("litellm_id") or "").strip()
            model_name = litellm_id.split("/", 1)[1].strip() if litellm_id.lower().startswith("openai/") else litellm_id
        relay_strategy = str(model_info.get("relay_strategy") or "").strip().lower()
        relay_label = model_info.get("relay_name", "?")
        if not model_name:
            return {"success": False, "output": "", "error": "Relay model name missing"}

        system_prompt = self._compose_system_prompt(node, input_data=input_data)
        system_prompt = self._mask_outbound_system_prompt(node, system_prompt)

        if on_progress:
            await self._emit_noncritical_progress(
                on_progress,
                {"stage": "calling_relay", "relay": relay_label, "model": model_name},
            )

        messages = [
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": input_data},
        ]
        if relay_strategy == "pool" or model_info.get("relay_pool_model"):
            result = await relay_mgr.call_best(
                model=model_name,
                messages=messages,
            )
        else:
            result = await relay_mgr.call(
                endpoint_id=relay_id,
                model=model_name,
                messages=messages,
            )

        if result.get("success"):
            return {
                "success": True,
                "output": result.get("content", ""),
                "model": result.get("model", model_name),
                "tool_results": [],
                "mode": "relay",
                "relay": result.get("relay", ""),
                "usage": self._normalize_usage(result.get("usage", {})),
                "cost": float(result.get("cost", 0) or 0),
            }
        else:
            return {"success": False, "output": "", "error": _sanitize_error(result.get("error", "Relay call failed"))}

    # ─────────────────────────────────────────
    # Path 1: CUA Responses Loop
    # ─────────────────────────────────────────
    async def _execute_cua_loop(self, node, plugins, input_data, on_progress) -> Dict:
        client = await self._get_openai()
        if not client:
            return {"success": False, "output": "", "error": "OpenAI API key not configured"}

        if on_progress:
            await self._emit_noncritical_progress(
                on_progress,
                {"stage": "cua_start", "instruction": input_data[:100]},
            )

        system_prompt = self._compose_system_prompt(node, plugins=plugins, input_data=input_data)
        system_prompt = self._mask_outbound_system_prompt(node, system_prompt)

        tools = [{"type": "computer_use_preview", "display_width": 1920, "display_height": 1080, "environment": "mac"}]
        for p in plugins:
            if p.name != "computer_use":
                tools.append(p.get_tool_definition())

        input_messages = [{"role": "system", "content": system_prompt}, {"role": "user", "content": input_data}]
        all_artifacts, output_text, tool_results = [], "", []
        iteration, max_iterations = 0, 15
        usage_totals = {"prompt_tokens": 0, "completion_tokens": 0, "total_tokens": 0}

        try:
            response = await client.responses.create(
                model="computer-use-preview", tools=tools, input=input_messages, truncation="auto"
            )
            usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
            while iteration < max_iterations:
                iteration += 1
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        {"stage": "cua_iteration", "iteration": iteration, "max": max_iterations},
                    )
                has_action, new_input = False, []
                for item in response.output:
                    item_type = getattr(item, "type", None)
                    if item_type == "message":
                        for block in getattr(item, "content", []):
                            if hasattr(block, "text"):
                                output_text += block.text
                    elif item_type == "computer_call":
                        has_action = True
                        action = item.action
                        if on_progress:
                            await self._emit_noncritical_progress(
                                on_progress,
                                {"stage": "cua_action", "action": getattr(action, "type", "unknown"), "iteration": iteration},
                            )
                        await self._execute_cua_action(action, plugins)
                        ss_plugin = PluginRegistry.get("screenshot")
                        ss_b64 = ""
                        if ss_plugin:
                            ss_result = await ss_plugin.execute({}, context=self.config)
                            if ss_result.success and ss_result.artifacts:
                                ss_b64 = ss_result.artifacts[0].get("base64", "")
                                all_artifacts.append(ss_result.artifacts[0])
                        new_input.append({"type": "computer_call_output", "call_id": item.call_id,
                                          "output": {"type": "computer_screenshot", "image_url": f"data:image/png;base64,{ss_b64}"}})
                    elif item_type == "function_call":
                        has_action = True
                        result = await self._run_plugin(
                            item.name,
                            item.arguments,
                            plugins,
                            node_type=node.get("type", "builder"),
                            node=node,
                        )
                        tool_results.append(result)
                        new_input.append({"type": "function_call_output", "call_id": item.call_id, "output": json.dumps(result)})
                if not has_action:
                    break
                response = await client.responses.create(model="computer-use-preview", tools=tools, input=new_input, truncation="auto")
                usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
            return {"success": True, "output": output_text, "tool_results": tool_results, "artifacts": all_artifacts,
                    "model": "computer-use-preview", "iterations": iteration, "mode": "cua_loop", "usage": usage_totals,
                    "cost": self._estimate_response_cost("computer-use-preview", usage_totals)}
        except Exception as e:
            logger.error(f"CUA loop error: {_sanitize_error(str(e))}")
            return {"success": False, "output": output_text, "error": _sanitize_error(str(e))}

    async def _execute_cua_action(self, action, plugins) -> Dict:
        action_type = getattr(action, "type", "unknown")
        ui = PluginRegistry.get("ui_control")
        try:
            if action_type == "click" and ui:
                return (await ui.execute({"action": "click", "x": getattr(action, "x", 0), "y": getattr(action, "y", 0)}, context=self.config)).to_dict()
            elif action_type == "type" and ui:
                return (await ui.execute({"action": "type", "text": getattr(action, "text", "")}, context=self.config)).to_dict()
            elif action_type == "scroll" and ui:
                return (await ui.execute({"action": "scroll", "amount": getattr(action, "amount", -3)}, context=self.config)).to_dict()
            elif action_type == "key" and ui:
                return (await ui.execute({"action": "hotkey", "keys": getattr(action, "keys", [])}, context=self.config)).to_dict()
            elif action_type == "screenshot":
                ss = PluginRegistry.get("screenshot")
                if ss: return (await ss.execute({}, context=self.config)).to_dict()
            elif action_type == "wait":
                await asyncio.sleep(getattr(action, "duration", 1))
            return {"success": True}
        except Exception as e:
            return {"success": False, "error": str(e)}

    def _compact_partial_output(self, text: Any, limit: int = 6000) -> str:
        """Compact output for report summaries.

        V4.5: Increased default limit 1800→6000 to preserve report quality.
        Uses 60/40 head/tail split to keep conclusions (usually at end).
        """
        preview = str(text or "").strip()
        if not preview:
            return ""
        if len(preview) <= limit:
            return preview
        head = int(limit * 0.6)
        tail = int(limit * 0.35)
        return f"{preview[:head]}\n\n[...truncated {len(preview) - head - tail} chars...]\n\n{preview[-tail:]}"

    @staticmethod
    def _count_code_metrics(text: str) -> Dict[str, Any]:
        """Count code output metrics for real-time progress display.

        Returns line counts, byte size, and detected language breakdown
        so the frontend can show e.g. '已输出 342 行代码 / 15.2KB (HTML+JS+CSS)'.
        """
        if not text:
            return {"total_lines": 0, "code_bytes": 0, "languages": []}
        lines = text.splitlines()
        total_lines = len(lines)
        code_bytes = len(text.encode("utf-8", errors="replace"))

        # Detect language breakdown from content markers
        languages: List[str] = []
        lower = text[:8000].lower()
        if "<html" in lower or "<!doctype" in lower or "<div" in lower:
            languages.append("HTML")
        if "<script" in lower or "function " in lower or "const " in lower or "let " in lower:
            languages.append("JS")
        # v3.0 fix: CSS detection requires <style> tag as anchor. No longer triggers
        # on bare `{` which exists in all JS code (was causing false positives).
        if "<style" in lower or ("color:" in lower and "margin:" in lower and "display:" in lower):
            languages.append("CSS")
        if "import three" in lower or "three.js" in lower or "scene.add" in lower:
            languages.append("Three.js")
        if "canvas" in lower and ("getcontext" in lower or "drawimage" in lower):
            languages.append("Canvas")

        # Count non-empty, non-comment lines as "code lines"
        code_lines = 0
        for line in lines:
            stripped = line.strip()
            if stripped and not stripped.startswith(("//", "#", "/*", "*/", "<!--", "-->")):
                code_lines += 1

        return {
            "total_lines": total_lines,
            "code_lines": code_lines,
            "code_bytes": code_bytes,
            "code_kb": round(code_bytes / 1024, 1),
            "languages": languages[:5],
        }

    def _written_file_code_metrics(self, path: Any) -> Dict[str, Any]:
        """Read a just-written artifact so code metrics also update on file writes."""
        raw_path = str(path or "").strip()
        if not raw_path:
            return {}
        try:
            candidate = Path(raw_path)
            if not candidate.is_file():
                return {}
            if candidate.suffix.lower() not in {".html", ".htm", ".js", ".mjs", ".css", ".json"}:
                return {}
            text = candidate.read_text(encoding="utf-8", errors="replace")
        except Exception:
            return {}
        metrics = self._count_code_metrics(text)
        return {
            "code_lines": metrics.get("code_lines", 0),
            "total_lines": metrics.get("total_lines", 0),
            "code_kb": metrics.get("code_kb", 0),
            "languages": metrics.get("languages", []),
        }

    def _build_partial_output_event(self, text: Any, phase: str = "drafting") -> Optional[Dict[str, Any]]:
        partial_output = str(text or "").strip()
        preview = self._compact_partial_output(partial_output)
        if not preview:
            return None
        # v3.0: Include code metrics for real-time progress visibility
        metrics = self._count_code_metrics(partial_output)
        return {
            "stage": "partial_output",
            "phase": phase,
            "preview": preview,
            # Preserve the raw stream text so the orchestrator can salvage
            # builder timeouts from the real HTML instead of from a compacted UI preview.
            "partial_output": partial_output[:240000],
            "source": "model",
            # v3.0: Code output metrics for UI display
            "code_lines": metrics.get("code_lines", 0),
            "total_lines": metrics.get("total_lines", 0),
            "code_kb": metrics.get("code_kb", 0),
            "languages": metrics.get("languages", []),
        }

    async def _publish_partial_output(self, on_progress, text: Any, phase: str = "drafting") -> None:
        if not on_progress:
            return
        event = self._build_partial_output_event(text, phase=phase)
        if event:
            await self._emit_noncritical_progress(on_progress, event)

    def _attach_browser_action_events(
        self,
        payload: Dict[str, Any],
        browser_action_events: Optional[List[Dict[str, Any]]] = None,
    ) -> Dict[str, Any]:
        if not isinstance(payload, dict):
            return payload
        if browser_action_events:
            payload["browser_action_events"] = [
                dict(item)
                for item in browser_action_events
                if isinstance(item, dict)
            ]
        return payload

    # ─────────────────────────────────────────
    # Path 2.5: Direct OpenAI-compatible SDK (for APIs needing custom headers, e.g. Kimi Coding)
    #           Now supports tool calling for file_ops, shell, etc.
    # ─────────────────────────────────────────
    async def _execute_openai_compatible(self, node, input_data, model_info, on_progress, plugins=None) -> Dict:
        """Execute via OpenAI SDK directly with custom default_headers (bypasses LiteLLM).
        Now supports tool calling so AI can use file_ops/shell plugins."""
        from openai import OpenAI

        node_type = node.get("type", "builder")
        normalized_node_type = normalize_node_role(node_type)
        system_prompt = self._compose_system_prompt(node, plugins=plugins, input_data=input_data)
        # ── v7.3.4 outbound PII gate ────────────────────────────────────
        # system_prompt is composed AFTER input_data was already masked
        # (line 13895), but the system prompt itself can still embed user
        # paths like /path/to/Desktop, OUTPUT_DIR, ALLOWED_DIRS.
        # Mask the system prompt now so absolutely nothing reaches the
        # relay with raw filesystem identity. The accumulated restore_map
        # is stored on `node` so the streaming-loop restores it in tool
        # results / final output below.
        try:
            _outbound_masker = get_masker()
            if _outbound_masker and getattr(_outbound_masker, "enabled", True) and not (node_type in getattr(_outbound_masker, "exclude_node_types", set())):
                _masked_sp, _sp_restore = _outbound_masker.mask(system_prompt, node_type=node_type)
                if _sp_restore:
                    system_prompt = _masked_sp
                    # Stash restore_map on the node for any post-processing
                    # paths that need to recover original strings (rare —
                    # most LLM outputs don't echo user paths).
                    _existing = node.setdefault("_outbound_restore_map", {})
                    _existing.update(_sp_restore)
                    logger.info(
                        "Outbound PII mask: node=%s system_prompt items=%d (paths/IPs/emails sanitised before relay)",
                        normalized_node_type or node_type, len(_sp_restore),
                    )
        except Exception as _mask_err:
            logger.warning("Outbound PII mask skipped: %s", str(_mask_err)[:200])
        # ────────────────────────────────────────────────────────────────
        model_name = model_info["litellm_id"].replace("openai/", "")
        max_tokens = self._max_tokens_for_node(
            node_type,
            retry_attempt=int(node.get("retry_attempt", 0)),
            node=node,
        )
        timeout_sec = self._effective_timeout_for_node(node_type, input_data, node=node)
        max_continuations = self._read_int_env("EVERMIND_MAX_CONTINUATIONS", 2, 0, 5)
        output_text = ""
        latest_stream_text = ""
        latest_stream_activity_at = 0.0
        meaningful_stream_activity_at = 0.0
        stream_activity_events = 0
        stream_has_initial_activity = False
        stream_has_meaningful_activity = False
        builder_stream_pending_write = False
        builder_stream_pending_write_at = 0.0
        builder_stream_pending_write_started_at = 0.0
        tool_results: List[Dict[str, Any]] = []
        builder_support_snapshots: Dict[str, Dict[str, Any]] = {}
        tool_call_stats: Dict[str, int] = {}
        stream_tool_calls_map: Dict[int, Dict[str, Any]] = {}
        builder_has_written_file = False
        polisher_has_written_file = False
        builder_non_write_streak = 0
        polisher_non_write_streak = 0
        # v6.7 (maintainer 2026-04-23): post-write full-rewrite loop guard.
        # Existing post_write_read_loop guard only fires when non_write_streak
        # >= 4 after a write. If the model keeps emitting full <!DOCTYPE>…</html>
        # rewrites, every write resets non_write_streak to 0, so the guard
        # never triggers. Track large HTML rewrites to the same deliverable
        # path separately and break on the 2nd one (≥10KB + same path).
        builder_full_rewrite_streak = 0
        builder_last_write_path = ""
        custom_gateway = bool(self._custom_compatible_gateway_base(model_info))

        # Get API key
        api_key = self._resolved_api_key_for_model_info(model_info)

        if not api_key:
            return {"success": False, "output": "", "error": f"API key not configured for {model_info.get('provider')}"}

        logger.info(
            "_execute_openai_compatible: model=%s timeout=%ss stall=%ss tools=%s",
            model_name, timeout_sec, self._effective_stream_stall_timeout(node_type, input_data, node=node),
            len(plugins) if plugins else 0,
        )
        if on_progress:
            await self._emit_noncritical_progress(
                on_progress,
                {"stage": "calling_ai", "model": model_name, "mode": "openai_compatible"},
            )

        # Build tools from plugins
        # V4.5: Sort deterministically by function name for stable prefix caching.
        # OpenAI auto-caches prefixes >1024 tokens; shuffled tool order breaks cache.
        # v5.8.6: defense-in-depth tool allowlist. router/planner/scribe YAML
        # already declare tools=[], but if any code path leaks tools through,
        # the bloat (3-5K tokens) can trigger private-relay / relay routers
        # into reasoning mode. uidesign (browser) + deployer (file_ops) keep
        # their tools because they legitimately use them.
        _CHAT_ONLY_ROLES = {"router", "planner", "scribe"}
        tools = []
        if plugins and normalized_node_type not in _CHAT_ONLY_ROLES:
            for p in plugins:
                if p.name != "computer_use":
                    defn = p.get_tool_definition()
                    tools.append({"type": "function", "function": defn} if "function" not in defn else defn)
            tools.sort(key=lambda t: str((t.get("function") or {}).get("name") or ""))
        available_tool_names = self._tool_names_from_defs(tools)
        qa_browser_use_available = self._qa_browser_use_available(node_type, available_tool_names)
        logger.info(
            "openai_compatible request profile: node=%s model=%s system_chars=%s user_chars=%s msg_chars=%s tool_names=%s assigned_targets=%s",
            normalized_node_type or node_type,
            model_name,
            len(system_prompt or ""),
            len(str(input_data or "")),
            self._messages_char_count([
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": input_data},
            ]),
            self._tool_names_for_log(tools),
            len(self._builder_assigned_html_targets(input_data)) if normalized_node_type == "builder" else 0,
        )

        try:
            client = self._get_or_create_openai_client(
                api_key=api_key,
                base_url=self._resolved_api_base_for_model_info(model_info),
                extra_headers=model_info.get("extra_headers", {}),
                timeout=timeout_sec,
            )
            loop = asyncio.get_running_loop()

            # V4.6 SPEED: Inject builder deferred context (CSS, design system, topic
            # images) into user message instead of system prompt. This keeps the
            # system prefix small and stable for prompt caching.
            effective_user_input = input_data
            builder_deferred = getattr(self, "_builder_deferred_context", "")
            if builder_deferred and normalized_node_type == "builder":
                effective_user_input = (
                    "=== REFERENCE MATERIAL ===\n"
                    + builder_deferred
                    + "\n=== END REFERENCE ===\n\n"
                    + input_data
                )
                self._builder_deferred_context = ""  # Clear after use
                logger.info(
                    "Builder deferred context injected: %d chars moved from system to user message",
                    len(builder_deferred),
                )
            messages = [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": effective_user_input},
            ]
            qa_task_type = self._classify_task_type(input_data)
            browser_action_events: List[Dict[str, Any]] = []
            await self._maybe_seed_qa_browser_use(
                node=node,
                node_type=node_type,
                task_type=qa_task_type,
                input_data=input_data,
                plugins=plugins,
                available_tool_names=available_tool_names,
                tool_results=tool_results,
                tool_call_stats=tool_call_stats,
                browser_action_events=browser_action_events,
                messages=messages,
                on_progress=on_progress,
            )
            await self._maybe_seed_qa_browser(
                node=node,
                node_type=node_type,
                task_type=qa_task_type,
                input_data=input_data,
                plugins=plugins,
                available_tool_names=available_tool_names,
                tool_results=tool_results,
                tool_call_stats=tool_call_stats,
                browser_action_events=browser_action_events,
                messages=messages,
                on_progress=on_progress,
            )

            # Streaming stall timeout: cancel when the stream stops producing chunks.
            stall_timeout = self._effective_stream_stall_timeout(node_type, input_data, node=node)

            def _call_streaming(msgs, tls, cancel_event: Optional[threading.Event] = None):
                """Make API call with streaming to detect stalls early."""
                nonlocal latest_stream_text, latest_stream_activity_at, meaningful_stream_activity_at
                nonlocal stream_has_initial_activity, stream_has_meaningful_activity
                nonlocal builder_stream_pending_write, builder_stream_pending_write_at
                nonlocal builder_stream_pending_write_started_at
                nonlocal stream_tool_calls_map
                nonlocal stream_activity_events
                stream_has_initial_activity = False
                stream_has_meaningful_activity = False
                meaningful_stream_activity_at = 0.0
                latest_stream_activity_at = 0.0
                stream_activity_events = 0
                builder_stream_pending_write = False
                builder_stream_pending_write_at = 0.0
                builder_stream_pending_write_started_at = 0.0
                stream_tool_calls_map = {}
                # v6.1.1: per-stream <think> state machine. Kimi k2.6-code-preview
                # and other relay-mediated reasoning models occasionally fold
                # <think>...</think> back into delta.content. We strip live and
                # keep the reasoning only in memory for logs.
                _think_strip_enabled = str(os.getenv("EVERMIND_STRIP_THINK", "1")).strip().lower() not in ("0", "false", "off", "no")
                _think_stripper = ThinkStripper()
                prepared_msgs = self._prepare_messages_for_request(msgs, model_name)
                # V4.6 SPEED: Inject cache_control breakpoints for ALL providers.
                # Anthropic: explicit cache_control on system/user message blocks
                # OpenAI: auto-caches >1024 tokens, but explicit markers help
                # Kimi/DeepSeek/relay: cache_control is silently ignored if unsupported,
                #   but some relay backends (e.g. OpenRouter) do honor it.
                # Cost: zero risk (unknown fields ignored), benefit: cache hits on
                # any backend that supports it.
                # v6.1.5 (Opus A N3): was missing `model` arg → no-op for
                # Anthropic detection. Pass model_name so cache actually fires.
                prepared_msgs = self._inject_prompt_cache_breakpoints(prepared_msgs, model=model_name)
                kwargs = {
                    "model": model_name,
                    "messages": prepared_msgs,
                    "max_tokens": max_tokens,
                    "stream": True,
                    # F4-1: Request usage data in streaming mode for accurate token monitoring
                    "stream_options": {"include_usage": True},
                    # V4.3.1: Transport timeout uses 3x stall for first-chunk grace.
                    # relay can have high cold-start latency; 2x was too tight.
                    "timeout": stall_timeout * 3,
                }
                if tls:
                    kwargs["tools"] = tls
                    # v6.4.5 (maintainer 2026-04-21): force file_ops for write-
                    # critical nodes (builder/merger/patcher/polisher) instead
                    # of "auto" to stop model from streaming 60KB prose without
                    # calling the write tool. See _tool_choice_for_node.
                    kwargs["tool_choice"] = self._tool_choice_for_node(
                        normalized_node_type or node_type, tls, model_name
                    )
                    # v6.1.2: stabilise tool schemas + disable parallel for
                    # write-path nodes. Research (Composio 2026 guide,
                    # OpenAI#14485) shows GPT-5+ parallel tool_calls cause
                    # ordering bugs in file_write / shell / git; only read-only
                    # nodes benefit. Also harden schemas per Kimi #11357:
                    #   - every tool MUST have "properties": {} if empty
                    #   - additionalProperties: false on param objects
                    #   - keep tool lists deterministically sorted so
                    #     OpenAI/DeepSeek automatic prefix cache hits.
                    _hardened_tls = []
                    for _tool in kwargs["tools"]:
                        if not isinstance(_tool, dict):
                            _hardened_tls.append(_tool); continue
                        _fn = _tool.get("function") if _tool.get("type") == "function" else None
                        if isinstance(_fn, dict):
                            _params = _fn.get("parameters") or {}
                            if isinstance(_params, dict):
                                _params.setdefault("type", "object")
                                if _params.get("type") == "object":
                                    _params.setdefault("properties", {})
                                    _params.setdefault("required", [])
                                    if "additionalProperties" not in _params:
                                        _params["additionalProperties"] = False
                                _fn["parameters"] = _params
                        _hardened_tls.append(_tool)
                    # stable order by tool name
                    try:
                        _hardened_tls.sort(key=lambda t: (
                            str((t.get("function") or {}).get("name") or "") if t.get("type") == "function" else str(t.get("name") or "")
                        ))
                    except Exception:
                        pass
                    kwargs["tools"] = _hardened_tls
                    _role = normalize_node_role(node_type) or node_type or ""
                    # Opus review #2 P2: reviewer/tester added to serial list.
                    # Observed interleaving bug: parallel browser.observe + file_ops read
                    # from Kimi can emit mismatched tool_call_id on some relays
                    # (v6.1 logs #ID 2026-04-17). Sequential is safe everywhere.
                    _serial_nodes = {"builder", "merger", "polisher", "debugger",
                                     "deployer", "reviewer", "tester"}
                    # v6.3 (maintainer 2026-04-20): asset-producing nodes (imagegen/
                    # spritesheet/assetimport) benefit from parallel file_ops on
                    # kimi/openai-compat, but Anthropic's parallel write path is
                    # known-broken (claude-code issue #24131: only one write per
                    # batch succeeds, others silently drop). When routed to an
                    # Anthropic-family provider, coerce these nodes into serial
                    # mode so a parallel batch doesn't lose files.
                    _prov = str((model_info or {}).get("provider") or "").lower()
                    _asset_nodes = {"imagegen", "spritesheet", "assetimport"}
                    _anthropic_like = _prov in ("anthropic", "claude")
                    if _role in _asset_nodes and _anthropic_like:
                        _serial_nodes = _serial_nodes | _asset_nodes
                    if _role in _serial_nodes:
                        # Don't force-set parallel_tool_calls=False on providers
                        # that don't support the field (Anthropic ignores it,
                        # Gemini 400s on unknown kwargs). OpenAI/Kimi/Qwen/
                        # DeepSeek/Zhipu/Doubao/MiniMax all accept it.
                        if _prov not in ("anthropic", "google", "gemini"):
                            kwargs.setdefault("parallel_tool_calls", False)
                # v6.1: Unified thinking/reasoning config — replaces 12 per-provider
                # if-branches previously duplicated across compat + chat paths.
                # Deep mode actually enables thinking now (was only disabling);
                # fast mode forces off; env overrides still win per-provider.
                _role_v722a = normalized_node_type or node_type or "node"
                _diff_v722a = str((node or {}).get("difficulty") or "std").lower()
                _cache_key = f"evermind-{_role_v722a}-{_diff_v722a}"[:128]
                self._apply_thinking_config_to_kwargs(
                    kwargs,
                    model_info,
                    model_name,
                    cache_key=_cache_key,
                    node_type=normalized_node_type or node_type or "",
                    input_data=input_data,
                )
                if os.getenv("EVERMIND_DEBUG_KIMI_CALLS"):
                    print(
                        f"KIMI_DEBUG_CALL model={model_name} msg_count={len(prepared_msgs)} "
                        f"tools={bool(tls)} stream=True",
                        flush=True,
                    )
                self._debug_log_tool_messages(prepared_msgs, model_name)
                stream = None

                # Collect streamed chunks with stall detection
                content_parts = []
                tool_calls_map = stream_tool_calls_map
                finish_reason = None
                usage_data = None
                last_chunk_time = time.time()
                last_preview_emit = 0.0
                last_pending_write_emit = 0.0
                stream_started_at = last_chunk_time
                first_chunk_at: Optional[float] = None
                first_content_at: Optional[float] = None
                first_tool_call_at: Optional[float] = None
                chunk_count = 0

                # v7.6: per-stream duration watchdog. Was disabled by default
                # in v5.8.6 to prevent killing legit slow-decode streams. But
                # in 8-round PvZ/dashboard/slides testing, 3 cancellations
                # (Round 1, 4, 6) all came from kimi getting STUCK in a
                # single tool_call stream for 14-28 minutes — chunks trickled
                # in just often enough to escape `stall_timeout * 6 = 18min`.
                # Set default to 900s (15min): if any single LLM stream call
                # can't complete in 15 minutes, abort + force retry. Real
                # builder code-gen on kimi-coding tops out around 5-7 min;
                # 15 min is generous safety margin. Override via env if
                # needed.  Applied to ALL streaming nodes, not just builder.
                _stream_watchdog_sec = self._read_int_env(
                    "EVERMIND_STREAM_DECODE_WATCHDOG_SEC",
                    900,   # default 15 min (was: 0 = disabled)
                    60,
                    3600,
                )
                try:
                    stream = client.chat.completions.create(**kwargs)
                    for chunk in stream:
                        if cancel_event is not None and cancel_event.is_set():
                            raise asyncio.CancelledError()
                        now = time.time()
                        latest_stream_activity_at = now
                        # v5.8.6: decode watchdog (see comment above)
                        if (
                            _stream_watchdog_sec
                            and now - stream_started_at > _stream_watchdog_sec
                        ):
                            raise TimeoutError(
                                f"Stream decode watchdog: node={normalized_node_type or node_type} "
                                f"exceeded {_stream_watchdog_sec}s on a single stream "
                                f"(likely oversized tool_call payload). Forcing retry with smaller segments."
                            )
                        # V4.3.1: First-chunk grace window.
                        # v5.8.6 P1-1: when tools present AND first_content not seen,
                        # use 6x grace instead of 3x — relay reasoning-mode
                        # models emit `delta.reasoning_content` for 30-60s before
                        # first `delta.content`. 3x = 90s was killing Kimi p99.
                        _has_tools = bool(tools) if 'tools' in locals() else False
                        _grace_mul = 6 if (first_content_at is None and _has_tools) else 3
                        _effective_stall = (stall_timeout * _grace_mul) if first_content_at is None else stall_timeout
                        if now - last_chunk_time > _effective_stall:
                            raise TimeoutError(f"Stream stalled: no chunk for {_effective_stall:.0f}s")
                        if first_chunk_at is None:
                            first_chunk_at = now
                        chunk_count += 1
                        stream_activity_events += 1
                        last_chunk_time = now

                        if not chunk.choices:
                            # Usage-only final chunk
                            if hasattr(chunk, "usage") and chunk.usage:
                                usage_data = chunk.usage
                            continue

                        delta = chunk.choices[0].delta
                        # v5.8.6 P0-1: read reasoning_content (and non-standard
                        # `reasoning` field on some relays) — if model is
                        # streaming thinking, that's proof-of-life. Reset
                        # last_chunk_time already done above; just make sure
                        # first_content_at gets marked so we don't stay in
                        # 6x-grace mode forever.
                        _reasoning_delta = getattr(delta, "reasoning_content", None)
                        if _reasoning_delta is None:
                            _reasoning_delta = getattr(delta, "reasoning", None)
                        if _reasoning_delta is None:
                            _model_extra = getattr(delta, "model_extra", None) or {}
                            if isinstance(_model_extra, dict):
                                _reasoning_delta = _model_extra.get("reasoning_content") or _model_extra.get("reasoning")
                        if _reasoning_delta:
                            # v6.1.1: vendor-provided reasoning field — log but
                            # NEVER emit to content. Model thinks internally,
                            # file stays clean.
                            _think_stripper.reasoning_parts.append(str(_reasoning_delta))
                            stream_has_initial_activity = True
                            if first_content_at is None:
                                # Keep grace window tight once reasoning starts;
                                # the real answer will follow once reasoning ends.
                                first_content_at = now
                        if delta.content:
                            # v6.1.1: route delta through ThinkStripper state
                            # machine so any inline <think>...</think> the relay
                            # folded back into content (kimi k2.6-code-preview
                            # via relay / MiniMax M2 default / Qwen3 open ckpt)
                            # gets stripped BEFORE append. Model still gets to
                            # think — we just don't write the monologue to disk.
                            _raw_delta = delta.content
                            _clean_delta = _think_stripper.feed(_raw_delta) if _think_strip_enabled else _raw_delta
                            if _clean_delta:
                                content_parts.append(_clean_delta)
                            latest_stream_text = "".join(content_parts)
                            # v6.4.7 (maintainer 2026-04-21) — PROSE-ABORT GUARD.
                            # For write-critical nodes (builder/merger/
                            # polisher/patcher), if the model streams >8 KB
                            # of pure prose WITHOUT a tool_call and without
                            # HTML markers, abort the stream. Forces retry
                            # on a tightened prompt instead of wasting a
                            # full hard-timeout window (6×600s grace).
                            # Research: Kimi K2.6 trained to emit reasoning
                            # before tool_call → without this guard we burn
                            # 5-10 min/retry on prose-only first turns.
                            if (
                                first_tool_call_at is None
                                and normalized_node_type in ("builder", "merger", "polisher", "patcher")
                            ):
                                _prose_len = len(latest_stream_text)
                                _lower_head = latest_stream_text[:1024].lower()
                                _has_html_marker = (
                                    "<!doctype" in _lower_head
                                    or "<html" in _lower_head
                                    or "<body" in _lower_head
                                    or "<style" in _lower_head
                                    or "<script" in _lower_head
                                )
                                _abort_cap = int(os.getenv("EVERMIND_PROSE_ABORT_BYTES", "8192"))
                                if _prose_len >= _abort_cap and not _has_html_marker:
                                    logger.warning(
                                        "PROSE-ABORT: node=%s model=%s streamed %d chars of prose without any tool_call or HTML marker — cutting stream to retry with tighter prompt.",
                                        normalized_node_type, model_name, _prose_len,
                                    )
                                    try:
                                        stream.close()
                                    except Exception:
                                        pass
                                    raise TimeoutError(
                                        f"prose_before_tool_abort: {_prose_len} chars of prose without tool_call"
                                    )
                            _is_inside_think = _think_stripper.in_think if _think_strip_enabled else (
                                "<think>" in latest_stream_text
                                and latest_stream_text.count("<think>") > latest_stream_text.count("</think>")
                            )
                            if first_content_at is None and not _is_inside_think and _clean_delta:
                                first_content_at = now
                            stream_has_initial_activity = True
                            latest_trimmed = latest_stream_text.strip()
                            if (
                                latest_trimmed
                                and (
                                    len(latest_trimmed) >= 256
                                    or "<!doctype" in latest_trimmed.lower()
                                    or "<html" in latest_trimmed.lower()
                                    or "<body" in latest_trimmed.lower()
                                )
                            ):
                                stream_has_meaningful_activity = True
                                meaningful_stream_activity_at = now
                            if on_progress and (now - last_preview_emit >= 0.75):
                                event = self._build_partial_output_event(latest_stream_text, phase="streaming")
                                if event:
                                    try:
                                        asyncio.run_coroutine_threadsafe(on_progress(event), loop)
                                    except RuntimeError:
                                        pass
                                last_preview_emit = now
                        if delta.tool_calls:
                            for tc in delta.tool_calls:
                                idx = tc.index
                                if idx not in tool_calls_map:
                                    tool_calls_map[idx] = {
                                        "id": tc.id or "",
                                        "type": "function",
                                        "function": {"name": "", "arguments": ""},
                                    }
                                entry = tool_calls_map[idx]
                                if tc.id:
                                    entry["id"] = tc.id
                                if tc.function:
                                    if first_tool_call_at is None:
                                        first_tool_call_at = now
                                    stream_has_initial_activity = True
                                    if tc.function.name:
                                        entry["function"]["name"] = tc.function.name
                                    if tc.function.arguments:
                                        entry["function"]["arguments"] += tc.function.arguments
                                    if normalized_node_type == "builder":
                                        if self._builder_streaming_tool_call_looks_like_write(
                                            entry["function"].get("name", ""),
                                            entry["function"].get("arguments", ""),
                                        ):
                                            stream_has_meaningful_activity = True
                                            meaningful_stream_activity_at = now
                                            builder_stream_pending_write = True
                                            if builder_stream_pending_write_started_at <= 0:
                                                builder_stream_pending_write_started_at = now
                                            builder_stream_pending_write_at = now
                                            if on_progress and (now - last_pending_write_emit >= 5.0):
                                                # V4.3: Estimate code_lines from streaming tool_call args
                                                # so tool-path builders show real-time code progress like
                                                # direct_text builders do.
                                                _pw_args = entry["function"].get("arguments", "")
                                                _pw_metrics = self._count_code_metrics(_pw_args) if len(_pw_args) > 100 else {}
                                                try:
                                                    asyncio.run_coroutine_threadsafe(
                                                        on_progress({
                                                            "stage": "builder_pending_write",
                                                            "message": "Builder is still streaming a write-like file_ops payload.",
                                                            "code_lines": _pw_metrics.get("code_lines", 0),
                                                            "code_kb": _pw_metrics.get("code_kb", 0),
                                                            "languages": _pw_metrics.get("languages", []),
                                                        }),
                                                        loop,
                                                    )
                                                except RuntimeError:
                                                    pass
                                                last_pending_write_emit = now
                                    else:
                                        stream_has_meaningful_activity = True
                                        meaningful_stream_activity_at = now
                        if chunk.choices[0].finish_reason:
                            finish_reason = chunk.choices[0].finish_reason
                    if cancel_event is not None and cancel_event.is_set():
                        raise asyncio.CancelledError()
                finally:
                    _close_stream_quietly(stream)

                logger.info(
                    "openai_compatible stream stats: node=%s model=%s chunks=%s first_chunk=%s first_content=%s first_tool_call=%s finish=%s content_chars=%s tool_calls=%s total_stream=%s",
                    normalized_node_type or node_type,
                    model_name,
                    chunk_count,
                    self._format_latency_for_log(
                        None if first_chunk_at is None else first_chunk_at - stream_started_at
                    ),
                    self._format_latency_for_log(
                        None if first_content_at is None else first_content_at - stream_started_at
                    ),
                    self._format_latency_for_log(
                        None if first_tool_call_at is None else first_tool_call_at - stream_started_at
                    ),
                    finish_reason or "stop",
                    len("".join(content_parts)),
                    len(tool_calls_map),
                    self._format_latency_for_log(time.time() - stream_started_at),
                )

                # Broadcast stream stats to frontend via on_progress
                if on_progress:
                    _total_stream_sec = time.time() - stream_started_at
                    _first_content_sec = (first_content_at - stream_started_at) if first_content_at else None
                    _chars_per_sec = round(len("".join(content_parts)) / max(_total_stream_sec, 0.1), 1)
                    try:
                        asyncio.run_coroutine_threadsafe(
                            on_progress({
                                "stage": "stream_stats",
                                "model": model_name,
                                "chunks": chunk_count,
                                "first_content_sec": round(_first_content_sec, 2) if _first_content_sec else None,
                                "total_stream_sec": round(_total_stream_sec, 2),
                                "content_chars": len("".join(content_parts)),
                                "chars_per_sec": _chars_per_sec,
                                "tool_calls": len(tool_calls_map),
                            }),
                            loop,
                        )
                    except Exception:
                        pass

                # ── Fix: Validate tool call JSON when finish=length (Kimi K2.5 truncation) ──
                # When Kimi hits max_tokens mid-tool-call, the arguments JSON is incomplete.
                # Instead of discarding, try to repair JSON or extract HTML from the truncated args.
                if finish_reason == "length" and tool_calls_map:
                    valid_tc_map = {}
                    stripped_count = 0
                    recovered_html = None
                    for _idx, tc_data in tool_calls_map.items():
                        fn_name = tc_data["function"].get("name", "")
                        fn_args = tc_data["function"].get("arguments", "")
                        if not fn_name:
                            stripped_count += 1
                            continue
                        try:
                            json.loads(fn_args)
                            valid_tc_map[_idx] = tc_data
                        except (json.JSONDecodeError, ValueError):
                            # ── P0 FIX: Don't just discard — try to recover HTML from truncated args ──
                            repaired = False

                            # Strategy 0: Claude Code-style suffix guessing (openaiShim.ts pattern)
                            # Try cheap bracket/brace combinations to close truncated JSON.
                            # This handles the most common case where only closing delimiters are missing.
                            _suffix_combos = (
                                "}", '"}', "]}", '"]}', "}}", '"}}',
                                '"]}}', "]}}", '"}]}', '"]}}',
                                '"}]', '"]', '"}]}]}',
                            )
                            trimmed = fn_args.rstrip()
                            for suffix in _suffix_combos:
                                try:
                                    json.loads(trimmed + suffix)
                                    tc_data["function"]["arguments"] = trimmed + suffix
                                    valid_tc_map[_idx] = tc_data
                                    repaired = True
                                    logger.info(
                                        "Suffix-guessing repaired truncated tool call: node=%s fn=%s suffix=%r args_len=%s",
                                        normalized_node_type or node_type,
                                        fn_name,
                                        suffix,
                                        len(fn_args),
                                    )
                                    break
                                except (json.JSONDecodeError, ValueError):
                                    continue

                            # Strategy 1: json_repair library (best-effort structural repair)
                            if not repaired and _json_repair_fn and fn_name in ("file_ops", "write_file", "write"):
                                try:
                                    repaired_str = _json_repair_fn(fn_args)
                                    repaired_obj = json.loads(repaired_str) if isinstance(repaired_str, str) else repaired_str
                                    if isinstance(repaired_obj, dict) and repaired_obj.get("content"):
                                        tc_data["function"]["arguments"] = json.dumps(repaired_obj, ensure_ascii=False)
                                        valid_tc_map[_idx] = tc_data
                                        repaired = True
                                        logger.info(
                                            "json_repair recovered truncated tool call: node=%s fn=%s args_len=%s→%s",
                                            normalized_node_type or node_type,
                                            fn_name,
                                            len(fn_args),
                                            len(tc_data["function"]["arguments"]),
                                        )
                                except Exception as repair_exc:
                                    logger.debug("json_repair failed for %s: %s", fn_name, str(repair_exc)[:100])

                            # Strategy 2: Regex extract HTML content from truncated args
                            if not repaired and fn_name in ("file_ops", "write_file", "write"):
                                extracted = self._extract_html_from_truncated_tool_args(fn_args)
                                if extracted and len(extracted) > 500:
                                    recovered_html = extracted
                                    logger.info(
                                        "Regex-extracted HTML from truncated tool call: node=%s fn=%s "
                                        "raw_args_len=%s extracted_html_len=%s",
                                        normalized_node_type or node_type,
                                        fn_name,
                                        len(fn_args),
                                        len(extracted),
                                    )

                            if not repaired:
                                stripped_count += 1
                                logger.warning(
                                    "Stripped truncated tool call: node=%s model=%s fn=%s args_len=%s finish=length",
                                    normalized_node_type or node_type,
                                    model_name,
                                    fn_name,
                                    len(fn_args),
                                )
                    if stripped_count > 0:
                        logger.info(
                            "finish=length tool call sanitization: node=%s stripped=%s valid=%s recovered_html=%s",
                            normalized_node_type or node_type,
                            stripped_count,
                            len(valid_tc_map),
                            bool(recovered_html),
                        )
                    # If we recovered HTML from a truncated tool call, inject it into
                    # latest_stream_text so the salvage path can use it.
                    preferred_salvage = self._select_builder_salvage_text(
                        latest_stream_text,
                        output_text,
                        recovered_html=recovered_html,
                    )
                    if preferred_salvage and preferred_salvage != latest_stream_text:
                        latest_stream_text = preferred_salvage
                        logger.info(
                            "Injected preferred salvage HTML/text into latest_stream_text (%s chars, recovered_html=%s)",
                            len(preferred_salvage),
                            bool(recovered_html),
                        )
                    tool_calls_map = valid_tc_map
                    stream_tool_calls_map = valid_tc_map

                # Reassemble into a response-like object
                from types import SimpleNamespace
                tool_calls_list = None
                if tool_calls_map:
                    tool_calls_list = []
                    for _idx in sorted(tool_calls_map.keys()):
                        tc_data = tool_calls_map[_idx]
                        tool_calls_list.append(SimpleNamespace(
                            id=tc_data["id"],
                            type="function",
                            function=SimpleNamespace(
                                name=tc_data["function"]["name"],
                                arguments=tc_data["function"]["arguments"],
                            ),
                        ))

                # v6.1.1: flush stripper. If stream ended mid-<think>, drop
                # any still-buffered open block; otherwise re-append the safe
                # tail that had been held back to avoid splitting a tag.
                if _think_strip_enabled:
                    _tail = _think_stripper.flush()
                    if _tail:
                        content_parts.append(_tail)
                    if _think_stripper.reasoning_parts:
                        _reasoning_chars = sum(len(p) for p in _think_stripper.reasoning_parts)
                        logger.info(
                            "stream thinking stripped: model=%s reasoning_chars=%d content_chars=%d",
                            model_name, _reasoning_chars, sum(len(p) for p in content_parts),
                        )
                final_content = "".join(content_parts) if content_parts else None
                if final_content and _think_strip_enabled:
                    # Non-streaming fallback — catches <think> blocks the state
                    # machine might have missed (e.g. nested tags, weird
                    # capitalisation, half tags the stripper decided to emit).
                    _post_clean = strip_think_tags_full(final_content)
                    if _post_clean != final_content:
                        logger.info(
                            "stream thinking stripped (post-process): model=%s removed_chars=%d",
                            model_name, len(final_content) - len(_post_clean),
                        )
                        final_content = _post_clean
                # v6.1.14c (maintainer 2026-04-20): mirror the litellm-wrapper fix —
                # openai-compat streaming wrapper also must attach reasoning_content
                # so downstream `_serialize_assistant_message` preserves it. Without
                # this, uidesign / any kimi-direct node with tools gets 400
                # "reasoning_content missing" on the next request round because the
                # first assistant message went out without a reasoning_content key,
                # and my synth in _prepare_messages_for_request sees only what's on
                # the dict (which doesn't carry it because the stream wrapper dropped it).
                _reasoning_joined = "".join(_think_stripper.reasoning_parts) if getattr(_think_stripper, "reasoning_parts", None) else ""
                message = SimpleNamespace(
                    content=final_content,
                    tool_calls=tool_calls_list,
                    role="assistant",
                    reasoning_content=_reasoning_joined,
                )
                choice = SimpleNamespace(
                    message=message,
                    finish_reason=finish_reason or "stop",
                )
                response_obj = SimpleNamespace(
                    choices=[choice],
                    usage=usage_data,
                )
                return response_obj

            async def _force_builder_text_timeout_fallback(reason: str) -> Optional[Dict[str, Any]]:
                nonlocal builder_has_written_file, tool_results, tool_call_stats
                if normalized_node_type != "builder" or builder_has_written_file:
                    return None
                # P0 FIX: Prioritize recovered HTML from truncated tool args over
                # often-empty output_text (Kimi sends content_chars=0, all HTML in tool args)
                tool_result_text = self._builder_tool_result_salvage_text(tool_results, input_data)
                stream_tool_call_text = self._builder_stream_tool_call_salvage_text(stream_tool_calls_map, input_data)
                disk_result_text = self._builder_disk_salvage_text(
                    input_data,
                    incremental_text=output_text or latest_stream_text,
                )
                combined_salvage_text = "\n\n".join(
                    part
                    for part in (stream_tool_call_text, tool_result_text, disk_result_text)
                    if str(part or "").strip()
                )
                salvage_text = self._select_builder_salvage_text(
                    latest_stream_text,
                    output_text,
                    tool_result_text=combined_salvage_text,
                )
                async def _request_builder_continuation(cont_messages):
                    return await _await_stream_call(cont_messages, [])

                salvage_text, _, _ = await self._attempt_builder_game_text_continuation(
                    output_text=salvage_text,
                    input_data=input_data,
                    system_prompt=system_prompt,
                    continuation_count=0,
                    max_continuations=1,
                    request_continuation=_request_builder_continuation,
                    on_progress=on_progress,
                    log_prefix="Builder timeout salvage",
                )
                if not salvage_text or len(salvage_text) < 200:
                    # latest_stream_text may be empty when Kimi uses tool-call-only mode.
                    # The truncation handler above may have injected recovered HTML.
                    logger.debug(
                        "Salvage text thin (%s chars), latest_stream_text may contain recovered HTML",
                        len(salvage_text or ""),
                    )

                # ── P0 FIX C: If salvage_text has HTML, auto-save it to disk first ──
                # This handles the case where the prewrite timeout killed a text-mode
                # stream that had significant HTML content (e.g. 37k chars with full body).
                if salvage_text and len(salvage_text) > 2000:
                    saved_paths = await self._auto_save_builder_text_output(
                        output_text=salvage_text,
                        input_data=input_data,
                        node=node,
                        tool_results=tool_results,
                        tool_call_stats=tool_call_stats,
                        on_progress=on_progress,
                    )
                    if saved_paths:
                        builder_has_written_file = True
                        return {
                            "success": True,
                            "output": salvage_text,
                            "model": model_name,
                            "tool_results": tool_results,
                            "mode": "openai_compatible_text_mode_auto_save",
                            "tool_call_stats": dict(tool_call_stats),
                        }

                salvage = await self._builder_partial_text_salvage_result(
                    node=node,
                    input_data=input_data,
                    output_text=salvage_text,
                    reason=reason or "prewrite_call_timeout",
                    on_progress=on_progress,
                    tool_results=tool_results,
                    model_name=model_name,
                    mode="openai_compatible_partial_timeout_salvage",
                    tool_call_stats=tool_call_stats,
                )
                if salvage is not None:
                    return salvage
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, reason or "prewrite_call_timeout"),
                    )
                forced_messages = self._builder_forced_text_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    reason or "prewrite_call_timeout",
                )
                forced_timeout = self._read_int_env(
                    "EVERMIND_BUILDER_FORCED_TEXT_TIMEOUT_SEC",
                    45,
                    15,
                    120,
                )
                try:
                    final_resp = await asyncio.wait_for(
                        asyncio.to_thread(_call_streaming, forced_messages, []),
                        timeout=forced_timeout,
                    )
                except Exception as fallback_exc:
                    salvage = await self._builder_partial_text_salvage_result(
                        node=node,
                        input_data=input_data,
                        output_text=latest_stream_text or output_text,
                        reason=fallback_exc,
                        on_progress=on_progress,
                        tool_results=tool_results,
                        model_name=model_name,
                        mode="openai_compatible_partial_timeout_salvage",
                        tool_call_stats=tool_call_stats,
                    )
                    if salvage is not None:
                        return salvage
                    logger.warning(
                        "Builder forced text fallback after timeout failed: %s",
                        _sanitize_error(str(fallback_exc)),
                    )
                    return None

                final_msg = final_resp.choices[0].message
                final_content = getattr(final_msg, "content", "") or ""
                if not final_content.strip():
                    return await self._builder_partial_text_salvage_result(
                        node=node,
                        input_data=input_data,
                        output_text=latest_stream_text or output_text,
                        reason=reason or "forced_text_empty",
                        on_progress=on_progress,
                        tool_results=tool_results,
                        model_name=model_name,
                        mode="openai_compatible_partial_timeout_salvage",
                        usage=self._normalize_usage(getattr(final_resp, "usage", None)),
                        tool_call_stats=tool_call_stats,
                    )
                await self._publish_partial_output(on_progress, final_content, phase="finalizing")
                return {
                    "success": True,
                    "output": final_content,
                    "model": model_name,
                    "tool_results": tool_results,
                    "mode": "openai_compatible_forced_text_timeout",
                    "usage": self._normalize_usage(getattr(final_resp, "usage", None)),
                    "tool_call_stats": dict(tool_call_stats),
                }

            async def _await_stream_call(msgs, tls, timeout_override: Optional[float] = None):
                nonlocal latest_stream_text
                cancel_event = threading.Event()
                call_task = asyncio.create_task(asyncio.to_thread(_call_streaming, msgs, tls, cancel_event))

                def _request_stream_stop() -> None:
                    cancel_event.set()
                    call_task.cancel()

                timeout_phase = "hard"
                timeout_value = 0
                hard_timeout = 0
                prewrite_timeout = 0
                builder_tool_only_timeout = 0
                initial_activity_timeout = 0
                if normalized_node_type == "builder" and not builder_has_written_file:
                    prewrite_timeout = self._builder_prewrite_call_timeout(node_type, input_data, node=node)
                    builder_tool_only_timeout = self._builder_tool_only_call_timeout(node_type, input_data, node=node)
                    if builder_non_write_streak > 0:
                        repair_timeout = self._builder_repair_write_timeout(node_type, input_data, node=node)
                        prewrite_timeout = min(prewrite_timeout, repair_timeout)
                elif normalized_node_type == "polisher" and not polisher_has_written_file:
                    prewrite_timeout = self._polisher_prewrite_call_timeout(node_type, input_data)
                if custom_gateway:
                    initial_activity_timeout = self._gateway_initial_activity_timeout_for_node(node_type, input_data, model_info=model_info)
                elif normalized_node_type not in ("builder", "polisher"):
                    # v6.3 (maintainer 2026-04-20): non-build nodes on native kimi/claude
                    # also suffer relay TTFB hangs — observed run_85ef3b62fcd3
                    # where analyst's 10th LLM call silently ate 200s before
                    # hard-ceiling (no stream chunks arrived). Apply the same
                    # initial-activity guard previously reserved for compatible
                    # gateways. Builder/polisher have their own richer ladder
                    # (prewrite/tool-only/repair) so we skip them here.
                    initial_activity_timeout = self._gateway_initial_activity_timeout_for_node(
                        node_type, input_data, model_info=model_info
                    )
                # Always enforce a hard ceiling timeout — even after the first file write.
                if timeout_override is None:
                    hard_timeout = timeout_sec
                else:
                    try:
                        hard_timeout = max(1.0, min(float(timeout_override), float(timeout_sec)))
                    except Exception:
                        hard_timeout = timeout_sec
                pending_write_cap = (
                    self._builder_pending_write_stream_cap_seconds(prewrite_timeout, hard_timeout)
                    if normalized_node_type == "builder"
                    else 0.0
                )
                effective = prewrite_timeout if prewrite_timeout > 0 else hard_timeout
                logger.info(
                    "_await_stream_call: prewrite_timeout=%s tool_only_timeout=%s initial_activity_timeout=%s hard_timeout=%s pending_write_cap=%s effective=%s written=%s",
                    prewrite_timeout,
                    builder_tool_only_timeout,
                    initial_activity_timeout,
                    hard_timeout,
                    pending_write_cap,
                    effective,
                    builder_has_written_file if normalized_node_type == "builder" else polisher_has_written_file,
                )
                try:
                    started_at = time.time()
                    hard_deadline = started_at + hard_timeout
                    prewrite_deadline = started_at + prewrite_timeout if prewrite_timeout > 0 else None
                    builder_tool_only_deadline = (
                        started_at + builder_tool_only_timeout
                        if builder_tool_only_timeout > 0
                        else None
                    )
                    initial_activity_deadline = (
                        started_at + initial_activity_timeout if initial_activity_timeout > 0 else None
                    )
                    activity_grace = self._prewrite_activity_grace_seconds(stall_timeout)

                    while True:
                        now = time.time()
                        remaining_hard = hard_deadline - now
                        if remaining_hard <= 0:
                            latest_text_is_salvageable = len(latest_stream_text or "") > 0
                            if normalized_node_type == "builder":
                                latest_text_is_salvageable = self._builder_partial_text_is_salvageable(
                                    input_data,
                                    latest_stream_text,
                                )
                            meaningful_age = (
                                now - meaningful_stream_activity_at
                                if meaningful_stream_activity_at > 0
                                else None
                            )
                            pending_write_age = (
                                now - builder_stream_pending_write_at
                                if builder_stream_pending_write_at > 0
                                else None
                            )
                            pending_write_total_age = (
                                now - builder_stream_pending_write_started_at
                                if builder_stream_pending_write_started_at > 0
                                else None
                            )
                            active_hard_grace = max(
                                0.0,
                                min(
                                    float(self._read_int_env("EVERMIND_BUILDER_ACTIVE_HARD_TIMEOUT_GRACE_SEC", 120, 30, 300)),
                                    max(0.0, hard_timeout / 4.0),
                                ),
                            )
                            if normalized_node_type == "builder" and (
                                (
                                    stream_activity_events >= 2
                                    and latest_text_is_salvageable
                                    and stream_has_meaningful_activity
                                    and meaningful_age is not None
                                    and meaningful_age <= active_hard_grace
                                )
                                or (
                                    stream_activity_events >= 2
                                    and builder_stream_pending_write
                                    and pending_write_age is not None
                                    and pending_write_total_age is not None
                                    and pending_write_age <= active_hard_grace
                                    and pending_write_total_age <= pending_write_cap
                                )
                            ):
                                hard_deadline = now + active_hard_grace
                                logger.info(
                                    "builder hard timeout reached but stream is still active (meaningful_age=%s pending_write_age=%s pending_write_total_age=%s grace=%ss cap=%ss) — extending deadline",
                                    None if meaningful_age is None else round(meaningful_age, 2),
                                    None if pending_write_age is None else round(pending_write_age, 2),
                                    None if pending_write_total_age is None else round(pending_write_total_age, 2),
                                    int(active_hard_grace),
                                    round(pending_write_cap, 2),
                                )
                                continue
                            _request_stream_stop()
                            timeout_phase = "hard"
                            timeout_value = hard_timeout
                            raise asyncio.TimeoutError()

                        next_poll = min(1.0, remaining_hard)
                        if initial_activity_deadline is not None:
                            next_poll = min(next_poll, max(0.01, initial_activity_deadline - now))
                        if prewrite_deadline is not None:
                            next_poll = min(next_poll, max(0.01, prewrite_deadline - now))
                        done, _ = await asyncio.wait({call_task}, timeout=next_poll)
                        if call_task in done:
                            return call_task.result()

                        now = time.time()
                        if stream_has_initial_activity:
                            initial_activity_deadline = None
                        elif initial_activity_deadline is not None and now >= initial_activity_deadline:
                            _request_stream_stop()
                            timeout_phase = "initial-activity"
                            timeout_value = initial_activity_timeout
                            raise asyncio.TimeoutError()

                        if (
                            normalized_node_type == "builder"
                            and not builder_has_written_file
                            and builder_tool_only_deadline is not None
                            and now >= builder_tool_only_deadline
                            and not builder_stream_pending_write
                            and not self._builder_partial_text_is_salvageable(input_data, latest_stream_text)
                        ):
                            _request_stream_stop()
                            timeout_phase = "tool-only"
                            timeout_value = builder_tool_only_timeout
                            raise asyncio.TimeoutError()

                        if prewrite_deadline is None or now < prewrite_deadline:
                            continue

                        meaningful_age = None
                        pending_write_age = None
                        pending_write_total_age = None
                        if meaningful_stream_activity_at > 0:
                            meaningful_age = now - meaningful_stream_activity_at
                        if builder_stream_pending_write_at > 0:
                            pending_write_age = now - builder_stream_pending_write_at
                        if builder_stream_pending_write_started_at > 0:
                            pending_write_total_age = now - builder_stream_pending_write_started_at
                        latest_len = len(latest_stream_text or "")
                        active_writer = (
                            builder_has_written_file if normalized_node_type == "builder"
                            else polisher_has_written_file
                        )
                        latest_text_is_salvageable = latest_len > 0
                        if normalized_node_type == "builder":
                            latest_text_is_salvageable = self._builder_partial_text_is_salvageable(
                                input_data,
                                latest_stream_text,
                            )
                        if (
                            not active_writer
                            and latest_text_is_salvageable
                            and stream_has_meaningful_activity
                            and meaningful_age is not None
                            and meaningful_age <= activity_grace
                        ):
                            logger.info(
                                "%s prewrite deadline reached but stream is active (latest_chars=%s meaningful_age=%.2fs grace=%.2fs) — extending prewrite deadline",
                                normalized_node_type or node_type,
                                latest_len,
                                meaningful_age,
                                activity_grace,
                            )
                            prewrite_deadline = now + activity_grace
                            continue

                        if (
                            normalized_node_type == "builder"
                            and not active_writer
                            and builder_stream_pending_write
                            and pending_write_age is not None
                            and pending_write_total_age is not None
                            and pending_write_age <= activity_grace
                            and pending_write_total_age <= pending_write_cap
                        ):
                            logger.info(
                                "builder prewrite deadline reached but a write-like file_ops payload is still streaming (pending_write_age=%.2fs total_age=%.2fs grace=%.2fs cap=%.2fs) — extending prewrite deadline",
                                pending_write_age,
                                pending_write_total_age,
                                activity_grace,
                                pending_write_cap,
                            )
                            prewrite_deadline = now + activity_grace
                            continue

                        _request_stream_stop()
                        timeout_phase = "pre-write"
                        timeout_value = prewrite_timeout
                        raise asyncio.TimeoutError()
                except asyncio.TimeoutError as exc:
                    if normalized_node_type == "builder":
                        if timeout_phase == "initial-activity":
                            kind = "initial-activity"
                            detail = "compatible gateway produced no content or tool activity."
                        elif timeout_phase == "tool-only":
                            kind = "tool-only"
                            detail = (
                                "stream stayed in tool-planning mode without any deliverable HTML "
                                "or write-like file_ops payload."
                            )
                        else:
                            kind = timeout_phase if timeout_phase == "pre-write" else "hard-ceiling"
                            detail = (
                                "no file write produced"
                                if not builder_has_written_file
                                else "API call exceeded node timeout"
                            )
                        raise TimeoutError(
                            f"builder {kind} timeout after {timeout_value or effective}s: {detail}."
                        ) from exc
                    if normalized_node_type == "polisher":
                        if timeout_phase == "initial-activity":
                            kind = "initial-activity"
                            detail = "compatible gateway produced no content or tool activity."
                        else:
                            kind = timeout_phase if timeout_phase == "pre-write" else "hard-ceiling"
                            detail = (
                                "no real file write was produced"
                                if not polisher_has_written_file
                                else "API call exceeded node timeout"
                            )
                        raise TimeoutError(
                            f"polisher {kind} timeout after {timeout_value or effective}s: {detail}."
                        ) from exc
                    node_label = normalized_node_type or str(node_type or "node").strip().lower() or "node"
                    if timeout_phase == "initial-activity":
                        raise TimeoutError(
                            f"{node_label} initial-activity timeout after {timeout_value or effective}s: compatible gateway produced no content or tool activity."
                        ) from exc
                    raise TimeoutError(
                        f"{node_label} hard-ceiling timeout after {timeout_value or effective}s: API call exceeded node timeout."
                    ) from exc

            response = await _await_stream_call(messages, tools)

            await self._publish_partial_output(
                on_progress,
                getattr(response.choices[0].message, "content", "") or "",
                phase="sectioning" if node_type == "planner" else "drafting",
            )

            iteration = 0
            max_iterations = self._max_tool_iterations_for_node(node_type, node=node)
            # v5.2: Per-iteration tool-call signature history — breaks tool-calling
            # loops where the model calls the same (tool, args) combination repeatedly
            # without producing content. Inspired by Watchtower/Inngest loop detection.
            tool_signature_history: List[str] = []
            tool_loop_streak_limit = self._read_int_env(
                "EVERMIND_TOOL_LOOP_STREAK", 3, 2, 8,
            )
            continuation_count = 0
            usage_totals = self._normalize_usage(getattr(response, "usage", None))
            builder_non_write_streak = 0
            builder_force_text_early = False
            builder_force_reason = ""
            builder_force_threshold = self._builder_force_text_threshold(input_data)
            builder_repair_prompts_sent = 0
            polisher_non_write_streak = 0
            polisher_force_threshold = self._polisher_force_write_threshold(input_data)
            polisher_loop_guard_reason = ""
            polisher_repair_prompts_sent = 0
            polisher_force_write_grace_available = False
            polisher_force_write_grace_used = False
            # v6.4.58 (maintainer 2026-04-23) — PATCHER loop guard. Observed
            # Apr 23 14:54-15:00: patcher spun 42+ tool iters in 6 min,
            # messages=80, all 0 content / no write. Tighter than
            # polisher since patcher tasks are small targeted edits.
            patcher_non_write_streak = 0
            patcher_has_written_file = False
            # v6.4.59 (maintainer 2026-04-23): threshold 8→5. Patcher should
            # diff + apply within 3 tool calls; 5 is the pain threshold.
            _PATCHER_LOOP_GUARD_THRESHOLD = 10  # v7.20a (maintainer 2026-04-28): 5→10. Read-heavy patchers (need to scan large root before fix) were tripping at 5 even when about to write. 10 keeps the runaway-loop guarantee while letting careful patchers locate the fix site.
            patcher_loop_guard_reason = ""
            qa_followup_count = 0
            analyst_followup_count = 0
            review_format_followup_count = 0
            plain_text_force_reason = ""
            length_truncation_tool_count = 0  # Track consecutive finish=length with tool calls
            length_truncation_break_reason = ""  # v5.8.6: set when tool-loop breaks on 2+ truncations; forwarded to error field so retry triggers direct_text mode
            # v6.1.12 (maintainer 2026-04-20): per-path file_ops edit-miss counter.
            # Protects merger/builder/polisher/debugger from edit-loop that
            # shrinks already-landed files.
            edit_failures_by_path: Dict[str, int] = {}
            edit_rewrite_prompts_sent: set = set()
            edit_loop_break_reason = ""

            while iteration < max_iterations:
                iteration += 1
                msg = response.choices[0].message
                msg_content = getattr(msg, "content", "") or ""
                if msg.tool_calls and msg_content:
                    output_text += msg.content
                    # v5.8.6: dedup — previously this fired twice with identical args
                    # (copy-paste), doubling progress events reaching frontend.
                    await self._publish_partial_output(on_progress, output_text, phase="drafting")

                # Check for tool calls
                if not msg.tool_calls:
                    finish_reason = str(getattr(response.choices[0], "finish_reason", "") or "").lower()
                    candidate_plain_text_output = output_text + (msg_content or "")
                    if self._plain_text_node_output_is_materializable(node_type, candidate_plain_text_output):
                        if msg_content:
                            output_text = candidate_plain_text_output
                            await self._publish_partial_output(on_progress, output_text, phase="drafting")
                        break
                    analyst_followup_reason = self._analyst_browser_followup_reason(
                        node_type,
                        tool_call_stats,
                        tool_results,
                        available_tool_names=available_tool_names,
                    )
                    if analyst_followup_reason and analyst_followup_count < 2 and tools:
                        analyst_followup_count += 1
                        if msg_content:
                            messages.append({"role": "assistant", "content": msg_content})
                        messages.append({
                            "role": "user",
                            "content": self._analyst_browser_followup_message(analyst_followup_reason),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "analyst_followup",
                                "message": analyst_followup_reason,
                                "continuation": analyst_followup_count,
                            })
                        response = await _await_stream_call(messages, tools)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        continue
                    followup_reason = self._review_browser_followup_reason(
                        node_type,
                        qa_task_type,
                        browser_action_events,
                        input_data,
                        tool_call_stats=tool_call_stats,
                        available_tool_names=available_tool_names,
                    )
                    if followup_reason and qa_followup_count < 2 and tools:
                        qa_followup_count += 1
                        if msg_content:
                            messages.append({"role": "assistant", "content": msg_content})
                        messages.append({
                            "role": "user",
                            "content": self._review_browser_followup_message(followup_reason, qa_task_type),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "qa_followup",
                                "message": followup_reason,
                                "continuation": qa_followup_count,
                            })
                        response = await _await_stream_call(messages, tools)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        continue
                    format_followup_reason = self._review_output_format_followup_reason(
                        node_type,
                        msg_content,
                    )
                    if format_followup_reason and review_format_followup_count < 2:
                        review_format_followup_count += 1
                        if msg_content:
                            messages.append({"role": "assistant", "content": msg_content})
                        messages.append({
                            "role": "user",
                            "content": self._review_output_format_followup_message(format_followup_reason),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "review_format_followup",
                                "message": format_followup_reason,
                                "continuation": review_format_followup_count,
                            })
                        response = await _await_stream_call(messages, tools)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        continue
                    if msg_content:
                        output_text += msg_content
                        await self._publish_partial_output(on_progress, output_text, phase="drafting")
                    if self._asset_plan_output_complete(node_type, output_text):
                        if finish_reason == "length":
                            logger.info(
                                "Asset plan JSON looks complete despite finish=length — stopping continuation chain for %s",
                                normalize_node_role(node_type) or node_type,
                            )
                        break
                    if finish_reason == "length" and continuation_count < max_continuations:
                        continuation_count += 1
                        messages.append(self._serialize_assistant_message(msg))
                        messages.append({
                            "role": "user",
                            "content": (
                                "Continue from exactly where you stopped. "
                                "Do not repeat previous content. "
                                "Keep the same format and finish the full result."
                            ),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "continuing",
                                "reason": "length_truncated",
                                "continuation": continuation_count,
                            })
                        response = await _await_stream_call(messages, tools)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        continue
                    break

                # ── Guard: detect finish=length with tool calls (truncated tool loop) ──
                tc_finish = str(getattr(response.choices[0], "finish_reason", "") or "").lower()
                if tc_finish == "length":
                    length_truncation_tool_count += 1
                    logger.warning(
                        "finish=length with tool_calls detected: node=%s model=%s iteration=%s truncation_count=%s",
                        normalized_node_type or node_type,
                        model_name,
                        iteration,
                        length_truncation_tool_count,
                    )
                    # v6.1.10 (maintainer 2026-04-19, research opencode#18108):
                    # tool_call arguments CANNOT be prefill-resumed on any
                    # provider (Kimi partial/OpenAI/Claude prefill all only
                    # apply to `content`, not `tool_calls`). So one truncation
                    # is already enough evidence that tool_call mode can't
                    # fit the payload for builder/merger that output big HTML
                    # — break immediately and let the orchestrator switch to
                    # direct_text on retry.
                    # v6.1.10-fix (maintainer 2026-04-19): only apply the aggressive
                    # 1-truncation break to BUILDER/MERGER nodes. Non-builder
                    # nodes (assetimport/imagegen/spritesheet/etc) don't have
                    # a direct_text fallback path and were getting killed on
                    # first truncation — keep their legacy 2-truncation gate.
                    _is_builder_family = normalized_node_type in {"builder", "merger"}
                    _default_threshold = "1" if _is_builder_family else "2"
                    _break_threshold = int(os.getenv(
                        "EVERMIND_BUILDER_TOOLCALL_LENGTH_BREAK_AT", _default_threshold
                    ) or _default_threshold)
                    if length_truncation_tool_count >= max(1, _break_threshold):
                        error_msg = (
                            f"Model hit token limit during tool calls {length_truncation_tool_count} times. "
                            f"Breaking truncated tool loop for node {normalized_node_type or node_type}. "
                            f"Next retry will switch to direct_text mode."
                        )
                        logger.error(error_msg)
                        # v5.8.6: stash so the failure-return path below can surface
                        # "token limit during tool calls" in the error field — the
                        # orchestrator retry gate (direct_text_retry_markers) uses
                        # that substring to force direct_text delivery on retry.
                        length_truncation_break_reason = error_msg
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "length_truncation_break",
                                "message": error_msg,
                                "truncation_count": length_truncation_tool_count,
                            })
                        # P0 FIX: Salvage any accumulated output before breaking.
                        # If we have partial HTML from truncated tool calls or stream text,
                        # write it to disk so it's not completely lost.
                        salvage_text = (output_text or "").strip()
                        if not salvage_text and latest_stream_text:
                            salvage_text = latest_stream_text.strip()
                        if salvage_text and len(salvage_text) > 200:
                            logger.info(
                                "Salvaging %s chars of partial output before truncation break for %s",
                                len(salvage_text),
                                normalized_node_type or node_type,
                            )
                            output_text = salvage_text
                        break
                else:
                    length_truncation_tool_count = 0  # Reset on non-truncated response

                # Process tool calls
                messages.append(self._serialize_assistant_message(msg))
                # v5.2: Loop-guard — signature = sorted set of (tool, args_hash).
                # Break out if the same exact batch repeats tool_loop_streak_limit times.
                _batch_sigs: List[str] = []
                for _tc in msg.tool_calls:
                    if isinstance(_tc, dict):
                        _name = (_tc.get("function") or {}).get("name", "")
                        _args = (_tc.get("function") or {}).get("arguments", "{}")
                    else:
                        _fn = getattr(_tc, "function", None)
                        _name = getattr(_fn, "name", "") if _fn else ""
                        _args = getattr(_fn, "arguments", "{}") if _fn else "{}"
                    _args_str = _args if isinstance(_args, str) else json.dumps(_args, sort_keys=True)
                    _batch_sigs.append(f"{_name}:{hashlib.sha256(_args_str.encode('utf-8', errors='replace')).hexdigest()[:12]}")
                _batch_sig = "|".join(sorted(_batch_sigs))
                if _batch_sig:
                    tool_signature_history.append(_batch_sig)
                    _recent = tool_signature_history[-tool_loop_streak_limit:]
                    if len(_recent) >= tool_loop_streak_limit and len(set(_recent)) == 1:
                        logger.warning(
                            "Tool-call loop detected: node=%s streak=%d signature=%s — forcing recovery",
                            node_type, tool_loop_streak_limit, _batch_sig[:80],
                        )
                        # v5.2: Recovery pattern from LangGraph/CrewAI — inject synthetic
                        # tool_result placeholders (so the assistant message with tool_calls
                        # is valid OpenAI-format) plus a forcing user message, then rerun
                        # ONCE with tools=[] to produce a final plain-text answer.
                        _recovery_tool_msg = (
                            "Tool call loop detected; tool access revoked for this turn. "
                            "Output your final answer now without calling any more tools."
                        )
                        # v6.4.20 (maintainer 2026-04-22) — patcher/merger recovery.
                        # For patcher/merger the "revoke tools, emit prose" pattern
                        # produces 8192-char prose runs that get PROSE-ABORTed and
                        # then timeout at 138s (observed 19:47-19:49 run). The real
                        # failure was kimi calling `file_ops read` on the same path
                        # 3x — meaning it was asking for the file content. So
                        # instead of revoking tools, we RESPOND to that read with
                        # the actual file bytes, keep tools enabled, and nudge the
                        # model toward a single edit/write call.
                        _patcher_recovery_active = (
                            normalized_node_type in ("patcher", "merger")
                        )
                        _patcher_tool_payload_map: Dict[str, str] = {}
                        if _patcher_recovery_active:
                            for _tc in msg.tool_calls:
                                if isinstance(_tc, dict):
                                    _fn_name = (_tc.get("function") or {}).get("name", "")
                                    _fn_args = (_tc.get("function") or {}).get("arguments", "{}")
                                    _tc_id = _tc.get("id", "")
                                else:
                                    _fn = getattr(_tc, "function", None)
                                    _fn_name = getattr(_fn, "name", "") if _fn else ""
                                    _fn_args = getattr(_fn, "arguments", "{}") if _fn else "{}"
                                    _tc_id = getattr(_tc, "id", "")
                                if _fn_name != "file_ops":
                                    continue
                                try:
                                    _args_obj = json.loads(_fn_args) if isinstance(_fn_args, str) else dict(_fn_args or {})
                                except Exception:
                                    _args_obj = {}
                                _action = str(_args_obj.get("action") or "").strip().lower()
                                _path = str(_args_obj.get("path") or "").strip()
                                if _action != "read" or not _path:
                                    continue
                                try:
                                    _norm_path = os.path.abspath(_path)
                                    if not _norm_path.startswith("/tmp/evermind_output"):
                                        continue
                                    _p = Path(_norm_path)
                                    if _p.exists() and _p.is_file() and _p.stat().st_size <= 200_000:
                                        _content = _p.read_text(encoding="utf-8", errors="replace")
                                        _patcher_tool_payload_map[_tc_id] = json.dumps({
                                            "success": True,
                                            "path": _norm_path,
                                            "content": _content,
                                            "_recovery_note": (
                                                "Loop-guard replayed this read. Do NOT call file_ops read "
                                                "again on this path — the content above is final. Emit "
                                                "file_ops edit or file_ops write NEXT."
                                            ),
                                        })
                                except Exception:
                                    continue
                        for _tc in msg.tool_calls:
                            _tc_id = _tc.get("id") if isinstance(_tc, dict) else getattr(_tc, "id", "")
                            if _tc_id:
                                _payload = _patcher_tool_payload_map.get(_tc_id) if _patcher_recovery_active else None
                                messages.append({
                                    "role": "tool",
                                    "tool_call_id": _tc_id,
                                    "content": _payload or _recovery_tool_msg,
                                })
                        if _patcher_recovery_active and _patcher_tool_payload_map:
                            _patcher_force_prompt = (
                                "Loop-guard intervened. The file content you kept re-reading is now in the "
                                "tool_result above — treat that as final. Your NEXT tool call MUST be "
                                "`file_ops` with `action=\"edit\"` (preferred) or `action=\"write\"` — "
                                "do NOT call `action=\"read\"` again on any path. One edit per blocking "
                                "issue, surgical changes only."
                            )
                            messages.append({"role": "user", "content": _patcher_force_prompt})
                            try:
                                _patcher_recovery_tools = tools or []
                                response = await _await_stream_call(messages, _patcher_recovery_tools)
                                usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                                msg = response.choices[0].message
                                logger.info(
                                    "Patcher/merger loop-guard recovery re-ran WITH tools (node=%s) — "
                                    "awaiting edit/write call.",
                                    normalized_node_type or node_type,
                                )
                                # Continue the outer tool-loop — do NOT break.
                                tool_signature_history.clear()
                                continue
                            except Exception as exc:
                                logger.warning(
                                    "Patcher/merger loop-guard tool-continuation failed: %s — falling back to prose recovery.",
                                    str(exc)[:200],
                                )
                        if normalized_node_type in ("reviewer", "tester", "qa"):
                            _force_prompt = (
                                "Your tool usage has been capped due to a repeat-call loop. "
                                "Output your final REVIEWER VERDICT right now in strict JSON "
                                "on a single line, no tools, no prose:\n"
                                '{"verdict":"APPROVED" or "REJECTED","scores":'
                                '{"layout":n,"color":n,"typography":n,"animation":n,"responsive":n,'
                                '"functionality":n,"completeness":n,"originality":n,"ship_readiness":n},'
                                '"blocking_issues":[...],"strengths":[...],"missing_deliverables":[...]}'
                            )
                        elif normalized_node_type == "planner":
                            _force_prompt = (
                                "Your tool usage has been capped. Call file_ops write ONE MORE TIME "
                                "to save the final plan to /tmp/evermind_output/plan.json, or output the "
                                "plan JSON inline if writes are failing. No more list/read/grep calls."
                            )
                        elif normalized_node_type == "builder":
                            _force_prompt = (
                                "Your tool usage has been capped. Output the final HTML directly as "
                                "plain text now, or write it with ONE file_ops write call. No more "
                                "read/list/grep — deliver the artifact."
                            )
                        else:
                            _force_prompt = (
                                "Your tool usage has been capped due to a repeat-call loop. "
                                "Commit to your final natural-language answer right now without any more tools."
                            )
                        messages.append({"role": "user", "content": _force_prompt})
                        try:
                            response = await _await_stream_call(messages, [])
                            usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                            _final_msg = response.choices[0].message
                            _final_text = getattr(_final_msg, "content", "") or ""
                            if _final_text.strip():
                                output_text = _final_text
                                await self._publish_partial_output(on_progress, output_text, phase="drafting")
                                logger.info(
                                    "Loop-guard recovery produced %d chars for node=%s",
                                    len(_final_text), normalized_node_type or node_type,
                                )
                        except Exception as exc:
                            logger.warning("Loop-guard recovery call failed: %s", str(exc)[:200])
                        if not output_text.strip():
                            output_text = (
                                "[Loop guard: identical tool call batch repeated and recovery call "
                                "failed to produce output — exited loop.]"
                            )
                        break
                processed_calls = 0
                pending_repair_prompts: List[str] = []
                for tc in msg.tool_calls:
                    if isinstance(tc, dict):
                        tc_id = tc.get("id", "")
                        tc_type = tc.get("type", "function")
                        fn_payload = tc.get("function") or {}
                        fn_name = fn_payload.get("name", "")
                        fn_args = fn_payload.get("arguments", "{}")
                    else:
                        tc_id = getattr(tc, "id", "")
                        tc_type = getattr(tc, "type", "function")
                        fn_payload = getattr(tc, "function", None)
                        fn_name = getattr(fn_payload, "name", "") if fn_payload else ""
                        fn_args = getattr(fn_payload, "arguments", "{}") if fn_payload else "{}"
                    parsed_args = self._safe_json_object(fn_args)

                    if tc_type != "function" or not fn_name:
                        logger.warning("Skipping unsupported tool call payload: type=%s id=%s", tc_type, tc_id)
                        continue

                    _tool_call_start_ts = time.time()

                    if on_progress:
                        await self._emit_noncritical_progress(
                            on_progress,
                            self._tool_execution_progress_payload(fn_name, parsed_args),
                        )
                    if fn_name in {"browser", "browser_use"} and self._desktop_qa_browser_suppressed(node_type, input_data):
                        result = {
                            "success": False,
                            "data": {},
                            "error": (
                                "Desktop QA evidence already exists for this reviewer/tester pass. "
                                "Use the provided Evermind internal QA record instead of opening browser/browser_use."
                            ),
                            "artifacts": [],
                        }
                    elif fn_name == "browser" and self._should_block_browser_call(node_type, tool_call_stats, node=node):
                        limit = (
                            self._polisher_browser_call_limit(node=node)
                            if normalized_node_type == "polisher"
                            else self._analyst_browser_call_limit(node=node)
                        )
                        node_label = "Polisher" if normalized_node_type == "polisher" else "Analyst"
                        guidance = (
                            "Stop browsing and write concrete file improvements now."
                            if normalized_node_type == "polisher"
                            else "Skip additional browsing and summarize from collected insights."
                        )
                        result = {
                            "success": False,
                            "data": {},
                            "error": (
                                f"{node_label} browser call limit reached ({limit}). "
                                f"{guidance}"
                            ),
                            "artifacts": [],
                        }
                    elif fn_name == "source_fetch" and self._should_block_source_fetch_call(node_type, tool_call_stats, node=node):
                        # v6.3 (maintainer 2026-04-20): enforce per-tool cap on source_fetch
                        # for analyst so tutorial search can't diverge indefinitely.
                        _sf_limit = self._analyst_source_fetch_call_limit(node=node)
                        logger.info(
                            "Analyst source_fetch cap reached (%d) — forcing synthesis",
                            _sf_limit,
                        )
                        result = {
                            "success": False,
                            "data": {},
                            "error": (
                                f"Analyst source_fetch cap reached ({_sf_limit} fetches). "
                                "You have enough material — synthesize the final report from "
                                "what you already fetched. Do NOT call source_fetch again; "
                                "produce the report with all required XML tags now."
                            ),
                            "artifacts": [],
                        }
                    elif fn_name == "file_ops" and normalized_node_type in ("analyst", "scribe", "uidesign"):
                        # Guard: analyst/scribe/uidesign must NOT write code files.
                        # If the model tries file_ops write, return an error forcing it
                        # to produce a text report instead. This prevents the 100s+
                        # token-truncated HTML generation observed in production.
                        parsed_args = self._safe_json_object(fn_args)
                        action = str(parsed_args.get("action", "")).strip().lower()
                        if action in ("write", "edit"):
                            result = {
                                "success": False,
                                "data": {},
                                "error": self._plain_text_node_write_guard_error(normalized_node_type),
                                "artifacts": [],
                            }
                            plain_text_force_reason = plain_text_force_reason or "blocked_file_write"
                            logger.warning(
                                "Blocked file_ops write/edit for %s node — must produce text report only",
                                normalized_node_type,
                            )
                        else:
                            result = await self._run_plugin(
                                fn_name,
                                fn_args,
                                plugins or [],
                                node_type=node_type,
                                node=node,
                            )
                    elif fn_name == "file_ops" and normalized_node_type == "patcher":
                        # v7.32 (maintainer 2026-04-29): hard-block patcher's
                        # `action="read"`. The patcher.yaml v6.6 already
                        # FORBIDS reads — the file_snapshot is embedded in
                        # the system prompt — but kimi LLMs ignored that
                        # rule and burned 6 turns of read calls in
                        # run_c9462fad38c7 instead of emitting edits.
                        # Without this guard, the run failed because v7.11
                        # blocked SOFT-PASS on reviewer-flagged runtime
                        # errors and patcher.retries=1 was already used.
                        # Returning a hard error on the first read forces
                        # the LLM to switch to edit/write within 1 turn
                        # instead of 6.
                        parsed_args = self._safe_json_object(fn_args)
                        action = str(parsed_args.get("action", "")).strip().lower()
                        if action in ("read", "list", "search"):
                            _read_path = str(parsed_args.get("path", "")).strip()
                            result = {
                                "success": False,
                                "data": {},
                                "error": (
                                    f"BLOCKED (v7.32): patcher cannot use `file_ops {action}`. "
                                    f"The current on-disk content for every file you might patch "
                                    f"is already embedded in the <file_snapshot> blocks of your "
                                    f"prompt. Find the `old_string` there directly and emit "
                                    f"`file_ops edit` (preferred) or `file_ops write` "
                                    f"(only for tiny new files) NEXT — do NOT call read/list/search "
                                    f"again. Path you tried: {_read_path[-80:]}"
                                ),
                                "artifacts": [],
                            }
                            logger.warning(
                                "[v7.32] Blocked patcher file_ops %s on %s — forcing edit/write next turn",
                                action, _read_path[-60:],
                            )
                        else:
                            if fn_name == "file_ops":
                                self._builder_capture_prewrite_snapshot(
                                    node=node,
                                    input_data=input_data,
                                    tool_action=action,
                                    parsed_args=parsed_args,
                                    snapshot_cache=builder_support_snapshots,
                                )
                            result = await self._run_plugin(
                                fn_name,
                                fn_args,
                                plugins or [],
                                node_type=node_type,
                                node=node,
                            )
                    else:
                        if fn_name == "file_ops":
                            self._builder_capture_prewrite_snapshot(
                                node=node,
                                input_data=input_data,
                                tool_action=str(parsed_args.get("action", "")).strip().lower(),
                                parsed_args=parsed_args,
                                snapshot_cache=builder_support_snapshots,
                            )
                        result = await self._run_plugin(
                            fn_name,
                            fn_args,
                            plugins or [],
                            node_type=node_type,
                            node=node,
                        )
                    tool_action = (
                        self._infer_file_ops_action(fn_args, result)
                        if fn_name == "file_ops"
                        else str(parsed_args.get("action", "")).strip().lower()
                    )
                    if fn_name == "file_ops":
                        result = self._builder_guard_support_lane_write_result(
                            node=node,
                            tool_action=tool_action,
                            result=result,
                            snapshot_cache=builder_support_snapshots,
                        )
                        result = self._builder_guard_html_write_result(
                            node=node,
                            input_data=input_data,
                            tool_action=tool_action,
                            result=result,
                            snapshot_cache=builder_support_snapshots,
                        )
                    # V4.2: Enrich tool result for report trace table
                    if isinstance(result, dict):
                        result.setdefault("tool", fn_name)
                        result.setdefault("started_at", _tool_call_start_ts)
                        result.setdefault("duration_ms", int((time.time() - _tool_call_start_ts) * 1000) if _tool_call_start_ts else 0)
                        # V4.2 FIX (Codex #3): inject args for ALL tools, not just file_ops
                        result.setdefault("args", parsed_args)
                    tool_results.append(result)
                    tool_call_stats[fn_name] = tool_call_stats.get(fn_name, 0) + 1
                    if fn_name == "browser":
                        browser_data = result.get("data", {}) if isinstance(result, dict) else {}
                        if not isinstance(browser_data, dict):
                            browser_data = {}
                        browser_event = {
                            "action": tool_action or parsed_args.get("action") or "unknown",
                            "subaction": browser_data.get("subaction"),
                            "intent": browser_data.get("intent"),
                            "ok": bool(result.get("success", False)) if isinstance(result, dict) else False,
                            "url": browser_data.get("url"),
                            "target": browser_data.get("target"),
                            "observation": browser_data.get("observation"),
                            "snapshot_refs_preview": browser_data.get("snapshot_refs_preview", []),
                            "snapshot_ref_count": browser_data.get("snapshot_ref_count", 0),
                            "state_hash": browser_data.get("state_hash"),
                            "previous_state_hash": browser_data.get("previous_state_hash"),
                            "state_changed": bool(browser_data.get("state_changed", False)),
                            "scroll_y": browser_data.get("scroll_y", 0),
                            "viewport_height": browser_data.get("viewport_height", 0),
                            "page_height": browser_data.get("page_height", 0),
                            "at_page_top": bool(browser_data.get("at_page_top", False)),
                            "at_page_bottom": bool(browser_data.get("at_page_bottom", False)),
                            "keys_count": browser_data.get("keys_count", 0),
                            "console_error_count": browser_data.get("console_error_count", 0),
                            "page_error_count": browser_data.get("page_error_count", 0),
                            "failed_request_count": browser_data.get("failed_request_count", 0),
                            "recent_console_errors": browser_data.get("recent_console_errors", []),
                            "recent_page_errors": browser_data.get("recent_page_errors", []),
                            "browser_mode": browser_data.get("browser_mode"),
                            "requested_mode": browser_data.get("requested_mode"),
                            "launch_note": browser_data.get("launch_note"),
                            "error": (result.get("error") if isinstance(result, dict) else "") or "",
                        }
                        browser_action_events.append(browser_event)
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "browser_action",
                                "plugin": "browser",
                                **browser_event,
                            })
                    elif fn_name == "browser_use":
                        browser_use_events = self._browser_use_action_events(result)
                        for browser_event in browser_use_events:
                            browser_action_events.append(browser_event)
                            if on_progress:
                                await self._emit_noncritical_progress(on_progress, {
                                    "stage": "browser_action",
                                    "plugin": "browser_use",
                                    **browser_event,
                                })
                    repair_prompt = None
                    wrote_file = False
                    if fn_name == "file_ops":
                        wrote_file = self._tool_result_has_write(result)
                    normalized_node_type = normalize_node_role(node_type)
                    # v6.1.13: merger shares builder's write-streak tracking.
                    # Observed real run where merger wasted 4.5min in a read
                    # loop before `tool_iterations_exhausted` fired and
                    # switched to direct_text. The streak counter + tighter
                    # break threshold (see below) force the switch earlier.
                    if normalized_node_type in {"builder", "merger"}:
                        if wrote_file:
                            # v6.7 full-rewrite detection (see init comment).
                            try:
                                _wr_path = ""
                                if isinstance(result, dict):
                                    _data_v67 = result.get("data")
                                    if isinstance(_data_v67, dict):
                                        _wr_path = str(_data_v67.get("path") or "").strip()
                                if (
                                    builder_has_written_file
                                    and _wr_path
                                    and _wr_path.lower().endswith((".html", ".htm"))
                                ):
                                    try:
                                        from pathlib import Path as _FPv67
                                        _sz_v67 = _FPv67(_wr_path).stat().st_size
                                    except Exception:
                                        _sz_v67 = 0
                                    if _sz_v67 >= 10000:
                                        if (not builder_last_write_path) or _wr_path == builder_last_write_path:
                                            builder_full_rewrite_streak += 1
                                        else:
                                            builder_full_rewrite_streak = 1
                                    else:
                                        builder_full_rewrite_streak = 0
                                if _wr_path:
                                    builder_last_write_path = _wr_path
                            except Exception:
                                pass
                            builder_has_written_file = True
                            builder_non_write_streak = 0
                            if on_progress:
                                write_path = ""
                                if isinstance(result, dict):
                                    data = result.get("data")
                                    if isinstance(data, dict):
                                        write_path = str(data.get("path") or "").strip()
                                metrics = self._written_file_code_metrics(write_path)
                                await self._emit_noncritical_progress(on_progress, {
                                    "stage": "builder_write",
                                    "plugin": fn_name,
                                    "path": write_path,
                                    **metrics,
                                })
                        else:
                            # Count all non-write tool turns so malformed file_ops args
                            # cannot bypass the loop guard.
                            builder_non_write_streak += 1
                    else:
                        if normalized_node_type == "polisher":
                            if wrote_file:
                                # Only count as a real deliverable write if it targets
                                # a .html/.css/.js file inside the output directory.
                                write_path_str = ""
                                if isinstance(result, dict):
                                    data = result.get("data")
                                    if isinstance(data, dict):
                                        write_path_str = str(data.get("path") or "").strip()
                                is_deliverable = False
                                if write_path_str:
                                    try:
                                        from pathlib import Path as _P
                                        wp = _P(write_path_str).resolve()
                                        od = _P(self._current_output_dir()).resolve()
                                        if str(wp).startswith(str(od)):
                                            deliverable_exts = {".html", ".htm", ".css", ".js", ".mjs"}
                                            if wp.suffix.lower() in deliverable_exts:
                                                is_deliverable = True
                                    except Exception:
                                        pass
                                if is_deliverable:
                                    polisher_has_written_file = True
                                    polisher_non_write_streak = 0
                                else:
                                    # Non-deliverable write (e.g. list, read, tmp file) —
                                    # do not disable the prewrite timeout.
                                    polisher_non_write_streak += 1
                            else:
                                polisher_non_write_streak += 1
                        # v6.4.58: patcher streak tracking (parallel to polisher).
                        if normalized_node_type == "patcher":
                            if wrote_file:
                                _write_path_str_p = ""
                                if isinstance(result, dict):
                                    _data_p = result.get("data")
                                    if isinstance(_data_p, dict):
                                        _write_path_str_p = str(_data_p.get("path") or "").strip()
                                _is_del = False
                                if _write_path_str_p:
                                    try:
                                        from pathlib import Path as _P
                                        _wp = _P(_write_path_str_p).resolve()
                                        _od = _P(self._current_output_dir()).resolve()
                                        if str(_wp).startswith(str(_od)):
                                            if _wp.suffix.lower() in {".html", ".htm", ".css", ".js", ".mjs"}:
                                                _is_del = True
                                    except Exception:
                                        pass
                                if _is_del:
                                    patcher_has_written_file = True
                                    patcher_non_write_streak = 0
                                else:
                                    patcher_non_write_streak += 1
                            else:
                                patcher_non_write_streak += 1
                        if wrote_file and on_progress:
                            write_path = ""
                            if isinstance(result, dict):
                                data = result.get("data")
                                if isinstance(data, dict):
                                    write_path = str(data.get("path") or "").strip()
                            metrics = self._written_file_code_metrics(write_path)
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "artifact_write",
                                "plugin": fn_name,
                                "path": write_path,
                                "agent": normalized_node_type or node_type,
                                "writer": normalized_node_type or node_type,
                                **metrics,
                            })
                    if fn_name == "file_ops" and normalized_node_type == "builder" and builder_repair_prompts_sent < 2:
                        repair_prompt = self._builder_tool_repair_prompt(input_data, tool_action, result)
                        if not repair_prompt and not wrote_file:
                            repair_prompt = self._builder_non_write_followup_prompt(
                                input_data,
                                tool_action,
                                result,
                                builder_non_write_streak,
                            )
                    elif normalized_node_type == "polisher" and polisher_repair_prompts_sent < 2 and not wrote_file:
                        repair_prompt = self._polisher_non_write_followup_prompt(
                            fn_name,
                            tool_action,
                            result,
                            polisher_non_write_streak,
                        )
                    # v6.1.12: edit-miss escalation. Applies to merger/builder/
                    # polisher/debugger. Fires once per path at 2 failures.
                    if (
                        fn_name == "file_ops"
                        and normalized_node_type in {"merger", "builder", "polisher", "debugger"}
                    ):
                        _total_ef, _per_path_ef, _ef_path = self._register_edit_failure(
                            edit_failures_by_path, tool_action, parsed_args, result
                        )
                        if (
                            _per_path_ef >= 2
                            and _ef_path
                            and _ef_path not in edit_rewrite_prompts_sent
                        ):
                            edit_rewrite_prompts_sent.add(_ef_path)
                            escalation = self._edit_rewrite_escalation_prompt(
                                _ef_path, _per_path_ef, _total_ef
                            )
                            if escalation and escalation not in pending_repair_prompts:
                                pending_repair_prompts.append(escalation)
                                logger.warning(
                                    "file_ops edit miss streak on %s (per-path=%s, total=%s) — nudging %s to full rewrite",
                                    _ef_path, _per_path_ef, _total_ef, normalized_node_type,
                                )
                                if on_progress:
                                    await self._emit_noncritical_progress(on_progress, {
                                        "stage": "edit_rewrite_escalation",
                                        "path": _ef_path,
                                        "per_path_failures": _per_path_ef,
                                        "total_failures": _total_ef,
                                        "node": normalized_node_type,
                                    })
                        if _total_ef >= 3:
                            edit_loop_break_reason = (
                                f"file_ops edit-miss loop: {_total_ef} failed edits "
                                f"across {len(edit_failures_by_path)} path(s)"
                            )
                    # Truncate tool output to prevent token overflow (Kimi 262K limit)
                    result_str = json.dumps(result)
                    _tool_char_limit = MAX_ANALYST_TOOL_RESULT_CHARS if normalized_node_type == "analyst" else MAX_TOOL_RESULT_CHARS
                    if len(result_str) > _tool_char_limit:
                        result_str = result_str[:_tool_char_limit] + '... [TRUNCATED]'
                    # v7.3.9 audit-fix CRITICAL — file_ops/shell tool results
                    # contain raw user paths, IPs, and arbitrary file content
                    # which the v7.3.4 system_prompt mask did NOT cover. Mask
                    # tool_results before re-injecting into the relay LLM.
                    try:
                        _ob_masker = get_masker()
                        if _ob_masker and getattr(_ob_masker, "enabled", True) and not (node_type in getattr(_ob_masker, "exclude_node_types", set())):
                            _masked_rs, _rs_restore = _ob_masker.mask(result_str, node_type=node_type)
                            if _rs_restore:
                                result_str = _masked_rs
                                _existing = node.setdefault("_outbound_restore_map", {})
                                _existing.update(_rs_restore)
                    except Exception:
                        pass
                    messages.append({"role": "tool", "tool_call_id": tc_id, "content": result_str})
                    if repair_prompt and repair_prompt not in pending_repair_prompts:
                        pending_repair_prompts.append(repair_prompt)
                        if normalized_node_type == "builder":
                            builder_repair_prompts_sent += 1
                        elif normalized_node_type == "polisher":
                            polisher_repair_prompts_sent += 1
                            if fn_name == "file_ops" and not polisher_force_write_grace_used:
                                polisher_force_write_grace_available = True
                    processed_calls += 1

                if msg.tool_calls and processed_calls == 0:
                    raise ValueError("No supported function tool calls were produced by model response")

                if pending_repair_prompts:
                    messages.append({"role": "user", "content": "\n\n".join(pending_repair_prompts)})

                if (
                    normalized_node_type in {"analyst", "scribe", "uidesign"}
                    and plain_text_force_reason == "blocked_file_write"
                ):
                    logger.info(
                        "Plain-text node blocked from file_ops write — ending tool loop and switching to final no-tool synthesis (%s)",
                        normalized_node_type,
                    )
                    break

                # v6.1.13: merger gets a tighter streak threshold (4) because
                # it has two full builder outputs in hand — it should NOT
                # need to read more than 2-3 times before writing. Builder
                # keeps its existing heuristic threshold.
                _normalized_nr = normalize_node_role(node_type)
                _streak_threshold = (
                    min(builder_force_threshold, 4)
                    if _normalized_nr == "merger"
                    else builder_force_threshold
                )
                if (
                    _normalized_nr in {"builder", "merger"}
                    and builder_non_write_streak >= _streak_threshold
                    and not any(self._tool_result_has_write(tr) for tr in tool_results)
                ):
                    builder_force_text_early = True
                    builder_force_reason = (
                        "merger_tool_research_loop"
                        if _normalized_nr == "merger"
                        else "tool_research_loop"
                    )
                    logger.info(
                        "%s loop guard triggered: non-write tool streak=%s (threshold=%s)",
                        _normalized_nr.capitalize(),
                        builder_non_write_streak,
                        _streak_threshold,
                    )
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "builder_loop_guard",
                            "node": _normalized_nr,
                            "streak": builder_non_write_streak,
                            "threshold": _streak_threshold,
                            "reason": builder_force_reason,
                        })
                    break

                # v6.1.14 (maintainer 2026-04-20): POST-WRITE read-loop guard.
                # Observed: builder writes once (written=True), then spends
                # 15+ min cycling short tool_calls that never produce another
                # write. Existing guard above only fires PRE-first-write
                # (tool_results has no write yet), so it can't catch this.
                # After any write, cap further non-writes at POST_WRITE_MAX.
                if (
                    _normalized_nr in {"builder", "merger"}
                    and builder_has_written_file
                    and builder_non_write_streak >= 4
                ):
                    builder_force_text_early = True
                    builder_force_reason = "post_write_read_loop"
                    logger.info(
                        "%s post-write read loop guard triggered: non-write streak=%s after first write — stopping to avoid kimi/glm tool-loop waste",
                        _normalized_nr.capitalize(),
                        builder_non_write_streak,
                    )
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "builder_post_write_loop_guard",
                            "node": _normalized_nr,
                            "streak": builder_non_write_streak,
                            "reason": builder_force_reason,
                        })
                    break

                # v6.7 (maintainer 2026-04-23): POST-WRITE FULL-REWRITE guard.
                # Companion to post_write_read_loop above. Covers the case
                # where kimi keeps re-emitting full <!DOCTYPE>…</html> after
                # the first legitimate write — each rewrite resets
                # non_write_streak, so the read-loop guard never fires.
                # Break on the 2nd full-HTML rewrite (≥10KB + same target),
                # which is already a violation of builder.yaml stop_contract.
                # Env override: EVERMIND_BUILDER_FULL_REWRITE_MAX (default 1).
                if (
                    _normalized_nr in {"builder", "merger"}
                    and builder_full_rewrite_streak >= self._read_int_env(
                        "EVERMIND_BUILDER_FULL_REWRITE_MAX", 1, 1, 5
                    )
                ):
                    builder_force_text_early = True
                    builder_force_reason = "post_write_full_rewrite_loop"
                    logger.info(
                        "%s full-rewrite loop guard triggered: full-rewrite streak=%s path=%s — stopping to avoid repeated HTML overwrites",
                        _normalized_nr.capitalize(),
                        builder_full_rewrite_streak,
                        builder_last_write_path,
                    )
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "builder_full_rewrite_loop_guard",
                            "node": _normalized_nr,
                            "streak": builder_full_rewrite_streak,
                            "path": builder_last_write_path,
                            "reason": builder_force_reason,
                        })
                    break

                # v6.1.12: bail out if edit-miss loop dominates the turn.
                if (
                    edit_loop_break_reason
                    and normalized_node_type in {"merger", "builder", "polisher", "debugger"}
                ):
                    logger.warning(
                        "%s terminated tool loop early: %s",
                        normalized_node_type,
                        edit_loop_break_reason,
                    )
                    if normalized_node_type == "builder":
                        builder_force_text_early = True
                        builder_force_reason = "edit_miss_loop"
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "edit_loop_break",
                            "node": normalized_node_type,
                            "reason": edit_loop_break_reason,
                            "paths": list(edit_failures_by_path.keys()),
                        })
                    break

                if (
                    normalized_node_type == "polisher"
                    and not polisher_has_written_file
                    and polisher_non_write_streak >= polisher_force_threshold
                ):
                    if polisher_force_write_grace_available and not polisher_force_write_grace_used:
                        polisher_force_write_grace_available = False
                        polisher_force_write_grace_used = True
                        logger.info(
                            "Polisher force-write grace granted: non-write tool streak=%s (threshold=%s)",
                            polisher_non_write_streak,
                            polisher_force_threshold,
                        )
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "polisher_force_write_warning",
                                "streak": polisher_non_write_streak,
                                "threshold": polisher_force_threshold,
                                "message": "Polisher inspection limit reached; one final response is allowed to obey the forced-write prompt.",
                            })
                        response = await _await_stream_call(messages, tools)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        continue
                    polisher_loop_guard_reason = (
                        "polisher loop guard triggered after "
                        f"{polisher_non_write_streak} non-write tool iterations without any file write."
                    )
                    logger.warning(polisher_loop_guard_reason)
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "polisher_loop_guard",
                            "streak": polisher_non_write_streak,
                            "threshold": polisher_force_threshold,
                            "reason": polisher_loop_guard_reason,
                        })
                    break

                # v6.4.58 (maintainer 2026-04-23) — PATCHER loop guard.
                # Parallel to polisher: if patcher runs ≥ 8 consecutive
                # non-write tool iterations (no deliverable .html/.js/.css
                # written) AND has never written a file this turn,
                # break out of the tool loop so orchestrator can salvage
                # or mark failure instead of burning the 30-min subtask
                # budget on a read-only loop.
                if (
                    normalized_node_type == "patcher"
                    and not patcher_has_written_file
                    and patcher_non_write_streak >= _PATCHER_LOOP_GUARD_THRESHOLD
                ):
                    patcher_loop_guard_reason = (
                        "patcher loop guard triggered after "
                        f"{patcher_non_write_streak} non-write tool iterations without any file write."
                    )
                    logger.warning(patcher_loop_guard_reason)
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "patcher_loop_guard",
                            "streak": patcher_non_write_streak,
                            "threshold": _PATCHER_LOOP_GUARD_THRESHOLD,
                            "reason": patcher_loop_guard_reason,
                        })
                    break

                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        {"stage": "continuing", "iteration": iteration},
                    )
                response = await _await_stream_call(messages, tools)
                usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))

            if polisher_loop_guard_reason:
                # v6.1.14f (maintainer 2026-04-20): treat polisher guard as SUCCESS
                # when builder's output was already high-quality. The polisher
                # harness explicitly allows "polish skipped" as a valid outcome.
                # Downstream (reviewer/tester/deployer) works on the builder's
                # artifact unchanged — no harm, no retry.
                # v6.1.14h (maintainer 2026-04-20): EXCEPTION — when polisher is
                # doing a reviewer-rejection-patch retry, skipping is NOT OK.
                # The reviewer flagged concrete issues; polisher MUST edit.
                # Detect by checking input_data for the patch-mandate marker.
                _is_reviewer_patch_retry = (
                    normalized_node_type == "polisher"
                    and "REVIEWER REJECTED — APPLY SURGICAL PATCHES" in str(input_data or "")
                )
                _polisher_skip_ok = (
                    normalized_node_type == "polisher"
                    and not _is_reviewer_patch_retry
                    and any(self._tool_result_has_write(tr) for tr in tool_results) is False
                )
                return self._attach_browser_action_events({
                    "success": _polisher_skip_ok,
                    "output": output_text or "Polish skipped: existing artifact already meets quality bar (no edits needed).",
                    "error": "" if _polisher_skip_ok else polisher_loop_guard_reason,
                    "warning": polisher_loop_guard_reason if _polisher_skip_ok else "",
                    "model": model_name,
                    "tool_results": tool_results,
                    "mode": "openai_compatible",
                    "usage": usage_totals,
                    "tool_call_stats": dict(tool_call_stats),
                    "qa_browser_use_available": qa_browser_use_available,
                }, browser_action_events)

            # ── Forced final text-only call for builder / plain-text handoff nodes ──
            force_text_reason = ""
            if self._builder_needs_forced_text(node_type, output_text, tool_results):
                if builder_force_text_early:
                    force_text_reason = builder_force_reason or "tool_research_loop"
                elif iteration >= max_iterations:
                    force_text_reason = "tool_iterations_exhausted"
                else:
                    force_text_reason = "no_html_or_file_output"

            if force_text_reason:
                logger.info("Builder missing HTML/file output — forcing final text-only call (%s)", force_text_reason)
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, force_text_reason),
                    )
                forced_messages = self._builder_forced_text_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    force_text_reason,
                )
                try:
                    final_resp = await _await_stream_call(forced_messages, [])  # No tools
                    final_msg = final_resp.choices[0].message
                    if final_msg.content:
                        output_text += final_msg.content
                        await self._publish_partial_output(on_progress, output_text, phase="finalizing")
                    usage_totals = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                    logger.info(f"Forced text output: {len(final_msg.content or '')} chars")
                except Exception as e:
                    logger.warning(f"Forced text-only call failed: {_sanitize_error(str(e))}")

            plain_text_final_reason = ""
            if self._plain_text_node_needs_forced_output(node_type, output_text, tool_results):
                if plain_text_force_reason:
                    plain_text_final_reason = plain_text_force_reason
                elif iteration >= max_iterations:
                    plain_text_final_reason = "tool_iterations_exhausted"
                else:
                    plain_text_final_reason = "missing_final_handoff"

            if plain_text_final_reason:
                logger.info(
                    "Plain-text handoff node missing final output — forcing no-tool synthesis (%s)",
                    plain_text_final_reason,
                )
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, plain_text_final_reason),
                    )
                forced_messages = self._plain_text_node_forced_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    node_type,
                    plain_text_final_reason,
                )
                forced_timeout = self._plain_text_final_timeout_for_node(
                    node_type,
                    plain_text_final_reason,
                )
                try:
                    final_resp = await _await_stream_call(
                        forced_messages,
                        [],
                        timeout_override=forced_timeout or None,
                    )
                    final_msg = final_resp.choices[0].message
                    final_content = str(final_msg.content or "").strip()
                    if final_content:
                        if output_text and not output_text.endswith("\n"):
                            output_text += "\n"
                        output_text += final_content
                        await self._publish_partial_output(on_progress, output_text, phase="finalizing")
                    usage_totals = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                except Exception as e:
                    logger.warning("Forced plain-text handoff failed: %s", _sanitize_error(str(e)))

            reviewer_force_reason = ""
            if self._reviewer_needs_forced_verdict(node_type, output_text, tool_results):
                reviewer_force_reason = (
                    self._review_output_format_followup_reason(node_type, output_text)
                    or "missing_reviewer_verdict_json"
                )

            if reviewer_force_reason:
                logger.info(
                    "Reviewer output missing strict verdict JSON — forcing final no-tool verdict synthesis (%s)",
                    reviewer_force_reason,
                )
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, reviewer_force_reason),
                    )
                forced_messages = self._reviewer_forced_verdict_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    reviewer_force_reason,
                )
                try:
                    final_resp = await _await_stream_call(forced_messages, [])
                    final_msg = final_resp.choices[0].message
                    final_content = str(final_msg.content or "").strip()
                    if (
                        final_content
                        and self._review_output_format_followup_reason(node_type, final_content) is None
                    ):
                        output_text = final_content
                        await self._publish_partial_output(on_progress, output_text, phase="finalizing")
                    usage_totals = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                except Exception as e:
                    logger.warning("Forced reviewer verdict synthesis failed: %s", _sanitize_error(str(e)))

                # v5.8.6: LAST-RESORT reviewer fallback. If both the tool-loop
                # AND the forced no-tool synthesis produced empty prose, the
                # orchestrator would mark subtask failed → consume a rejection
                # round → eventually hit "rejection budget reached" with no
                # salvage. Observed 3 times in a single run. Synthesize a
                # deterministic REJECTED verdict in code so the orchestrator
                # ALWAYS gets a parseable verdict; the reviewer round still
                # counts, but the downstream soft-ship / debugger paths kick in
                # instead of hard-blocking delivery.
                if (
                    not str(output_text or "").strip()
                    or self._review_output_format_followup_reason(node_type, output_text) is not None
                ):
                    fallback_verdict = self._reviewer_empty_output_fallback_verdict(
                        tool_results=tool_results,
                        original_reason=reviewer_force_reason,
                    )
                    if fallback_verdict:
                        logger.warning(
                            "Reviewer returned empty output twice — injecting deterministic "
                            "REJECTED verdict so orchestrator can proceed (reason=%s)",
                            reviewer_force_reason,
                        )
                        output_text = fallback_verdict
                        await self._publish_partial_output(
                            on_progress, output_text, phase="finalizing"
                        )

            if normalized_node_type == "builder":
                tool_result_text = self._builder_tool_result_salvage_text(tool_results, input_data)
                disk_result_text = self._builder_disk_salvage_text(
                    input_data,
                    incremental_text=output_text,
                )
                combined_salvage_text = "\n\n".join(
                    part for part in (tool_result_text, disk_result_text) if str(part or "").strip()
                )
                preferred_output = self._select_builder_salvage_text(
                    "",
                    output_text,
                    tool_result_text=combined_salvage_text,
                )
                if (
                    preferred_output
                    and preferred_output != output_text
                    and self._builder_partial_text_is_salvageable(input_data, preferred_output)
                ):
                    output_text = preferred_output
                    await self._publish_partial_output(on_progress, output_text, phase="finalizing")

            # ── P0 FIX B: Auto-save HTML from text output if builder never used file_ops ──
            # Kimi K2.5 sometimes outputs full HTML as markdown code blocks in content text
            # instead of calling file_ops. When this happens, output_text has 37k+ chars of
            # complete HTML that needs to be saved to disk, otherwise quality gate sees empty body.
            if (
                normalized_node_type == "builder"
                and not builder_has_written_file
                and output_text
                and len(output_text) > 120
            ):
                async def _request_builder_continuation(cont_messages):
                    return await _await_stream_call(cont_messages, [])

                output_text, continuation_count, cont_resp = await self._attempt_builder_game_text_continuation(
                    output_text=output_text,
                    input_data=input_data,
                    system_prompt=system_prompt,
                    continuation_count=continuation_count,
                    max_continuations=max_continuations,
                    request_continuation=_request_builder_continuation,
                    on_progress=on_progress,
                )
                if cont_resp is not None:
                    usage_totals = self._merge_usage(usage_totals, getattr(cont_resp, "usage", None))

                saved_paths = await self._auto_save_builder_text_output(
                    output_text=output_text,
                    input_data=input_data,
                    node=node,
                    tool_results=tool_results,
                    tool_call_stats=tool_call_stats,
                    on_progress=on_progress,
                )
                if saved_paths:
                    builder_has_written_file = True
                elif not self._builder_text_output_has_persistable_html(output_text, input_data):
                    failure_msg = self._builder_non_deliverable_output_reason(output_text, input_data)
                    # v5.8.6: surface tool-call truncation in the failure reason
                    # so orchestrator retry triggers direct_text delivery next time.
                    if length_truncation_break_reason:
                        failure_msg = f"{length_truncation_break_reason} | {failure_msg}"
                    logger.warning(failure_msg)
                    return self._attach_browser_action_events({
                        "success": False,
                        "output": output_text,
                        "error": failure_msg,
                        "model": getattr(response, "model", model_name),
                        "tool_results": tool_results,
                        "mode": "openai_compatible",
                        "usage": usage_totals,
                        "tool_call_stats": dict(tool_call_stats),
                        "qa_browser_use_available": qa_browser_use_available,
                    }, browser_action_events)

            return self._attach_browser_action_events({
                "success": True, "output": output_text,
                "model": getattr(response, "model", model_name),
                "tool_results": tool_results, "mode": "openai_compatible",
                "usage": usage_totals,
                "tool_call_stats": tool_call_stats,
                "qa_browser_use_available": qa_browser_use_available,
            }, browser_action_events)
        except TimeoutError as e:
            fallback = await _force_builder_text_timeout_fallback(str(e))
            if fallback is not None:
                return fallback
            if on_progress:
                await self._emit_noncritical_progress(
                    on_progress,
                    {"stage": "stream_stalled", "reason": str(e)},
                )
            return self._attach_browser_action_events(
                {"success": False, "output": "", "error": _sanitize_error(str(e))},
                locals().get("browser_action_events"),
            )
        except Exception as e:
            err = _sanitize_error(str(e))
            # V4.3 connection self-healing: evict cached client on transport-level
            # failures so the orchestrator's retry creates a fresh TCP+TLS session.
            _err_lower = err.lower()
            _is_connection_error = any(kw in _err_lower for kw in (
                "connectionerror", "connecterror", "connection reset",
                "connection refused", "transport", "reset by peer",
                "broken pipe", "unexpectedeof", "ssl handshake",
                "socket error", "networkerror",
            ))
            if _is_connection_error:
                self._invalidate_openai_client(
                    api_key=api_key,
                    base_url=self._resolved_api_base_for_model_info(model_info),
                    reason=err[:200],
                )
            if normalized_node_type == "builder" and not builder_has_written_file and "timeout" in _err_lower:
                fallback = await _force_builder_text_timeout_fallback(err)
                if fallback is not None:
                    return fallback
            if on_progress and ("timed out" in _err_lower or "timeout" in _err_lower):
                await self._emit_noncritical_progress(
                    on_progress,
                    {"stage": "stream_stalled", "reason": err},
                )
            return self._attach_browser_action_events(
                {"success": False, "output": "", "error": err},
                locals().get("browser_action_events"),
            )

    async def _execute_openai_compatible_chat(self, node, input_data, model_info, on_progress) -> Dict:
        from openai import OpenAI

        node_type = node.get("type", "builder")
        system_prompt = self._compose_system_prompt(node, input_data=input_data)
        # v7.3.4 outbound PII gate (mirror of _execute_openai_compatible).
        try:
            _outbound_masker = get_masker()
            if _outbound_masker and getattr(_outbound_masker, "enabled", True) and not (node_type in getattr(_outbound_masker, "exclude_node_types", set())):
                _masked_sp, _sp_restore = _outbound_masker.mask(system_prompt, node_type=node_type)
                if _sp_restore:
                    system_prompt = _masked_sp
                    _existing = node.setdefault("_outbound_restore_map", {})
                    _existing.update(_sp_restore)
                    logger.info(
                        "Outbound PII mask (chat path): node=%s items=%d",
                        node_type, len(_sp_restore),
                    )
        except Exception as _mask_err:
            logger.warning("Outbound PII mask skipped (chat path): %s", str(_mask_err)[:200])
        model_name = model_info["litellm_id"].replace("openai/", "")
        max_tokens = self._max_tokens_for_node(
            node_type,
            retry_attempt=int(node.get("retry_attempt", 0)),
            node=node,
        )
        timeout_sec = self._effective_timeout_for_node(node_type, input_data, node=node)
        direct_multifile = (
            normalize_node_role(node_type) == "builder"
            and str(node.get("builder_delivery_mode") or "").strip().lower() == "direct_multifile"
        )
        if direct_multifile:
            max_tokens, timeout_sec = self._builder_direct_multifile_budget(
                input_data,
                max_tokens=max_tokens,
                timeout_sec=timeout_sec,
            )

        api_key = self._resolved_api_key_for_model_info(model_info)
        if not api_key:
            return {"success": False, "output": "", "error": f"API key not configured for {model_info.get('provider')}"}

        if on_progress:
            await self._emit_noncritical_progress(
                on_progress,
                {"stage": "calling_ai", "model": model_name, "tools_count": 0, "mode": "openai_compatible_chat"},
            )

        stall_timeout = self._effective_stream_stall_timeout(node_type, input_data, node=node)
        latest_stream_text = ""
        output_parts: List[str] = []
        stream_has_initial_activity = False
        custom_gateway = bool(self._custom_compatible_gateway_base(model_info))
        loop = asyncio.get_running_loop()
        # v6.1.8 Wave A (maintainer 2026-04-19): Bolt.new-style incremental
        # stream-to-disk parser. When builder is in direct_text mode writing
        # index.html, flush on </script> / </style> / </html> boundaries so
        # the preview materializes ~5s in instead of ~170s. No-op when
        # parser isn't applicable (no target path / non-builder / tool_call).
        _stream_parser = self._maybe_make_incremental_stream_parser(
            node=node, node_type=node_type, direct_multifile=direct_multifile,
        )
        # v6.1.9 Task 1 (maintainer 2026-04-19): emit stream_flush event to the
        # frontend when the parser materializes a boundary so the preview
        # iframe can reload from /api/preview/streaming/:task_id.
        if _stream_parser is not None and on_progress is not None:
            _task_id_for_event = str((node or {}).get("subtask_id") or (node or {}).get("task_id") or "")
            def _on_parser_flush(path: str, content: str, is_final: bool) -> None:
                try:
                    asyncio.run_coroutine_threadsafe(
                        on_progress({
                            "stage": "stream_flush",
                            "task_id": _task_id_for_event,
                            "staging_path": path,
                            "bytes": len(content),
                            "is_final": is_final,
                        }),
                        loop,
                    )
                except RuntimeError:
                    pass
                # Still do the default disk flush
                try:
                    _stream_parser._default_disk_flush(content, is_final)
                except Exception:
                    pass
            _stream_parser.on_flush = _on_parser_flush
        logger.info(
            "openai_compatible_chat request profile: node=%s model=%s system_chars=%s user_chars=%s assigned_targets=%s direct_multifile=%s incremental_parser=%s",
            normalize_node_role(node_type) or node_type,
            model_name,
            len(system_prompt or ""),
            len(str(input_data or "")),
            len(self._builder_assigned_html_targets(input_data)) if normalize_node_role(node_type) == "builder" else 0,
            direct_multifile,
            bool(_stream_parser),
        )

        try:
            client = self._get_or_create_openai_client(
                api_key=api_key,
                base_url=self._resolved_api_base_for_model_info(model_info),
                extra_headers=model_info.get("extra_headers", {}),
                timeout=timeout_sec,
            )
            kwargs_base: Dict[str, Any] = {
                "model": model_name,
                "max_tokens": max_tokens,
            }
            # V4.3 PERF: Node-specific temperature (was fixed 0.7 for all)
            _node_temp = self._temperature_for_node(node_type, model_name)
            if _node_temp is not None:
                kwargs_base["temperature"] = _node_temp
            # v6.1: Unified thinking/reasoning config (chat path). See
            # _apply_thinking_config_to_kwargs — one source of truth for both
            # compat and chat paths; deep mode truly enables thinking now.
            _run_id = str((node or {}).get("run_id") or "").strip() if isinstance(node, dict) else ""
            _ne_id = str((node or {}).get("node_execution_id") or "").strip() if isinstance(node, dict) else ""
            _cache_key_parts = [p for p in [_run_id, node_type or "node", _ne_id] if p]
            _cache_key = "-".join(_cache_key_parts)[:128] if _cache_key_parts else ""
            self._apply_thinking_config_to_kwargs(
                kwargs_base,
                model_info,
                model_name,
                cache_key=_cache_key,
                node_type=node_type or "",
                input_data=input_data,
            )

            def _call_chat_streaming(current_messages, cancel_event: Optional[threading.Event] = None):
                """Make API call with streaming to detect stalls early."""
                nonlocal latest_stream_text, stream_has_initial_activity
                latest_stream_text = ""
                stream_has_initial_activity = False
                kwargs = dict(kwargs_base)
                kwargs["messages"] = current_messages
                kwargs["stream"] = True
                # F4-1: Request usage data in streaming mode for accurate token monitoring
                kwargs["stream_options"] = {"include_usage": True}
                # V4.3.1: Transport timeout uses 3x stall for first-chunk grace
                kwargs["timeout"] = stall_timeout * 3
                # v6.1.1: same <think> stripper as compat path — thinking stays
                # internal, content_parts only gets the clean deliverable.
                _chat_think_strip_enabled = str(os.getenv("EVERMIND_STRIP_THINK", "1")).strip().lower() not in ("0", "false", "off", "no")
                _chat_think_stripper = ThinkStripper()
                stream = client.chat.completions.create(**kwargs)
                content_parts = []
                usage_data = None
                finish_reason = None
                last_chunk_time = time.time()
                last_preview_emit = 0.0
                stream_started_at = last_chunk_time
                first_chunk_at: Optional[float] = None
                first_content_at: Optional[float] = None
                chunk_count = 0
                try:
                    for chunk in stream:
                        if cancel_event is not None and cancel_event.is_set():
                            raise asyncio.CancelledError()
                        now = time.time()
                        # V4.3.1: First-chunk grace for chat streaming path too (3x)
                        _eff_stall = stall_timeout * 3 if first_content_at is None else stall_timeout
                        if now - last_chunk_time > _eff_stall:
                            raise TimeoutError(f"Chat stream stalled: no chunk for {_eff_stall:.0f}s")
                        if first_chunk_at is None:
                            first_chunk_at = now
                        chunk_count += 1
                        last_chunk_time = now
                        if not chunk.choices:
                            if hasattr(chunk, "usage") and chunk.usage:
                                usage_data = chunk.usage
                            continue
                        delta = chunk.choices[0].delta
                        # v6.1.1: absorb reasoning_content field for log only.
                        _rc_chat = getattr(delta, "reasoning_content", None) or getattr(delta, "reasoning", None)
                        if _rc_chat:
                            _chat_think_stripper.reasoning_parts.append(str(_rc_chat))
                        if delta.content:
                            _raw_chat_delta = delta.content
                            _clean_chat_delta = _chat_think_stripper.feed(_raw_chat_delta) if _chat_think_strip_enabled else _raw_chat_delta
                            if _clean_chat_delta:
                                if first_content_at is None:
                                    first_content_at = now
                                stream_has_initial_activity = True
                                content_parts.append(_clean_chat_delta)
                                latest_stream_text = "".join(content_parts)
                                # v6.1.8 Wave A: feed parser for stream-to-disk
                                if _stream_parser is not None:
                                    try:
                                        _stream_parser.feed(_clean_chat_delta)
                                    except Exception:
                                        logger.debug("stream parser feed failed", exc_info=True)
                                if on_progress and (now - last_preview_emit >= 0.75):
                                    event = self._build_partial_output_event(latest_stream_text, phase="streaming")
                                    if event:
                                        try:
                                            asyncio.run_coroutine_threadsafe(on_progress(event), loop)
                                        except RuntimeError:
                                            pass
                                    last_preview_emit = now
                            elif _rc_chat is None and _chat_think_stripper.in_think:
                                # still inside <think> — mark activity so stall
                                # detector doesn't cut a legitimately thinking model
                                stream_has_initial_activity = True
                        if chunk.choices[0].finish_reason:
                            finish_reason = chunk.choices[0].finish_reason
                    if cancel_event is not None and cancel_event.is_set():
                        raise asyncio.CancelledError()
                finally:
                    _close_stream_quietly(stream)
                # v6.1.1: flush stripper — return any held tail that wasn't a
                # real <think> tag, drop content still inside an unclosed block.
                if _chat_think_strip_enabled:
                    _chat_tail = _chat_think_stripper.flush()
                    if _chat_tail:
                        content_parts.append(_chat_tail)
                # Post-process fallback — catch anything the state machine missed
                if _chat_think_strip_enabled and content_parts:
                    _joined = "".join(content_parts)
                    _cleaned = strip_think_tags_full(_joined)
                    if _cleaned != _joined:
                        logger.info(
                            "chat stream thinking stripped (post-process): model=%s removed_chars=%d",
                            model_name, len(_joined) - len(_cleaned),
                        )
                        content_parts = [_cleaned]
                # v6.1.8 Wave A: finalize incremental parser (flush staging file
                # tail so downstream postprocess sees the complete bytes).
                if _stream_parser is not None:
                    try:
                        _final_flushed = _stream_parser.finalize()
                        _p_stats = _stream_parser.stats
                        logger.info(
                            "incremental_stream: flushes=%d first_flush=%.0fms total_bytes=%d boundaries=%s tail=%d",
                            _p_stats.flushes, _p_stats.first_flush_ms,
                            _p_stats.flush_bytes, _p_stats.boundaries_hit[:5],
                            _final_flushed,
                        )
                    except Exception:
                        logger.debug("stream parser finalize failed", exc_info=True)
                logger.info(
                    "openai_compatible_chat stream stats: node=%s model=%s chunks=%s first_chunk=%s first_content=%s finish=%s content_chars=%s total_stream=%s",
                    normalize_node_role(node_type) or node_type,
                    model_name,
                    chunk_count,
                    self._format_latency_for_log(
                        None if first_chunk_at is None else first_chunk_at - stream_started_at
                    ),
                    self._format_latency_for_log(
                        None if first_content_at is None else first_content_at - stream_started_at
                    ),
                    finish_reason or "stop",
                    len("".join(content_parts)),
                    self._format_latency_for_log(time.time() - stream_started_at),
                )

                # Broadcast stream stats to frontend
                if on_progress:
                    _total_sec = time.time() - stream_started_at
                    _fc_sec = (first_content_at - stream_started_at) if first_content_at else None
                    _cps = round(len("".join(content_parts)) / max(_total_sec, 0.1), 1)
                    try:
                        asyncio.run_coroutine_threadsafe(
                            on_progress({
                                "stage": "stream_stats",
                                "model": model_name,
                                "chunks": chunk_count,
                                "first_content_sec": round(_fc_sec, 2) if _fc_sec else None,
                                "total_stream_sec": round(_total_sec, 2),
                                "content_chars": len("".join(content_parts)),
                                "chars_per_sec": _cps,
                                "tool_calls": 0,
                            }),
                            loop,
                        )
                    except Exception:
                        pass

                from types import SimpleNamespace
                message = SimpleNamespace(
                    content="".join(content_parts) if content_parts else None,
                    role="assistant",
                )
                choice = SimpleNamespace(
                    message=message,
                    finish_reason=finish_reason or "stop",
                )
                return SimpleNamespace(choices=[choice], usage=usage_data)

            async def _call_chat(current_messages):
                cancel_event = threading.Event()
                call_task = asyncio.create_task(asyncio.to_thread(_call_chat_streaming, current_messages, cancel_event))

                def _request_stream_stop() -> None:
                    cancel_event.set()
                    call_task.cancel()

                initial_activity_timeout = (
                    self._gateway_initial_activity_timeout_for_node(node_type, input_data, model_info=model_info)
                    if custom_gateway
                    else 0
                )
                started_at = time.time()
                hard_deadline = started_at + timeout_sec
                initial_activity_deadline = (
                    started_at + initial_activity_timeout if initial_activity_timeout > 0 else None
                )
                # v5.8.6 REDESIGN: Content rate check RELAXED. Was 30s/100 chars
                # which killed slow Chinese models (Kimi ~100 tok/s = ~260 chars
                # in 30s — borderline; smaller models can be under 100 chars if
                # they're still in reasoning phase). New: 120s/100 chars, so
                # only truly dead streams get killed. Can disable entirely via
                # EVERMIND_DISABLE_CONTENT_RATE_CHECK=1.
                _CONTENT_RATE_CHECK_SEC = 120
                _CONTENT_RATE_MIN_CHARS = 100
                if os.getenv("EVERMIND_DISABLE_CONTENT_RATE_CHECK", "0").lower() in {"1", "true", "yes"}:
                    _CONTENT_RATE_CHECK_SEC = 10_000_000  # effectively disabled
                _content_rate_checked = False
                _content_started_at: Optional[float] = None
                while True:
                    now = time.time()
                    remaining_hard = hard_deadline - now
                    if remaining_hard <= 0:
                        _request_stream_stop()
                        node_label = normalize_node_role(node_type) or str(node_type or "node").strip().lower() or "node"
                        raise TimeoutError(
                            f"{node_label} hard-ceiling timeout after {timeout_sec}s: API call exceeded node timeout."
                        )
                    next_poll = min(1.0, remaining_hard)
                    if initial_activity_deadline is not None:
                        next_poll = min(next_poll, max(0.01, initial_activity_deadline - now))
                    done, _ = await asyncio.wait({call_task}, timeout=next_poll)
                    if call_task in done:
                        return call_task.result()
                    now = time.time()
                    if stream_has_initial_activity:
                        initial_activity_deadline = None
                        if _content_started_at is None:
                            _content_started_at = now
                        # V4.6 SPEED: Content rate check for chat path
                        if (
                            custom_gateway
                            and not _content_rate_checked
                            and _content_started_at is not None
                            and (now - _content_started_at) >= _CONTENT_RATE_CHECK_SEC
                        ):
                            _content_rate_checked = True
                            _current_chars = len(latest_stream_text or "")
                            if _current_chars < _CONTENT_RATE_MIN_CHARS:
                                _request_stream_stop()
                                node_label = normalize_node_role(node_type) or str(node_type or "node").strip().lower() or "node"
                                logger.warning(
                                    "Chat content rate too slow: node=%s model=%s chars=%d after %ds",
                                    node_label, model_name, _current_chars, _CONTENT_RATE_CHECK_SEC,
                                )
                                raise TimeoutError(
                                    f"{node_label} content-rate timeout: only {_current_chars} chars "
                                    f"after {_CONTENT_RATE_CHECK_SEC}s of content generation."
                                )
                        continue
                    if initial_activity_deadline is not None and now >= initial_activity_deadline:
                        _request_stream_stop()
                        node_label = normalize_node_role(node_type) or str(node_type or "node").strip().lower() or "node"
                        raise TimeoutError(
                            f"{node_label} initial-activity timeout after {initial_activity_timeout}s: compatible gateway produced no content."
                        )

            # V4.6 SPEED: Inject builder deferred context into user message (chat path)
            effective_chat_input = input_data
            builder_deferred_chat = getattr(self, "_builder_deferred_context", "")
            if builder_deferred_chat and normalize_node_role(node_type) == "builder":
                effective_chat_input = (
                    "=== REFERENCE MATERIAL ===\n"
                    + builder_deferred_chat
                    + "\n=== END REFERENCE ===\n\n"
                    + input_data
                )
                self._builder_deferred_context = ""
                logger.info(
                    "Builder deferred context injected (chat path): %d chars moved from system to user",
                    len(builder_deferred_chat),
                )
            # v6.1.2: always log endpoint + UA so users can audit routing
            # (client cache previously hid this info after the first request).
            _effective_base = self._resolved_api_base_for_model_info(model_info) or "<registry-default>"
            _extra_hdrs = (model_info or {}).get("extra_headers") or {}
            _ua_debug = str(_extra_hdrs.get("User-Agent") or "<default>")
            logger.info(
                "openai_compatible_chat: starting API call model=%s endpoint=%s ua=%s timeout=%ss stall=%ss multifile=%s",
                model_name, _effective_base, _ua_debug, timeout_sec, stall_timeout, direct_multifile,
            )
            # v6.1.3 (Codex multi-step): for direct_text (single-file) builder
            # outputs, auto-loop on finish_reason=length with assistant prefill
            # continuation. Previous single-shot hit 40K-token cap mid-HTML
            # and failed entire node. Loop = Aider pattern
            # (base_coder.py:1491-1510). Kimi/Qwen don't support prefix=true,
            # so we use a synthetic [CONTINUE] user turn.
            _base_messages = (
                self._builder_direct_multifile_initial_messages(system_prompt, effective_chat_input)
                if direct_multifile
                else [
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": effective_chat_input},
                ]
            )
            response = await _call_chat(_base_messages)
            usage = self._normalize_usage(getattr(response, "usage", None))
            content = response.choices[0].message.content or ""

            # Continuation loop only applies to non-multifile direct_text.
            # Self-debug #1: rebuild messages from _base_messages each round
            # instead of appending — otherwise round N has N duplicate
            # assistant turns, bloating context by O(N * content_size) and
            # confusing the model into re-writing earlier chunks.
            # Self-debug #2: break when a round makes near-zero progress
            # (< 200 chars) to avoid futile loops on a stuck model.
            _continuation_rounds = 0
            _max_continuations = int(os.getenv("EVERMIND_DIRECT_TEXT_MAX_CONTINUATIONS", "6") or "6")
            # Opus R3: reset per-call prefill disable flag so a 400 in a
            # previous call doesn't poison new calls.
            self._prefill_disabled_this_call = False
            _normalized_node_type_local = normalize_node_role(node_type) or node_type or ""
            _is_builder_chat = _normalized_node_type_local == "builder"

            def _build_continue_turn(prior_content: str) -> Dict[str, str]:
                """v6.1.10 (maintainer 2026-04-19): semantic anchor continue turn.

                Community research (OpenAI forum + Aider #1492) confirms that
                naive "please continue" prompts cause 20-200 char repetition
                on GPT/Gemini (40-50% failure on code/JSON). Including the
                LAST 300 chars as a verbatim anchor lets the model find its
                exact cursor position — reduces repeat rate to single-digit
                characters in practice.
                """
                tail = prior_content[-300:] if prior_content else ""
                tail_block = f"```\n{tail}\n```" if tail else "(previous response was empty)"
                return {
                    "role": "user",
                    "content": (
                        "[CONTINUE] Your previous response was truncated at the "
                        "token limit. The LAST 300 characters you emitted were:\n"
                        f"{tail_block}\n\n"
                        "Output EXACTLY the next character after that snippet. "
                        "Do NOT repeat the snippet. Do NOT restart. Do NOT "
                        "apologise. Do NOT explain. Resume writing and keep "
                        "going until the HTML is fully closed (</html>)."
                    ),
                }
            # Legacy placeholder kept for any external reference; not used below.
            _CONTINUE_USER_TURN = _build_continue_turn("")
            while (
                _is_builder_chat
                and not direct_multifile
                and _continuation_rounds < _max_continuations
                and str(self._response_finish_reason(response) or "").lower() == "length"
                and content
            ):
                _continuation_rounds += 1
                # Rebuild from the stable base prefix: [sys, user_original].
                # One assistant turn carrying the FULL accumulated output.
                # One user turn asking to continue. Prefix byte-stability =
                # 100% prompt-cache hit on sys+user block (50% input discount).
                # v6.1.8 Wave B (maintainer 2026-04-19): Aider-style assistant
                # prefill retry. For providers that support `prefix: true`
                # (Anthropic, DeepSeek, some Kimi), send the partial content
                # as the LAST message and the model continues writing the
                # next character. Saves 2x: (a) no re-decode of emitted text
                # (b) no redundant [CONTINUE] user turn token.
                # Opus R3 + research 2026-04-19: provider-aware prefill.
                # Field name varies: Claude = none (bare assistant), Mistral/
                # DeepSeek = "prefix", Kimi/Qwen = "partial". Fall back to
                # [CONTINUE] if provider doesn't support or 400-rejected earlier.
                _prefill_field = None
                if not getattr(self, "_prefill_disabled_this_call", False):
                    _prefill_field = self._assistant_prefill_field(model_info, model_name)
                if _prefill_field is not None:
                    _assistant_msg = {"role": "assistant", "content": content}
                    if _prefill_field:
                        _assistant_msg[_prefill_field] = True
                    _chat_messages = list(_base_messages) + [_assistant_msg]
                else:
                    _chat_messages = list(_base_messages) + [
                        {"role": "assistant", "content": content},
                        _build_continue_turn(content),
                    ]
                logger.info(
                    "direct_text continuation round %s/%s: prior_chars=%s model=%s",
                    _continuation_rounds, _max_continuations, len(content), model_name,
                )
                if on_progress:
                    try:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "continuing",
                            "reason": "length_truncated",
                            "continuation": _continuation_rounds,
                            "accumulated_chars": len(content),
                        })
                    except Exception:
                        pass
                # Opus R3: catch 400-level rejection of `prefix: true` and
                # retry once with the classic [CONTINUE] user turn.
                try:
                    _next_response = await _call_chat(_chat_messages)
                except Exception as _prefill_exc:
                    _msg = str(_prefill_exc).lower()
                    _looks_like_bad_request = (
                        "400" in _msg
                        or "bad request" in _msg
                        or "unknown field" in _msg
                        or "unexpected" in _msg
                        or "prefix" in _msg
                    )
                    if _looks_like_bad_request and (
                        _chat_messages and _chat_messages[-1].get("role") == "assistant"
                        and _chat_messages[-1].get("prefix") is True
                    ):
                        logger.warning(
                            "Prefill rejected (%s) — falling back to [CONTINUE] user turn for rest of this call",
                            _msg[:120],
                        )
                        self._prefill_disabled_this_call = True
                        _chat_messages = list(_base_messages) + [
                            {"role": "assistant", "content": content},
                            _CONTINUE_USER_TURN,
                        ]
                        _next_response = await _call_chat(_chat_messages)
                    else:
                        raise
                usage = self._merge_usage(usage, getattr(_next_response, "usage", None))
                _next_content = _next_response.choices[0].message.content or ""
                _prior_len = len(content)
                if not _next_content.strip():
                    logger.warning(
                        "direct_text continuation returned empty — stopping loop (round %s)",
                        _continuation_rounds,
                    )
                    break
                # Progress-floor: a round producing < 200 chars is effectively
                # stuck (model repeating "</html>" or echoing). Don't burn more
                # rounds on it.
                if len(_next_content.strip()) < 200:
                    logger.warning(
                        "direct_text continuation made near-zero progress (%s chars) — stopping loop (round %s)",
                        len(_next_content),
                        _continuation_rounds,
                    )
                    content = self._merge_with_overlap_dedup(content, _next_content)
                    response = _next_response
                    break
                content = self._merge_with_overlap_dedup(content, _next_content)
                response = _next_response
                logger.info(
                    "direct_text continuation round %s complete: +%s chars → total %s (finish=%s)",
                    _continuation_rounds,
                    len(content) - _prior_len,
                    len(content),
                    str(self._response_finish_reason(response) or "").lower(),
                )
            # v5.8.7: reasoning-mode fallback for non-streaming direct_multifile.
            # Some relay stations (aigate, private-relay) silently route the deliverable
            # into `reasoning_content` when tools=[] are present. If `content` is
            # empty/short and reasoning carries a fenced HTML block, lift it over.
            if not self._builder_named_code_blocks(content):
                try:
                    _msg = response.choices[0].message
                    _reasoning = getattr(_msg, "reasoning_content", None) or getattr(_msg, "reasoning", None)
                    if isinstance(_reasoning, str) and self._builder_named_code_blocks(_reasoning):
                        logger.info(
                            "builder direct_multifile: lifted HTML from reasoning_content (content_chars=%s reasoning_chars=%s)",
                            len(content or ""),
                            len(_reasoning),
                        )
                        content = _reasoning if not content else f"{content}\n\n{_reasoning}"
                except Exception:
                    pass
            narration_only_initial = False
            if content:
                output_parts.append(content)
                returned_targets = self._builder_returned_html_targets(content)
                completed_targets = self._builder_completed_html_targets(content)
                logger.info(
                    "builder direct_multifile batch ready: node=%s model=%s batch_index=%s returned_targets=%s completed_targets=%s finish=%s chars=%s",
                    normalize_node_role(node_type) or node_type,
                    model_name,
                    len(output_parts),
                    returned_targets[:12],
                    completed_targets[:12],
                    self._response_finish_reason(response) or "stop",
                    len(content),
                )
                # v5.8.2 auto-learn: track empty batches; after 2, flip the
                # instance-wide kill-switch so future builders skip direct_multifile.
                # v5.8.6: only count as "empty" if the model really produced no
                # substantial content. A 73K-char batch with empty returned_targets
                # still contained valid HTML extracted by the text-mode fallback —
                # counting that as "empty" prematurely kills direct_text for merger
                # and downstream builders, causing the merger to degrade to tool_call
                # (10+ min death spiral).
                # v5.8.7: bumped threshold 2KB → 10KB. Minimax observed producing
                # 2.2KB → 1.6KB → 1KB → 572B narratives with returned_targets=[] —
                # all are pure planning prose, far below any real HTML deliverable.
                # The text-mode fallback extracts only when content carries real
                # tags, so a 10KB ceiling keeps the fallback safety net alive while
                # counting these narrative-only batches as empty.
                # v6.0 FIX: the narration guard + empty-batch auto-learn must
                # only apply when we ACTUALLY asked for direct_multifile output.
                # The previous implementation ran it on every node (including
                # router/planner which are NOT builders and don't emit HTML)
                # because this log block runs regardless of `direct_multifile`.
                # Effect of the bug: router's 3.6 KB classification JSON and
                # planner's 3.6 KB plan text were classified as "narration-only"
                # and flipped the session-wide kill switch BEFORE the builder
                # even got to run. Diagnosed from the 2026-04-18 13:29 run.
                is_builder_node = normalize_node_role(node_type) == "builder"
                guard_active = bool(direct_multifile) and is_builder_node
                is_truly_empty_batch = (
                    guard_active
                    and not returned_targets
                    and not completed_targets
                    and len(content or "") < 10240
                )
                # v5.8.7: narration-only guard. Short planning prose with no
                # HTML skeleton counts as empty regardless of length bucket.
                narration_only_initial = (
                    guard_active
                    and not returned_targets
                    and not completed_targets
                    and self._builder_response_looks_like_narration_only(content)
                )
                if narration_only_initial:
                    is_truly_empty_batch = True
                if is_truly_empty_batch:
                    self._builder_empty_batch_count = getattr(self, "_builder_empty_batch_count", 0) + 1
                    if self._builder_empty_batch_count >= 2:
                        self._builder_direct_multifile_disabled = True
                        logger.warning(
                            "Builder auto-learn: disabled direct_multifile for the rest of this run "
                            "after %d empty batches. Further builders will use tool-call mode.",
                            self._builder_empty_batch_count,
                        )
                if on_progress:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "builder_multifile_batch_ready",
                        "batch_index": len(output_parts),
                        "returned_targets": returned_targets[:12],
                        "completed_targets": completed_targets[:12],
                        "finish_reason": self._response_finish_reason(response),
                        "content": content,
                    })
                await self._publish_partial_output(on_progress, content, phase="drafting")

            continuation_limit = self._builder_direct_multifile_continuation_limit(input_data) if direct_multifile else 0
            if narration_only_initial:
                logger.warning(
                    "builder direct_multifile: initial batch was narration-only; skipping continuation budget and arming kill switch (node=%s model=%s chars=%s)",
                    normalize_node_role(node_type) or node_type,
                    model_name,
                    len(content or ""),
                )
                continuation_limit = 0
                # v5.8.7: a format failure on the very first batch is load-bearing
                # evidence the model/provider combination can't honour the fenced
                # multifile contract this session. Fire the kill switch now so the
                # next builder invocation skips straight to tool_call instead of
                # re-learning via another round of narration.
                self._builder_direct_multifile_disabled = True
                if on_progress:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "builder_multifile_narration_abort",
                        "reason": "initial_batch_was_narration_only",
                        "chars": len(content or ""),
                        "assignedModel": model_name,
                        "assignedProvider": (model_info or {}).get("provider", ""),
                    })
            continuation_count = 0
            while direct_multifile and continuation_count < continuation_limit:
                combined_output = "\n\n".join(part for part in output_parts if str(part).strip())
                remaining_targets = self._builder_missing_html_targets(input_data, combined_output)
                if not remaining_targets:
                    break
                previous_remaining = list(remaining_targets)
                next_batch = remaining_targets[: self._builder_direct_multifile_batch_size(input_data)]
                logger.info(
                    "builder direct_multifile continuation request: node=%s model=%s continuation=%s next_batch=%s remaining=%s prior_finish=%s",
                    normalize_node_role(node_type) or node_type,
                    model_name,
                    continuation_count + 1,
                    next_batch[:12],
                    len(remaining_targets),
                    self._response_finish_reason(response) or "stop",
                )
                if on_progress:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "builder_multifile_continue",
                        "continuation": continuation_count + 1,
                        "next_batch": next_batch[:12],
                        "remaining_targets": remaining_targets[:12],
                        "finish_reason": self._response_finish_reason(response),
                    })
                response = await _call_chat(
                    self._builder_direct_multifile_continuation_messages(
                        system_prompt,
                        input_data,
                        combined_output,
                        remaining_targets,
                    )
                )
                usage = self._merge_usage(usage, getattr(response, "usage", None))
                continuation_count += 1
                continuation_content = response.choices[0].message.content or ""
                # v5.8.7: same reasoning_content rescue for continuations.
                if not self._builder_named_code_blocks(continuation_content):
                    try:
                        _msg = response.choices[0].message
                        _reasoning = getattr(_msg, "reasoning_content", None) or getattr(_msg, "reasoning", None)
                        if isinstance(_reasoning, str) and self._builder_named_code_blocks(_reasoning):
                            continuation_content = (
                                _reasoning if not continuation_content else f"{continuation_content}\n\n{_reasoning}"
                            )
                    except Exception:
                        pass
                if not continuation_content.strip():
                    break
                # v5.8.7: break the continuation loop on narration-only responses.
                # Without this the loop kept firing requests while output shrank
                # 2202 → 1619 → 1066 → 572 chars of prose and never recovered.
                # v6.0 FIX: only apply when the node is truly a builder — the
                # outer while-loop is gated on direct_multifile, but belt-and-
                # suspenders ensures router/planner forced into direct_multifile
                # (never happens today) can't trip this guard either.
                if (
                    normalize_node_role(node_type) == "builder"
                    and not self._builder_returned_html_targets(continuation_content)
                    and not self._builder_completed_html_targets(continuation_content)
                    and self._builder_response_looks_like_narration_only(continuation_content)
                ):
                    logger.warning(
                        "builder direct_multifile: continuation #%s was narration-only; aborting loop (node=%s model=%s chars=%s)",
                        continuation_count,
                        normalize_node_role(node_type) or node_type,
                        model_name,
                        len(continuation_content or ""),
                    )
                    self._builder_empty_batch_count = getattr(self, "_builder_empty_batch_count", 0) + 1
                    if self._builder_empty_batch_count >= 2:
                        self._builder_direct_multifile_disabled = True
                    break
                output_parts.append(continuation_content)
                returned_targets = self._builder_returned_html_targets(continuation_content)
                completed_targets = self._builder_completed_html_targets(continuation_content)
                logger.info(
                    "builder direct_multifile batch ready: node=%s model=%s batch_index=%s returned_targets=%s completed_targets=%s finish=%s chars=%s",
                    normalize_node_role(node_type) or node_type,
                    model_name,
                    len(output_parts),
                    returned_targets[:12],
                    completed_targets[:12],
                    self._response_finish_reason(response) or "stop",
                    len(continuation_content),
                )
                if on_progress:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "builder_multifile_batch_ready",
                        "batch_index": len(output_parts),
                        "returned_targets": returned_targets[:12],
                        "completed_targets": completed_targets[:12],
                        "finish_reason": self._response_finish_reason(response),
                        "content": continuation_content,
                    })
                await self._publish_partial_output(on_progress, continuation_content, phase="finalizing")
                next_remaining = self._builder_missing_html_targets(
                    input_data,
                    "\n\n".join(output_parts),
                )
                if len(next_remaining) >= len(previous_remaining) and self._response_finish_reason(response).lower() not in {"length", "max_tokens"}:
                    break

            final_output = "\n\n".join(part for part in output_parts if str(part).strip()).strip()
            # §FIX: Detect empty model response for builder nodes.
            # gpt-5.4 sometimes returns chunks=2, content_chars=0 on retry
            # (likely token exhaustion or context overflow). Returning success=True
            # with empty output wastes a retry on a guaranteed quality-gate failure.
            if normalize_node_role(node_type) == "builder" and not final_output.strip():
                empty_err = (
                    f"{model_name} returned empty content for builder node "
                    f"(stream had {len(output_parts)} parts, all empty). "
                    "Possible cause: context overflow or model refusal."
                )
                logger.warning("Builder empty-response detected: %s", empty_err)
                return {
                    "success": False,
                    "output": "",
                    "error": empty_err,
                    "model": model_name,
                    "tool_results": [],
                    "mode": "openai_compatible_chat",
                    "usage": usage,
                    "cost": self._estimate_response_cost(model_name, usage),
                }
            if normalize_node_role(node_type) == "builder":
                saved_paths, tool_results, tool_call_stats, failure_msg = await self._finalize_builder_chat_output(
                    output_text=final_output,
                    input_data=input_data,
                    node=node,
                    tool_results=[],
                    tool_call_stats={},
                    on_progress=on_progress,
                )
                if failure_msg:
                    logger.warning("Builder chat returned non-deliverable output: %s", failure_msg)
                    return {
                        "success": False,
                        "output": final_output,
                        "error": failure_msg,
                        "model": model_name,
                        "tool_results": tool_results,
                        "mode": "openai_compatible_chat",
                        "usage": usage,
                        "cost": self._estimate_response_cost(model_name, usage),
                        "tool_call_stats": tool_call_stats,
                    }
                logger.info(
                    "Builder chat auto-saved %s file(s) from direct text output: %s",
                    len(saved_paths),
                    saved_paths[:6],
                )
                return {
                    "success": True,
                    "output": final_output,
                    "model": model_name,
                    "tool_results": tool_results,
                    "mode": "openai_compatible_chat",
                    "usage": usage,
                    "cost": self._estimate_response_cost(model_name, usage),
                    "tool_call_stats": tool_call_stats,
                }
            return {
                "success": True,
                "output": final_output,
                "model": model_name,
                "tool_results": [],
                "mode": "openai_compatible_chat",
                "usage": usage,
                "cost": self._estimate_response_cost(model_name, usage),
            }
        except (TimeoutError, asyncio.TimeoutError) as e:
            err = _sanitize_error(str(e))
            stitched_parts = [part for part in output_parts if str(part).strip()]
            stitched_output = "\n\n".join(stitched_parts).strip()
            latest_trimmed = str(latest_stream_text or "").strip()
            if latest_trimmed:
                if not stitched_output:
                    stitched_output = latest_trimmed
                elif latest_trimmed not in stitched_output:
                    stitched_output = f"{stitched_output}\n\n{latest_trimmed}".strip()
            logger.warning(
                "openai_compatible_chat timeout: %s (partial=%s chars prior_batches=%s)",
                err,
                len(stitched_output or latest_stream_text or ""),
                len(output_parts),
            )
            # v4.1: Record timeout so subsequent nodes auto-skip this model+gateway
            # V4.5: Pass node_type for node-aware cooldown duration
            self._record_gateway_timeout(model_info, f"timeout: {err}", node_type=node_type)
            # Try to salvage whatever the stream produced before the timeout
            if normalize_node_role(node_type) == "builder" and stitched_output:
                salvage = await self._builder_partial_text_salvage_result(
                    node=node,
                    input_data=input_data,
                    output_text=stitched_output,
                    reason=err,
                    on_progress=on_progress,
                    tool_results=[],
                    model_name=model_name,
                    mode="openai_compatible_chat_timeout_salvage",
                    tool_call_stats={},
                )
                if salvage is not None:
                    return salvage
            if on_progress:
                await self._emit_noncritical_progress(
                    on_progress,
                    {"stage": "stream_stalled", "reason": err},
                )
            return {"success": False, "output": "", "error": err}
        except Exception as e:
            err = _sanitize_error(str(e))
            # V4.3 connection self-healing (chat path)
            _err_lower = err.lower()
            if any(kw in _err_lower for kw in (
                "connection", "connect", "transport", "reset by peer",
                "broken pipe", "eof", "ssl", "socket", "network",
            )):
                self._invalidate_openai_client(
                    api_key=api_key,
                    base_url=self._resolved_api_base_for_model_info(model_info),
                    reason=err[:200],
                )
            stitched_parts = [part for part in output_parts if str(part).strip()]
            stitched_output = "\n\n".join(stitched_parts).strip()
            latest_trimmed = str(latest_stream_text or "").strip()
            if latest_trimmed:
                if not stitched_output:
                    stitched_output = latest_trimmed
                elif latest_trimmed not in stitched_output:
                    stitched_output = f"{stitched_output}\n\n{latest_trimmed}".strip()
            if normalize_node_role(node_type) == "builder" and stitched_output:
                salvage = await self._builder_partial_text_salvage_result(
                    node=node,
                    input_data=input_data,
                    output_text=stitched_output,
                    reason=err,
                    on_progress=on_progress,
                    tool_results=[],
                    model_name=model_name,
                    mode="openai_compatible_chat_exception_salvage",
                    tool_call_stats={},
                )
                if salvage is not None:
                    return salvage
            logger.error(f"OpenAI-compatible chat error: {err}")
            return {"success": False, "output": "", "error": err}

    # ─────────────────────────────────────────
    # Path 2b: Agentic Loop (Think-Act-Observe)
    # ─────────────────────────────────────────

    def _agentic_loop_enabled(self) -> bool:
        """Check if the v3.0 AgenticLoop is enabled via feature flag."""
        if not _AGENTIC_RUNTIME_AVAILABLE:
            return False
        cfg = getattr(self, "config", {}) or {}
        if isinstance(cfg, dict) and cfg.get("agentic_loop"):
            return True
        return os.getenv("EVERMIND_AGENTIC_LOOP", "0").strip().lower() in {"1", "true", "yes"}

    async def _execute_agentic_loop(
        self,
        node: Dict,
        plugins: List,
        input_data: str,
        model_info: Dict,
        on_progress: Callable = None,
    ) -> Dict:
        """Execute a node using the AgenticLoop (Think-Act-Observe cycle).

        Full tool capabilities (11 registered):
        - file_read / file_write / file_list: Filesystem operations
        - file_edit: Precise string replacement (à la Claude Code FileEditTool)
        - grep_search: Pattern search via ripgrep
        - glob: Fast file pattern matching (**/*.js, etc.)
        - bash: Shell command execution (sandboxed, timeout 60s)
        - web_fetch: HTTP fetch + HTML→text (TLS verified)
        - web_search: DuckDuckGo-powered web search (no API key)
        - context_compress: Manual context compression trigger (L1/L2/L3)
        - multi_file_read: Batch file reading for efficiency

        Self-correction is limited to within the loop's iteration budget.
        """
        from agentic_runtime import AgenticLoop, LoopConfig, get_tool_registry
        from agentic_runtime import get_tools_for_role as _get_tools_for_role

        node_type = node.get("type", "builder")
        normalized_node_type = normalize_node_role(node_type)
        litellm_model = model_info["litellm_id"]
        max_tokens = self._max_tokens_for_node(
            node_type,
            retry_attempt=int(node.get("retry_attempt", 0)),
            node=node,
        )
        # v5.8.6 REDESIGN: hard cap 600s → 1800s. Trust the agent; only stop
        # if truly dead. Per-chunk stall + global watchdog handle real hangs.
        timeout_sec = min(self._effective_timeout_for_node(node_type, input_data, node=node), 1800.0)
        system_prompt = self._compose_system_prompt(node, plugins=plugins, input_data=input_data)
        system_prompt = self._mask_outbound_system_prompt(node, system_prompt)

        max_iterations, max_tool_calls = self._agentic_loop_limits(node_type, node=node)

        config = LoopConfig(
            max_iterations=max_iterations,
            max_tool_calls=max_tool_calls,
            timeout_seconds=timeout_sec,
            enable_thinking_trace=True,
            enable_sub_agents=False,
            enable_context_compression=True,
            node_type=normalized_node_type,
            node_key=str(node.get("key", node.get("id", ""))),
            model_name=litellm_model,
            allowed_tools=_get_tools_for_role(normalized_node_type),
        )

        # Build LLM call closure
        api_base = model_info.get("api_base", "")
        extra_headers = model_info.get("extra_headers")
        api_key_env = {"kimi": "KIMI_API_KEY", "qwen": "QWEN_API_KEY"}.get(model_info.get("provider"))
        api_key = None
        if api_key_env:
            api_key = (getattr(self, "config", {}) or {}).get(api_key_env.lower()) or os.getenv(api_key_env)

        async def llm_call(messages, tools=None, tool_choice=None):
            kwargs = {
                "model": litellm_model,
                "messages": self._prepare_messages_for_request(messages, litellm_model),
                "max_tokens": max_tokens,
                "timeout": min(timeout_sec, 120),
                "num_retries": 0,
            }
            # V4.3 PERF: Node-specific temperature
            _node_temp = self._temperature_for_node(normalized_node_type, litellm_model)
            if _node_temp is not None:
                kwargs["temperature"] = _node_temp
            if tools:
                # v6.1.6 (maintainer 2026-04-19): claim the 4th Anthropic cache
                # breakpoint on the tools array — static across the run, so
                # free compute savings (Cline anthropic.ts:L125 pattern).
                kwargs["tools"] = self._apply_tools_cache_breakpoint(tools, model=litellm_model)
                # v6.4.5: force file_ops for write-critical nodes
                kwargs["tool_choice"] = tool_choice or self._tool_choice_for_node(
                    normalized_node_type, tools, litellm_model
                )
            if api_base:
                kwargs["api_base"] = api_base
            if extra_headers:
                kwargs["extra_headers"] = extra_headers
            if api_key:
                kwargs["api_key"] = api_key

            resp = await self._litellm_stream_completion(**kwargs)
            msg = resp.choices[0].message

            # Convert tool_calls to serializable format
            tool_calls_raw = None
            if getattr(msg, "tool_calls", None):
                tool_calls_raw = []
                for tc in msg.tool_calls:
                    tool_calls_raw.append({
                        "id": getattr(tc, "id", f"tc_{id(tc)}"),
                        "function": {
                            "name": getattr(tc.function, "name", ""),
                            "arguments": getattr(tc.function, "arguments", "{}"),
                        },
                    })

            return {
                "message": {
                    "content": getattr(msg, "content", "") or "",
                    "tool_calls": tool_calls_raw,
                },
                "usage": self._normalize_usage(getattr(resp, "usage", None)),
            }

        # Event forwarding to UI
        async def on_event(event):
            if on_progress:
                try:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": f"agentic_{event.event_type}",
                        "iteration": event.data.get("iteration", 0),
                        "tool": event.data.get("tool", ""),
                        "detail": str(event.data.get("text", event.data.get("result_preview", "")))[:300],
                        "agentic_mode": True,
                    })
                except Exception:
                    pass

        tool_registry = get_tool_registry()
        loop = AgenticLoop(config, tool_registry, llm_call, on_event=on_event)

        logger.info(
            "Starting AgenticLoop for node=%s type=%s model=%s tools=%d max_iter=%d",
            config.node_key,
            normalized_node_type,
            litellm_model,
            len(tool_registry.list_tools(config.allowed_tools)),
            max_iterations,
        )

        if on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "agentic_loop_start",
                "model": litellm_model,
                "tools_count": len(tool_registry.list_tools(config.allowed_tools)),
                "max_iterations": max_iterations,
                "agentic_mode": True,
            })

        result = await loop.run(system_prompt, input_data)

        logger.info(
            "AgenticLoop completed: node=%s success=%s iterations=%d tool_calls=%d files_created=%d duration=%.1fs",
            config.node_key,
            result.get("success"),
            result.get("iterations", 0),
            sum(result.get("tool_call_stats", {}).values()),
            len(result.get("files_created", [])),
            result.get("duration_seconds", 0),
        )

        if on_progress:
            await self._emit_noncritical_progress(on_progress, {
                "stage": "agentic_loop_complete",
                "iterations": result.get("iterations", 0),
                "tool_calls": sum(result.get("tool_call_stats", {}).values()),
                "files_created": result.get("files_created", [])[:8],
                "files_modified": result.get("files_modified", [])[:8],
                "agentic_mode": True,
            })

        return {
            "success": result.get("success", False),
            "error": (
                f"Agentic loop exhausted: {result.get('exhaustion_reason', 'unknown')}"
                if not result.get("success", False) and result.get("exhausted")
                else ""
            ),
            "output": result.get("output", ""),
            "tool_results": result.get("tool_results", []),
            "model": litellm_model,
            "iterations": result.get("iterations", 0),
            "mode": "agentic_loop",
            "usage": result.get("usage", {}),
            "cost": self._estimate_response_cost(litellm_model, result.get("usage", {})),
            "tool_call_stats": result.get("tool_call_stats", {}),
            "files_created": result.get("files_created", []),
            "files_modified": result.get("files_modified", []),
            "context_compressions": result.get("context_compressions", {}),
            "exhausted": bool(result.get("exhausted", False)),
            "exhaustion_reason": str(result.get("exhaustion_reason", "") or ""),
        }

    # ─────────────────────────────────────────
    # Path 3: LiteLLM with Tool Calling
    # ─────────────────────────────────────────
    async def _execute_litellm_tools(self, node, plugins, input_data, model_info, on_progress) -> Dict:
        node_type = node.get("type", "builder")
        normalized_node_type = normalize_node_role(node_type)
        system_prompt = self._compose_system_prompt(node, plugins=plugins, input_data=input_data)
        system_prompt = self._mask_outbound_system_prompt(node, system_prompt)
        litellm_model = model_info["litellm_id"]
        max_tokens = self._max_tokens_for_node(
            node_type,
            retry_attempt=int(node.get("retry_attempt", 0)),
            node=node,
        )
        timeout_sec = self._effective_timeout_for_node(node_type, input_data, node=node)
        builder_has_written_file = False
        polisher_has_written_file = False
        builder_non_write_streak = 0
        polisher_non_write_streak = 0
        # v6.7 (see sibling path above for rationale)
        builder_full_rewrite_streak = 0
        builder_last_write_path = ""
        output_text = ""
        tool_results: List[Dict[str, Any]] = []
        tool_call_stats: Dict[str, int] = {}
        usage_totals: Dict[str, int] = {"prompt_tokens": 0, "completion_tokens": 0, "total_tokens": 0}
        total_cost = 0.0
        builder_support_snapshots: Dict[str, Dict[str, Any]] = {}
        max_continuations = self._read_int_env("EVERMIND_MAX_CONTINUATIONS", 2, 0, 5)

        # Build OpenAI-format tools from plugins
        # V4.5: Sort by name for stable prefix caching (same as openai_compatible path)
        tools = []
        for p in plugins:
            if p.name != "computer_use":
                defn = p.get_tool_definition()
                tools.append({"type": "function", "function": defn} if "function" not in defn else defn)
        tools.sort(key=lambda t: str((t.get("function") or {}).get("name") or ""))
        available_tool_names = self._tool_names_from_defs(tools)
        qa_browser_use_available = self._qa_browser_use_available(node_type, available_tool_names)

        # V4.6 SPEED: Inject builder deferred context into user message (litellm tool path)
        effective_litellm_input = input_data
        builder_deferred_litellm = getattr(self, "_builder_deferred_context", "")
        if builder_deferred_litellm and normalized_node_type == "builder":
            effective_litellm_input = (
                "=== REFERENCE MATERIAL ===\n"
                + builder_deferred_litellm
                + "\n=== END REFERENCE ===\n\n"
                + input_data
            )
            self._builder_deferred_context = ""
            logger.info(
                "Builder deferred context injected (litellm tool path): %d chars moved from system to user",
                len(builder_deferred_litellm),
            )
        messages = [{"role": "system", "content": system_prompt}, {"role": "user", "content": effective_litellm_input}]
        qa_task_type = self._classify_task_type(input_data)
        browser_action_events: List[Dict[str, Any]] = []
        await self._maybe_seed_qa_browser_use(
            node=node,
            node_type=node_type,
            task_type=qa_task_type,
            input_data=input_data,
            plugins=plugins,
            available_tool_names=available_tool_names,
            tool_results=tool_results,
            tool_call_stats=tool_call_stats,
            browser_action_events=browser_action_events,
            messages=messages,
            on_progress=on_progress,
        )
        await self._maybe_seed_qa_browser(
            node=node,
            node_type=node_type,
            task_type=qa_task_type,
            input_data=input_data,
            plugins=plugins,
            available_tool_names=available_tool_names,
            tool_results=tool_results,
            tool_call_stats=tool_call_stats,
            browser_action_events=browser_action_events,
            messages=messages,
            on_progress=on_progress,
        )

        if on_progress:
            await self._emit_noncritical_progress(
                on_progress,
                {"stage": "calling_ai", "model": litellm_model, "tools_count": len(tools)},
            )

        try:
            # V4.6 SPEED: Inject cache breakpoints for litellm_tools path too
            _prepared_msgs = self._inject_prompt_cache_breakpoints(
                self._prepare_messages_for_request(messages, litellm_model)
            )
            kwargs = {
                "model": litellm_model,
                "messages": _prepared_msgs,
                "timeout": timeout_sec,
                "num_retries": 0,
                "max_tokens": max_tokens,
            }
            if tools:
                kwargs["tools"] = tools
                # v6.4.5: force file_ops for write-critical nodes
                kwargs["tool_choice"] = self._tool_choice_for_node(
                    normalized_node_type, tools, litellm_model
                )
            if model_info.get("api_base"):
                # Allow env-based override for relay/proxy users
                provider = model_info.get("provider", "")
                env_base_key = self._provider_api_base_env_key(provider)
                env_base = os.getenv(env_base_key, "") if env_base_key else ""
                kwargs["api_base"] = env_base if env_base else model_info["api_base"]
            if model_info.get("extra_headers"):
                kwargs["extra_headers"] = model_info["extra_headers"]
            api_key_env = self._provider_api_key_env_key(model_info.get("provider", ""))
            if api_key_env:
                kwargs["api_key"] = self.config.get(api_key_env.lower()) or os.getenv(api_key_env)

            async def _force_builder_text_timeout_fallback(reason: str) -> Optional[Dict[str, Any]]:
                nonlocal output_text, usage_totals, total_cost
                if normalized_node_type != "builder" or builder_has_written_file:
                    return None
                tool_result_text = self._builder_tool_result_salvage_text(tool_results, input_data)
                disk_result_text = self._builder_disk_salvage_text(
                    input_data,
                    incremental_text=output_text,
                )
                combined_salvage_text = "\n\n".join(
                    part for part in (tool_result_text, disk_result_text) if str(part or "").strip()
                )
                output_text = self._select_builder_salvage_text(
                    "",
                    output_text,
                    tool_result_text=combined_salvage_text,
                )

                async def _request_builder_continuation(cont_messages):
                    cont_kwargs = dict(kwargs)
                    cont_kwargs.pop("tools", None)
                    cont_kwargs.pop("tool_choice", None)
                    cont_kwargs["messages"] = self._prepare_messages_for_request(cont_messages, litellm_model)
                    return await self._litellm_stream_completion(**cont_kwargs)

                output_text, _, cont_resp = await self._attempt_builder_game_text_continuation(
                    output_text=output_text,
                    input_data=input_data,
                    system_prompt=system_prompt,
                    continuation_count=0,
                    max_continuations=1,
                    request_continuation=_request_builder_continuation,
                    on_progress=on_progress,
                    log_prefix="Builder timeout salvage (litellm)",
                )
                if cont_resp is not None:
                    usage_totals = self._merge_usage(usage_totals, getattr(cont_resp, "usage", None))
                    total_cost += self._estimate_litellm_cost(cont_resp, litellm_model)

                salvage = await self._builder_partial_text_salvage_result(
                    node=node,
                    input_data=input_data,
                    output_text=output_text,
                    reason=reason or "prewrite_call_timeout",
                    on_progress=on_progress,
                    tool_results=tool_results,
                    model_name=litellm_model,
                    mode="litellm_tools_partial_timeout_salvage",
                    usage=usage_totals,
                    cost=total_cost,
                    tool_call_stats=tool_call_stats,
                )
                if salvage is not None:
                    return salvage
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, reason or "prewrite_call_timeout"),
                    )
                forced_messages = self._builder_forced_text_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    reason or "prewrite_call_timeout",
                )
                forced_timeout = self._read_int_env(
                    "EVERMIND_BUILDER_FORCED_TEXT_TIMEOUT_SEC",
                    45,
                    15,
                    120,
                )
                final_kwargs = dict(kwargs)
                final_kwargs.pop("tools", None)
                final_kwargs.pop("tool_choice", None)
                final_kwargs["messages"] = self._prepare_messages_for_request(forced_messages, litellm_model)
                try:
                    final_resp = await asyncio.wait_for(
                        self._litellm_stream_completion(**final_kwargs),
                        timeout=forced_timeout,
                    )
                except Exception as fallback_exc:
                    salvage = await self._builder_partial_text_salvage_result(
                        node=node,
                        input_data=input_data,
                        output_text=output_text,
                        reason=fallback_exc,
                        on_progress=on_progress,
                        tool_results=tool_results,
                        model_name=litellm_model,
                        mode="litellm_tools_partial_timeout_salvage",
                        usage=usage_totals,
                        cost=total_cost,
                        tool_call_stats=tool_call_stats,
                    )
                    if salvage is not None:
                        return salvage
                    logger.warning(
                        "Builder forced text fallback (litellm) after timeout failed: %s",
                        _sanitize_error(str(fallback_exc)),
                    )
                    return None
                final_msg = final_resp.choices[0].message
                final_content = getattr(final_msg, "content", "") or ""
                if not final_content.strip():
                    return await self._builder_partial_text_salvage_result(
                        node=node,
                        input_data=input_data,
                        output_text=output_text,
                        reason=reason or "forced_text_empty",
                        on_progress=on_progress,
                        tool_results=tool_results,
                        model_name=litellm_model,
                        mode="litellm_tools_partial_timeout_salvage",
                        usage=usage_totals,
                        cost=total_cost,
                        tool_call_stats=tool_call_stats,
                    )
                await self._publish_partial_output(on_progress, final_content, phase="finalizing")
                merged_usage = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                merged_cost = total_cost + self._estimate_litellm_cost(final_resp, litellm_model)
                return {
                    "success": True,
                    "output": final_content,
                    "tool_results": tool_results,
                    "model": litellm_model,
                    "iterations": 0,
                    "mode": "litellm_tools_forced_text_timeout",
                    "usage": merged_usage,
                    "cost": merged_cost,
                    "tool_call_stats": dict(tool_call_stats),
                }

            async def _await_completion(current_kwargs):
                call = self._litellm_stream_completion(**current_kwargs)
                timeout = 0
                if normalized_node_type == "builder" and not builder_has_written_file:
                    timeout = self._builder_prewrite_call_timeout(node_type, input_data, node=node)
                    if builder_non_write_streak > 0:
                        repair_timeout = self._builder_repair_write_timeout(node_type, input_data, node=node)
                        timeout = min(timeout, repair_timeout)
                elif normalized_node_type == "polisher" and not polisher_has_written_file:
                    timeout = self._polisher_prewrite_call_timeout(node_type, input_data)
                if timeout <= 0:
                    return await call
                try:
                    return await asyncio.wait_for(call, timeout=timeout)
                except asyncio.TimeoutError as exc:
                    if normalized_node_type == "builder":
                        raise TimeoutError(
                            f"builder pre-write timeout after {timeout}s: no real file write or tool progress was produced."
                        ) from exc
                    if normalized_node_type == "polisher":
                        raise TimeoutError(
                            f"polisher pre-write timeout after {timeout}s: no real file write was produced."
                        ) from exc
                    raise

            response = await _await_completion(kwargs)

            iteration = 0
            max_iterations = (
                self._max_tool_iterations_for_node(node_type, node=node)
                if normalized_node_type in {"builder", "polisher"}
                else self._read_int_env("EVERMIND_LITELLM_MAX_TOOL_ITERS", 40, 1, 100)
            )
            usage_totals = self._normalize_usage(getattr(response, "usage", None))
            total_cost = self._estimate_litellm_cost(response, litellm_model)
            continuation_count = 0
            builder_non_write_streak = 0
            builder_force_text_early = False
            builder_force_reason = ""
            builder_force_threshold = self._builder_force_text_threshold(input_data)
            builder_repair_prompts_sent = 0
            polisher_non_write_streak = 0
            polisher_force_threshold = self._polisher_force_write_threshold(input_data)
            polisher_loop_guard_reason = ""
            polisher_repair_prompts_sent = 0
            polisher_force_write_grace_available = False
            polisher_force_write_grace_used = False
            # v6.4.58 (maintainer 2026-04-23) — PATCHER loop guard. Observed
            # Apr 23 14:54-15:00: patcher spun 42+ tool iters in 6 min,
            # messages=80, all 0 content / no write. Tighter than
            # polisher since patcher tasks are small targeted edits.
            patcher_non_write_streak = 0
            patcher_has_written_file = False
            # v6.4.59 (maintainer 2026-04-23): threshold 8→5. Patcher should
            # diff + apply within 3 tool calls; 5 is the pain threshold.
            _PATCHER_LOOP_GUARD_THRESHOLD = 10  # v7.20a (maintainer 2026-04-28): 5→10. Read-heavy patchers (need to scan large root before fix) were tripping at 5 even when about to write. 10 keeps the runaway-loop guarantee while letting careful patchers locate the fix site.
            patcher_loop_guard_reason = ""
            qa_followup_count = 0
            analyst_followup_count = 0
            review_format_followup_count = 0
            plain_text_force_reason = ""
            # v6.1.12: edit-miss loop tracker (CUA path mirror of primary loop).
            edit_failures_by_path: Dict[str, int] = {}
            edit_rewrite_prompts_sent: set = set()
            edit_loop_break_reason = ""

            while iteration < max_iterations:
                iteration += 1
                msg = response.choices[0].message
                msg_content = getattr(msg, "content", "") or ""
                if msg.tool_calls and msg_content:
                    output_text += msg.content

                # Check for tool calls
                if not msg.tool_calls:
                    candidate_plain_text_output = output_text + (msg_content or "")
                    if self._plain_text_node_output_is_materializable(node_type, candidate_plain_text_output):
                        if msg_content:
                            output_text = candidate_plain_text_output
                        break
                    analyst_followup_reason = self._analyst_browser_followup_reason(
                        node_type,
                        tool_call_stats,
                        tool_results,
                        available_tool_names=available_tool_names,
                    )
                    if analyst_followup_reason and analyst_followup_count < 2 and tools:
                        analyst_followup_count += 1
                        if msg_content:
                            messages.append({"role": "assistant", "content": msg_content})
                        messages.append({
                            "role": "user",
                            "content": self._analyst_browser_followup_message(analyst_followup_reason),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "analyst_followup",
                                "message": analyst_followup_reason,
                                "continuation": analyst_followup_count,
                            })
                        kwargs["messages"] = self._prepare_messages_for_request(messages, litellm_model)
                        response = await _await_completion(kwargs)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        total_cost += self._estimate_litellm_cost(response, litellm_model)
                        continue
                    followup_reason = self._review_browser_followup_reason(
                        node_type,
                        qa_task_type,
                        browser_action_events,
                        input_data,
                        tool_call_stats=tool_call_stats,
                        available_tool_names=available_tool_names,
                    )
                    if followup_reason and qa_followup_count < 2 and tools:
                        qa_followup_count += 1
                        if msg_content:
                            messages.append({"role": "assistant", "content": msg_content})
                        messages.append({
                            "role": "user",
                            "content": self._review_browser_followup_message(followup_reason, qa_task_type),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "qa_followup",
                                "message": followup_reason,
                                "continuation": qa_followup_count,
                            })
                        kwargs["messages"] = self._prepare_messages_for_request(messages, litellm_model)
                        response = await _await_completion(kwargs)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        total_cost += self._estimate_litellm_cost(response, litellm_model)
                        continue
                    format_followup_reason = self._review_output_format_followup_reason(
                        node_type,
                        msg_content,
                    )
                    if format_followup_reason and review_format_followup_count < 2:
                        review_format_followup_count += 1
                        if msg_content:
                            messages.append({"role": "assistant", "content": msg_content})
                        messages.append({
                            "role": "user",
                            "content": self._review_output_format_followup_message(format_followup_reason),
                        })
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "review_format_followup",
                                "message": format_followup_reason,
                                "continuation": review_format_followup_count,
                            })
                        kwargs["messages"] = self._prepare_messages_for_request(messages, litellm_model)
                        response = await _await_completion(kwargs)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        total_cost += self._estimate_litellm_cost(response, litellm_model)
                        continue
                    if msg_content:
                        output_text += msg_content
                    if self._asset_plan_output_complete(node_type, output_text):
                        break
                    break

                messages.append(self._serialize_assistant_message(msg))
                pending_repair_prompts: List[str] = []
                for tc in msg.tool_calls:
                    fn_name = tc.function.name
                    fn_args = tc.function.arguments
                    parsed_args = self._safe_json_object(fn_args)
                    _tool_call_start_ts = time.time()
                    if on_progress:
                        await self._emit_noncritical_progress(
                            on_progress,
                            self._tool_execution_progress_payload(fn_name, parsed_args),
                        )
                    if fn_name in {"browser", "browser_use"} and self._desktop_qa_browser_suppressed(node_type, input_data):
                        result = {
                            "success": False,
                            "data": {},
                            "error": (
                                "Desktop QA evidence already exists for this reviewer/tester pass. "
                                "Use the provided Evermind internal QA record instead of opening browser/browser_use."
                            ),
                            "artifacts": [],
                        }
                    elif fn_name == "browser" and self._should_block_browser_call(node_type, tool_call_stats, node=node):
                        limit = (
                            self._polisher_browser_call_limit(node=node)
                            if normalized_node_type == "polisher"
                            else self._analyst_browser_call_limit(node=node)
                        )
                        node_label = "Polisher" if normalized_node_type == "polisher" else "Analyst"
                        guidance = (
                            "Stop browsing and write concrete file improvements now."
                            if normalized_node_type == "polisher"
                            else "Skip additional browsing and summarize from collected insights."
                        )
                        result = {
                            "success": False,
                            "data": {},
                            "error": (
                                f"{node_label} browser call limit reached ({limit}). "
                                f"{guidance}"
                            ),
                            "artifacts": [],
                        }
                    elif fn_name == "source_fetch" and self._should_block_source_fetch_call(node_type, tool_call_stats, node=node):
                        # v6.3 (maintainer 2026-04-20): enforce per-tool cap on source_fetch
                        # for analyst so tutorial search can't diverge indefinitely.
                        _sf_limit = self._analyst_source_fetch_call_limit(node=node)
                        logger.info(
                            "Analyst source_fetch cap reached (%d) — forcing synthesis",
                            _sf_limit,
                        )
                        result = {
                            "success": False,
                            "data": {},
                            "error": (
                                f"Analyst source_fetch cap reached ({_sf_limit} fetches). "
                                "You have enough material — synthesize the final report from "
                                "what you already fetched. Do NOT call source_fetch again; "
                                "produce the report with all required XML tags now."
                            ),
                            "artifacts": [],
                        }
                    elif fn_name == "file_ops" and normalized_node_type in ("analyst", "scribe", "uidesign"):
                        parsed_block_args = self._safe_json_object(fn_args)
                        block_action = str(parsed_block_args.get("action", "")).strip().lower()
                        if block_action in ("write", "edit"):
                            result = {
                                "success": False,
                                "data": {},
                                "error": self._plain_text_node_write_guard_error(normalized_node_type),
                                "artifacts": [],
                            }
                            plain_text_force_reason = plain_text_force_reason or "blocked_file_write"
                            logger.warning(
                                "Blocked file_ops write/edit for %s node (CUA path)",
                                normalized_node_type,
                            )
                        else:
                            result = await self._run_plugin(
                                fn_name,
                                fn_args,
                                plugins,
                                node_type=node_type,
                                node=node,
                            )
                    else:
                        if fn_name == "file_ops":
                            self._builder_capture_prewrite_snapshot(
                                node=node,
                                input_data=input_data,
                                tool_action=str(parsed_args.get("action", "")).strip().lower(),
                                parsed_args=parsed_args,
                                snapshot_cache=builder_support_snapshots,
                            )
                        result = await self._run_plugin(
                            fn_name,
                            fn_args,
                            plugins,
                            node_type=node_type,
                            node=node,
                        )
                    # V4.2: Enrich tool result for report trace table
                    if isinstance(result, dict):
                        result.setdefault("tool", fn_name)
                        result.setdefault("started_at", _tool_call_start_ts)
                        result.setdefault("duration_ms", int((time.time() - _tool_call_start_ts) * 1000) if _tool_call_start_ts else 0)
                        # V4.2 FIX (Codex #3): inject args for ALL tools
                        result.setdefault("args", parsed_args)
                    tool_results.append(result)
                    tool_call_stats[fn_name] = tool_call_stats.get(fn_name, 0) + 1
                    tool_action = (
                        self._infer_file_ops_action(fn_args, result)
                        if fn_name == "file_ops"
                        else str(parsed_args.get("action", "")).strip().lower()
                    )
                    if fn_name == "file_ops":
                        result = self._builder_guard_html_write_result(
                            node=node,
                            input_data=input_data,
                            tool_action=tool_action,
                            result=result,
                            snapshot_cache=builder_support_snapshots,
                        )
                    if fn_name == "browser":
                        browser_data = result.get("data", {}) if isinstance(result, dict) else {}
                        if not isinstance(browser_data, dict):
                            browser_data = {}
                        browser_event = {
                            "action": tool_action or parsed_args.get("action") or "unknown",
                            "subaction": browser_data.get("subaction"),
                            "intent": browser_data.get("intent"),
                            "ok": bool(result.get("success", False)) if isinstance(result, dict) else False,
                            "url": browser_data.get("url"),
                            "target": browser_data.get("target"),
                            "observation": browser_data.get("observation"),
                            "snapshot_refs_preview": browser_data.get("snapshot_refs_preview", []),
                            "snapshot_ref_count": browser_data.get("snapshot_ref_count", 0),
                            "state_hash": browser_data.get("state_hash"),
                            "previous_state_hash": browser_data.get("previous_state_hash"),
                            "state_changed": bool(browser_data.get("state_changed", False)),
                            "scroll_y": browser_data.get("scroll_y", 0),
                            "viewport_height": browser_data.get("viewport_height", 0),
                            "page_height": browser_data.get("page_height", 0),
                            "at_page_top": bool(browser_data.get("at_page_top", False)),
                            "at_page_bottom": bool(browser_data.get("at_page_bottom", False)),
                            "keys_count": browser_data.get("keys_count", 0),
                            "console_error_count": browser_data.get("console_error_count", 0),
                            "page_error_count": browser_data.get("page_error_count", 0),
                            "failed_request_count": browser_data.get("failed_request_count", 0),
                            "recent_console_errors": browser_data.get("recent_console_errors", []),
                            "recent_page_errors": browser_data.get("recent_page_errors", []),
                            "browser_mode": browser_data.get("browser_mode"),
                            "requested_mode": browser_data.get("requested_mode"),
                            "launch_note": browser_data.get("launch_note"),
                            "error": (result.get("error") if isinstance(result, dict) else "") or "",
                        }
                        browser_action_events.append(browser_event)
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "browser_action",
                                "plugin": "browser",
                                **browser_event,
                            })
                    elif fn_name == "browser_use":
                        browser_use_events = self._browser_use_action_events(result)
                        for browser_event in browser_use_events:
                            browser_action_events.append(browser_event)
                            if on_progress:
                                await self._emit_noncritical_progress(on_progress, {
                                    "stage": "browser_action",
                                    "plugin": "browser_use",
                                    **browser_event,
                                })
                    repair_prompt = None
                    wrote_file = False
                    if fn_name == "file_ops":
                        wrote_file = self._tool_result_has_write(result)
                    normalized_node_type = normalize_node_role(node_type)
                    # v6.1.13: merger shares builder's write-streak tracking.
                    # Observed real run where merger wasted 4.5min in a read
                    # loop before `tool_iterations_exhausted` fired and
                    # switched to direct_text. The streak counter + tighter
                    # break threshold (see below) force the switch earlier.
                    if normalized_node_type in {"builder", "merger"}:
                        if wrote_file:
                            # v6.7 full-rewrite detection (see init comment).
                            try:
                                _wr_path = ""
                                if isinstance(result, dict):
                                    _data_v67 = result.get("data")
                                    if isinstance(_data_v67, dict):
                                        _wr_path = str(_data_v67.get("path") or "").strip()
                                if (
                                    builder_has_written_file
                                    and _wr_path
                                    and _wr_path.lower().endswith((".html", ".htm"))
                                ):
                                    try:
                                        from pathlib import Path as _FPv67
                                        _sz_v67 = _FPv67(_wr_path).stat().st_size
                                    except Exception:
                                        _sz_v67 = 0
                                    if _sz_v67 >= 10000:
                                        if (not builder_last_write_path) or _wr_path == builder_last_write_path:
                                            builder_full_rewrite_streak += 1
                                        else:
                                            builder_full_rewrite_streak = 1
                                    else:
                                        builder_full_rewrite_streak = 0
                                if _wr_path:
                                    builder_last_write_path = _wr_path
                            except Exception:
                                pass
                            builder_has_written_file = True
                            builder_non_write_streak = 0
                            if on_progress:
                                write_path = ""
                                if isinstance(result, dict):
                                    data = result.get("data")
                                    if isinstance(data, dict):
                                        write_path = str(data.get("path") or "").strip()
                                metrics = self._written_file_code_metrics(write_path)
                                await self._emit_noncritical_progress(on_progress, {
                                    "stage": "builder_write",
                                    "plugin": fn_name,
                                    "path": write_path,
                                    **metrics,
                                })
                        else:
                            # Count all non-write tool turns so malformed file_ops args
                            # cannot bypass the loop guard.
                            builder_non_write_streak += 1
                    else:
                        if normalized_node_type == "polisher":
                            if wrote_file:
                                polisher_has_written_file = True
                                polisher_non_write_streak = 0
                            else:
                                polisher_non_write_streak += 1
                        if wrote_file and on_progress:
                            write_path = ""
                            if isinstance(result, dict):
                                data = result.get("data")
                                if isinstance(data, dict):
                                    write_path = str(data.get("path") or "").strip()
                            metrics = self._written_file_code_metrics(write_path)
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "artifact_write",
                                "plugin": fn_name,
                                "path": write_path,
                                "agent": normalized_node_type or node_type,
                                "writer": normalized_node_type or node_type,
                                **metrics,
                            })
                    if fn_name == "file_ops" and normalized_node_type == "builder" and builder_repair_prompts_sent < 2:
                        repair_prompt = self._builder_tool_repair_prompt(input_data, tool_action, result)
                        if not repair_prompt and not wrote_file:
                            repair_prompt = self._builder_non_write_followup_prompt(
                                input_data,
                                tool_action,
                                result,
                                builder_non_write_streak,
                            )
                    elif normalized_node_type == "polisher" and polisher_repair_prompts_sent < 2 and not wrote_file:
                        repair_prompt = self._polisher_non_write_followup_prompt(
                            fn_name,
                            tool_action,
                            result,
                            polisher_non_write_streak,
                        )
                    # v6.1.12: edit-miss escalation (CUA path).
                    if (
                        fn_name == "file_ops"
                        and normalized_node_type in {"merger", "builder", "polisher", "debugger"}
                    ):
                        _total_ef, _per_path_ef, _ef_path = self._register_edit_failure(
                            edit_failures_by_path, tool_action, parsed_args, result
                        )
                        if (
                            _per_path_ef >= 2
                            and _ef_path
                            and _ef_path not in edit_rewrite_prompts_sent
                        ):
                            edit_rewrite_prompts_sent.add(_ef_path)
                            escalation = self._edit_rewrite_escalation_prompt(
                                _ef_path, _per_path_ef, _total_ef
                            )
                            if escalation and escalation not in pending_repair_prompts:
                                pending_repair_prompts.append(escalation)
                                logger.warning(
                                    "file_ops edit miss streak on %s (per-path=%s, total=%s) — nudging %s to full rewrite (litellm)",
                                    _ef_path, _per_path_ef, _total_ef, normalized_node_type,
                                )
                                if on_progress:
                                    await self._emit_noncritical_progress(on_progress, {
                                        "stage": "edit_rewrite_escalation",
                                        "path": _ef_path,
                                        "per_path_failures": _per_path_ef,
                                        "total_failures": _total_ef,
                                        "node": normalized_node_type,
                                    })
                        if _total_ef >= 3:
                            edit_loop_break_reason = (
                                f"file_ops edit-miss loop: {_total_ef} failed edits "
                                f"across {len(edit_failures_by_path)} path(s)"
                            )
                    # Truncate tool output to prevent token overflow
                    result_str = json.dumps(result)
                    _tool_char_limit = MAX_ANALYST_TOOL_RESULT_CHARS if normalized_node_type == "analyst" else MAX_TOOL_RESULT_CHARS
                    if len(result_str) > _tool_char_limit:
                        result_str = result_str[:_tool_char_limit] + '... [TRUNCATED]'
                    # v7.3.9 audit-fix CRITICAL — mirror tool-result PII mask.
                    try:
                        _ob_masker = get_masker()
                        if _ob_masker and getattr(_ob_masker, "enabled", True) and not (node_type in getattr(_ob_masker, "exclude_node_types", set())):
                            _masked_rs, _rs_restore = _ob_masker.mask(result_str, node_type=node_type)
                            if _rs_restore:
                                result_str = _masked_rs
                                _existing = node.setdefault("_outbound_restore_map", {})
                                _existing.update(_rs_restore)
                    except Exception:
                        pass
                    messages.append({"role": "tool", "tool_call_id": tc.id, "content": result_str})
                    if repair_prompt and repair_prompt not in pending_repair_prompts:
                        pending_repair_prompts.append(repair_prompt)
                        if normalized_node_type == "builder":
                            builder_repair_prompts_sent += 1
                        elif normalized_node_type == "polisher":
                            polisher_repair_prompts_sent += 1
                            if fn_name == "file_ops" and not polisher_force_write_grace_used:
                                polisher_force_write_grace_available = True

                if pending_repair_prompts:
                    messages.append({"role": "user", "content": "\n\n".join(pending_repair_prompts)})

                if (
                    normalized_node_type in {"analyst", "scribe", "uidesign"}
                    and plain_text_force_reason == "blocked_file_write"
                ):
                    logger.info(
                        "Plain-text node blocked from file_ops write (litellm) — ending tool loop and switching to final no-tool synthesis (%s)",
                        normalized_node_type,
                    )
                    break

                if (
                    normalize_node_role(node_type) == "builder"
                    and builder_non_write_streak >= builder_force_threshold
                    and not any(self._tool_result_has_write(tr) for tr in tool_results)
                ):
                    builder_force_text_early = True
                    builder_force_reason = "tool_research_loop"
                    logger.info(
                        "Builder loop guard triggered (litellm): non-write tool streak=%s (threshold=%s)",
                        builder_non_write_streak,
                        builder_force_threshold,
                    )
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "builder_loop_guard",
                            "streak": builder_non_write_streak,
                            "threshold": builder_force_threshold,
                            "reason": builder_force_reason,
                        })
                    break

                # v6.1.14: post-write read-loop guard (litellm path mirror).
                if (
                    normalize_node_role(node_type) in {"builder", "merger"}
                    and builder_has_written_file
                    and builder_non_write_streak >= 4
                ):
                    builder_force_text_early = True
                    builder_force_reason = "post_write_read_loop"
                    logger.info(
                        "Builder post-write read loop guard triggered (litellm): non-write streak=%s after first write",
                        builder_non_write_streak,
                    )
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "builder_post_write_loop_guard",
                            "node": normalize_node_role(node_type),
                            "streak": builder_non_write_streak,
                            "reason": builder_force_reason,
                        })
                    break

                # v6.1.12: edit-miss loop bailout (litellm path).
                if (
                    edit_loop_break_reason
                    and normalized_node_type in {"merger", "builder", "polisher", "debugger"}
                ):
                    logger.warning(
                        "%s terminated tool loop early (litellm): %s",
                        normalized_node_type,
                        edit_loop_break_reason,
                    )
                    if normalized_node_type == "builder":
                        builder_force_text_early = True
                        builder_force_reason = "edit_miss_loop"
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "edit_loop_break",
                            "node": normalized_node_type,
                            "reason": edit_loop_break_reason,
                            "paths": list(edit_failures_by_path.keys()),
                        })
                    break

                if (
                    normalized_node_type == "polisher"
                    and not polisher_has_written_file
                    and polisher_non_write_streak >= polisher_force_threshold
                ):
                    if polisher_force_write_grace_available and not polisher_force_write_grace_used:
                        polisher_force_write_grace_available = False
                        polisher_force_write_grace_used = True
                        logger.info(
                            "Polisher force-write grace granted (litellm): non-write tool streak=%s (threshold=%s)",
                            polisher_non_write_streak,
                            polisher_force_threshold,
                        )
                        if on_progress:
                            await self._emit_noncritical_progress(on_progress, {
                                "stage": "polisher_force_write_warning",
                                "streak": polisher_non_write_streak,
                                "threshold": polisher_force_threshold,
                                "message": "Polisher inspection limit reached; one final response is allowed to obey the forced-write prompt.",
                            })
                        kwargs["messages"] = self._prepare_messages_for_request(messages, litellm_model)
                        response = await _await_completion(kwargs)
                        usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                        total_cost += self._estimate_litellm_cost(response, litellm_model)
                        continue
                    polisher_loop_guard_reason = (
                        "polisher loop guard triggered after "
                        f"{polisher_non_write_streak} non-write tool iterations without any file write."
                    )
                    logger.warning("%s (litellm)", polisher_loop_guard_reason)
                    if on_progress:
                        await self._emit_noncritical_progress(on_progress, {
                            "stage": "polisher_loop_guard",
                            "streak": polisher_non_write_streak,
                            "threshold": polisher_force_threshold,
                            "reason": polisher_loop_guard_reason,
                        })
                    break

                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        {"stage": "continuing", "iteration": iteration},
                    )
                kwargs["messages"] = self._prepare_messages_for_request(messages, litellm_model)
                response = await _await_completion(kwargs)
                usage_totals = self._merge_usage(usage_totals, getattr(response, "usage", None))
                total_cost += self._estimate_litellm_cost(response, litellm_model)

            if polisher_loop_guard_reason:
                # v6.1.14f: mirror of openai_compat path — allow polisher skip
                # when builder output was already high-quality and no edits made.
                _polisher_skip_ok_ll = (
                    normalize_node_role(node_type) == "polisher"
                    and any(self._tool_result_has_write(tr) for tr in tool_results) is False
                )
                return self._attach_browser_action_events({
                    "success": _polisher_skip_ok_ll,
                    "output": output_text or "Polish skipped: existing artifact already meets quality bar (no edits needed).",
                    "tool_results": tool_results,
                    "model": litellm_model,
                    "iterations": iteration,
                    "mode": "litellm_tools",
                    "usage": usage_totals,
                    "cost": total_cost,
                    "tool_call_stats": dict(tool_call_stats),
                    "error": "" if _polisher_skip_ok_ll else polisher_loop_guard_reason,
                    "warning": polisher_loop_guard_reason if _polisher_skip_ok_ll else "",
                    "qa_browser_use_available": qa_browser_use_available,
                }, browser_action_events)

            force_text_reason = ""
            if self._builder_needs_forced_text(node_type, output_text, tool_results):
                if builder_force_text_early:
                    force_text_reason = builder_force_reason or "tool_research_loop"
                elif iteration >= max_iterations:
                    force_text_reason = "tool_iterations_exhausted"
                else:
                    force_text_reason = "no_html_or_file_output"

            if force_text_reason:
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, force_text_reason),
                    )
                final_messages = self._builder_forced_text_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    force_text_reason,
                )
                final_kwargs = dict(kwargs)
                final_kwargs.pop("tools", None)
                final_kwargs.pop("tool_choice", None)
                final_kwargs["messages"] = self._prepare_messages_for_request(final_messages, litellm_model)
                final_resp = await _await_completion(final_kwargs)
                final_msg = final_resp.choices[0].message
                if final_msg.content:
                    output_text += final_msg.content
                    await self._publish_partial_output(on_progress, output_text, phase="finalizing")
                usage_totals = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                total_cost += self._estimate_litellm_cost(final_resp, litellm_model)

            plain_text_final_reason = ""
            if self._plain_text_node_needs_forced_output(node_type, output_text, tool_results):
                if plain_text_force_reason:
                    plain_text_final_reason = plain_text_force_reason
                elif iteration >= max_iterations:
                    plain_text_final_reason = "tool_iterations_exhausted"
                else:
                    plain_text_final_reason = "missing_final_handoff"

            if plain_text_final_reason:
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, plain_text_final_reason),
                    )
                final_messages = self._plain_text_node_forced_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    node_type,
                    plain_text_final_reason,
                )
                final_kwargs = dict(kwargs)
                final_kwargs.pop("tools", None)
                final_kwargs.pop("tool_choice", None)
                final_kwargs["messages"] = self._prepare_messages_for_request(final_messages, litellm_model)
                final_resp = await _await_completion(final_kwargs)
                final_msg = final_resp.choices[0].message
                final_content = str(final_msg.content or "").strip()
                if final_content:
                    if output_text and not output_text.endswith("\n"):
                        output_text += "\n"
                    output_text += final_content
                    await self._publish_partial_output(on_progress, output_text, phase="finalizing")
                usage_totals = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                total_cost += self._estimate_litellm_cost(final_resp, litellm_model)

            reviewer_force_reason = ""
            if self._reviewer_needs_forced_verdict(node_type, output_text, tool_results):
                reviewer_force_reason = (
                    self._review_output_format_followup_reason(node_type, output_text)
                    or "missing_reviewer_verdict_json"
                )

            if reviewer_force_reason:
                if on_progress:
                    await self._emit_noncritical_progress(
                        on_progress,
                        self._forcing_text_progress_payload(node_type, reviewer_force_reason),
                    )
                final_messages = self._reviewer_forced_verdict_messages(
                    system_prompt,
                    input_data,
                    tool_results,
                    output_text,
                    reviewer_force_reason,
                )
                final_kwargs = dict(kwargs)
                final_kwargs.pop("tools", None)
                final_kwargs.pop("tool_choice", None)
                final_kwargs["messages"] = self._prepare_messages_for_request(final_messages, litellm_model)
                final_resp = await _await_completion(final_kwargs)
                final_msg = final_resp.choices[0].message
                final_content = str(final_msg.content or "").strip()
                if (
                    final_content
                    and self._review_output_format_followup_reason(node_type, final_content) is None
                ):
                    output_text = final_content
                    await self._publish_partial_output(on_progress, output_text, phase="finalizing")
                usage_totals = self._merge_usage(usage_totals, getattr(final_resp, "usage", None))
                total_cost += self._estimate_litellm_cost(final_resp, litellm_model)

            if normalized_node_type == "builder":
                tool_result_text = self._builder_tool_result_salvage_text(tool_results, input_data)
                disk_result_text = self._builder_disk_salvage_text(
                    input_data,
                    incremental_text=output_text,
                )
                combined_salvage_text = "\n\n".join(
                    part for part in (tool_result_text, disk_result_text) if str(part or "").strip()
                )
                preferred_output = self._select_builder_salvage_text(
                    "",
                    output_text,
                    tool_result_text=combined_salvage_text,
                )
                if (
                    preferred_output
                    and preferred_output != output_text
                    and self._builder_partial_text_is_salvageable(input_data, preferred_output)
                ):
                    output_text = preferred_output
                    await self._publish_partial_output(on_progress, output_text, phase="finalizing")

                async def _request_builder_continuation(cont_messages):
                    cont_kwargs = dict(kwargs)
                    cont_kwargs.pop("tools", None)
                    cont_kwargs.pop("tool_choice", None)
                    cont_kwargs["messages"] = self._prepare_messages_for_request(cont_messages, litellm_model)
                    return await self._litellm_stream_completion(**cont_kwargs)

                output_text, continuation_count, cont_resp = await self._attempt_builder_game_text_continuation(
                    output_text=output_text,
                    input_data=input_data,
                    system_prompt=system_prompt,
                    continuation_count=continuation_count,
                    max_continuations=max_continuations,
                    request_continuation=_request_builder_continuation,
                    on_progress=on_progress,
                    log_prefix="Builder text-mode (litellm)",
                )
                if cont_resp is not None:
                    usage_totals = self._merge_usage(usage_totals, getattr(cont_resp, "usage", None))
                    total_cost += self._estimate_litellm_cost(cont_resp, litellm_model)

                saved_paths = await self._auto_save_builder_text_output(
                    output_text=output_text,
                    input_data=input_data,
                    node=node,
                    tool_results=tool_results,
                    tool_call_stats=tool_call_stats,
                    on_progress=on_progress,
                )
                if saved_paths:
                    builder_has_written_file = True
                elif (
                    not builder_has_written_file
                    and not self._builder_text_output_has_persistable_html(output_text, input_data)
                ):
                    # v6.1.3 (maintainer 2026-04-19): only fail on narration if the
                    # builder truly hasn't written anything. If file_ops.write
                    # tool_call already landed a real artifact earlier in the
                    # loop, narration-only final assistant content is a natural
                    # "done, here's what I did" signoff — not a failure. GLM-5.1
                    # specifically tends to narrate after successful writes.
                    failure_msg = self._builder_non_deliverable_output_reason(output_text, input_data)
                    logger.warning("%s (litellm)", failure_msg)
                    return self._attach_browser_action_events({
                        "success": False,
                        "output": output_text,
                        "tool_results": tool_results,
                        "model": litellm_model,
                        "iterations": iteration,
                        "mode": "litellm_tools",
                        "usage": usage_totals,
                        "cost": total_cost,
                        "tool_call_stats": dict(tool_call_stats),
                        "error": failure_msg,
                        "qa_browser_use_available": qa_browser_use_available,
                    }, browser_action_events)

            return self._attach_browser_action_events(
                {"success": True, "output": output_text, "tool_results": tool_results,
                 "model": litellm_model, "iterations": iteration, "mode": "litellm_tools", "usage": usage_totals, "cost": total_cost,
                 "tool_call_stats": tool_call_stats, "qa_browser_use_available": qa_browser_use_available},
                browser_action_events,
            )
        except Exception as e:
            err = _sanitize_error(str(e))
            if normalized_node_type == "builder" and not builder_has_written_file and "timeout" in err.lower():
                fallback = await _force_builder_text_timeout_fallback(err)
                if fallback is not None:
                    return fallback
            logger.error(f"LiteLLM tools error: {_sanitize_error(str(e))}")
            return self._attach_browser_action_events(
                {"success": False, "output": "", "error": err},
                locals().get("browser_action_events"),
            )

    # ─────────────────────────────────────────
    # Path 3: LiteLLM Direct Chat
    # ─────────────────────────────────────────
    async def _execute_litellm_chat(self, node, input_data, model_info, on_progress) -> Dict:
        system_prompt = self._compose_system_prompt(node, input_data=input_data)
        system_prompt = self._mask_outbound_system_prompt(node, system_prompt)
        node_type = node.get("type", "builder")
        litellm_model = model_info["litellm_id"]
        max_tokens = self._max_tokens_for_node(
            node_type,
            retry_attempt=int(node.get("retry_attempt", 0)),
            node=node,
        )
        # v5.8.6 REDESIGN: 240s → 900s (same philosophy as openai_compatible path).
        timeout_sec = min(self._effective_timeout_for_node(node_type, input_data, node=node), 900)
        direct_multifile = (
            normalize_node_role(node_type) == "builder"
            and str(node.get("builder_delivery_mode") or "").strip().lower() == "direct_multifile"
        )
        if direct_multifile:
            max_tokens, timeout_sec = self._builder_direct_multifile_budget(
                input_data,
                max_tokens=max_tokens,
                timeout_sec=timeout_sec,
            )

        if on_progress:
            await self._emit_noncritical_progress(
                on_progress,
                {"stage": "calling_ai", "model": litellm_model, "tools_count": 0},
            )

        try:
            kwargs_base = {
                "model": litellm_model,
                "timeout": timeout_sec,
                "num_retries": 0,
                "max_tokens": max_tokens,
            }
            # V4.3 PERF: Node-specific temperature
            _node_temp = self._temperature_for_node(node_type, litellm_model)
            if _node_temp is not None:
                kwargs_base["temperature"] = _node_temp
            if model_info.get("api_base"):
                provider = model_info.get("provider", "")
                env_base_key = self._provider_api_base_env_key(provider)
                env_base = os.getenv(env_base_key, "") if env_base_key else ""
                kwargs_base["api_base"] = env_base if env_base else model_info["api_base"]
            if model_info.get("extra_headers"):
                kwargs_base["extra_headers"] = model_info["extra_headers"]
            api_key_env = self._provider_api_key_env_key(model_info.get("provider", ""))
            if api_key_env:
                kwargs_base["api_key"] = self.config.get(api_key_env.lower()) or os.getenv(api_key_env)

            async def _call_chat(current_messages: List[Dict[str, str]]):
                kwargs = dict(kwargs_base)
                # V4.6 SPEED: Inject cache breakpoints for litellm_chat path
                # v6.1.5 (Opus A N3): pass model so Anthropic detection works.
                kwargs["messages"] = self._inject_prompt_cache_breakpoints(
                    self._prepare_messages_for_request(current_messages, litellm_model),
                    model=litellm_model,
                )
                return await self._litellm_stream_completion(**kwargs)

            # V4.6 SPEED: Inject builder deferred context (litellm chat path)
            effective_litellm_chat_input = input_data
            builder_deferred_lc = getattr(self, "_builder_deferred_context", "")
            if builder_deferred_lc and normalize_node_role(node_type) == "builder":
                effective_litellm_chat_input = (
                    "=== REFERENCE MATERIAL ===\n"
                    + builder_deferred_lc
                    + "\n=== END REFERENCE ===\n\n"
                    + input_data
                )
                self._builder_deferred_context = ""
                logger.info(
                    "Builder deferred context injected (litellm chat path): %d chars",
                    len(builder_deferred_lc),
                )
            response = await _call_chat([
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": effective_litellm_chat_input},
            ])
            usage = self._normalize_usage(getattr(response, "usage", None))
            total_cost = self._estimate_litellm_cost(response, litellm_model)
            output_parts: List[str] = []
            content = response.choices[0].message.content or ""
            if content:
                output_parts.append(content)
                await self._publish_partial_output(on_progress, content, phase="drafting")

            continuation_limit = (
                self._read_int_env("EVERMIND_BUILDER_DIRECT_MULTIFILE_CONTINUATIONS", 2, 0, 4)
                if direct_multifile
                else 0
            )
            continuation_count = 0
            while direct_multifile and continuation_count < continuation_limit:
                combined_output = "\n\n".join(part for part in output_parts if str(part).strip())
                remaining_targets = self._builder_missing_html_targets(input_data, combined_output)
                if not remaining_targets:
                    break
                previous_remaining = list(remaining_targets)
                if on_progress:
                    await self._emit_noncritical_progress(on_progress, {
                        "stage": "builder_multifile_continue",
                        "continuation": continuation_count + 1,
                        "remaining_targets": remaining_targets[:12],
                        "finish_reason": self._response_finish_reason(response),
                    })
                response = await _call_chat(
                    self._builder_direct_multifile_continuation_messages(
                        system_prompt,
                        input_data,
                        combined_output,
                        remaining_targets,
                    )
                )
                usage = self._merge_usage(usage, getattr(response, "usage", None))
                total_cost += self._estimate_litellm_cost(response, litellm_model)
                continuation_count += 1
                continuation_content = response.choices[0].message.content or ""
                if not continuation_content.strip():
                    break
                output_parts.append(continuation_content)
                await self._publish_partial_output(on_progress, continuation_content, phase="finalizing")
                next_remaining = self._builder_missing_html_targets(
                    input_data,
                    "\n\n".join(output_parts),
                )
                if len(next_remaining) >= len(previous_remaining) and self._response_finish_reason(response).lower() not in {"length", "max_tokens"}:
                    break

            final_output = "\n\n".join(part for part in output_parts if str(part).strip()).strip()
            if normalize_node_role(node_type) == "builder":
                saved_paths, tool_results, tool_call_stats, failure_msg = await self._finalize_builder_chat_output(
                    output_text=final_output,
                    input_data=input_data,
                    node=node,
                    tool_results=[],
                    tool_call_stats={},
                    on_progress=on_progress,
                )
                if failure_msg:
                    logger.warning("Builder LiteLLM chat returned non-deliverable output: %s", failure_msg)
                    return {
                        "success": False,
                        "output": final_output,
                        "error": failure_msg,
                        "model": litellm_model,
                        "tool_results": tool_results,
                        "mode": "litellm_chat",
                        "usage": usage,
                        "cost": total_cost,
                        "tool_call_stats": tool_call_stats,
                    }
                logger.info(
                    "Builder LiteLLM chat auto-saved %s file(s) from direct text output: %s",
                    len(saved_paths),
                    saved_paths[:6],
                )
                return {
                    "success": True,
                    "output": final_output,
                    "model": litellm_model,
                    "tool_results": tool_results,
                    "mode": "litellm_chat",
                    "usage": usage,
                    "cost": total_cost,
                    "tool_call_stats": tool_call_stats,
                }
            return {"success": True, "output": final_output,
                    "model": litellm_model, "tool_results": [], "mode": "litellm_chat",
                    "usage": usage,
                    "cost": total_cost}
        except Exception as e:
            logger.error(f"LiteLLM chat error: {_sanitize_error(str(e))}")
            return {"success": False, "output": "", "error": _sanitize_error(str(e))}

    # ─────────────────────────────────────────
    # Fallback: Direct OpenAI
    # ─────────────────────────────────────────
    async def _execute_openai_direct(self, node, plugins, input_data, on_progress) -> Dict:
        client = await self._get_openai()
        if not client:
            return {"success": False, "output": "", "error": "No AI backend available"}
        system_prompt = self._compose_system_prompt(node, plugins=plugins, input_data=input_data)
        system_prompt = self._mask_outbound_system_prompt(node, system_prompt)
        try:
            response = await client.chat.completions.create(
                model="gpt-4o", messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": input_data}
                ]
            )
            await self._publish_partial_output(on_progress, response.choices[0].message.content or "", phase="drafting")
            usage = self._normalize_usage(getattr(response, "usage", None))
            cost = self._estimate_litellm_cost(response, "gpt-4o") if self._litellm else self._estimate_response_cost("gpt-4o", usage)
            return {"success": True, "output": response.choices[0].message.content, "model": "gpt-4o", "tool_results": [], "mode": "openai_direct",
                    "usage": usage, "cost": cost}
        except Exception as e:
            return {"success": False, "output": "", "error": _sanitize_error(str(e))}

    # ─────────────────────────────────────────
    # Helpers
    # ─────────────────────────────────────────
    async def _run_plugin(
        self,
        name: str,
        args,
        plugins: List[Plugin],
        node_type: str = "",
        node: Optional[Dict[str, Any]] = None,
    ) -> Dict:
        # Enforce per-node plugin allowlist.
        normalized_node_type = normalize_node_role(node_type) or str(node_type or "").strip().lower()
        plugin = next((p for p in plugins if p and p.name == name), None)
        if not plugin:
            return {"error": f"Plugin {name} not enabled for this node"}
        if args is None:
            parsed: Dict[str, Any] = {}
        elif isinstance(args, str):
            try:
                parsed_obj = json.loads(args)
            except json.JSONDecodeError:
                # Keep plugin call alive even with malformed tool args.
                parsed_obj = {}
            parsed = parsed_obj if isinstance(parsed_obj, dict) else {"value": parsed_obj}
        elif isinstance(args, dict):
            parsed = args
        else:
            parsed = {"value": args}
        parsed = self._apply_qa_browser_tool_defaults(name, node_type, parsed)

        plugin_context = dict(self.config or {})
        force_visible = str(
            plugin_context.get(
                "reviewer_tester_force_headful",
                os.getenv("EVERMIND_REVIEWER_TESTER_FORCE_HEADFUL", "0"),
            )
        ).strip().lower() in ("1", "true", "yes", "on")
        # v6.1.3: uidesign also benefits from headful + overlay (the user wants
        # to watch the AI inspect reference sites). Keep browser/uicontrol too.
        _visible_browser_nodes = ("reviewer", "tester", "uidesign", "browser", "uicontrol")
        if name in {"browser", "browser_use"} and normalized_node_type not in _visible_browser_nodes:
            plugin_context.pop("browser_headful", None)
            plugin_context.pop("browser_force_reason", None)
        if name == "browser" and force_visible and normalized_node_type in ("reviewer", "tester", "uidesign"):
            plugin_context["browser_headful"] = True
            plugin_context["browser_force_reason"] = f"{normalized_node_type}_visible_review"
        # v7.11 (maintainer 2026-04-28): EXPLICITLY force headless for reviewer/
        # tester unless EVERMIND_REVIEWER_TESTER_FORCE_HEADFUL is set.
        # User reported "reviewer 打开外部浏览器之前还是会先打开内部浏览器" — the
        # second visible Chromium window confused them. Default operation
        # MUST be backend headless (no visible window), with the reviewer's
        # browser tool driven invisibly via Playwright. Visible mode kept
        # only as opt-in for power users debugging review failures.
        if name in ("browser", "browser_use") and not force_visible \
                and normalized_node_type in ("reviewer", "tester"):
            plugin_context["browser_headful"] = False
        if name == "browser":
            node_meta = node if isinstance(node, dict) else {}
            plugin_context["node_type"] = normalized_node_type or node_type
            plugin_context["node_execution_id"] = str(node_meta.get("node_execution_id") or "").strip()
            plugin_context["run_id"] = str(node_meta.get("run_id") or "").strip()
            plugin_context["browser_save_evidence"] = normalized_node_type in ("reviewer", "tester")
            action = str(parsed.get("action", "navigate") or "navigate").strip().lower()
            url = str(parsed.get("url") or "").strip()
            if normalized_node_type == "analyst" and action == "navigate" and self._is_local_preview_or_nonweb_url(url):
                return {
                    "success": False,
                    "data": {},
                    "error": (
                        "Analyst browser research must use external implementation sources only. "
                        "Do not open localhost, /preview/, or blank URLs."
                    ),
                    "artifacts": [],
                    "_plugin": name,
                }
        if name == "browser_use":
            node_meta = node if isinstance(node, dict) else {}
            plugin_context["node_type"] = normalized_node_type or node_type
            plugin_context["node_execution_id"] = str(node_meta.get("node_execution_id") or "").strip()
            plugin_context["run_id"] = str(node_meta.get("run_id") or "").strip()
            plugin_context["output_dir"] = str(
                node_meta.get("output_dir")
                or plugin_context.get("output_dir")
                or self._current_output_dir()
            ).strip()
            # v5.8.1: browser_use pays a 30-50% latency tax for headful mode
            # (UI rendering + display I/O + GPU init). The reviewer/tester
            # force-visible flag was designed for the internal BrowserPlugin
            # (Playwright-level screenshot evidence), NOT for browser_use's
            # agentic loop which already captures per-step screenshots.
            # Force headless here unless the user explicitly asked for headful
            # via EVERMIND_BROWSER_USE_FORCE_HEADFUL=1.
            _bu_force_headful = str(os.getenv("EVERMIND_BROWSER_USE_FORCE_HEADFUL", "0")).strip().lower() in ("1", "true", "yes", "on")
            if _bu_force_headful:
                plugin_context["browser_headful"] = True
                plugin_context["browser_force_reason"] = "user_opt_in_headful"
            else:
                # Override any upstream force-visible — browser_use screenshots
                # work fine headless and run 30-50% faster.
                plugin_context["browser_headful"] = False
        if name == "file_ops":
            node_meta = node if isinstance(node, dict) else {}
            plugin_context["file_ops_node_type"] = normalized_node_type or node_type
            plugin_context["node_execution_id"] = str(node_meta.get("node_execution_id") or "").strip()
            # v6.1.7: expose original user goal + task brief so file_ops
            # validators (e.g. 3D-vs-2D contract check) can cite them.
            goal_text = str(node_meta.get("goal") or node_meta.get("user_goal") or "").strip()
            if goal_text:
                plugin_context["goal"] = goal_text
            task_desc = str(node_meta.get("task") or node_meta.get("task_description") or "").strip()
            if task_desc:
                plugin_context["task_description"] = task_desc
            output_dir = str(
                node_meta.get("output_dir")
                or plugin_context.get("output_dir")
                or self._current_output_dir()
            ).strip()
            if output_dir:
                plugin_context["file_ops_output_dir"] = output_dir
            if normalized_node_type in ("reviewer", "tester", "deployer", "analyst", "scribe", "uidesign"):
                plugin_context["file_ops_mode"] = "read_only"
            elif normalized_node_type == "builder":
                builder_output_dir = str(
                    node_meta.get("builder_file_ops_output_dir")
                    or node_meta.get("builder_staging_output_dir")
                    or node_meta.get("output_dir")
                    or plugin_context.get("output_dir")
                    or self._current_output_dir()
                ).strip()
                if builder_output_dir:
                    plugin_context["file_ops_output_dir"] = builder_output_dir
                allowed_html_targets = node_meta.get("allowed_html_targets") or node_meta.get("file_ops_allowed_html_targets") or []
                if isinstance(allowed_html_targets, list) and allowed_html_targets:
                    plugin_context["file_ops_allowed_html_targets"] = [
                        str(item).strip()
                        for item in allowed_html_targets
                        if str(item).strip()
                    ]
                plugin_context["file_ops_write_token"] = str(
                    node_meta.get("file_ops_write_token")
                    or node_meta.get("write_token")
                    or ""
                ).strip()
                plugin_context["file_ops_can_write_root_index"] = bool(
                    node_meta.get("can_write_root_index")
                    or node_meta.get("file_ops_can_write_root_index")
                )
                plugin_context["file_ops_enforce_html_targets"] = bool(
                    node_meta.get("enforce_html_targets")
                    or node_meta.get("file_ops_enforce_html_targets")
                )
                plugin_context["file_ops_require_existing_artifact_read"] = bool(
                    node_meta.get("builder_existing_artifact_patch_mode")
                    or node_meta.get("file_ops_require_existing_artifact_read")
                )
                # v6.1.3 (maintainer 2026-04-19): propagate patch-only mode flag to
                # file_ops so write actions get BLOCKED during reviewer-rejection
                # retries. Forces builder to use action=edit only, preventing
                # regression from full-file rewrites losing existing features.
                plugin_context["file_ops_patch_only_mode"] = bool(
                    node_meta.get("builder_existing_artifact_patch_mode")
                    or node_meta.get("file_ops_patch_only_mode")
                )
                required_read_targets = node_meta.get("builder_patch_required_read_targets") or []
                if isinstance(required_read_targets, list) and required_read_targets:
                    plugin_context["file_ops_required_read_targets"] = [
                        str(item).strip()
                        for item in required_read_targets
                        if str(item).strip()
                    ]

        result = await plugin.execute(parsed, context=plugin_context)
        if result is None:
            return {"error": f"Plugin {name} returned no result"}
        if hasattr(result, "to_dict"):
            payload = result.to_dict()
        elif isinstance(result, dict):
            payload = result
        else:
            payload = {"ok": True, "data": str(result)}
        if isinstance(payload, dict):
            payload.setdefault("_plugin", name)
        return payload


# ─────────────────────────────────────────────
# Handoff Manager
# ─────────────────────────────────────────────
class HandoffManager:
    """Agent-to-agent task delegation (OpenAI Agents SDK pattern)."""

    def __init__(self, ai_bridge: AIBridge):
        self.ai_bridge = ai_bridge

    async def handoff(self, from_node: Dict, to_node_type: str, task: str,
                      all_nodes: List[Dict], on_progress: Callable = None) -> Dict:
        target = next((n for n in all_nodes if n["type"] == to_node_type), None)
        if not target:
            return {"success": False, "error": f"No {to_node_type} node found"}
        if on_progress:
            await self.ai_bridge._emit_noncritical_progress(
                on_progress,
                {
                    "stage": "handoff",
                    "from": from_node.get("name", ""),
                    "to": target.get("name", ""),
                    "task": task[:100],
                },
            )
        enabled = resolve_enabled_plugins_for_node(
            to_node_type,
            explicit_plugins=target.get("plugins"),
            config=self.ai_bridge.config,
        )
        plugins = [PluginRegistry.get(p) for p in enabled if PluginRegistry.get(p)]
        return await self.ai_bridge.execute(node=target, plugins=plugins,
                                            input_data=f"[Handoff from {from_node.get('name', '?')}] {task}", on_progress=on_progress)
